INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('897ca680-0c3a-4a29-a051-a510f2dffb5d', '2025-10-08T22:47:11.935298', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding hypertension management. Blood pressure was 148/92 mmHg, and heart rate was 78 bpm. Physical examination was unremarkable except for a BMI indicating obesity. Advised continuation of antihypertensive medication and lifestyle modifications including dietary changes and regular physical activity. Recommended further monitoring of blood glucose levels due to prediabetes status and scheduled a lipid panel for the next visit to assess hyperlipidemia management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('897ca680-0c3a-4a29-a051-a510f2dffb5d', '2025-07-01T22:47:11.935298', 'Consultation', 'Patient presented for routine consultation to manage hypertension. Blood pressure was measured at 145/88 mmHg and heart rate at 78 bpm. Noted elevated blood pressure and discussed lifestyle modifications, including dietary changes and increased physical activity. Recommended continuation of current antihypertensive medication, review of lipid panel, and follow-up in three months to reassess blood pressure and metabolic parameters.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('3545d194-d796-43a7-971d-6066c7a37dc4', '2025-11-17T22:47:15.204858', 'Emergency Visit', 'Patient presented to the emergency department with acute exacerbation of asthma, experiencing shortness of breath and wheezing. On examination, respiratory rate was 28 breaths per minute, heart rate 110 bpm, and O2 saturation 92% on room air. Patient''s symptoms were consistent with an asthma flare possibly triggered by ongoing hay fever. Albuterol nebulizer treatment was initiated with significant improvement in respiratory distress. Recommended follow-up with primary care provider for asthma management and continuation of antihistamines for hay fever control.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('3545d194-d796-43a7-971d-6066c7a37dc4', '2025-08-09T22:47:15.204858', 'Follow-up Visit', 'Patient presented for follow-up regarding hay fever and asthma management. Reported persistent nasal congestion and occasional wheezing, especially during recent pollen increase. Vitals were stable: BP 98/60 mmHg, HR 88 bpm, RR 20 breaths/min. Physical examination revealed nasal mucosa swelling, but clear lungs upon auscultation. Continued antihistamine and inhaler use was recommended, with a plan to review symptoms in three months or sooner if exacerbation occurs.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('3545d194-d796-43a7-971d-6066c7a37dc4', '2025-07-06T22:47:15.204858', 'Consultation', 'Patient presented for consultation regarding worsening hay fever symptoms. Physical examination revealed mild nasal congestion and watery eyes. Patient''s vitals were stable: BP 110/70 mmHg, HR 78 bpm, respiratory rate 18 breaths/min, SpO2 98% on room air. Assessment: Seasonal allergic rhinitis exacerbated by environmental allergens. Recommended starting a daily antihistamine and advised on allergen avoidance strategies. Follow-up in 4 weeks or sooner if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('0e7f32f0-3f03-4d43-aa76-9c4213aab909', '2026-01-03T22:47:20.926718', 'Urgent Care', 'Patient presented for acute abdominal pain and nausea. Vitals: BP 142/88 mmHg, HR 88 bpm, Temp 98.6°F. Physical examination revealed mild tenderness in the epigastric region, no guarding or rebound tenderness. Assessment: Possible gastritis exacerbated by underlying GERD; consider peptic ulcer disease. Recommended continuation of proton pump inhibitors and advised dietary modifications. Referral to oncology for further evaluation of cancer-related symptoms was made. Follow-up in two weeks or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('0e7f32f0-3f03-4d43-aa76-9c4213aab909', '2025-07-31T22:47:20.926718', 'Follow-up Visit', 'Patient presented for a follow-up visit concerning ongoing cancer management. Vital signs: BP 138/82 mmHg, HR 78 bpm, weight stable. Patient reported persistent fatigue and mild nausea, controlled with current antiemetic regimen. Physical examination revealed no new abnormalities. Recommended continuation of current oncologic treatment plan and scheduled routine imaging to assess disease progression. Advised patient to maintain dietary modifications for GERD management and to monitor blood pressure regularly.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b2f9484d-e41b-47be-977c-507728221448', '2025-11-05T22:47:24.929988', 'Follow-up Visit', 'Patient presented for follow-up of strep pharyngitis. Vital signs were stable, with BP at 110/70 mmHg and HR at 78 bpm. Throat examination showed mild erythema with no exudate. Patient reported improvement in sore throat and no fever. Assessment: resolving strep pharyngitis. Plan: advised to complete the current antibiotic course and maintain hydration. Discussed lifestyle modifications for obesity management, including dietary changes and increased physical activity. Recommended follow-up in four weeks to reassess weight management progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b2f9484d-e41b-47be-977c-507728221448', '2025-09-22T22:47:24.929988', 'Annual Checkup', 'Patient presented for an annual checkup with a current condition of strep pharyngitis. Vital signs were as follows: BP 118/76 mmHg, HR 82 bpm, Temp 100.2°F. Physical examination revealed erythematous pharynx with tonsillar exudates. Assessment confirmed ongoing strep pharyngitis, and the patient was advised to complete the current course of antibiotics. Given medical history of obesity, dietary modifications and increased physical activity were recommended to achieve a healthier BMI. Follow-up in three months for weight management progress was advised.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b2f9484d-e41b-47be-977c-507728221448', '2025-03-25T22:47:24.929988', 'Follow-up Visit', 'Patient presented for follow-up of strep pharyngitis. Vitals were stable: BP 110/70 mmHg, HR 78 bpm, Temp 98.6°F. Throat examination revealed mild erythema with no exudates, and lymphadenopathy has resolved. Patient has completed the course of antibiotics with significant symptom improvement. Advised continuation of supportive care and follow-up with nutritionist regarding obesity management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('46fe9322-4372-4452-9f9a-fa1efd65caa2', '2025-12-30T22:47:30.444083', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding asthma management. Vital signs were stable: BP 132/80 mmHg, HR 76 bpm, SpO2 96% on room air. The patient reported experiencing increased wheezing and night-time coughing episodes over the past two weeks. Assessment revealed suboptimal asthma control likely triggered by seasonal changes. Recommended adjusting inhaler dosage and advised on proper inhaler technique. Additionally, reviewed adherence to current GERD and antihypertensive medications. Follow-up in 3 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('46fe9322-4372-4452-9f9a-fa1efd65caa2', '2025-10-10T22:47:30.444083', 'Follow-up Visit', 'Patient presented for follow-up of chronic conditions. Blood pressure was 138/82 mmHg, heart rate 78 bpm, respiratory rate 18 breaths per minute, and oxygen saturation 96% on room air. She reported increased dyspnea and wheezing over the past week, particularly at night. Examination revealed bilateral expiratory wheezes. Asthma was assessed as uncontrolled; recommended adjustment of inhaler regimen to include a low-dose ICS-LABA combination. Advised continuation of current antihypertensive and GERD medications, and follow-up in 3 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('46fe9322-4372-4452-9f9a-fa1efd65caa2', '2025-06-26T22:47:30.444083', 'Consultation', 'Patient presented for routine follow-up and management of asthma and hypertension. Vital signs were stable: BP 132/78 mmHg, HR 72 bpm, RR 18 breaths/min, SpO2 96% on room air. The patient reported occasional wheezing and shortness of breath, particularly at night. Physical examination revealed mild wheezing on auscultation. Recommended continuation of inhaled corticosteroid therapy and advised adding a leukotriene receptor antagonist for better asthma control. Advised dietary modifications and regular exercise to manage GERD and osteoarthritis symptoms. Follow-up in 3 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('46fe9322-4372-4452-9f9a-fa1efd65caa2', '2025-05-02T22:47:30.444083', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 132/78 mmHg, heart rate 78 bpm, and respiratory rate 18 breaths per minute. Patient reported occasional shortness of breath, particularly during exertion, attributed to asthma. On examination, lungs were clear with no wheezing noted. Osteoarthritic changes in the knees were noted with mild discomfort on palpation. Recommended continuation of current asthma management plan and advised on weight management to alleviate joint stress. Encouraged to monitor blood pressure regularly and follow up in 6 months for hypertension assessment.', NULL);
