VALUES ('acedb1d1-8144-403c-b35c-6748c8d86b24', '2025-09-29T22:47:39.675697', 'Follow-up Visit', 'Patient presented for a follow-up visit and general checkup. Vitals were stable: HR 110 bpm, RR 30 breaths/min, temperature 98.6°F. Skin examination revealed mild dry patches consistent with eczema, no signs of infection or significant flare-ups. Assessment: Eczema well-controlled. Plan: Continue current emollient therapy and avoidance of known triggers; follow-up in 6 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('91659b80-3865-4cfe-8c0e-977aa6b6df9e', '2025-12-06T22:47:43.055434', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding diabetes management. Blood pressure was 138/85 mmHg, and heart rate was 78 bpm. The patient reported occasional dizziness and increased joint pain, primarily in the knees and hips. Recommended continuing current medications, including metformin and lisinopril, and advised weight management through a low-carbohydrate diet and regular low-impact exercise. Consider referral to a physical therapist for osteoarthritis management if symptoms persist. Follow-up scheduled in three months to reassess blood glucose levels and evaluate symptom progression.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('91659b80-3865-4cfe-8c0e-977aa6b6df9e', '2025-10-24T22:47:43.055434', 'Urgent Care', 'Patient presented for evaluation of acute right knee pain exacerbated over the past 48 hours. Vitals: BP 148/92 mmHg, HR 78 bpm, Temp 98.6°F. Examination revealed mild swelling and tenderness over the medial aspect of the right knee with limited range of motion due to pain. Assessment: Likely osteoarthritis flare. Recommended NSAIDs for pain management, application of ice, and advised follow-up with primary care for potential physical therapy referral. Blood glucose levels were checked and advised to continue monitoring closely due to diabetic status.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('91659b80-3865-4cfe-8c0e-977aa6b6df9e', '2025-06-20T22:47:43.055434', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding diabetes management. Blood pressure was 138/85 mmHg, heart rate was 78 bpm, and fasting blood glucose was 145 mg/dL. Patient reported increased joint pain, particularly in the knees, consistent with osteoarthritis. Advised on dietary modifications for better glycemic control and recommended continuation of metformin. Suggested physical therapy consultation to address osteoarthritis symptoms and discussed potential adjustment of antihypertensive therapy.', NULL);
