INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('34cc2518-2be0-4873-9c26-0a1ad0373264', '2025-09-29T22:47:48.790674', 'Urgent Care', 'Patient presented for chest discomfort experienced over the past 48 hours. Blood pressure was elevated at 158/92 mmHg, and heart rate was 88 bpm. Examination revealed no acute distress but noted mild dyspnea on exertion. Assessment indicated potential angina; the patient was advised to undergo an ECG and laboratory tests, including lipid panel and cardiac enzymes. Recommended follow-up with a cardiologist and advised continuation of antihypertensive and statin therapy.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
