INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5d3fe652-626b-4291-b2f7-2e176bc08446', '2025-10-24T22:48:15.691795', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 142/88 mmHg, HR 78 bpm. Notable for persistent erythematous rash on both forearms, consistent with contact dermatitis; patient reports itching and mild discomfort. Assessment revealed stable osteoarthritis and well-controlled GERD, but obesity and hypertension require ongoing management. Continued current medications for hypertension and hyperlipidemia; advised lifestyle modifications for weight management and prediabetes. Prescribed topical corticosteroid for dermatitis. Follow-up in 6 months or sooner if symptoms worsen.', NULL);
