VALUES ('5d3fe652-626b-4291-b2f7-2e176bc08446', '2025-10-04T22:48:15.691795', 'Annual Checkup', 'Patient presented for an annual checkup with ongoing management of contact dermatitis. Vital signs noted: BP 140/85 mmHg, HR 78 bpm. Exam revealed mild erythematous patches on the forearms consistent with dermatitis; no signs of infection. Assessment included well-managed hypertension and hyperlipidemia, with recommendations to continue current medications. Advised continuation of topical corticosteroids for dermatitis, dietary modifications for GERD, and regular physical activity to address obesity and prediabetes. Follow-up in six months for routine monitoring and management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
