INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5d3fe652-626b-4291-b2f7-2e176bc08446', '2024-08-19T22:48:15.691795', 'Follow-up Visit', 'Patient presented for follow-up of contact dermatitis and management of chronic conditions. Blood pressure was 138/86 mmHg, heart rate was 78 bpm. Erythematous rash on bilateral forearms noted, consistent with contact dermatitis, without signs of secondary infection. Continued use of topical corticosteroid cream recommended; advised to avoid known irritants. Discussed lifestyle modifications for weight management and reinforced adherence to antihypertensive and lipid-lowering medications. Follow-up in three months for reassessment of dermatitis and chronic condition management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('0b805433-79ce-443d-a13c-c3bc85ae5390', '2025-11-14T22:48:24.528968', 'Urgent Care', 'Patient presented for acute abdominal pain, localized to the right upper quadrant, worsening over the past 24 hours. Vital signs: BP 128/82 mmHg, HR 88 bpm, afebrile. Physical examination revealed tenderness on palpation over the gallbladder region, no rebound tenderness noted. Assessment: Suspected acute cholecystitis secondary to gallstones. Plan: Recommended ultrasound imaging of the abdomen for further evaluation, prescribed pain management with acetaminophen, and advised follow-up with gastroenterology for potential surgical intervention.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('0b805433-79ce-443d-a13c-c3bc85ae5390', '2025-06-18T22:48:24.528968', 'Urgent Care', 'Patient presented for acute right upper quadrant abdominal pain ongoing for 48 hours, radiating to the back, associated with nausea and vomiting. Vital signs were stable: BP 128/82 mmHg, HR 88 bpm, RR 16 breaths/min, Temp 98.6°F. Physical examination revealed tenderness in the right upper quadrant with a positive Murphy''s sign. Assessment indicated likely biliary colic secondary to gallstones. Recommended abdominal ultrasound for further evaluation and advised dietary modifications to avoid fatty foods. Prescribed analgesics for pain management and antiemetics for nausea. Follow-up with gastroenterology was suggested for further management options, including potential cholecystectomy.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('0b805433-79ce-443d-a13c-c3bc85ae5390', '2025-02-14T22:48:24.528968', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were stable with BP at 118/76 mmHg and HR at 72 bpm. Patient reported occasional right upper quadrant pain, likely related to known gallstones, with no acute distress noted. Recommended continued monitoring of gallstones and adherence to dietary modifications, with referral to gastroenterology for further evaluation. Advised to continue current management for asthma and GERD, and prescribed loratadine for seasonal hay fever symptoms. Follow-up in one year or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('879ae6fc-7f6b-442d-8237-87deab9e4e34', '2026-02-11T22:48:29.751868', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding asthma management. Vitals were stable: BP 118/75 mmHg, HR 72 bpm, SpO2 98% on room air. The patient reported increased frequency of wheezing and nocturnal cough over the past month, despite adherence to her current inhaled corticosteroid regimen. Assessment indicated poorly controlled asthma, likely exacerbated by seasonal allergens. Plan included adjusting asthma medication to a higher-dose inhaled corticosteroid and recommending continued use of a rescue inhaler as needed. Advised to schedule an appointment with an allergist for further evaluation of allergic rhinitis management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('879ae6fc-7f6b-442d-8237-87deab9e4e34', '2025-10-23T22:48:29.751868', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were within normal limits: BP 118/76 mmHg, HR 72 bpm, SpO2 98% on room air. She reported experiencing increased frequency of asthma symptoms, particularly at night, and occasional migraines. Physical examination revealed clear lung fields and no acute distress. Assessment included stable asthma, controlled allergic rhinitis, and episodic migraines. Recommended optimization of asthma management with an updated action plan, continuation of current migraine prophylaxis, and advised annual influenza vaccination. Follow-up scheduled in 6 months or sooner if symptoms exacerbate.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('879ae6fc-7f6b-442d-8237-87deab9e4e34', '2025-06-20T22:48:29.751868', 'Consultation', 'Patient presented for routine asthma management and evaluation of recent migraine episodes. Vitals were stable: BP 118/76 mmHg, HR 72 bpm, SpO2 98% on room air. Physical examination revealed clear lung fields upon auscultation. Assessment: Well-controlled asthma with mild intermittent symptoms; migraines increasing in frequency. Plan: Continue current asthma management with albuterol PRN, initiate prophylactic treatment for migraines with topiramate, and follow up in 3 months to reassess symptoms. Advised patient on trigger avoidance for both asthma and migraines.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('bd38ac07-c71c-415f-8238-f68b9ab03163', '2025-10-03T22:48:34.863882', 'Follow-up Visit', 'Patient presented for follow-up of allergic rhinitis. Symptoms included nasal congestion and intermittent sneezing, with no reports of fever. Physical examination revealed clear nasal discharge and mild nasal mucosal edema. Recommended continuation of current antihistamine therapy and advised environmental modifications to minimize allergen exposure. Follow-up scheduled in 6 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('bd38ac07-c71c-415f-8238-f68b9ab03163', '2025-07-08T22:48:34.863882', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were within normal limits: BP 90/60 mmHg, HR 88 bpm, Temp 98.5°F, RR 20 breaths/min. Patient continued to experience nasal congestion and sneezing consistent with allergic rhinitis, but no additional symptoms were reported. Advised continuation of current antihistamine therapy and recommended follow-up in one year or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('bd38ac07-c71c-415f-8238-f68b9ab03163', '2025-06-25T22:48:34.863882', 'Emergency Visit', 'Patient presented for acute exacerbation of allergic rhinitis with complaints of severe nasal congestion, sneezing, and itchy eyes. On examination, the patient appeared well-nourished and alert, with clear breath sounds and no wheezing noted. Vital signs were stable: BP 100/60 mmHg, HR 90 bpm, RR 20 bpm, Temp 98.6°F. Assessment indicated a flare-up of allergic rhinitis. Recommended continuation of daily antihistamine and initiation of a nasal corticosteroid spray, with follow-up in primary care for long-term management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('bd38ac07-c71c-415f-8238-f68b9ab03163', '2025-05-14T22:48:34.863882', 'Urgent Care', 'Patient presented for evaluation of worsening nasal congestion, sneezing, and itchy eyes. Physical examination revealed bilateral nasal turbinates swelling and clear rhinorrhea. Vitals were stable: BP 100/65 mmHg, HR 90 bpm, RR 18 breaths/min, Temp 98.6°F. Assessment indicated exacerbation of allergic rhinitis. Recommended continuation of current antihistamine therapy and initiation of a nasal corticosteroid spray. Advised follow-up with primary care provider if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('61bb266e-049f-4d4a-aece-8a0672ddde1b', '2026-01-06T22:48:40.811304', 'Urgent Care', 'Patient presented for evaluation of acute chest pain and shortness of breath. Vital signs were notable for blood pressure at 150/92 mmHg and heart rate at 88 bpm. Physical examination revealed mild wheezing on auscultation and no peripheral edema. Assessment indicated possible angina pectoris; an ECG was performed, showing no acute ischemic changes. Recommended immediate referral to cardiology for further evaluation and adjustment of antihypertensive and lipid-lowering therapy. Advised continuation of current diabetes management plan and scheduling follow-up for comprehensive cardiovascular assessment.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('61bb266e-049f-4d4a-aece-8a0672ddde1b', '2025-08-16T22:48:40.811304', 'Consultation', 'Patient presented for routine consultation and management of chronic conditions, including hyperlipidemia and diabetes. Blood pressure was 138/85 mmHg, heart rate was 76 bpm, and BMI was 27. Physical examination was unremarkable except for mild crepitus in bilateral knees consistent with osteoarthritis. Recommended continuation of current statin therapy and adjustment of antihypertensive medication to improve blood pressure control. Advised regular follow-up for diabetes management and scheduled ophthalmology referral for cataract evaluation.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('61bb266e-049f-4d4a-aece-8a0672ddde1b', '2025-07-01T22:48:40.811304', 'Consultation', 'Patient presented for routine consultation and management of hyperlipidemia. Vitals were stable: BP 138/85 mmHg, HR 72 bpm. Physical examination was unremarkable, with no acute distress noted. Recommended continuation of current statin therapy and emphasized adherence to a low-fat diet. Discussed management of diabetes and hypertension, and advised follow-up in three months for lab work to assess lipid and glucose levels.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('61bb266e-049f-4d4a-aece-8a0672ddde1b', '2025-01-21T22:48:40.811304', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding management of hyperlipidemia and diabetes. Vitals: BP 138/82 mmHg, HR 76 bpm. Patient reported no new symptoms, but noted occasional episodes of joint stiffness attributed to osteoarthritis. Continued current statin therapy and advised monitoring blood glucose levels regularly. Recommended dietary modifications and increased physical activity to aid in the management of hyperlipidemia and diabetes. Follow-up in 3 months or as needed for any changes in symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('0c9f131f-8fc0-480f-951f-26b956fb3340', '2026-01-21T22:48:47.774385', 'Follow-up Visit', 'Patient presented for a follow-up visit to monitor hyperlipidemia and associated conditions. Vital signs were as follows: BP 142/88 mmHg, HR 78 bpm. Physical examination revealed no acute distress, and BMI calculation indicated ongoing obesity. Assessment included stable hyperlipidemia, with lipid panel results pending. Recommended continuation of current statin therapy, reinforced dietary modifications, and encouraged regular physical activity. Follow-up in 6 months or as needed for any new symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('0c9f131f-8fc0-480f-951f-26b956fb3340', '2025-09-30T22:48:47.774385', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 138/86 mmHg and heart rate was 78 bpm. The patient reported ongoing joint pain associated with osteoarthritis but denied any new symptoms. Lipid profile will be checked to monitor hyperlipidemia; continue current statin therapy. Advised weight management strategies given the history of obesity and prediabetes. Recommended continuation of proton pump inhibitor for GERD management. Follow-up scheduled in six months for routine monitoring.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('0c9f131f-8fc0-480f-951f-26b956fb3340', '2025-07-19T22:48:47.774385', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 135/85 mmHg, HR 78 bpm, BMI 32.2 kg/m². The patient reported occasional heartburn and joint stiffness, consistent with her medical history of GERD and osteoarthritis. Lipid panel reviewed, showing elevated LDL cholesterol. Recommended continuation of low-fat diet and regular physical activity, with a follow-up lipid panel in six months. Discussed weight management strategies to address obesity and monitored prediabetes. Prescribed a PPI for GERD symptoms and advised NSAIDs as needed for joint pain.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('d0b39c7c-4d2f-4202-964f-a780a16097ea', '2025-11-09T22:48:52.689823', 'Follow-up Visit', 'Patient presented for follow-up regarding a vaginal yeast infection. She reported persistent itching and discharge, though symptoms have slightly improved since the initial visit. Vitals were stable: BP 110/70 mmHg, HR 72 bpm. Assessment indicated a resolving yeast infection. Recommended continuation of antifungal treatment for an additional 7 days and advised maintaining good genital hygiene. Follow-up scheduled in two weeks to reassess symptoms and monitor for recurrence.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('d0b39c7c-4d2f-4202-964f-a780a16097ea', '2025-09-07T22:48:52.689823', 'Annual Checkup', 'Patient presented for an annual checkup and reported symptoms of itching and discharge consistent with a vaginal yeast infection. Vitals were as follows: BP 110/70 mmHg, HR 72 bpm, RR 16 breaths/min, SpO2 98% on room air, temperature 98.6°F. Physical examination confirmed erythema and discharge suggestive of candidiasis. Advised the use of an over-the-counter antifungal cream and to return if symptoms persist. Reviewed management of existing conditions, including migraine, asthma, and allergic rhinitis. Refilled prescriptions for albuterol inhaler and nasal corticosteroid spray as needed. Recommended follow-up in one year or as needed.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('d0b39c7c-4d2f-4202-964f-a780a16097ea', '2025-04-27T22:48:52.689823', 'Annual Checkup', 'Patient presented for an annual checkup and reported symptoms consistent with a vaginal yeast infection, including itching and discharge. Vitals were stable: BP 110/70 mmHg, HR 72 bpm, RR 16 breaths/min, Temp 98.6°F. History of migraine, well-controlled asthma, and allergic rhinitis noted. Assessment confirmed yeast infection, and treatment with an antifungal agent was recommended. Advised on maintaining asthma management plan and regular follow-up for migraine management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('99c7a59b-fc81-4b83-8a65-816c04de63fc', '2025-11-03T22:48:58.935770', 'Follow-up Visit', 'Patient presented for a general checkup follow-up visit. Vital signs were stable: BP 118/76 mmHg, HR 72 bpm, RR 16/min, Temp 98.4°F. No acute symptoms were reported. Physical examination was unremarkable with well-healed surgical scar from previous appendectomy noted. Recommended maintaining a balanced diet and regular exercise. Follow-up in one year for routine wellness exam unless concerns arise sooner.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('99c7a59b-fc81-4b83-8a65-816c04de63fc', '2025-08-11T22:48:58.935770', 'Urgent Care', 'Patient presented for a routine general checkup at urgent care. Vital signs were within normal limits: BP 118/76 mmHg, HR 72 bpm, RR 16 breaths/min, Temp 98.6°F. Physical examination revealed no acute distress, and all systems were unremarkable. Patient was advised to continue a balanced diet, regular exercise, and to schedule follow-up with primary care for annual wellness exam.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('99c7a59b-fc81-4b83-8a65-816c04de63fc', '2025-06-20T22:48:58.935770', 'Urgent Care', 'Patient presented for a general checkup with no complaints. Vital signs were within normal limits: BP 118/72 mmHg, HR 72 bpm, RR 16 breaths/min, Temp 98.6°F. Physical examination was unremarkable. Given patient''s history of appendicitis, advised to maintain a balanced diet and regular physical activity. Recommended routine follow-up in one year or sooner if symptoms arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5992a467-13dd-4d52-9bd8-2c477b02af28', '2026-02-18T22:49:03.032626', 'Follow-up Visit', 'Patient presented for follow-up of tinea infection. Exam revealed erythematous, scaly patches on the inner thigh with minimal improvement since last visit. BP was 118/76 mmHg, HR 72 bpm. Continued treatment with topical antifungal cream was advised, and patient was instructed to maintain good hygiene. Psychological status reviewed; patient reports stable mood on current antidepressant regimen. Follow-up visit in 4 weeks recommended for reassessment of fungal infection and asthma management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5992a467-13dd-4d52-9bd8-2c477b02af28', '2025-08-13T22:49:03.032626', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable with BP 118/76 mmHg, HR 72 bpm, RR 16 breaths/min, and SpO2 98% on room air. Physical examination revealed erythematous, scaly patches consistent with Tinea on the left forearm. Asthma well-controlled with current regimen; no exacerbations reported. Patient reported mild improvement in mood with current antidepressant therapy. Recommended continuation of topical antifungal treatment and advised follow-up if symptoms persist or worsen. Encouraged routine asthma management and mental health support.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ca3ae0b7-7b5d-4bf8-b273-a36c87c334ec', '2025-12-12T22:49:06.820466', 'Emergency Visit', 'Patient presented for evaluation of a severe insect bite reaction on the right forearm. Noted erythema, swelling, and pruritus at the site, with no signs of infection. Vital signs stable: BP 102/68, HR 88, Temp 98.4°F. Assessment: Insect bite exacerbating underlying eczema. Recommended application of topical corticosteroid and oral antihistamine for symptom management. Advised monitoring for signs of secondary infection and follow-up with primary care physician if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ca3ae0b7-7b5d-4bf8-b273-a36c87c334ec', '2025-09-26T22:49:06.820466', 'Consultation', 'Patient presented for evaluation of an insect bite reaction on the right forearm. Physical examination revealed localized erythema, swelling, and pruritus at the site of the bite. The patient has a known history of eczema, which may exacerbate the reaction. Plan included prescribing a topical corticosteroid to reduce inflammation and an oral antihistamine to manage itching, with instructions to monitor for any signs of infection or worsening symptoms. Vitals were stable with BP 102/68 mmHg, HR 88 bpm. Follow-up recommended in one week or sooner if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ca3ae0b7-7b5d-4bf8-b273-a36c87c334ec', '2025-02-09T22:49:06.820466', 'Consultation', 'Patient presented for evaluation of an insect bite reaction. On examination, erythematous and edematous papules were noted on the right forearm with mild pruritus. The patient has a history of eczema, currently controlled. Vitals were stable with a BP of 102/66 mmHg and HR of 88 bpm. Assessment confirmed localized insect bite reaction without signs of secondary infection. Recommended application of a topical corticosteroid and advised antihistamines for symptomatic relief. Follow-up in one week if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ca3ae0b7-7b5d-4bf8-b273-a36c87c334ec', '2024-10-08T22:49:06.820466', 'Follow-up Visit', 'Patient presented for follow-up assessment of an insect bite reaction. The affected area, located on the left forearm, showed mild erythema and swelling, with no signs of infection. The patient reported pruritus but denied pain or fever. Vital signs were within normal limits (BP: 112/72, HR: 88). Assessment indicated a mild allergic reaction, likely exacerbated by underlying eczema. Advised continued use of oral antihistamines and topical corticosteroid cream. Follow-up recommended if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f53ac2d6-7aca-4801-a947-46d18acc6bfe', '2025-09-29T22:49:14.356140', 'Urgent Care', 'Patient presented for evaluation of acute knee pain, worsening over the past week. Vital signs were stable with BP 128/76 mmHg and HR 78 bpm. Physical examination revealed mild swelling and tenderness in the right knee, consistent with an exacerbation of osteoarthritis. Recommended conservative management with NSAIDs, ice application, and follow-up with primary care for possible referral to orthopedics if symptoms persist. Also advised continuation of statin therapy for hyperlipidemia control.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f53ac2d6-7aca-4801-a947-46d18acc6bfe', '2025-08-28T22:49:14.356140', 'Emergency Visit', 'Patient presented for acute onset chest pain and shortness of breath. Vitals were significant for BP 158/92 mmHg and HR 98 bpm. Physical exam revealed mild bilateral crackles on lung auscultation. EKG showed nonspecific ST changes; troponin levels were pending. Assessment included possible acute coronary syndrome. Recommended immediate cardiology consultation and initiation of nitroglycerin and aspirin therapy. Further workup and monitoring in the emergency department were advised.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f53ac2d6-7aca-4801-a947-46d18acc6bfe', '2025-07-06T22:49:14.356140', 'Follow-up Visit', 'Patient presented for follow-up regarding hyperlipidemia management and osteoarthritis symptoms. Blood pressure was 132/78 mmHg and heart rate was 72 bpm. The patient reported increased joint stiffness and mild pain in the knees, particularly in the morning. Recommended continuation of statin therapy and advised starting a low-impact exercise regimen to improve joint mobility. Scheduled a follow-up appointment in three months to reassess lipid levels and joint symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
