VALUES ('c7da4117-4502-4a28-beb9-7b2e7df2d462', '2025-09-18T22:49:20.850981', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding hay fever management. Vital signs were stable: BP 118/76 mmHg, HR 72 bpm, respiratory rate 16 breaths/min. Reported persistent nasal congestion and sneezing, especially in the mornings. Assessment indicated well-controlled asthma with continued symptomatic allergic rhinitis. Recommended continuation of antihistamine therapy and advised on environmental control measures to reduce allergen exposure. Follow-up in 6 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
