VALUES ('d9bb6f7b-550a-472e-bddd-da4e09180f7c', '2025-08-07T22:49:25.765785', 'Consultation', 'Patient presented for routine consultation and management of existing conditions. Vital signs were as follows: BP 138/85 mmHg, HR 78 bpm, BMI 32.3 kg/m². No new symptoms were reported; however, patient expressed concerns about recent weight gain. Assessment included stable hyperlipidemia and controlled GERD with current medication regimen. Recommended continuation of current pharmacotherapy, dietary modifications, and initiation of a structured exercise program to address obesity. Follow-up scheduled in three months to monitor progress and adjust treatment plan as necessary.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
