INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b41a30b4-65a1-4ce5-9cb1-7aba6bed504b', '2025-10-21T22:49:30.483009', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were as follows: BP 128/82 mmHg, HR 76 bpm, BMI 32 kg/m². Noted persistent symptoms of contact dermatitis on bilateral forearms with erythema and pruritus. Recommended continuation of topical corticosteroids and avoidance of known irritants. Discussed weight management strategies and advised continuation of current migraine prophylaxis. Follow-up in 6 months to monitor dermatitis and weight management progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b41a30b4-65a1-4ce5-9cb1-7aba6bed504b', '2025-02-23T22:49:30.483009', 'Follow-up Visit', 'Patient presented for a follow-up regarding contact dermatitis. Physical examination revealed mild erythema and pruritus on the dorsal aspect of both hands. Blood pressure was 128/80 mmHg, heart rate was 76 bpm. Assessment confirmed ongoing contact dermatitis with improvement since last visit. Recommended continued use of topical corticosteroid and advised avoidance of identified allergens. Follow-up in four weeks or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
