INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('42e44664-d9fb-4761-9942-1f266a55d7d0', '2025-07-05T22:49:35.904650', 'Follow-up Visit', 'Patient presented for follow-up of a viral upper respiratory infection. Physical examination revealed mild nasal congestion with clear rhinorrhea; lungs were clear on auscultation. Vital signs were stable: HR 110 bpm, RR 24, temperature 99.1°F. Assessment indicated improvement since the last visit. Recommended continued supportive care with adequate hydration and monitored for any new symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f8b76571-4f26-4a02-8183-674dfae9ddc6', '2025-11-05T22:49:38.976801', 'Follow-up Visit', 'Patient presented for follow-up of osteoporosis and management of chronic conditions. Vital signs were stable with BP: 132/78 mmHg, HR: 74 bpm. Patient reported mild back pain, manageable with current analgesics, and no new symptoms. Osteoporosis management with bisphosphonates to continue; advised calcium and vitamin D supplementation. Discussed maintaining exercise regimen and reviewed dietary modifications for GERD. Follow-up in six months for routine evaluation and monitoring.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f8b76571-4f26-4a02-8183-674dfae9ddc6', '2025-10-14T22:49:38.976801', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 138/82 mmHg, HR 76 bpm, BMI 28.1. The patient reported experiencing increased episodes of back pain and joint stiffness, particularly in the lumbar region, likely related to osteoarthritis and chronic low back pain. Noted appropriate management of osteoporosis with current bisphosphonate therapy. Recommended continuation of current medications for hypertension and GERD. Advised weight-bearing exercises and reviewed dietary calcium intake to support bone health. Scheduled follow-up with ophthalmology for cataract evaluation.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f8b76571-4f26-4a02-8183-674dfae9ddc6', '2025-08-05T22:49:38.976801', 'Follow-up Visit', 'Patient presented for a follow-up on osteoporosis management. Vital signs included BP 138/82 mmHg and HR 76 bpm. Patient reported experiencing increased lower back pain, likely secondary to osteoporosis and chronic low back pain. Physical examination revealed decreased lumbar range of motion. Recommended continuation of bisphosphonate therapy, calcium and vitamin D supplementation, and referral for physical therapy to assist with pain management and mobility. Follow-up in 6 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f8b76571-4f26-4a02-8183-674dfae9ddc6', '2025-05-29T22:49:38.976801', 'Follow-up Visit', 'Patient presented for follow-up on osteoporosis and management of chronic conditions. Blood pressure was 132/78 mmHg, and heart rate was 72 bpm. He reported increased lower back discomfort, likely secondary to osteoporosis, and continued mild dyspepsia related to GERD. Recommended continuation of bisphosphonate therapy, and advised dietary calcium and vitamin D supplementation. Suggested regular exercise to improve bone density and referred to physical therapy for back pain management. Advised follow-up in 6 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('2e46f53a-602d-4857-a75b-441a54d7108b', '2026-01-30T22:49:45.938738', 'Annual Checkup', 'Patient presented for annual checkup. Vital signs were as follows: BP 138/82 mmHg, HR 76 bpm, BMI 28.3. Patient reported occasional knee discomfort associated with osteoarthritis but denied any new symptoms. Lipid panel from last month showed LDL cholesterol at 145 mg/dL. GERD and hypertension are well-managed with current medications. Recommended continuation of statin therapy and advised dietary modifications to address hyperlipidemia. Encouraged regular exercise to manage weight and joint health. Follow-up in six months or as needed for any new symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('2e46f53a-602d-4857-a75b-441a54d7108b', '2025-09-28T22:49:45.938738', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 138/82 mmHg, and heart rate was 78 bpm. Patient reported experiencing occasional heartburn, managed with OTC antacids, and mild knee pain consistent with osteoarthritis. Lipid profile to be reviewed; advised continuation of statin therapy. Recommended lifestyle modifications including a low-fat diet and regular exercise for hyperlipidemia management. Follow-up in 6 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('75c370c6-912c-4293-80ed-a48218b7de64', '2025-11-26T22:49:49.828956', 'Follow-up Visit', 'Patient presented for follow-up visit regarding acute diverticulitis. Vital signs were stable: BP 138/82 mmHg, HR 78 bpm. Patient reported mild abdominal pain and bloating, with no fever or chills. Continued on current antibiotic regimen, advised to maintain a low-fiber diet temporarily and increase fluid intake. Follow-up in 2 weeks or sooner if symptoms worsen. Chronic conditions remain managed under current treatment plan.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('75c370c6-912c-4293-80ed-a48218b7de64', '2025-08-27T22:49:49.828956', 'Annual Checkup', 'Patient presented for an annual checkup with a current condition of acute diverticulitis. Vitals were notable for BP 142/88 mmHg and HR 78 bpm. He reported abdominal pain and altered bowel habits consistent with his recent diverticulitis diagnosis. Plan included continuation of antibiotic therapy, dietary modifications, and close monitoring of blood glucose levels due to diabetes. Recommended follow-up in 4 weeks to reassess diverticulitis and manage chronic conditions.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('75c370c6-912c-4293-80ed-a48218b7de64', '2025-08-07T22:49:49.828956', 'Annual Checkup', 'Patient presented for an annual checkup with a recent diagnosis of acute diverticulitis. Vital signs were within normal limits: BP 135/80 mmHg, HR 76 bpm. The patient reported mild abdominal discomfort, managed with antibiotics and dietary modifications. Continued management of chronic conditions including hyperlipidemia, diabetes, and hypertension was emphasized, with medication adherence reinforced. Recommended follow-up in 3 months for diverticulitis reassessment and routine lab work to monitor diabetes and lipid levels.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('75c370c6-912c-4293-80ed-a48218b7de64', '2025-03-15T22:49:49.828956', 'Consultation', 'Patient presented for consultation regarding acute diverticulitis. Vital signs were stable: BP 132/78 mmHg, HR 76 bpm. Patient reported lower abdominal pain, fever, and changes in bowel habits. Physical examination revealed mild abdominal tenderness in the left lower quadrant without guarding or rebound tenderness. Assessment confirmed acute diverticulitis. Recommended continuation of antibiotic therapy, a low-fiber diet initially, and follow-up in one week to reassess symptoms. Advised to monitor blood glucose levels closely due to diabetes and to maintain current medication regimen for chronic conditions.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('75c370c6-912c-4293-80ed-a48218b7de64', '2024-08-28T22:49:49.828956', 'Follow-up Visit', 'Patient presented for follow-up of acute diverticulitis. Vital signs were stable: BP 130/85 mmHg, HR 78 bpm. Patient reported reduced abdominal pain and improved bowel habits. Assessment showed resolution of acute symptoms. Recommended continuation of high-fiber diet and hydration. Advised follow-up in 4 weeks, or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('14d018a2-6503-47a2-b950-652bea8625d4', '2026-02-13T22:49:57.514139', 'Emergency Visit', 'Patient presented for acute constipation persisting for 4 days, accompanied by abdominal discomfort and decreased appetite. Physical examination revealed a soft but distended abdomen with hypoactive bowel sounds; no guarding or rebound tenderness noted. Assessment: Constipation, likely functional. Recommended increasing dietary fiber and fluid intake, and advised the use of pediatric glycerin suppositories if no bowel movement within 24 hours. Follow-up with primary care provider in one week or return if symptoms worsen. Vitals: HR 110 bpm, Temp 98.6°F, RR 24 breaths/min.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('14d018a2-6503-47a2-b950-652bea8625d4', '2025-08-09T22:49:57.514139', 'Emergency Visit', 'Patient presented for constipation. Vital signs were within normal limits for age. Physical examination revealed mild abdominal distention but was otherwise unremarkable. Assessment indicated functional constipation. Recommended dietary modifications including increased fiber intake and adequate hydration, and advised the use of polyethylene glycol as needed. Follow-up with pediatrician advised if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('14d018a2-6503-47a2-b950-652bea8625d4', '2025-04-27T22:49:57.514139', 'Urgent Care', 'Patient presented for evaluation of constipation. Physical examination revealed a mildly distended abdomen with no palpable masses, and bowel sounds were present. Assessment: Functional constipation likely related to dietary factors. Recommended increasing dietary fiber and fluid intake, and advised the use of polyethylene glycol 3350 as needed. Follow-up with primary care provider if symptoms persist or worsen. Vitals were stable: HR 98 bpm, RR 24/min, Temp 98.6°F.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('14d018a2-6503-47a2-b950-652bea8625d4', '2024-10-15T22:49:57.514139', 'Annual Checkup', 'Patient presented for annual checkup with a primary concern of constipation. Vitals were within normal limits: HR 110 bpm, RR 24 breaths/min, temperature 98.6°F. Physical examination revealed a soft, non-distended abdomen and normal bowel sounds. Assessment indicated functional constipation; advised dietary modifications including increased fiber intake and adequate hydration. Considered use of pediatric glycerin suppositories if symptoms persist. Follow-up in 4 weeks if no improvement.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('95a77cfa-e44d-4b5c-b8c5-6b574f555d2c', '2025-12-24T22:50:06.100842', 'Consultation', 'Patient presented for follow-up consultation regarding management of diabetes and hypertension. Blood pressure was 142/88 mmHg, heart rate was 78 bpm. No new symptoms reported, but patient expressed concern over occasional dizziness, likely secondary to antihypertensive medication. Recommended adjustment of medication dosage and advised monitoring blood glucose levels regularly. Encouraged adherence to dietary modifications and regular physical activity to manage weight and blood sugar levels. Follow-up scheduled in 3 months for reassessment.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('95a77cfa-e44d-4b5c-b8c5-6b574f555d2c', '2025-09-05T22:50:06.100842', 'Follow-up Visit', 'Patient presented for a follow-up visit to manage diabetes and hypertension. Vitals recorded: BP 145/90 mmHg, HR 82 bpm, BMI 32.2 kg/m². Reports good adherence to medication but occasional episodes of nocturnal dyspepsia, likely related to GERD. Advised dietary modifications, including smaller evening meals, and reviewed current medication regimen. Recommended continuation of metformin and lisinopril, and to schedule an ophthalmology consultation for diabetic retinopathy screening. Follow-up in 3 months to reassess blood pressure control and glycemic status.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('95a77cfa-e44d-4b5c-b8c5-6b574f555d2c', '2025-08-10T22:50:06.100842', 'Urgent Care', 'Patient presented for evaluation of persistent dizziness and fatigue over the past week. Vitals at visit: BP 145/90 mmHg, HR 88 bpm. Physical examination revealed mild dehydration and decreased skin turgor. Assessment suggested possible hypoglycemic episodes, likely related to diabetes management. Recommended adjustment of diabetes medication regimen and advised increased fluid intake. Follow-up appointment scheduled with primary care for further management of diabetes and hypertension.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('95a77cfa-e44d-4b5c-b8c5-6b574f555d2c', '2025-04-09T22:50:06.100842', 'Follow-up Visit', 'Patient presented for a follow-up visit for diabetes management. Blood pressure was 142/88 mmHg, and heart rate was 78 bpm. The patient reported occasional dizziness and polyuria. Assessment indicated suboptimal glycemic control with HbA1c at 8.2%. Plan included adjusting insulin dosage, recommending dietary modifications, and scheduling a follow-up in 3 months to reassess glycemic levels and blood pressure.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('95a77cfa-e44d-4b5c-b8c5-6b574f555d2c', '2024-06-10T22:50:06.100842', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 145/88 mmHg, heart rate was 78 bpm, and BMI was 32.2 kg/m². Physical examination revealed no acute distress, but there was mild peripheral edema in the lower extremities. Assessment included uncontrolled hypertension and poorly managed diabetes. Recommended adjustments to antihypertensive medication and an increase in metformin dosage. Encouraged dietary modifications and regular physical activity to address obesity and improve glycemic control. Follow-up scheduled in 3 months for blood pressure and diabetes management review.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('03bc7148-51c2-42b2-b492-a359cb940765', '2025-11-23T22:50:14.097618', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs revealed BP 145/90 mmHg and HR 78 bpm. Physical examination was unremarkable except for BMI of 32, indicating obesity. Assessment included poorly controlled hypertension and stable prediabetes. Recommended continuing current antihypertensive regimen and initiating lifestyle modifications, including dietary changes and regular physical activity, to aid in weight management and glycemic control. Referred to nutrition counseling and scheduled follow-up in 3 months to reassess blood pressure and metabolic parameters.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('03bc7148-51c2-42b2-b492-a359cb940765', '2025-07-28T22:50:14.097618', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was noted at 142/88 mmHg, and heart rate was 78 bpm. The patient reported adherence to current antihypertensive medication but expressed concerns about weight management and mood fluctuations. Assessment included poorly controlled hypertension and moderate depression. Recommended continuation of current antihypertensive therapy with close monitoring, referral to a dietitian for weight management, and adjustment of antidepressant dosage. Follow-up in 3 months to reassess blood pressure and mental health status.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('9241156c-2510-420b-9cdb-c3bcf4eab8dc', '2026-01-23T22:50:16.555876', 'Follow-up Visit', 'Patient presented for follow-up of tinea infection and management of chronic conditions. Blood pressure was 148/92 mmHg, heart rate 82 bpm. Physical examination revealed erythematous, scaly patches on the groin and intertriginous areas, consistent with ongoing tinea infection. Continued topical antifungal treatment was advised, and glycemic control measures were reinforced. Adjustments to antihypertensive medication were discussed to improve blood pressure management. Follow-up appointment scheduled in 3 months.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('9241156c-2510-420b-9cdb-c3bcf4eab8dc', '2025-10-04T22:50:16.555876', 'Follow-up Visit', 'Patient presented for follow-up of tinea infection and management of chronic conditions. Blood pressure was 145/90 mmHg, and heart rate was 82 bpm. The fungal infection showed mild improvement with topical antifungal treatment, but erythema and scaling persist. Advised continuation of current antifungal regimen and emphasized strict glycemic control to aid in infection resolution. Recommended dietary modifications and regular physical activity to address obesity and hypertension. Follow-up in 4 weeks to reassess infection and adjust treatment plan if necessary.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('9241156c-2510-420b-9cdb-c3bcf4eab8dc', '2025-03-08T22:50:16.555876', 'Annual Checkup', 'Patient presented for an annual checkup with complaints of a persistent itchy rash diagnosed as Tinea. Blood pressure was 145/90 mmHg, and heart rate was 82 bpm. Examination revealed erythematous, scaly patches on the inner thighs. Advised continuation of current antifungal treatment and recommended strict glycemic control to aid in management. Discussed lifestyle modifications to address obesity and hypertension, including dietary changes and regular physical activity. Follow-up in 3 months to reassess blood pressure and skin condition.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8074bddf-6530-410a-88f2-548c37b44776', '2025-12-21T22:50:21.782162', 'Annual Checkup', 'Patient presented for an annual checkup. The skin examination revealed mild erythematous patches consistent with eczema, primarily located on the antecubital and popliteal fossae. No acute distress noted. ADHD was stable, with no new behavioral concerns reported by parents. Recommended continuation of emollient therapy for eczema and regular follow-ups for ADHD management. Vitals: HR 98 bpm, BP 90/55 mmHg, Temp 98.6°F.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8074bddf-6530-410a-88f2-548c37b44776', '2025-09-15T22:50:21.782162', 'Annual Checkup', 'Patient presented for annual checkup. Vital signs were within normal limits: BP 90/60 mmHg, HR 110 bpm, Temp 98.6°F. Examination revealed mild erythema and dryness on the extensor surfaces of the arms and legs, consistent with eczema. Recommended continuation of topical emollients and hydrocortisone cream as needed for flare-ups. Discussed behavioral management strategies for ADHD with caregivers. Follow-up in one year or as needed for any concerns.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('9a9f7412-2e98-4113-bc4f-a139f3db877e', '2025-11-09T22:50:24.911028', 'Annual Checkup', 'Patient presented for an annual checkup. Physical examination revealed a healing abrasion on the left knee with no signs of infection. Vitals were within normal limits: BP 102/66 mmHg, HR 88 bpm. History of previous fracture was noted with no current issues reported. Recommended routine follow-up in one year and ensured tetanus vaccination was up to date.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('9a9f7412-2e98-4113-bc4f-a139f3db877e', '2025-09-18T22:50:24.911028', 'Follow-up Visit', 'Patient presented for follow-up evaluation of a right knee abrasion sustained 10 days ago. The abrasion appeared clean with no signs of infection; minimal scabbing noted. Vital signs were stable: BP 102/64, HR 88. Assessment: Healing abrasion, no complications. Plan: Continue with daily cleansing and application of topical antibiotic ointment; follow up in 1 week or sooner if symptoms of infection develop.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('9a9f7412-2e98-4113-bc4f-a139f3db877e', '2025-04-13T22:50:24.911028', 'Follow-up Visit', 'Patient presented for follow-up evaluation of an abrasion sustained during a recent fall. On examination, the abrasion on the right knee was healing appropriately with no signs of infection; surrounding tissue appeared slightly erythematous but without purulent discharge. Vital signs were stable: BP 100/65 mmHg, HR 90 bpm, afebrile. Recommended continued application of topical antibiotic ointment and advised to keep the area clean and covered. Discussed the importance of wearing protective gear during outdoor activities to prevent further injuries, given the history of previous fracture. Follow-up in two weeks if the condition does not improve or if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4e43c8d5-5f74-4287-83ec-f5867b75f9f7', '2025-11-14T22:50:29.154165', 'Follow-up Visit', 'Patient presented for follow-up of seasonal allergies and management of chronic conditions. Vital signs were stable: BP 128/82 mmHg, HR 72 bpm. Patient reported increased nasal congestion and sneezing, consistent with exacerbation of allergic rhinitis. Continued current antihistamine regimen was recommended, with addition of a nasal corticosteroid spray. Blood pressure and lipid levels to be monitored, and advised dietary modifications for better control of hypertension and hyperlipidemia. Follow-up in three months to reassess symptoms and management efficacy.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4e43c8d5-5f74-4287-83ec-f5867b75f9f7', '2025-10-07T22:50:29.154165', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding seasonal allergies and management of chronic conditions. Vital signs were stable: BP 130/85 mmHg, HR 72 bpm. He reported increased nasal congestion and sneezing over the past week, consistent with allergic rhinitis exacerbation. Continued current antihypertensive and statin therapy was advised, with the addition of a nasal corticosteroid spray for allergy symptom relief. Recommended lifestyle modifications for GERD management and follow-up in 3 months unless symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4e43c8d5-5f74-4287-83ec-f5867b75f9f7', '2025-04-30T22:50:29.154165', 'Follow-up Visit', 'Patient presented for follow-up on hypertension and seasonal allergies. Blood pressure was 138/86 mmHg and heart rate was 78 bpm. Patient reported increased nasal congestion and sneezing, consistent with allergic rhinitis exacerbation. Advised continuation of current antihypertensive regimen and recommended starting a second-generation antihistamine for allergy symptom relief. Follow-up in three months to reassess blood pressure and allergy control.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ba3a9267-75e1-4f5e-a74f-8354b2f17aed', '2026-01-22T22:50:33.352645', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were within normal limits: BP 118/76 mmHg, HR 72 bpm, RR 16 breaths/min, SpO2 98% on room air. Lungs were clear to auscultation bilaterally, with no wheezing noted. Asthma appears well-controlled; advised patient to continue current inhaler regimen and follow up in one year unless symptoms worsen.', NULL);
