VALUES ('ba3a9267-75e1-4f5e-a74f-8354b2f17aed', '2025-08-02T22:50:33.352645', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were stable: BP 118/76 mmHg, HR 72 bpm, RR 16, SpO2 98% on room air. No acute respiratory distress noted, lungs clear to auscultation bilaterally. Asthma well-controlled with current medication regimen; patient advised to continue using albuterol as needed and to follow up with pulmonology if symptoms worsen. Recommended routine vaccinations and discussed healthy lifestyle practices.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('16a8530c-59a1-4c33-9efb-1caaf0ef7037', '2025-11-05T22:50:35.605583', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were stable: BP 90/60 mmHg, HR 98 bpm, RR 20 breaths/min, Temp 98.6°F. The patient exhibited symptoms of nasal congestion and sneezing consistent with hay fever; lungs were clear to auscultation. Recommended continuation of current antihistamine regimen and advised environmental control measures to reduce allergen exposure. Follow-up in one year or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
