INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('49d38975-874b-440a-88a1-deeb0f32c494', '2025-07-27T22:50:46.253801', 'Consultation', 'Patient presented for a routine general checkup. Vital signs were within normal limits: BP 98/60 mmHg, HR 78 bpm, RR 18/min, Temp 98.6°F. Physical examination revealed no abnormalities; growth and development appropriate for age. Recommended continuation of balanced diet, regular physical activity, and routine vaccinations. Follow-up in one year unless concerns arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('49d38975-874b-440a-88a1-deeb0f32c494', '2024-10-15T22:50:46.253801', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were within normal limits: BP 102/64 mmHg, HR 88 bpm, Temp 98.6°F. Physical examination was unremarkable with no acute distress observed. Recommended continuation of a balanced diet, regular physical activity, and updated vaccinations as per schedule. Follow-up in one year for the next routine checkup unless concerns arise sooner.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('663d025b-0f14-4073-82dd-2f55775b04db', '2026-02-17T22:50:51.990201', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were within normal ranges: BP 90/60 mmHg, HR 90 bpm, Temp 98.6°F. No new complaints, but ongoing speech delay noted. Recommended continuation of speech therapy and follow-up with audiology to rule out hearing issues. Encouraged regular eye exams due to past conjunctivitis. Developmental milestones were reviewed and discussed with the guardian.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('663d025b-0f14-4073-82dd-2f55775b04db', '2025-08-30T22:50:51.990201', 'Urgent Care', 'Patient presented for evaluation of sore throat and fever. Vitals: Temperature 101.2°F, HR 110 bpm, BP 98/64 mmHg. Physical examination revealed mild erythema of the posterior pharynx and swollen tonsils with no exudate. Assessment was viral pharyngitis. Recommended supportive care, including adequate hydration and use of acetaminophen for fever management. Advised follow-up with primary care if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('663d025b-0f14-4073-82dd-2f55775b04db', '2025-03-17T22:50:51.990201', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: BP 90/60 mmHg, HR 100 bpm. The patient continues to exhibit speech delay with limited vocabulary for age; however, social interactions remain appropriate. Recommended continued speech therapy sessions and follow-up with a pediatric speech-language pathologist. No recurrence of conjunctivitis noted. Advised routine vaccinations as per schedule.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('80633c44-0da7-4ac4-8618-d64700255bb5', '2025-11-01T22:50:56.495605', 'Emergency Visit', 'Patient presented for evaluation of a jammed finger sustained during a basketball game. On examination, the left middle finger was swollen with limited range of motion and tenderness over the proximal interphalangeal joint. No obvious deformity or neurovascular compromise was noted. X-ray imaging was obtained, showing no fracture. Plan included buddy taping the finger for support, applying ice, and recommending NSAIDs for pain management. Follow-up advised if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('80633c44-0da7-4ac4-8618-d64700255bb5', '2025-10-21T22:50:56.495605', 'Annual Checkup', 'Patient presented for an annual checkup and reported a jammed finger sustained during basketball practice. Vital signs were stable: BP 110/70 mmHg, HR 78 bpm, RR 16 breaths/min, temperature 98.6°F. Physical examination revealed mild swelling and tenderness in the right index finger, with no apparent deformity. Recommended ice application, elevation, and NSAIDs for pain; advised follow-up if symptoms persist. Reviewed management of allergic rhinitis and anxiety; no acute distress noted.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('80633c44-0da7-4ac4-8618-d64700255bb5', '2025-05-01T22:50:56.495605', 'Urgent Care', 'Patient presented for evaluation of a jammed finger sustained during basketball practice. On examination, the right index finger appeared swollen with limited range of motion and tenderness at the proximal interphalangeal joint. No obvious deformity or signs of fracture were noted. Recommended ice application, elevation, and over-the-counter analgesics for pain management. Advised follow-up in one week if symptoms persist or worsen. Reviewed patient''s history of previous fracture and ensured no similar injuries were evident. Vitals were stable: BP 110/70 mmHg, HR 78 bpm.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('85435c4c-e0d0-4598-a2dd-f457860091c2', '2025-09-28T22:51:01.819715', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 136/84 mmHg, HR 72 bpm, SpO2 98% on room air. Hemoglobin levels remain stable under current anemia treatment, with no new symptoms reported. Hypertension and GERD are well-controlled with current medications; however, the patient reported increased joint stiffness, likely due to osteoarthritis. Recommended continuation of current management for chronic conditions and advised initiating a daily stretching routine to aid joint mobility. Follow-up in 6 months or as needed.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('85435c4c-e0d0-4598-a2dd-f457860091c2', '2025-09-27T22:51:01.819715', 'Follow-up Visit', 'Patient presented for follow-up evaluation of anemia and management of chronic conditions. Blood pressure was 138/82 mmHg, heart rate 76 bpm. Patient reported improved energy levels but noted increased knee discomfort attributed to osteoarthritis. Hemoglobin levels showed slight improvement. Continued current anemia treatment was advised, with referral to physical therapy for osteoarthritis management. Recommended continuation of antihypertensive and asthma medications, and advised dietary modifications for GERD. Follow-up in 3 months.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('bd972cef-1aa4-4f03-a4ca-53026248f5f1', '2025-10-13T22:51:04.997493', 'Annual Checkup', 'Patient presented for an annual checkup. During the examination, he exhibited mild abdominal distension and discomfort consistent with constipation, but no acute distress was noted. Vitals were stable: HR 130 bpm, RR 30 breaths/min, temperature 98.6°F. Assessment confirmed constipation, likely functional, and ongoing management of recurrent ear infections and eczema was discussed. Recommended dietary modifications including increased fiber and fluid intake, and advised continued monitoring of eczema and ear symptoms. Follow-up in three months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('bd972cef-1aa4-4f03-a4ca-53026248f5f1', '2025-06-28T22:51:04.997493', 'Follow-up Visit', 'Patient presented for a follow-up visit due to constipation. Physical examination revealed a soft, non-distended abdomen with normal bowel sounds; no masses or tenderness were noted. Assessment included constipation possibly secondary to dietary factors. Recommendations included increasing fluid and fiber intake and considering the use of a glycerin suppository if no improvement is noted within the next 48 hours. Continuation of monitoring for any recurrent ear infections or exacerbation of eczema was advised.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('bd972cef-1aa4-4f03-a4ca-53026248f5f1', '2025-04-06T22:51:04.997493', 'Follow-up Visit', 'Patient presented for follow-up regarding constipation. Mother reports improvement in bowel movements with recent dietary changes, though stools remain hard. Physical exam revealed mild abdominal distension with no tenderness or guarding. Recommended continued use of polyethylene glycol 3350 as needed and increasing fluid intake. Advised monitoring for signs of bowel obstruction and follow-up if symptoms persist.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('bd972cef-1aa4-4f03-a4ca-53026248f5f1', '2025-01-10T22:51:04.997493', 'Consultation', 'Patient presented for consultation due to constipation. No significant abnormalities were noted on physical examination; abdomen was soft and non-distended. Noted history of recurrent ear infections and eczema. Advised to increase fluid intake and consider a trial of glycerin suppositories if no improvement. Recommended follow-up if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('1e124f84-d229-47ee-9897-7b5f924bc0a9', '2026-01-28T22:51:16.721418', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were within normal limits: BP 100/60 mmHg, HR 88 bpm, SpO2 98% on room air. The patient reported occasional wheezing, particularly during physical activity, and increased nasal congestion consistent with allergic rhinitis. Lungs were clear to auscultation with no wheezes noted at rest. Asthma was assessed as well-controlled with current regimen. Recommended continuing inhaled corticosteroid and short-acting beta-agonist as needed. Advised allergy management strategies, including regular use of antihistamines during peak allergy seasons. Follow-up in one year or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('1e124f84-d229-47ee-9897-7b5f924bc0a9', '2025-07-20T22:51:16.721418', 'Consultation', 'Patient presented for routine asthma management consultation. No acute respiratory distress noted; oxygen saturation was 98% on room air. Parents reported recent increase in nighttime cough and wheezing. Physical examination revealed clear lung sounds with mild nasal congestion. Assessment indicated mild exacerbation of asthma, likely triggered by allergic rhinitis. Recommended adjustment of inhaled corticosteroid to Fluticasone 44 mcg, 2 puffs BID, and advised continuation of current antihistamine regimen. Follow-up in 3 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('60ffa515-53f0-41e4-a145-c6ce6df7f0e1', '2025-12-01T22:51:20.562541', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: HR 110 bpm, RR 30 breaths/min, temperature 98.6°F. Examination revealed a minor contusion on the left forearm, with no signs of infection or deeper tissue injury. History of eczema and asthma was noted; skin was clear with no current eczema flare-ups. Asthma was well-controlled with no recent exacerbations. Recommended maintaining current management plan for asthma, and advised parents to observe the contusion for any changes. Follow-up in one year unless symptoms arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('60ffa515-53f0-41e4-a145-c6ce6df7f0e1', '2025-10-02T22:51:20.562541', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding recent contusion and management of eczema and asthma. Vital signs were stable: HR 110 bpm, RR 30 breaths/min, BP not applicable for age. The contusion on the left knee showed signs of healing with mild residual bruising, and no signs of infection. Eczema was under control with current topical regimen; no acute asthma symptoms were reported. Recommended continued use of emollients for eczema and adherence to asthma action plan. Follow-up in 3 months unless symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('60ffa515-53f0-41e4-a145-c6ce6df7f0e1', '2025-03-30T22:51:20.562541', 'Annual Checkup', 'Patient presented for an annual checkup. Parents reported a recent contusion on the left shin, which appeared mild with no signs of infection. Physical examination revealed mild eczema on the elbows and knees, with no acute distress. Vitals were stable: HR 110 bpm, RR 30 breaths/min, Temp 98.6°F. Asthma well-controlled on current medication; no wheezing noted. Recommended continuation of current eczema management regimen and advised monitoring the contusion for any changes. Follow-up in one year unless new concerns arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('60ffa515-53f0-41e4-a145-c6ce6df7f0e1', '2024-12-23T22:51:20.562541', 'Urgent Care', 'Patient presented for evaluation of a contusion on the forehead following a fall from standing height. Physical examination revealed a 3 cm ecchymosis with mild swelling, no laceration or signs of infection. Vitals: HR 110 bpm, RR 30 breaths/min, BP not applicable for age, SpO2 98% on room air. Assessment: Contusion with no evidence of fracture or intracranial injury. Plan: Apply cold compress to the affected area, monitor for any signs of increased swelling or behavioral changes, and follow up with primary care if symptoms persist or worsen. Recommended maintaining asthma management plan and moisturizing regimen for eczema.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('60ffa515-53f0-41e4-a145-c6ce6df7f0e1', '2024-10-10T22:51:20.562541', 'Annual Checkup', 'Patient presented for annual checkup. Noted a contusion on the right forearm, likely from recent minor fall; no signs of infection or significant swelling. History of eczema and asthma were reviewed; skin appears well-hydrated with mild erythema in flexural areas, and lungs were clear to auscultation. Recommended continuation of current skincare regimen and asthma management plan; advised to monitor the contusion for any changes. Vitals: HR 120 bpm, RR 30/min, Temp 98.6°F.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ccb4e741-a6bf-46e6-96fa-558c2314a06f', '2026-02-04T22:51:30.800356', 'Follow-up Visit', 'Patient presented for follow-up of contact dermatitis. Exam revealed erythematous patches on the dorsal aspect of both hands, with mild pruritus reported. Vitals were stable: BP 112/68, HR 72. Assessment: contact dermatitis secondary to recent exposure to new soap. Plan included continued use of topical corticosteroid cream and avoidance of known irritants. Advised patient and guardian to monitor for any signs of infection and to follow up in 4 weeks or sooner if symptoms worsen. Asthma remains well-controlled; no exacerbations reported.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ccb4e741-a6bf-46e6-96fa-558c2314a06f', '2025-06-15T22:51:30.800356', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were stable: BP 110/70 mmHg, HR 78 bpm, respiratory rate 16 breaths per minute. The patient reported a recent flare-up of contact dermatitis with erythema and pruritus on the forearms, managed with topical corticosteroids. Asthma was well-controlled with current inhaler regimen. Recommended continuation of current asthma management plan and advised to avoid known allergens to prevent dermatitis exacerbations. Follow-up in one year or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('d9cfb097-be0b-4f4c-b031-f076b89855b3', '2025-11-21T22:51:34.282943', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were within normal limits: blood pressure 112/70 mmHg, heart rate 78 bpm, respiratory rate 16 breaths/min, temperature 98.6°F. No symptoms or abnormalities noted on physical examination. Advised to maintain a balanced diet and regular physical activity; follow-up in one year unless concerns arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5aa172e8-4f15-4561-bb60-bf2f7878d38e', '2026-02-09T22:51:35.716704', 'Annual Checkup', 'Patient presented for an annual checkup with a known history of asthma and allergies. Vitals were stable with BP 118/76 mmHg and HR 72 bpm. Patient reported no recent exacerbations of asthma, but mild increase in seasonal allergy symptoms. Lung auscultation revealed clear breath sounds bilaterally. Recommended continuation of current asthma management plan, advised on allergen avoidance strategies, and discussed potential need for adjustment of antihistamines during peak allergy seasons. Follow-up in 12 months or as needed for acute concerns.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5aa172e8-4f15-4561-bb60-bf2f7878d38e', '2025-09-14T22:51:35.716704', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: BP 118/76 mmHg, HR 72 bpm, Respiratory Rate 16 breaths/min, SpO2 98% on room air. Patient reported occasional wheezing and shortness of breath, primarily during physical exertion, which aligns with her asthma condition. Examination revealed clear lung fields with no audible wheeze at rest. Continued management with inhaled corticosteroid and as-needed albuterol was advised. Recommended patient to receive influenza vaccination and discussed strategies for allergen avoidance given her history of allergic rhinitis and seasonal allergies. Follow-up in one year or sooner if symptoms escalate.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e72ebfb0-7174-478b-b4e3-e1ba4045b139', '2026-02-08T22:51:42.066928', 'Annual Checkup', 'Patient presented for an annual checkup with ongoing management of bronchitis. Vital signs were as follows: BP 142/88 mmHg, HR 82 bpm, BMI 32.4 kg/m². Patient reported persistent cough and mild dyspnea with exertion. Assessment: Obesity, hypertension, diabetes, GERD, and acute bronchitis. Plan included continuation of current medications, addition of an inhaler for bronchitis symptoms, dietary counseling for weight management, and scheduling of a follow-up visit in three months.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e72ebfb0-7174-478b-b4e3-e1ba4045b139', '2025-07-13T22:51:42.066928', 'Follow-up Visit', 'Patient presented for follow-up on bronchitis. Vital signs were stable with BP 138/82 mmHg, HR 78 bpm, and SpO2 at 95% on room air. Patient reported persistent cough and mild dyspnea but noted improvement with prescribed bronchodilator. Continued management of comorbid conditions, emphasized weight management and adherence to antihypertensives, metformin, and proton pump inhibitors. Recommended follow-up in 4 weeks or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e72ebfb0-7174-478b-b4e3-e1ba4045b139', '2025-03-16T22:51:42.066928', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 142/88 mmHg, heart rate 78 bpm, and BMI indicated obesity. Patient reported persistent cough and wheezing, consistent with ongoing bronchitis. Recommended continuation of bronchodilator therapy and advised lifestyle modifications to address obesity. Discussed importance of glucose monitoring and blood pressure control to manage diabetes and hypertension, respectively. Advised follow-up in 3 months to reassess respiratory symptoms and overall health management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4051eab0-4052-4428-8f8d-da3f1f2b3ffa', '2025-10-12T22:51:47.227183', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding migraine management. Blood pressure was 128/82 mmHg, heart rate was 76 bpm. Reports improvement in migraine frequency with current medication regimen but noted increased joint discomfort likely related to osteoarthritis. Recommended continuation of current migraine treatment and advised low-impact exercises to alleviate joint symptoms. Scheduled an appointment with ophthalmology to assess for cataract progression.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4051eab0-4052-4428-8f8d-da3f1f2b3ffa', '2025-09-24T22:51:47.227183', 'Follow-up Visit', 'Patient presented for follow-up regarding migraines. Blood pressure was 128/82 mmHg, heart rate was 74 bpm. She reported persistent migraines occurring 1-2 times weekly, with moderate to severe intensity, partially alleviated by current medication regimen. Recommended continuation of current migraine prophylaxis with an increased dose of topiramate, and advised dietary modifications to identify potential triggers. Follow-up in 3 months to assess efficacy of treatment changes.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4051eab0-4052-4428-8f8d-da3f1f2b3ffa', '2025-05-06T22:51:47.227183', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable with blood pressure at 128/82 mmHg and heart rate at 76 bpm. She reported experiencing increased frequency of migraine episodes over the past month, averaging 3-4 times weekly, and occasional nausea associated with these episodes. Examination revealed no acute distress. Assessment indicated well-managed hypothyroidism and osteoarthritis, though migraine management needs adjustment. Advised to continue current levothyroxine and NSAID regimen; recommended initiating a low-dose beta-blocker for migraine prophylaxis. Follow-up in 3 months to evaluate migraine control and reassess treatment efficacy.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('45085d5d-7490-4b88-be15-dcab377aefe6', '2025-12-07T22:51:53.536645', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 150/95 mmHg, HR 82 bpm, weight 230 lbs, BMI 36.1 kg/m². Physical examination revealed no acute distress, but continued obesity was noted. Assessment included poorly controlled hypertension and hyperlipidemia. Recommended dietary modifications and increased physical activity. Continued current antihypertensive and statin therapy with follow-up in 3 months to re-evaluate blood pressure and lipid levels.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('45085d5d-7490-4b88-be15-dcab377aefe6', '2025-10-17T22:51:53.536645', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding obesity management and cardiovascular risk assessment. Blood pressure was recorded at 140/85 mmHg, and heart rate was 82 bpm. The patient reported no new symptoms but expressed difficulty in adhering to dietary changes. Continued management of hypertension and hyperlipidemia was advised, with a recommendation to consult with a nutritionist for personalized dietary planning. Weight loss goals were reviewed, and the patient was encouraged to increase physical activity to at least 150 minutes of moderate exercise per week. Follow-up scheduled in three months to reassess progress and adjust treatment as needed.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a60910c6-6df2-493c-8fe9-fe705431e4ae', '2025-10-16T22:51:57.189240', 'Follow-up Visit', 'Patient presented for a follow-up visit for cellulitis. Physical examination revealed mild erythema and warmth in the affected area on the lower left leg, with decreased swelling since the last visit. Blood pressure was 145/88 mmHg, heart rate 82 bpm. The cellulitis appears to be improving with current antibiotic regimen; advised to continue with antibiotics as prescribed and elevate the leg when possible. Recommended follow-up in one week to reassess and monitor progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a60910c6-6df2-493c-8fe9-fe705431e4ae', '2025-07-18T22:51:57.189240', 'Emergency Visit', 'Patient presented for evaluation of worsening cellulitis on the left lower extremity. Physical examination revealed erythema, warmth, and edema in the affected area, with tenderness upon palpation. Vitals: BP 150/88 mmHg, HR 92 bpm, Temp 101.2°F, RR 20 breaths/min. Assessment indicated worsening cellulitis potentially due to inadequate response to current antibiotic therapy. Recommended admission for IV antibiotic treatment and further monitoring, with adjustments in hypertension management as necessary. Advised follow-up with primary care and dermatology to evaluate underlying contributory factors, including obesity and poor circulation.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a60910c6-6df2-493c-8fe9-fe705431e4ae', '2025-07-17T22:51:57.189240', 'Follow-up Visit', 'Patient presented for follow-up on cellulitis of the left lower extremity. Physical examination revealed mild erythema and swelling with decreased warmth compared to the previous visit. Blood pressure was 138/82 mmHg, heart rate 78 bpm, and respiratory rate 16 breaths per minute. Assessment indicated improvement of cellulitis; advised continuation of current antibiotic regimen and elevation of the affected limb. Recommended follow-up in 1 week to reassess healing and manage underlying conditions.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a60910c6-6df2-493c-8fe9-fe705431e4ae', '2025-01-30T22:51:57.189240', 'Annual Checkup', 'Patient presented for an annual checkup and follow-up on cellulitis. Vital signs were stable: BP 138/82 mmHg, HR 76 bpm, RR 18/min, Temp 98.6°F. The lower left leg exhibited erythema and mild edema consistent with cellulitis, but no purulent discharge was noted. Continued management with oral antibiotics was recommended, and follow-up in one week for reassessment of the cellulitis was advised. Hypertension and asthma remained well-controlled with current medications. Patient was counseled on weight management strategies to address obesity.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a60910c6-6df2-493c-8fe9-fe705431e4ae', '2024-11-10T22:51:57.189240', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were stable: BP 138/86 mmHg, HR 78 bpm, RR 16/min, SpO2 96% on room air. Notable findings included erythema and warmth over the left lower extremity consistent with ongoing cellulitis; patient reported mild pain and tenderness in the affected area. Continued current antibiotic therapy was advised, along with elevation of the limb and follow-up if symptoms worsen. Reviewed and adjusted medications for hypertension and GERD. Recommended weight management strategies to address obesity, and referred to ophthalmology for cataract evaluation.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c29bbec4-2bf0-4db1-98c3-540a0556e5a0', '2025-12-27T22:52:06.643014', 'Follow-up Visit', 'Patient presented for follow-up regarding gallstones and management of chronic conditions. Blood pressure was 138/85 mmHg, heart rate 78 bpm, and BMI 32 kg/m². Patient reported intermittent right upper quadrant pain, managed with dietary changes. Continued current medications for hyperlipidemia, hypertension, and diabetes; advised weight management and scheduled an ultrasound to assess the gallstones. Recommended follow-up with the mental health provider for depression management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c29bbec4-2bf0-4db1-98c3-540a0556e5a0', '2025-10-18T22:52:06.643014', 'Annual Checkup', 'Patient presented for annual checkup. Physical examination revealed BP 145/90 mmHg, HR 78 bpm, BMI 32 kg/m². The patient reported intermittent episodes of abdominal pain consistent with gallstones. Labs showed controlled lipid levels, but HbA1c was 7.5%. Recommended dietary modifications and regular exercise to manage obesity and improve glycemic control. Continued current antihypertensive and lipid-lowering medications, and referral to gastroenterology for further evaluation of gallstones was provided. Adjusted diabetes medication regimen to improve blood sugar levels.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('97ed20ea-c39f-424f-841c-ece1ff0bb601', '2025-12-14T22:52:10.017206', 'Annual Checkup', 'Patient presented for an annual checkup. Physical examination revealed a BMI of 31, classifying the patient as obese. Vitals were stable with BP at 118/76 mmHg and HR at 72 bpm. No acute symptoms were reported. Recommended dietary modifications and increased physical activity, including at least 60 minutes of moderate exercise daily, to address weight management. Follow-up scheduled in 6 months to monitor progress and reassess health status.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('97ed20ea-c39f-424f-841c-ece1ff0bb601', '2025-06-23T22:52:10.017206', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding obesity management. Vitals were stable: BP 118/76 mmHg, HR 72 bpm. No new symptoms reported; continued healthy weight loss plan was advised, focusing on balanced diet and increased physical activity. Recommended follow-up with nutritionist and scheduled re-evaluation in three months to assess progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('97ed20ea-c39f-424f-841c-ece1ff0bb601', '2025-04-01T22:52:10.017206', 'Consultation', 'Patient presented for obesity management consultation. Vital signs were as follows: BP 128/85 mmHg, HR 82 bpm, weight 95 kg, height 165 cm, BMI 34.9 kg/m². No acute distress noted. Discussed dietary modifications, increased physical activity, and referred to a nutritionist for further guidance. Follow-up scheduled in 3 months to assess progress and adjust the management plan as needed.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('cacd05fd-6465-4ba0-8b88-4f8cafe0a5d0', '2026-01-16T22:52:14.548389', 'Annual Checkup', 'Patient presented for an annual checkup. Physical examination revealed dry, erythematous patches on the antecubital fossae consistent with eczema. Vital signs were stable: BP 90/60 mmHg, HR 92 bpm, RR 20 bpm, Temp 98.4°F. It was advised to continue using the prescribed emollient and topical corticosteroid as needed, with follow-up in 6 months or sooner if symptoms exacerbate. Recommended continued avoidance of known allergens to manage allergic rhinitis.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('cacd05fd-6465-4ba0-8b88-4f8cafe0a5d0', '2025-10-04T22:52:14.548389', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were within normal limits for age: BP 90/60 mmHg, HR 98 bpm, Temp 98.6°F, RR 20 breaths/min. Examination revealed mild erythematous patches on the antecubital and popliteal fossae consistent with eczema, with no signs of infection. Continued management of eczema with emollient use and intermittent topical corticosteroids was recommended. Advised on environmental control measures for allergic rhinitis, including dust mite reduction and air purifier use. Follow-up in one year or as needed for exacerbations.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('fc0d1a91-123f-4da6-b947-b8aea75907c8', '2025-10-15T22:52:18.713817', 'Follow-up Visit', 'Patient presented for a follow-up visit for urinary tract infection. Vitals: BP 145/88 mmHg, HR 78 bpm. Patient reported mild dysuria and increased frequency of urination but noted improvement since commencing antibiotics. Assessment indicated ongoing mild symptoms secondary to UTI, with stable management of osteoarthritis, obesity, asthma, and hypertension. Recommended continuation of current antibiotic regimen, increased fluid intake, and follow-up in 2 weeks to reassess infection resolution and blood pressure management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('fc0d1a91-123f-4da6-b947-b8aea75907c8', '2025-07-25T22:52:18.713817', 'Urgent Care', 'Patient presented for evaluation of urinary tract infection. Reported symptoms included dysuria and increased urinary frequency. Blood pressure was 142/88 mmHg, heart rate 78 bpm, and temperature 100.1°F. Physical examination revealed suprapubic tenderness. Urinalysis confirmed the presence of leukocytes and nitrites. Recommended antibiotic therapy with trimethoprim-sulfamethoxazole for 7 days and advised increased fluid intake. Follow-up in one week or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('fc0d1a91-123f-4da6-b947-b8aea75907c8', '2025-07-18T22:52:18.713817', 'Annual Checkup', 'Patient presented for an annual checkup and evaluation of a urinary tract infection. Vital signs: BP 150/85, HR 80 bpm, Temp 99.1°F. Patient reported dysuria and increased urinary frequency. Physical examination revealed mild suprapubic tenderness. Assessment confirmed UTI on top of existing conditions: osteoarthritis, obesity, asthma, and hypertension. Recommended continuation of prescribed antibiotics for UTI, advised weight management strategies, and discussed importance of asthma control and hypertension monitoring. Follow-up in 4 weeks for blood pressure re-evaluation.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('d1e4c650-91e0-42a7-a2f3-10d30eb45547', '2025-10-07T22:52:23.585278', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 138/85 mmHg, heart rate 78 bpm, and BMI 27.2 kg/m². Reports occasional right upper quadrant abdominal pain, consistent with known gallstones, but denies changes in bowel habits or jaundice. GERD symptoms are well-managed with current proton pump inhibitor regimen. Osteoarthritis is stable with acetaminophen use as needed. Recommended continued dietary modifications for hyperlipidemia and follow-up with gastroenterologist for gallstone management if symptoms worsen. Advised to maintain hypertension management and regular physical activity.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('d1e4c650-91e0-42a7-a2f3-10d30eb45547', '2025-06-02T22:52:23.585278', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 138/82 mmHg, heart rate was 76 bpm, and BMI was 28.3 kg/m². The patient reported intermittent right upper quadrant pain, likely related to gallstones, with no signs of jaundice or fever. GERD symptoms were controlled with current medication. Hypertension and hyperlipidemia remain stable under current management. Recommended continuation of current medication regimen, dietary modifications for gallstone management, and follow-up ultrasound if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('d1e4c650-91e0-42a7-a2f3-10d30eb45547', '2025-04-01T22:52:23.585278', 'Consultation', 'Patient presented for evaluation of gallstones. Reports intermittent episodes of right upper quadrant abdominal pain, particularly after meals. Vital signs were stable: BP 138/82 mmHg, HR 78 bpm. Physical exam revealed mild tenderness upon palpation of the right upper quadrant without guarding or rebound tenderness. Assessment confirmed symptomatic cholelithiasis. Recommended dietary modifications to manage symptoms, and discussed potential surgical intervention if symptoms persist. Follow-up scheduled in four weeks or sooner if acute symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('be8e944d-9789-4cf2-9145-12b66657a278', '2026-02-20T22:52:29.346928', 'Follow-up Visit', 'Patient presented for follow-up on contact dermatitis. Blood pressure was 138/82 mmHg, heart rate 76 bpm. Skin examination revealed erythematous, pruritic patches on the forearms, consistent with previous dermatitis. Continued topical corticosteroid treatment was recommended, and patient was advised to avoid known irritants. Assessment noted stable control of hypertension and GERD, with weight management and dietary modifications advised for obesity and prediabetes. Depression and anemia remained stable on current medications. Follow-up scheduled in three months.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('be8e944d-9789-4cf2-9145-12b66657a278', '2025-10-05T22:52:29.346928', 'Consultation', 'Patient presented for consultation regarding persistent contact dermatitis. Physical examination revealed erythematous, pruritic patches on bilateral forearms. Blood pressure recorded at 142/88 mmHg, heart rate at 78 bpm. Advised continuation of topical corticosteroids and avoidance of known irritants. Recommended follow-up with dermatology for potential patch testing and reviewed management of comorbid conditions, including monitoring blood glucose levels and maintaining blood pressure control.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('be8e944d-9789-4cf2-9145-12b66657a278', '2025-02-18T22:52:29.346928', 'Urgent Care', 'Patient presented for worsening contact dermatitis, reporting increased pruritus and erythema on the forearms. Vital signs noted: BP 142/88 mmHg, HR 78 bpm, SpO2 98% on room air. Examination revealed excoriated erythematous plaques with mild lichenification. Recommended topical corticosteroids and advised avoidance of known irritants. Given medical history, follow-up with primary care for comprehensive management of chronic conditions was advised.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('be8e944d-9789-4cf2-9145-12b66657a278', '2025-01-27T22:52:29.346928', 'Annual Checkup', 'Patient presented for an annual checkup with a history of contact dermatitis. Vitals were stable: BP 138/85 mmHg, HR 72 bpm. The patient reported intermittent pruritus and erythema on the hands, with no new lesions noted. Assessment included controlled hypertension and GERD, stable depression with current medication, and anemia improving with ongoing treatment. Recommended continuation of current management plan, including topical corticosteroids for dermatitis and regular follow-up for monitoring chronic conditions.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('be8e944d-9789-4cf2-9145-12b66657a278', '2024-06-22T22:52:29.346928', 'Consultation', 'Patient presented for evaluation of worsening contact dermatitis. Vital signs: BP 145/85 mmHg, HR 78 bpm. Physical examination revealed erythematous, pruritic patches on bilateral forearms. Recommended continuation of topical corticosteroids and avoidance of known irritants. Advised monitoring blood pressure closely due to history of hypertension and discussed dietary modifications to address obesity and prediabetes. Follow-up in 4 weeks for re-evaluation.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('39f1f93e-0296-4569-b85f-e45e206db3bb', '2026-02-12T22:52:37.125712', 'Follow-up Visit', 'Patient presented for follow-up of folliculitis. Physical examination revealed multiple erythematous papules on the posterior neck and upper back, consistent with ongoing folliculitis, no signs of infection. Vitals were stable: BP 128/82 mmHg, HR 76 bpm. Continued management with topical clindamycin was advised; patient was also counseled on proper skin hygiene. Plan includes follow-up in four weeks to assess treatment efficacy.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('39f1f93e-0296-4569-b85f-e45e206db3bb', '2025-08-26T22:52:37.125712', 'Follow-up Visit', 'Patient presented for a follow-up visit concerning folliculitis. Vitals were stable: BP 128/82 mmHg, HR 78 bpm. Examination revealed mild erythematous papules on the posterior neck, with no signs of secondary infection. Assessment confirmed improvement with ongoing topical antibiotic treatment. Recommended continuation of current regimen and follow-up in one month to monitor resolution. Advised patient on proper skin hygiene and weight management strategies given his obesity and hyperlipidemia. Asthma remains well-controlled with current inhaler use.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('39f1f93e-0296-4569-b85f-e45e206db3bb', '2025-07-19T22:52:37.125712', 'Annual Checkup', 'Patient presented for annual checkup. Vital signs were BP 130/85 mmHg, HR 78 bpm, BMI 32.2. Mild erythematous papules consistent with folliculitis noted on the anterior thighs. Asthma well-controlled with current management; advised continued use of inhaler as needed. Recommended dietary modifications and increased physical activity to address obesity and hyperlipidemia. Prescribed topical antibiotic for folliculitis and advised follow-up in one month if no improvement.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ea9bc4a8-0a07-437b-92f4-aa6eb7c8b1dc', '2025-10-02T22:52:41.937246', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding management of hyperlipidemia. Vitals were stable with blood pressure at 130/82 mmHg and heart rate at 74 bpm. Patient reported occasional joint pain consistent with osteoarthritis but no new symptoms. Lipid panel from last week showed LDL at 140 mg/dL; advised continuation of atorvastatin and encouraged dietary modifications and regular exercise. Follow-up in 6 months to re-evaluate lipid levels and address joint discomfort.', NULL);
