VALUES ('ea9bc4a8-0a07-437b-92f4-aa6eb7c8b1dc', '2025-07-01T22:52:41.937246', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding hyperlipidemia management. Vital signs were stable with BP 130/85 mmHg and HR 72 bpm. Patient reported mild joint stiffness, consistent with osteoarthritis, but no significant changes in GERD symptoms. Lipid panel results indicated LDL levels remained above target; atorvastatin dosage was adjusted. Recommended continued dietary modifications and regular exercise to further manage lipid levels. Follow-up in 3 months to reassess lipid control and joint symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ea9bc4a8-0a07-437b-92f4-aa6eb7c8b1dc', '2025-06-07T22:52:41.937246', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable with BP 128/76 mmHg and HR 72 bpm. Physical examination was unremarkable except for mild joint stiffness consistent with osteoarthritis. Lipid panel reviewed, showing elevated LDL levels; atorvastatin dose increased to 40 mg daily. Recommended continuation of proton pump inhibitor for GERD management. Advised follow-up with ophthalmology due to history of cataracts. Scheduled next annual checkup in one year, with interim follow-up for lipid management in six months.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ea9bc4a8-0a07-437b-92f4-aa6eb7c8b1dc', '2025-06-02T22:52:41.937246', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 128/76 mmHg, heart rate was 72 bpm, and BMI was 26.3 kg/m². Patient reported occasional joint stiffness, consistent with osteoarthritis, but no new symptoms. Lipid panel and liver function tests were recommended for hyperlipidemia management. Advised continuation of current medications for GERD and osteoarthritis, and to follow up with ophthalmology for cataracts monitoring. Discussed healthy lifestyle modifications, including diet and exercise, to maintain cardiovascular health.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ea9bc4a8-0a07-437b-92f4-aa6eb7c8b1dc', '2024-06-20T22:52:41.937246', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 138/82 mmHg and heart rate was 76 bpm. Patient reported no new symptoms but mentioned occasional joint pain, likely related to osteoarthritis, and managed with acetaminophen as needed. Lipid panel reviewed; LDL levels remain slightly elevated. Recommended continuation of current statin therapy for hyperlipidemia and dietary modifications. Follow-up in six months to reassess lipid levels and monitor joint symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4df86d25-c074-4fce-9dbf-841b8fdd6dd5', '2025-10-04T22:52:53.332333', 'Consultation', 'Patient presented for evaluation of social anxiety. Reported increased anxiety symptoms in school settings, including avoidance of group activities and difficulty speaking in class. No significant physical findings; vital signs were stable (BP 112/70 mmHg, HR 78 bpm). Assessment: Social Anxiety Disorder. Recommended cognitive behavioral therapy (CBT) and discussed potential referral to a child psychologist. Follow-up in 4 weeks to assess progress and consider further intervention if needed.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4df86d25-c074-4fce-9dbf-841b8fdd6dd5', '2025-07-25T22:52:53.332333', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were stable: BP 110/70 mmHg, HR 72 bpm, temperature 98.6°F. Patient reported experiencing symptoms of social anxiety, particularly in school settings, but no other significant findings were noted upon physical examination. Recommended continuation of current behavioral therapy and consideration of a referral to a child psychologist if symptoms persist or worsen. Follow-up in six months or as needed.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4df86d25-c074-4fce-9dbf-841b8fdd6dd5', '2025-02-04T22:52:53.332333', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were within normal limits: BP 110/70 mmHg, HR 76 bpm. The patient reported ongoing struggles with social anxiety, affecting school performance and social interactions. Physical exam was unremarkable. Recommended continuation of cognitive behavioral therapy and discussed possible referral to a pediatric psychologist for further evaluation and management. Follow-up appointment scheduled in 6 months.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('832353d6-7738-4873-894d-07bc70af7beb', '2026-01-21T22:52:58.217196', 'Consultation', 'Patient presented for routine hypertension management consultation. Vitals were recorded: BP 138/82 mmHg, HR 78 bpm. Patient reported occasional dizziness, but no other new symptoms. Assessment indicated stable hypertension, though lifestyle modifications were reinforced due to prediabetes and hyperlipidemia. Recommended continuation of current antihypertensive regimen, advised regular physical activity, and dietary modifications to manage weight and improve lipid profile. Scheduled follow-up in 3 months for further evaluation.', NULL);
