VALUES ('832353d6-7738-4873-894d-07bc70af7beb', '2025-07-13T22:52:58.217196', 'Follow-up Visit', 'Patient presented for a follow-up visit to monitor hypertension and review current management of chronic conditions. Blood pressure was recorded at 138/82 mmHg, and heart rate was 76 bpm. The patient reported mild knee pain attributed to osteoarthritis but denied any new symptoms or significant changes in her condition. Recommended continuation of current antihypertensive and hyperlipidemia medications, advised regular monitoring of blood glucose levels due to prediabetes, and suggested non-pharmacologic measures such as dietary adjustments and increased physical activity. Follow-up in 6 months unless symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('832353d6-7738-4873-894d-07bc70af7beb', '2025-05-30T22:52:58.217196', 'Consultation', 'Patient presented for routine consultation and management of hypertension. Blood pressure was recorded at 148/86 mmHg, and heart rate was 78 bpm. Patient reported occasional knee pain due to osteoarthritis and mild dyspepsia, consistent with GERD. Assessment revealed stable hypertension and hyperlipidemia, with controlled blood sugar levels. Recommended continued adherence to antihypertensive and statin therapy, advised dietary modifications for GERD, and suggested follow-up with rheumatology for osteoarthritis management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('832353d6-7738-4873-894d-07bc70af7beb', '2025-02-28T22:52:58.217196', 'Follow-up Visit', 'Patient presented for a follow-up visit to manage hypertension and review current medications. Blood pressure was 138/82 mmHg, and heart rate was 78 bpm. The patient reported mild joint stiffness in the mornings consistent with osteoarthritis, but no significant changes in prediabetes management. Recommended maintaining current antihypertensive regimen, advised continuation of low-sodium diet, and encouraged regular low-impact exercises to aid joint mobility and manage lipid levels. Follow-up in 6 months unless symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b7338496-f4f6-43cb-b508-08db10d6ed8a', '2026-01-10T22:53:06.347645', 'Consultation', 'Patient presented for routine follow-up consultation regarding hypertension management. Blood pressure was recorded at 150/92 mmHg, and heart rate was 82 bpm. Patient reported increased episodes of anxiety and occasional palpitations. Assessment indicated suboptimal blood pressure control and anxiety exacerbation. Recommended adjustment of antihypertensive therapy and consideration of increasing anxiolytic medication. Advised dietary modifications and regular physical activity to address obesity and hyperlipidemia. Scheduled follow-up appointment in 3 months to reassess blood pressure and anxiety symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b7338496-f4f6-43cb-b508-08db10d6ed8a', '2025-06-06T22:53:06.347645', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were recorded as BP 140/88 mmHg, HR 78 bpm, and BMI 32.2 kg/m². Physical examination was unremarkable except for mild conjunctival redness. Assessment indicated well-managed diabetes and stable hyperlipidemia, but blood pressure was elevated. Recommended increasing physical activity, dietary modifications, and adjusting antihypertensive medication. Advised follow-up in 3 months to reassess blood pressure management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a97793de-6c55-4ce0-aaeb-36bcd1f2e2e4', '2026-02-09T22:53:10.400610', 'Consultation', 'Patient presented for consultation regarding ongoing cancer management. Blood pressure was 142/88 mmHg, and heart rate was 86 bpm. Patient reported increased fatigue and joint pain, consistent with osteoarthritis exacerbation and cancer treatment side effects. Recommended adjustment of hypertension medication and initiation of low-impact physical therapy to address obesity and improve joint function. Consideration for oncology follow-up to evaluate current cancer treatment efficacy.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a97793de-6c55-4ce0-aaeb-36bcd1f2e2e4', '2025-09-10T22:53:10.400610', 'Emergency Visit', 'Patient presented to the emergency department with acute shortness of breath and chest pain. Vital signs revealed blood pressure at 160/95 mmHg, heart rate at 110 bpm, and oxygen saturation at 88% on room air. Physical examination showed decreased breath sounds in the right lower lung field. Assessment indicated possible pleural effusion secondary to cancer. Recommended immediate thoracentesis and initiated supplemental oxygen therapy. Follow-up with oncology and cardiology is advised.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a97793de-6c55-4ce0-aaeb-36bcd1f2e2e4', '2025-06-13T22:53:10.400610', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs: BP 142/88 mmHg, HR 78 bpm, BMI 33.4 kg/m². The patient reported mild joint pain consistent with osteoarthritis but no new symptoms related to her cancer diagnosis. Recommended continuation of current hypertension management, weight loss strategies, and regular follow-up with oncology to monitor cancer status.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a97793de-6c55-4ce0-aaeb-36bcd1f2e2e4', '2024-11-07T22:53:10.400610', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding ongoing cancer treatment. Vital signs were stable: BP 135/82 mmHg, HR 78 bpm. The patient reported mild fatigue and joint discomfort, consistent with osteoarthritis, but no significant changes in weight or appetite. Continued current chemotherapy regimen, with recommendations to maintain a low-sodium diet for hypertension management and engage in low-impact exercises to improve joint mobility. Follow-up scheduled in four weeks to monitor treatment progress and symptom management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a97793de-6c55-4ce0-aaeb-36bcd1f2e2e4', '2024-09-05T22:53:10.400610', 'Follow-up Visit', 'Patient presented for follow-up of cancer treatment. Blood pressure was 138/82 mmHg, heart rate 78 bpm, and weight remained stable. The patient reported mild fatigue, but denied pain or new symptoms. Assessment showed stable disease with no progression on recent imaging. Recommended continuation of current chemotherapy regimen and scheduled next follow-up in three months. Advised patient on maintaining a balanced diet and regular low-impact exercise to manage obesity and osteoarthritis symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('36f1f808-006d-429c-994b-02d957a7bc83', '2025-10-15T22:53:17.977365', 'Follow-up Visit', 'Patient presented for a follow-up visit concerning shingles. Vitals: BP 138/86 mmHg, HR 78 bpm, BMI 32 kg/m². Patient reported decreased pain but persistent pruritus at the site of the rash. Exam revealed healing lesions with mild erythema. Assessment: Improving herpes zoster. Plan: Continue valacyclovir for 7 more days and start gabapentin for neuropathic pain. Recommended weight loss through dietary modification and regular exercise to manage obesity and prediabetes. Follow-up in 4 weeks to reassess symptoms and metabolic parameters.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('36f1f808-006d-429c-994b-02d957a7bc83', '2025-08-28T22:53:17.977365', 'Consultation', 'Patient presented for consultation regarding shingles, currently affecting the right thoracic region. Vitals were as follows: BP 130/85 mmHg, HR 78 bpm. Physical examination revealed a vesicular rash with erythematous base along the T4 dermatome. Assessment confirmed Herpes Zoster. Recommended continuation of antiviral therapy (Valacyclovir) and analgesics for pain management. Advised patient on the importance of glycemic control and lifestyle modifications to address obesity, prediabetes, and hyperlipidemia. Follow-up scheduled in two weeks to monitor progress and reassess symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('36f1f808-006d-429c-994b-02d957a7bc83', '2025-05-03T22:53:17.977365', 'Follow-up Visit', 'Patient presented for follow-up of shingles outbreak. Vital signs were as follows: BP 138/86 mmHg, HR 78 bpm, BMI 33 kg/m². Patient reported improvement in rash with antiviral therapy but continued to experience postherpetic neuralgia. Recommended continuation of gabapentin for neuropathic pain management and advised maintaining a low-carbohydrate diet to manage prediabetes and hyperlipidemia. Follow-up in 4 weeks to reassess pain and metabolic parameters.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ac2d3bae-f61b-4224-b1cb-aecffb44cae5', '2025-10-25T22:53:22.988562', 'Follow-up Visit', 'Patient presented for follow-up evaluation of ADHD management and assessment of skin conditions. Vitals were stable: BP 110/70 mmHg, HR 78 bpm. ADHD symptoms remain well-controlled on current medication regimen, with no adverse effects reported. Notable improvement in acne with topical retinoid use; mild eczema flare-up observed on bilateral antecubital fossa. Recommended continuation of current ADHD medication and topical treatments, with the addition of a mild corticosteroid cream for eczema. Follow-up in three months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ac2d3bae-f61b-4224-b1cb-aecffb44cae5', '2025-10-16T22:53:22.988562', 'Urgent Care', 'Patient presented for evaluation of a rash that developed over the past three days. Physical examination revealed erythematous, pruritic patches on the antecubital and popliteal fossae consistent with an eczema flare. Vitals were stable: BP 110/70, HR 75. Assessment included eczema exacerbation possibly triggered by seasonal allergies. Recommended topical corticosteroids and advised follow-up with primary care for ongoing management of ADHD and depression.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ac2d3bae-f61b-4224-b1cb-aecffb44cae5', '2025-07-18T22:53:22.988562', 'Annual Checkup', 'Patient presented for annual checkup. Vitals were within normal limits: BP 110/70 mmHg, HR 78 bpm. Patient''s ADHD symptoms are stable on current medication regimen; however, there is a report of increased difficulty concentrating at school. Eczema and acne are well-controlled with current treatment. Recommended continuation of current ADHD medication, and advised follow-up with dermatologist for ongoing acne management. Discussed potential need for adjustment in ADHD treatment and importance of regular mental health follow-up for depression.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('241e836a-fc97-43f9-95ef-2157f6a5accd', '2026-02-01T22:53:27.984741', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding hypertension management. Blood pressure was 138/85 mmHg and heart rate was 72 bpm. Patient reported occasional dizziness, likely related to antihypertensive medication. Recommended adjustment of current medication dosage and advised dietary modifications and regular physical activity to better control blood pressure and weight. Follow-up scheduled in 3 months to reassess blood pressure control and address any ongoing symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('241e836a-fc97-43f9-95ef-2157f6a5accd', '2025-06-19T22:53:27.984741', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding hypertension management. Blood pressure was 142/88 mmHg, and heart rate was 76 bpm. Patient reported occasional headaches and increased anxiety levels. Assessment indicated suboptimal blood pressure control, likely influenced by stress. Recommended increasing the current antihypertensive medication dosage and continuing lifestyle modifications, including dietary changes and regular physical activity. Advised follow-up in 3 months to reassess blood pressure and anxiety management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5564efed-c525-4a1e-b6fe-5df0eedf7f2b', '2026-01-07T22:53:31.291364', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 138/86 mmHg, heart rate 76 bpm, and BMI 31.2 kg/m². Physical examination revealed no acute distress; however, mild wheezing was noted on auscultation. Recommended continuation of current antihypertensive and statin therapy, advised weight management strategies, and scheduled follow-up for asthma management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5564efed-c525-4a1e-b6fe-5df0eedf7f2b', '2025-10-21T22:53:31.291364', 'Consultation', 'Patient presented for routine consultation regarding hypertension management. Blood pressure was 145/90 mmHg, and heart rate was 82 bpm. Physical examination revealed no acute distress, and lung auscultation was clear with mild wheezing noted on exertion. Assessment indicated controlled hypertension but advised continued monitoring due to prediabetes and hyperlipidemia. Recommended lifestyle modifications, including dietary adjustments and increased physical activity, and continued current medication regimen. Follow-up scheduled in 3 months to reassess cardiovascular risk factors and monitor blood glucose levels.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5564efed-c525-4a1e-b6fe-5df0eedf7f2b', '2025-04-29T22:53:31.291364', 'Follow-up Visit', 'Patient presented for a follow-up visit for hypertension management. Vital signs recorded: BP 145/88 mmHg, HR 78 bpm. The patient reported occasional dizziness but denied any chest pain or shortness of breath. Assessment indicated suboptimal blood pressure control. Recommended adjustment of antihypertensive medication and encouraged adherence to a low-sodium diet and regular physical activity. Follow-up scheduled in 3 months to reassess blood pressure and medication efficacy.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5564efed-c525-4a1e-b6fe-5df0eedf7f2b', '2025-03-27T22:53:31.291364', 'Consultation', 'Patient presented for routine consultation and management of hypertension. Blood pressure was 148/92 mmHg, heart rate 78 bpm. Physical examination revealed mild bilateral pedal edema. Continued current antihypertensive regimen and recommended dietary modifications to address obesity and hyperlipidemia. Discussed importance of glycemic control and advised follow-up in 3 months to monitor blood pressure and lipid levels.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5564efed-c525-4a1e-b6fe-5df0eedf7f2b', '2024-06-05T22:53:31.291364', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 142/88 mmHg, HR 78 bpm, weight stable since last visit. Patient reported occasional shortness of breath, managed with inhaler use, and mild reflux symptoms. Physical examination revealed no acute distress, lungs clear to auscultation, and heart sounds regular. Continued management of hypertension with current medication was advised, along with dietary modifications to address obesity and hyperlipidemia. Recommended follow-up with ophthalmology for cataract monitoring and encouraged routine exercise for prediabetes management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a79956f8-6ca3-4fed-b7ce-c4979c1f2e90', '2026-01-15T22:53:39.995968', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 148/92 mmHg, HR 82 bpm, BMI 32.2 kg/m². Patient reported occasional heartburn managed with OTC antacids but denied any new symptoms. Assessment indicated poorly controlled hypertension and obesity. Recommended dietary modifications, increased physical activity, and adjustment of antihypertensive medication. Scheduled follow-up in 3 months to reassess blood pressure and weight management progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a79956f8-6ca3-4fed-b7ce-c4979c1f2e90', '2025-09-11T22:53:39.995968', 'Follow-up Visit', 'Patient presented for follow-up evaluation of hypertension management and obesity. Vitals: BP 150/92 mmHg, HR 84 bpm, weight 260 lbs, BMI 37.4 kg/m². Patient reported occasional heartburn with adherence to GERD medication. Assessment: Hypertension suboptimally controlled, obesity-related complications. Plan: Adjust antihypertensive regimen, refer to dietitian for weight management, continue current GERD treatment, follow-up in 3 months.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a79956f8-6ca3-4fed-b7ce-c4979c1f2e90', '2025-07-13T22:53:39.995968', 'Urgent Care', 'Patient presented with acute onset of chest discomfort and shortness of breath. Blood pressure was 152/94 mmHg, heart rate was 98 bpm. Physical examination revealed mild wheezing and abdominal obesity. Assessment indicated likely exacerbation of GERD with possible cardiac involvement. Recommended immediate EKG and lab work to rule out cardiac etiology, and advised lifestyle modifications for weight management. Prescribed proton pump inhibitor for GERD symptoms and referred for cardiology evaluation.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c8c54132-b84d-46d6-b93a-bcad7c144f66', '2025-10-24T22:53:44.806791', 'Consultation', 'Patient presented for routine consultation and management of chronic conditions. Vitals were as follows: BP 142/85 mmHg, HR 78 bpm, BMI 32 kg/m². Patient reported stable control of asthma and diabetes, but noted increased joint pain related to osteoarthritis. Recommended continuation of current medication regimen, referral to physical therapy for joint pain management, and scheduling an ophthalmology follow-up for cataracts. Advised dietary modifications and increased physical activity to address obesity and hyperlipidemia.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c8c54132-b84d-46d6-b93a-bcad7c144f66', '2025-08-26T22:53:44.806791', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 138/85 mmHg, heart rate 76 bpm, BMI 32 kg/m². Patient reported stable control of blood glucose levels, but noted increased joint stiffness, particularly in the knees, attributed to osteoarthritis. Recommended continuation of current diabetic, antihypertensive, and lipid-lowering medications, with addition of physical therapy referral for osteoarthritis management and dietary consultation to address obesity. Follow-up scheduled in 3 months to monitor progress on weight management and joint symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c8c54132-b84d-46d6-b93a-bcad7c144f66', '2025-06-19T22:53:44.806791', 'Emergency Visit', 'Patient presented for acute shortness of breath and chest tightness. Vitals showed BP 150/95 mmHg, HR 102 bpm, RR 24 breaths/min, SpO2 90% on room air. Physical examination revealed wheezing bilaterally and use of accessory muscles. Assessment indicated asthma exacerbation possibly compounded by poorly controlled hypertension and obesity. Administered nebulized albuterol with significant improvement in respiratory status. Advised continuation of home asthma management plan, adjustment of antihypertensive medication, and follow-up with primary care for further evaluation and medication adjustment.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c8c54132-b84d-46d6-b93a-bcad7c144f66', '2025-06-07T22:53:44.806791', 'Urgent Care', 'Patient presented for acute worsening of shortness of breath and cough. Physical exam revealed bilateral wheezing and cyanosis of the nail beds. Blood pressure was 148/92 mmHg, heart rate 88 bpm, respiratory rate 22 breaths per minute, and oxygen saturation was 92% on room air. Assessment indicated an exacerbation of asthma, likely triggered by recent upper respiratory infection. Recommended initiation of albuterol nebulization and adjustment of inhaled corticosteroids. Patient advised to monitor blood glucose levels closely due to potential impact of corticosteroid use and follow up with primary care for further management of chronic conditions.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('798e9e9c-7fbb-4f69-b5f2-c84a42ad9910', '2025-11-26T22:53:52.695190', 'Follow-up Visit', 'Patient presented for a follow-up visit for asthma management. Vital signs were within normal limits: BP 128/82 mmHg, HR 76 bpm, SpO2 97% on room air. Patient reported occasional wheezing and shortness of breath, particularly with exertion, but no recent exacerbations. Lung auscultation revealed mild expiratory wheezes. Continued current asthma management plan with Fluticasone/Salmeterol inhaler BID and encouraged regular use of rescue inhaler PRN. Recommended follow-up in 3 months and advised lifestyle modifications to aid in hypertension control.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('798e9e9c-7fbb-4f69-b5f2-c84a42ad9910', '2025-09-11T22:53:52.695190', 'Annual Checkup', 'Patient presented for annual checkup. Blood pressure was 138/86 mmHg and heart rate was 78 bpm. Physical examination revealed clear breath sounds with no wheezing noted. Asthma appeared well-controlled; advised continuation of current inhaler regimen. Recommended lifestyle modification to manage hypertension, including dietary changes and regular exercise. Follow-up in 6 months for blood pressure monitoring.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('05427f1d-f8e2-40c7-92e2-9dcfdd52dc12', '2025-10-27T22:53:56.889093', 'Follow-up Visit', 'Patient presented for a follow-up regarding low back strain. Reported persistent lower back pain rated 5/10 on the pain scale with occasional radiating discomfort to the left leg. Vitals: BP 118/76 mmHg, HR 72 bpm, RR 16, SpO2 98% on room air. Examination revealed mild tenderness over the lumbar region without significant spasm. Recommended continuation of physical therapy and prescribed a short course of NSAIDs for pain management. Advised on weight management and ergonomic adjustments at work. Follow-up in 4 weeks or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('05427f1d-f8e2-40c7-92e2-9dcfdd52dc12', '2025-07-01T22:53:56.889093', 'Annual Checkup', 'Patient presented for an annual checkup with a primary complaint of persistent low back strain. Vital signs were within normal limits: BP 118/76 mmHg, HR 72 bpm, RR 16 breaths per minute, Temp 98.6°F. Physical examination revealed mild tenderness in the lumbar region with limited range of motion. Management of back strain includes continuation of NSAIDs as needed, referral to physical therapy, and ergonomic assessment at work. Anxiety and insomnia were noted to be well-managed with current medication regimen; asthma and migraines were stable with no recent exacerbations. Recommended follow-up in six months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e6ebb771-cee6-4076-9b63-0ad7e1fa416d', '2025-12-13T22:54:02.011659', 'Annual Checkup', 'Patient presented for an annual checkup. Physical examination revealed erythematous and bulging tympanic membrane in the right ear consistent with acute otitis media. Vital signs were within normal limits for age: HR 95 bpm, RR 22 breaths per minute, temperature 99.1°F. Asthma was well-controlled with current medications. Recommended continuation of current asthma management plan and prescribed amoxicillin for otitis media. Follow-up in two weeks or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e6ebb771-cee6-4076-9b63-0ad7e1fa416d', '2025-10-15T22:54:02.011659', 'Follow-up Visit', 'Patient presented for a follow-up visit for acute otitis media. Vital signs were as follows: BP not applicable, HR 110 bpm, Temp 98.6°F. Tympanic membranes were erythematous with effusion noted bilaterally. Assessment: Improvement in ear infection symptoms, but mild residual middle ear effusion persists. Plan: Continue current antibiotic regimen, monitor for any exacerbation of asthma symptoms, and re-evaluate in one week.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e6ebb771-cee6-4076-9b63-0ad7e1fa416d', '2025-06-16T22:54:02.011659', 'Annual Checkup', 'Patient presented for an annual checkup with concurrent symptoms of ear pain and irritability, consistent with acute otitis media. Vitals were within normal limits for age: HR 100 bpm, RR 24 breaths/min, temperature 99.2°F. Otoscopic examination revealed erythematous and bulging tympanic membranes bilaterally. Asthma remains stable with no recent exacerbations. Prescribed amoxicillin for ear infection and advised follow-up in 10 days if symptoms persist. Recommended continuation of current asthma management plan and discussed allergy avoidance strategies.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6b41857f-0e69-4fc9-a832-b5ba8d5d0f81', '2026-01-04T22:54:07.435880', 'Urgent Care', 'Patient presented for acute shortness of breath and wheezing, with a history of asthma exacerbation. Physical examination revealed bilateral wheezing upon auscultation, BP 145/88 mmHg, HR 92 bpm, and SpO2 at 93% on room air. Assessment indicated an asthma exacerbation possibly triggered by seasonal allergens. Recommended initiating a short course of oral corticosteroids and increasing inhaler use; advised follow-up with primary care for asthma management and continued monitoring of hypertension and hyperlipidemia.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6b41857f-0e69-4fc9-a832-b5ba8d5d0f81', '2025-08-30T22:54:07.435880', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 142/88 mmHg, heart rate 78 bpm, and BMI was 32.5, indicating obesity. Physical examination revealed stable osteoarthritis symptoms with no new joint swelling or pain exacerbation, and well-controlled asthma with no recent exacerbations. Recommended continuation of current medications for hypertension and hyperlipidemia, advised dietary modifications and increased physical activity to address obesity, and scheduled follow-up in six months to monitor cardiovascular health and metabolic parameters.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6b41857f-0e69-4fc9-a832-b5ba8d5d0f81', '2025-08-14T22:54:07.435880', 'Follow-up Visit', 'Patient presented for a follow-up visit to monitor chronic conditions. Vital signs were as follows: BP 142/88 mmHg, HR 78 bpm. Physical exam revealed joint stiffness consistent with osteoarthritis and mild wheezing on auscultation. Assessment indicated stable hypertension and asthma control, but obesity management requires further intervention. Recommended continuation of antihypertensive and lipid-lowering medications, increased physical activity, and a referral to a nutritionist for weight management. Follow-up in three months to reassess weight and blood pressure control.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('eaaafb6a-4385-46d3-831d-8a56485e154a', '2025-12-11T22:54:14.196842', 'Urgent Care', 'Patient presented for acute right knee pain. Physical examination revealed mild swelling and tenderness over the right knee joint, with limited range of motion. Blood pressure was 138/84 mmHg, heart rate was 78 bpm. Assessment: Exacerbation of osteoarthritis. Plan included NSAID prescription for pain management and referral to orthopedics for further evaluation. Advised patient to follow up with primary care for routine management of chronic conditions.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('eaaafb6a-4385-46d3-831d-8a56485e154a', '2025-08-10T22:54:14.196842', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 132/84 mmHg, and heart rate was 78 bpm. The patient reported occasional joint pain attributed to osteoarthritis but denied any new symptoms. Lipid panel reviewed showed LDL levels slightly elevated. Continued current medications for hypertension and GERD. Recommended lifestyle modifications, including dietary adjustments and increased physical activity, to manage hyperlipidemia. Scheduled follow-up in six months for lipid panel reassessment.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('df3bb50a-b2b4-42dd-95c5-f0dc11c3482e', '2025-11-04T22:54:16.768720', 'Consultation', 'Patient presented for a routine follow-up consultation. Blood pressure measured at 142/88 mmHg, and heart rate was 78 bpm. Patient reported increased joint pain in knees, consistent with osteoarthritis, and noted difficulty with mobility due to obesity. Recommended continued use of NSAIDs for pain management, encouraged weight loss through a low-impact exercise regimen, and scheduled a follow-up in three months to assess blood pressure and joint health.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('df3bb50a-b2b4-42dd-95c5-f0dc11c3482e', '2025-08-07T22:54:16.768720', 'Urgent Care', 'Patient presented for acute left knee pain exacerbated by ambulation, likely due to underlying osteoarthritis. Vital signs were as follows: BP 145/85 mmHg, HR 78 bpm, within normal limits for this patient. Examination revealed moderate swelling and decreased range of motion in the left knee, with tenderness upon palpation. Assessment concluded a flare-up of osteoarthritis; recommended initiating NSAIDs for pain management and advised follow-up with primary care for possible referral to orthopedic specialist if symptoms persist. Advised weight management strategies to alleviate joint stress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('df3bb50a-b2b4-42dd-95c5-f0dc11c3482e', '2025-08-02T22:54:16.768720', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 142/88 mmHg and heart rate was 78 bpm. Physical examination revealed mild tenderness in the bilateral knees, consistent with osteoarthritis. Weight management was discussed due to obesity; patient was advised on dietary modifications and low-impact exercises. BP medication will continue, with a follow-up in 6 months to reassess hypertension control.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('df3bb50a-b2b4-42dd-95c5-f0dc11c3482e', '2024-11-19T22:54:16.768720', 'Emergency Visit', 'Patient presented for acute right knee pain following a fall at home. Physical examination revealed swelling and tenderness over the right knee with limited range of motion; no evident deformity. Vital signs were stable: BP 142/88 mmHg, HR 78 bpm. Assessment indicated exacerbation of osteoarthritis with possible soft tissue injury. Recommended imaging to rule out fracture and advised conservative management with ice, rest, and analgesics. Follow-up with primary care for further evaluation and management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('df3bb50a-b2b4-42dd-95c5-f0dc11c3482e', '2024-06-20T22:54:16.768720', 'Follow-up Visit', 'Patient presented for follow-up regarding management of obesity and hypertension. Vitals: BP 150/92 mmHg, HR 78 bpm, weight 92 kg, BMI 34.5 kg/m². Physical examination revealed mild edema in bilateral lower extremities, consistent with ongoing osteoarthritis. Recommended continuation of antihypertensive regimen, initiation of a low-impact exercise program, and referral to a dietitian for weight management. Follow-up in 3 months to reassess blood pressure control and weight loss progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5db1c412-722a-448c-b205-c12baee65fdf', '2025-10-31T22:54:26.587384', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding eczema management. Physical examination revealed dry, erythematous patches on the cheeks and extensor surfaces of the arms and legs, consistent with atopic dermatitis. No signs of infection or secondary complications were noted. Recommended continuation of emollient use and prescribed a mild topical corticosteroid for flare management. Advised parents to monitor for any signs of increased itching or infection. Follow-up visit in three months for reassessment.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5db1c412-722a-448c-b205-c12baee65fdf', '2025-08-11T22:54:26.587384', 'Annual Checkup', 'Patient presented for annual checkup. Vitals were as follows: HR 120 bpm, RR 30/min, weight 10 kg, height 75 cm. Skin examination revealed mild erythema and scaling consistent with eczema on the cheeks and arms, with no signs of secondary infection. History of conjunctivitis noted but no current symptoms. Recommended continuation of emollients and hydrocortisone 1% for flare-ups, and advised parents on avoiding known irritants. Follow-up in 6 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
