INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5db1c412-722a-448c-b205-c12baee65fdf', '2025-03-24T22:54:26.587384', 'Annual Checkup', 'Patient presented for annual checkup. Vital signs were within normal limits for age: HR 110 bpm, RR 28 breaths/min, with weight at the 50th percentile. Physical examination revealed mild erythema and scaling on the antecubital fossa bilaterally, consistent with eczema. Advised continued use of emollients and topical corticosteroids as needed. History of conjunctivitis noted, with no current ocular symptoms reported.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('32ead315-5b49-42f8-b877-bc139913fc89', '2026-01-06T22:54:33.141662', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding acne management. Vital signs were stable: BP 110/72 mmHg, HR 76 bpm, RR 18 breaths per minute. The patient reported mild improvement with current topical retinoid therapy but continues to experience persistent comedones and inflammatory lesions primarily on the forehead and chin. Recommended continuation of current regimen and added an oral antibiotic to address inflammatory acne, with a follow-up in 3 months to monitor progress. Asthma was stable with no recent exacerbations, and advised continuation of current inhaler usage as needed.', NULL);
