VALUES ('32ead315-5b49-42f8-b877-bc139913fc89', '2025-06-02T22:54:33.141662', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs: BP 110/70 mmHg, HR 72 bpm, RR 16 breaths/min. Skin examination revealed moderate acne on the face and upper back. Asthma was well-controlled with no recent exacerbations. Discussed ongoing acne management; recommended continuation of topical retinoids and consideration of oral antibiotics if no improvement. Advised routine follow-up in 6 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
