VALUES ('6fe68a0e-95c4-4fb6-acb2-0311980fae44', '2025-10-11T22:54:47.886093', 'Follow-up Visit', 'Patient presented for follow-up of contact dermatitis. Physical examination revealed erythematous patches with mild scaling on the forearms and neck. Blood pressure was 132/78 mmHg, heart rate 76 bpm. Assessment indicated mild improvement since last visit. Recommended continuing topical corticosteroid treatment and moisturizing regimen, and advised follow-up in four weeks. Reinforced lifestyle modifications for prediabetes and hyperlipidemia management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6fe68a0e-95c4-4fb6-acb2-0311980fae44', '2025-07-19T22:54:47.886093', 'Consultation', 'Patient presented for a follow-up consultation regarding contact dermatitis. Vitals were stable: BP 128/82 mmHg, HR 72 bpm. Physical examination revealed erythematous, pruritic patches on bilateral forearms, consistent with prior diagnosis. Advised continuation of topical corticosteroid and avoidance of known irritants. Reviewed management of chronic conditions, emphasizing lifestyle modifications for prediabetes and follow-up for hyperlipidemia.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6fe68a0e-95c4-4fb6-acb2-0311980fae44', '2025-03-02T22:54:47.886093', 'Annual Checkup', 'Patient presented for an annual checkup with ongoing management of contact dermatitis. Vital signs were stable: BP 132/78 mmHg, HR 76 bpm. Examination revealed mild erythema on the dorsal hands, consistent with dermatitis, and no acute joint swelling noted. Continued current topical corticosteroid for dermatitis and advised strict avoidance of known irritants. Discussed lifestyle modifications to address prediabetes and hyperlipidemia, including dietary changes and regular physical activity. Recommended follow-up in 6 months to monitor dermatologic and metabolic conditions.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b24e9945-0aed-4024-86e0-3095a2c77fb0', '2025-11-15T22:54:53.422287', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding ongoing cancer treatment. Blood pressure was 138/85 mmHg, heart rate was 78 bpm, and physical examination was unremarkable. The patient reported mild fatigue and occasional nausea, which were attributed to chemotherapy. Recommended continuation of current oncology treatment regimen and advised on dietary modifications to manage symptoms; scheduled follow-up appointment in four weeks.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b24e9945-0aed-4024-86e0-3095a2c77fb0', '2025-07-10T22:54:53.422287', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals: BP 138/85 mmHg, HR 78 bpm. Noted stable status of current cancer treatment with no new symptoms reported. Hypertension and hyperlipidemia remain under control with current medication regimen. Recommended continuation of antihypertensive and statin therapy, monitoring of lipid panel, and follow-up with oncology. Advised management of allergic rhinitis with antihistamines as needed. Encouraged regular follow-up appointments and lifestyle modifications to support overall health.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('23c77ca1-4c64-497d-b583-e8eb010e2754', '2026-02-06T22:54:57.000429', 'Urgent Care', 'Patient presented for evaluation of acute chest pain onset approximately 2 hours prior to arrival. Blood pressure measured at 158/92 mmHg, heart rate at 88 bpm, and oxygen saturation at 98% on room air. On examination, the patient reported substernal chest pain radiating to the left arm, with associated diaphoresis and mild dyspnea. Assessment indicated possible acute coronary syndrome. Immediate referral to the emergency department for further cardiac evaluation and management was recommended.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('23c77ca1-4c64-497d-b583-e8eb010e2754', '2025-08-25T22:54:57.000429', 'Urgent Care', 'Patient presented for evaluation of acute onset chest pain and shortness of breath. Vital signs revealed BP 165/98 mmHg, HR 102 bpm, and SpO2 at 94% on room air. Physical examination noted mild respiratory distress with clear lung fields; ECG showed non-specific ST changes. Assessment included suspected angina exacerbated by uncontrolled hypertension. Plan included immediate referral to cardiology for further evaluation, adjustment of antihypertensive medication, and recommendation for weight management counseling given obesity history.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('23c77ca1-4c64-497d-b583-e8eb010e2754', '2025-05-08T22:54:57.000429', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was recorded at 138/86 mmHg, and heart rate was 76 bpm. The patient reported no new symptoms but expressed concern about weight management. Physical examination was unremarkable. Hypertension remains managed with current medication. Recommended continuation of antihypertensive regimen, diet modification, and increase in physical activity. Follow-up in six months or sooner if symptoms develop.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('23c77ca1-4c64-497d-b583-e8eb010e2754', '2025-01-30T22:54:57.000429', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 148/92 mmHg, and heart rate was 78 bpm. The patient reported no new symptoms but expressed concerns about recent weight gain. Assessment indicated well-controlled hypertension with current medication, though lifestyle modifications were advised to address obesity. Recommended dietary adjustments and increased physical activity, with a follow-up appointment scheduled in six months to monitor progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('23c77ca1-4c64-497d-b583-e8eb010e2754', '2024-12-02T22:54:57.000429', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 138/86 mmHg, heart rate was 78 bpm, and BMI indicated obesity. No acute distress observed; however, patient reported occasional dizziness. Assessment indicated controlled hypertension, but lifestyle modifications were advised to address obesity. Recommended dietary changes and increased physical activity; follow-up in three months to reassess hypertension management and overall health.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4d038947-a867-4fab-975e-01387ec20c17', '2025-11-08T22:55:04.988444', 'Follow-up Visit', 'Patient presented for follow-up on gallstones. Vitals were stable: BP 130/80 mmHg, HR 72 bpm. Patient reported occasional right upper quadrant pain, particularly after fatty meals, with no new symptoms of jaundice or fever. Advised dietary modifications and scheduled for an abdominal ultrasound to evaluate gallbladder status. Discussed potential surgical intervention if symptoms persist or worsen. Follow-up in four weeks recommended.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4d038947-a867-4fab-975e-01387ec20c17', '2025-07-27T22:55:04.988444', 'Emergency Visit', 'Patient presented for severe abdominal pain and nausea. Vital signs were as follows: BP 140/85 mmHg, HR 88 bpm, RR 18 breaths/min, Temp 98.6°F. Physical examination revealed tenderness in the right upper quadrant with a positive Murphy''s sign. Assessment indicated acute cholecystitis likely secondary to gallstones. Recommended admission for further evaluation, pain management, and possible surgical consultation for cholecystectomy. Advised continuation of GERD management and instructed to use inhaler as needed for asthma symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4d038947-a867-4fab-975e-01387ec20c17', '2025-04-21T22:55:04.988444', 'Annual Checkup', 'Patient presented for an annual checkup with a known history of gallstones. Vital signs were stable: BP 130/80 mmHg, HR 72 bpm, RR 16 breaths/min, SpO2 98% on room air. No acute abdominal pain reported; however, mild dyspepsia noted, likely related to GERD. Recommended continuation of current GERD management and advised dietary modifications to prevent gallstone-related complications. Referral to ophthalmology for cataract evaluation was discussed. Follow-up in 6 months or as needed for any new symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4d038947-a867-4fab-975e-01387ec20c17', '2024-12-11T22:55:04.988444', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: BP 130/80 mmHg, HR 78 bpm, RR 18 breaths per minute, SpO2 98% on room air. She reported intermittent abdominal discomfort, attributed to known gallstones, but denied any acute pain, nausea, or vomiting. GERD symptoms were well-controlled with current medication regimen; no recent asthma exacerbations noted. Recommended continuation of current management for gallstones and GERD, and advised follow-up if symptoms worsen. Scheduled ophthalmology appointment for cataracts evaluation and discussed influenza vaccination given the patient''s age and respiratory history.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4d038947-a867-4fab-975e-01387ec20c17', '2024-11-11T22:55:04.988444', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 132/78 mmHg, HR 78 bpm, RR 16/min, SpO2 97% on room air. She reported intermittent right upper quadrant pain, consistent with her known gallstones, but no significant change in intensity or frequency. GERD symptoms were stable on current PPI regimen. Physical examination revealed clear lung fields and no acute distress. Recommended continued monitoring of gallstones, adherence to GERD management plan, and follow-up with ophthalmology for cataract evaluation.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('2b54e883-ecd1-42df-a091-4036c6debdfa', '2025-11-25T22:55:15.638449', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 142/86 mmHg, and heart rate was 78 bpm. The patient reported occasional wheezing, managed with current asthma inhaler regimen; no acute distress noted. Recommended continuation of current antihypertensive and statin therapy, with a follow-up on glycemic control due to prediabetes status. Advised lifestyle modifications including diet and exercise to address hyperlipidemia and GERD symptoms. Regular eye exams were suggested to monitor cataract progression.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('2b54e883-ecd1-42df-a091-4036c6debdfa', '2025-07-01T22:55:15.638449', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were as follows: BP 142/88 mmHg, HR 78 bpm, RR 16/min, SpO2 95% on room air. The patient reported occasional shortness of breath, particularly with exertion, consistent with her asthma history. Physical examination revealed clear lung fields with mild wheezing on forced expiration. Assessment included stable asthma, controlled hypertension, and hyperlipidemia. Recommendations included continuing current asthma management with albuterol as needed, monitoring blood pressure and lipid levels, and maintaining lifestyle modifications for prediabetes and GERD management. Follow-up in six months or as needed if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('2b54e883-ecd1-42df-a091-4036c6debdfa', '2025-06-23T22:55:15.638449', 'Follow-up Visit', 'Patient presented for routine follow-up of chronic conditions. Blood pressure was 142/88 mmHg, heart rate was 78 bpm, and respiratory rate was 16 breaths per minute. Lungs were clear to auscultation with no wheezing observed. Recommended continuation of current asthma management plan with an emphasis on inhaler technique review. Advised dietary modifications and regular exercise to address hypertension and prediabetes. Follow-up in 6 months unless symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('2b54e883-ecd1-42df-a091-4036c6debdfa', '2025-04-29T22:55:15.638449', 'Urgent Care', 'Patient presented for acute shortness of breath and wheezing. Vital signs: BP 142/88 mmHg, HR 88 bpm, SpO2 93% on room air. Physical examination revealed diffuse expiratory wheezes. Assessment: acute asthma exacerbation likely triggered by seasonal allergens. Plan: Initiated nebulized albuterol treatment, advised continuation of inhaled corticosteroids, and prescribed oral prednisone taper. Recommended follow-up with primary care for asthma management and adjustment of antihypertensive therapy.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('2b54e883-ecd1-42df-a091-4036c6debdfa', '2025-02-13T22:55:15.638449', 'Annual Checkup', 'Patient presented for annual checkup. Blood pressure was 138/82 mmHg, and heart rate was 78 bpm. Lungs were clear to auscultation with no wheezing noted; asthma is well-controlled with current regimen. Recommended continuation of current medications for hypertension and hyperlipidemia, advised dietary modifications to manage prediabetes, and suggested follow-up with ophthalmology for cataract assessment.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('68cc8110-dd09-4744-b041-f5a56d445355', '2025-10-16T22:55:25.366533', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were as follows: BP 142/88 mmHg, HR 78 bpm, BMI 34 kg/m². Patient reported increased knee pain attributable to osteoarthritis and occasional shortness of breath managed with current asthma medications. Assessment included poorly controlled hypertension and obesity. Recommended dietary modifications and increased physical activity to address obesity and hypertension. Continued monitoring of hyperlipidemia and prescribed a follow-up for potential cataract surgery evaluation. GERD managed with current regimen, advised continuation of proton pump inhibitors.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('68cc8110-dd09-4744-b041-f5a56d445355', '2025-10-12T22:55:25.366533', 'Emergency Visit', 'Patient presented for acute shortness of breath and chest discomfort. Vital signs showed BP 165/95 mmHg, HR 98 bpm, RR 24 breaths/min, and SpO2 90% on room air. Examination revealed wheezing upon auscultation and mild pitting edema in the lower extremities. Assessment indicated an exacerbation of asthma, likely triggered by uncontrolled hypertension and obesity. The patient was administered nebulized bronchodilators and IV diuretics, with recommendations to follow up with primary care for hypertension management and consider dietary modifications for weight control.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('68cc8110-dd09-4744-b041-f5a56d445355', '2025-07-18T22:55:25.366533', 'Urgent Care', 'Patient presented for evaluation of acute shortness of breath and chest tightness. Vital signs revealed BP 152/88 mmHg, HR 92 bpm, RR 24 breaths/min, and SpO2 90% on room air. Examination noted diffuse wheezing upon auscultation, consistent with an asthma exacerbation. Recommended initiating nebulized bronchodilator therapy and adjusting inhaler regimen; advised follow-up with primary care for asthma management and potential adjustment of antihypertensive therapy.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('68cc8110-dd09-4744-b041-f5a56d445355', '2024-10-17T22:55:25.366533', 'Emergency Visit', 'Patient presented for acute shortness of breath and chest tightness. On examination, vital signs showed BP 162/88 mmHg, HR 98 bpm, RR 24/min, and SpO2 91% on room air. Auscultation revealed bilateral wheezing and decreased breath sounds. Assessment indicated an exacerbation of asthma, likely triggered by upper respiratory infection. Plan included administration of nebulized bronchodilators, initiation of oral corticosteroids, and close monitoring of respiratory status. Advised follow-up with primary care for further management of chronic conditions.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('68cc8110-dd09-4744-b041-f5a56d445355', '2024-06-21T22:55:25.366533', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were recorded as follows: Blood Pressure 142/88 mmHg, Heart Rate 78 bpm, BMI 32.6 kg/m². Physical examination revealed bilateral knee crepitus and mild wheezing on lung auscultation. Assessment included stable osteoarthritis with symptoms managed, controlled hypertension, and well-managed hyperlipidemia. Recommendations included continuation of current medications, dietary modifications for weight management, and referral to ophthalmology for cataract evaluation. Advised follow-up in 6 months for routine monitoring.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c91a7ece-4aa4-4810-948e-b2cab54e0cec', '2025-12-14T22:55:34.888888', 'Emergency Visit', 'Patient presented for acute onset abdominal pain. Vital signs were stable with BP 110/70 mmHg, HR 82 bpm, RR 16 breaths/min, and temperature 98.6°F. Physical examination revealed mild tenderness in the lower right quadrant without rebound tenderness or guarding. Assessment suggested possible gastroenteritis versus early appendicitis. Recommended observation for symptom progression, advised hydration, and discussed red flags warranting immediate return to the emergency department.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c91a7ece-4aa4-4810-948e-b2cab54e0cec', '2025-09-17T22:55:34.888888', 'Follow-up Visit', 'Patient presented for a general follow-up visit. Vital signs were within normal limits: BP 118/72 mmHg, HR 72 bpm, RR 16/min, Temp 98.6°F. No new symptoms reported, and physical examination was unremarkable. Advised continuation of healthy lifestyle practices, including regular exercise and a balanced diet. Recommended to return in one year for annual checkup unless new concerns arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6860dbf8-6a18-4d0c-a20f-e1bba81579e0', '2025-12-31T22:55:38.064255', 'Follow-up Visit', 'Patient presented for follow-up on hyperlipidemia management and routine evaluation of chronic conditions. Blood pressure was 138/82 mmHg and heart rate was 72 bpm, regular. She reported mild joint stiffness in the mornings, consistent with osteoarthritis, but denied any new symptoms. Assessment: Hyperlipidemia, stable; Hypertension, well-controlled; Osteoarthritis, symptomatically managed. Plan: Continue current statin therapy, maintain antihypertensive regimen, and recommend OTC analgesics for joint pain as needed. Advised to return in 6 months for routine follow-up or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6860dbf8-6a18-4d0c-a20f-e1bba81579e0', '2025-08-20T22:55:38.064255', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 138/82 mmHg, heart rate 78 bpm, and BMI was 28.3 kg/m². No new symptoms were reported. Hyperlipidemia remained stable on current statin therapy. Recommended continuation of current medications for hypertension and GERD. Advised on lifestyle modifications to support joint health in osteoarthritis and scheduled follow-up in one year unless concerns arise sooner.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6860dbf8-6a18-4d0c-a20f-e1bba81579e0', '2025-03-30T22:55:38.064255', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding hyperlipidemia management. Blood pressure was 138/82 mmHg, and heart rate was 76 bpm. The patient reported mild joint stiffness consistent with osteoarthritis, and no new gastrointestinal symptoms were noted. Continued atorvastatin for lipid management was advised, and a follow-up lipid panel was scheduled in three months. Advised the patient to maintain a low-fat diet and increase physical activity as tolerated.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6860dbf8-6a18-4d0c-a20f-e1bba81579e0', '2025-03-16T22:55:38.064255', 'Urgent Care', 'Patient presented for acute onset of chest discomfort and shortness of breath. Vital signs showed BP 148/92 mmHg, HR 88 bpm, RR 20 breaths/min, and SpO2 96% on room air. Physical examination revealed mild bilateral wheezing and tenderness in the epigastric region. Assessment indicated possible angina; ECG and troponin levels were ordered. The patient was advised to take aspirin 81 mg daily and follow up with her primary care physician within 48 hours for further cardiovascular evaluation.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6860dbf8-6a18-4d0c-a20f-e1bba81579e0', '2025-03-10T22:55:38.064255', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: BP 138/82 mmHg, HR 72 bpm. No new complaints reported; however, patient mentioned occasional joint stiffness, consistent with osteoarthritis. Lipid panel from last week indicated elevated LDL. Recommended continuation of current antihypertensive and statin therapy, with emphasis on dietary modifications for lipid control. Advised follow-up with ophthalmology for cataract monitoring.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ceb8f7ca-5b33-4f94-852f-e4d160b606aa', '2025-11-08T22:55:48.406868', 'Follow-up Visit', 'Patient presented for follow-up of urinary tract infection. Vital signs: BP 138/85 mmHg, HR 76 bpm, Temp 98.6°F. Patient reported decreased dysuria and frequency since starting antibiotic therapy, but mild lower abdominal discomfort persists. Assessment: Improving urinary tract infection, well-controlled hypertension, hyperlipidemia, GERD, and diabetes. Plan: Continue current antibiotic regimen and monitor symptoms; advised increased fluid intake and follow-up if symptoms persist or worsen. Recommended maintaining current medication regimen for chronic conditions.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ceb8f7ca-5b33-4f94-852f-e4d160b606aa', '2025-09-06T22:55:48.406868', 'Annual Checkup', 'Patient presented for an annual checkup and follow-up on a recent urinary tract infection. Vital signs: BP 138/85 mmHg, HR 76 bpm, BMI 29.8 kg/m². Patient reported dysuria and increased urinary frequency, consistent with UTI. Physical examination was unremarkable; no fever or flank tenderness noted. Assessment: UTI, well-controlled GERD, hypertension, and hyperlipidemia; diabetes management stable. Plan: Continue current antihypertensive and lipid-lowering therapy, maintain diabetic diet and metformin, complete prescribed course of antibiotics for UTI, with follow-up in 2 weeks to reassess symptoms. Recommended lifestyle modifications to address elevated BMI.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ceb8f7ca-5b33-4f94-852f-e4d160b606aa', '2025-03-03T22:55:48.406868', 'Follow-up Visit', 'Patient presented for follow-up of urinary tract infection. Vital signs were as follows: BP 138/82 mmHg, HR 78 bpm, and temperature 98.6°F. She reported persistent dysuria and increased urinary frequency. Assessment confirmed ongoing UTI, likely due to E. coli, with current antibiotic regimen showing partial improvement. Recommended continuing the current antibiotic treatment for an additional 5 days, advised increased fluid intake, and scheduled a follow-up urinalysis in one week. Blood glucose levels remain stable with current diabetic management.', NULL);
