INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('29359093-15c3-44bf-96b6-f204c9d0f9c2', '2024-11-30T22:55:54.961156', 'Emergency Visit', 'Patient presented for evaluation following a fall from standing height with no loss of consciousness. Physical exam revealed a small abrasion on the forehead, otherwise alert and responsive with normal neurological findings. Vitals: HR 110 bpm, RR 24 breaths/min, Temp 37.2°C, BP unobtainable due to age and cooperation. Assessment: Minor head injury with no acute distress. Plan: Monitor for signs of concussion, recommend ice application to the affected area, and follow up with pediatrician if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('3760354c-b53c-4917-893e-f953e9a35380', '2025-12-14T22:56:01.307811', 'Follow-up Visit', 'Patient presented for follow-up of sinusitis. Reports ongoing nasal congestion, facial pressure, and postnasal drip. Vitals: BP 112/70 mmHg, HR 78 bpm, Temp 98.4°F. Physical examination revealed tenderness over the maxillary sinuses. Assessment: Sinusitis, likely viral etiology, with concurrent history of depression noted. Plan: Continue saline nasal irrigation, initiate a 5-day course of amoxicillin due to persistent symptoms, and follow up with mental health provider as scheduled for depression management.', NULL);
