VALUES ('fb4af03b-79c8-44d5-b1cd-f6e055f71c36', '2025-03-03T22:56:03.356888', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were noted: BP 145/90 mmHg, HR 78 bpm, and BMI of 32 kg/m². Physical examination revealed no acute distress, but patient reported occasional heartburn and feelings of low mood. Recommended continuation of antihypertensive and GERD medications, and discussed potential adjustment of antidepressant dosage; advised dietary modifications and increased physical activity to address obesity. Follow-up in 6 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('1b8f08e3-e6ed-463f-9168-46f775da7967', '2025-11-05T22:56:11.449263', 'Annual Checkup', 'Patient presented for an annual checkup and reported a jammed finger sustained during a recent basketball game. On examination, the finger exhibited mild swelling and limited range of motion; no fractures were palpable. Blood pressure was 118/76 mmHg, heart rate was 72 bpm, and respiratory rate was 16 breaths per minute. Asthma was well-controlled with current medications; advised continuation of inhaler regimen. Recommended RICE (rest, ice, compression, elevation) for the finger and follow-up if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('1b8f08e3-e6ed-463f-9168-46f775da7967', '2025-08-12T22:56:11.449263', 'Annual Checkup', 'Patient presented for an annual checkup with a secondary complaint of a jammed finger. Vital signs were within normal limits: BP 118/76 mmHg, HR 72 bpm, RR 16 breaths/min. Physical examination revealed mild swelling and tenderness in the right index finger with limited range of motion; no deformity or laceration noted. Asthma is well-controlled with current medication regimen. Recommended rest, ice, and elevation for the finger; advised following up if symptoms persist or worsen. Refilled asthma prescription and scheduled routine follow-up in one year.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('1b8f08e3-e6ed-463f-9168-46f775da7967', '2025-04-13T22:56:11.449263', 'Urgent Care', 'Patient presented with a jammed right index finger after a basketball injury. Physical examination revealed swelling and limited range of motion in the affected finger, with tenderness upon palpation but no visible deformity. Vital signs: BP 118/76 mmHg, HR 82 bpm, RR 16 breaths/min. Assessment indicated a probable sprain. Recommended RICE (Rest, Ice, Compression, Elevation) therapy and OTC analgesics for pain management, with instructions to follow up if symptoms persist or worsen. Patient''s history of asthma was noted, but no respiratory issues were reported at this visit.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('43f391ad-bf6f-4fcf-a397-b1eb7ecd0e2a', '2025-12-05T22:56:17.739914', 'Urgent Care', 'Patient presented for evaluation of worsening facial acne. Physical examination revealed moderate inflammatory papules and pustules concentrated on the forehead and cheeks, with no nodulocystic lesions. Blood pressure was 110/70 mmHg and heart rate was 72 bpm. Assessment indicated exacerbation of acne vulgaris likely secondary to recent stress and dietary changes. Recommended initiation of topical benzoyl peroxide 5% gel and advised on proper skin hygiene. Follow-up with dermatology was suggested for further management if no improvement in four weeks.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('43f391ad-bf6f-4fcf-a397-b1eb7ecd0e2a', '2025-08-17T22:56:17.739914', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were within normal limits: BP 110/70 mmHg, HR 72 bpm. The patient reported ongoing issues with acne, primarily on the forehead and chin. Upon examination, comedones and inflammatory papules were noted. Assessment indicated mild to moderate acne. Recommended continuation of topical benzoyl peroxide and initiation of topical adapalene. Patient also has a history of allergic rhinitis, but no current symptoms were reported. Advised follow-up in 6 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4a8feced-0010-4b97-918c-d4473569af8f', '2025-12-17T22:56:21.995101', 'Urgent Care', 'Patient presented for evaluation of acute chest pain and shortness of breath. Vital signs were as follows: BP 150/90 mmHg, HR 92 bpm, RR 22 breaths/min, SpO2 95% on room air. Physical examination revealed mild bilateral wheezing and tenderness upon palpation of the chest. Differential diagnosis includes acute coronary syndrome and respiratory infection. Recommended immediate transport to ER for further evaluation and management, including ECG and cardiac biomarkers. Advised patient to follow up with primary care physician for ongoing management of hyperlipidemia and hypertension.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4a8feced-0010-4b97-918c-d4473569af8f', '2025-07-23T22:56:21.995101', 'Urgent Care', 'Patient presented for evaluation of acute chest discomfort and shortness of breath. Physical examination revealed BP 150/92 mmHg, HR 88 bpm, and BMI indicating obesity. Differential diagnosis included angina pectoris exacerbated by underlying hyperlipidemia and hypertension. Recommended immediate EKG and lipid panel; advised continuation of antihypertensive and statin therapy, along with lifestyle modifications to address obesity. Follow-up with primary care physician for further management and cardiology referral if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4a8feced-0010-4b97-918c-d4473569af8f', '2025-07-19T22:56:21.995101', 'Consultation', 'Patient presented for a routine consultation to manage hyperlipidemia and hypertension. Blood pressure was 142/88 mmHg, and heart rate was 78 bpm. Physical examination revealed mild joint stiffness consistent with osteoarthritis. Lipid panel was reviewed, showing elevated LDL levels. Advised continuation of atorvastatin and lisinopril, encouraged adherence to a low-fat diet, and recommended a follow-up in 3 months to reassess lipid levels and blood pressure control.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4a8feced-0010-4b97-918c-d4473569af8f', '2024-10-20T22:56:21.995101', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 138/86 mmHg, HR 72 bpm, weight 230 lbs, BMI 31.2 kg/m². Physical examination revealed mild crepitus in bilateral knees consistent with osteoarthritis and no new ocular complaints post-cataract surgery. Assessment included well-controlled hypertension and hyperlipidemia with current medication regimen; obesity management was discussed. Recommended continuation of current antihypertensive and statin therapy, initiation of a structured weight loss program, and follow-up in 6 months for blood lipid panel and hypertension monitoring.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6dcd49d5-a013-4a21-a8c0-c38c8723fb55', '2025-12-29T22:56:29.775965', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding a viral upper respiratory infection. Vital signs were stable; heart rate 98 bpm, respiratory rate 22 breaths per minute, and temperature was 99.1°F. Patient reported persistent rhinorrhea and cough with mild wheezing noted on auscultation. Continued supportive care recommended, including hydration and rest, along with the use of a bronchodilator as needed for asthma symptoms. Follow-up in one week or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6dcd49d5-a013-4a21-a8c0-c38c8723fb55', '2025-10-13T22:56:29.775965', 'Annual Checkup', 'Patient presented for an annual checkup with concurrent symptoms of a viral upper respiratory infection, including rhinorrhea and mild cough. Physical examination revealed clear lung sounds and no wheezing, despite history of asthma. Vital signs were within normal limits: BP 98/60 mmHg, HR 92 bpm, Temp 99.1°F. Assessment confirmed viral URI with no signs of bacterial infection. Recommended symptomatic treatment with increased fluid intake and rest, and advised to continue current asthma and hay fever management plan. Follow-up advised if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6dcd49d5-a013-4a21-a8c0-c38c8723fb55', '2025-04-24T22:56:29.775965', 'Consultation', 'Patient presented for evaluation of symptoms consistent with a viral upper respiratory infection. Noted mild rhinorrhea, cough, and low-grade fever (T: 99.5°F). Respiratory exam revealed clear lung fields, though occasional wheezing was noted, consistent with asthma history. Recommended supportive care including increased fluid intake, rest, and use of albuterol inhaler as needed for wheezing. Advised follow-up if symptoms worsen or new symptoms develop.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('dc526f67-38b3-42ba-9250-07c596b2ea1f', '2026-01-01T22:56:35.006360', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 138/90 mmHg, HR 78 bpm, BMI 32.4 kg/m². The patient reported no new symptoms but expressed a desire to address weight management. Assessment included obesity without complications and a history of recurrent tonsillitis. Recommended lifestyle modifications, including dietary changes and increased physical activity, and discussed potential referral to a nutritionist for further support. Follow-up scheduled in 6 months to monitor progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('dc526f67-38b3-42ba-9250-07c596b2ea1f', '2025-08-24T22:56:35.006360', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were as follows: BP 138/86 mmHg, HR 78 bpm, BMI 32.1 kg/m². Physical examination was unremarkable except for obesity. Recommended continuation of a balanced diet and regular exercise to address weight management. Discussed potential referral to a nutritionist for further dietary guidance. Follow-up in 6 months to monitor progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('dbda9921-7591-4f91-8d1b-c5776c40b922', '2026-02-12T22:56:39.095706', 'Follow-up Visit', 'Patient presented for follow-up regarding gallstones and management of chronic conditions. Vitals were stable: BP 138/85 mmHg, HR 78 bpm. She reported intermittent right upper quadrant pain but denied nausea or vomiting. Assessment revealed stable symptoms of gallstones without acute cholecystitis. Recommendations included dietary modifications to manage hyperlipidemia and obesity, continuation of current asthma and hypertension medications, and scheduling an elective cholecystectomy consult. Follow-up in 3 months or earlier if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('dbda9921-7591-4f91-8d1b-c5776c40b922', '2025-07-14T22:56:39.095706', 'Urgent Care', 'Patient presented for acute abdominal pain and nausea, suspected to be related to gallstones. Vitals noted: BP 142/88 mmHg, HR 78 bpm, RR 18, Temp 98.6°F. Physical examination revealed tenderness in the right upper quadrant. Assessment confirmed symptomatic cholelithiasis. Recommended follow-up with gastroenterology for potential cholecystectomy and advised dietary modifications to manage symptoms. Pain management with acetaminophen was discussed.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('523fe3ac-1834-4c15-bbb4-7ef0a021a4ed', '2025-12-04T22:56:43.512779', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were stable with a blood pressure of 120/78 mmHg and heart rate of 72 bpm. BMI was 27.2, indicating overweight status, which is relevant given the patient''s prediabetes. No acute respiratory distress noted; asthma is well-controlled with current medication. Recommended lifestyle modifications including a low-sugar diet and increased physical activity to manage weight and prevent progression of prediabetes. Follow-up in six months to monitor glucose levels and reassess asthma control.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('523fe3ac-1834-4c15-bbb4-7ef0a021a4ed', '2025-07-25T22:56:43.512779', 'Emergency Visit', 'Patient presented for acute shortness of breath and wheezing. Vitals were BP 122/78 mmHg, HR 98 bpm, RR 20 breaths/min, SpO2 94% on room air. Physical examination revealed bilateral wheezing upon auscultation. Assessment: Exacerbation of asthma. Administered nebulized albuterol with improvement in respiratory status. Recommended follow-up with primary care provider and advised continuation of inhaled corticosteroids. Discussed importance of lifestyle modifications to manage prediabetes.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('808b60f1-4a28-41da-b69f-f2a587751fa6', '2025-10-30T22:56:47.616499', 'Follow-up Visit', 'Patient presented for a follow-up visit for hyperlipidemia management. Blood pressure was 138/85 mmHg, heart rate 78 bpm. Patient reported mild joint stiffness, likely related to osteoarthritis, but denied any new symptoms. Lipid panel results from last week showed LDL elevated at 145 mg/dL. Recommended continuation of atorvastatin 20 mg daily and advised dietary modifications to include increased fiber intake. Scheduled follow-up in three months to reassess lipid levels and blood pressure.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('808b60f1-4a28-41da-b69f-f2a587751fa6', '2025-07-26T22:56:47.616499', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were recorded as BP 130/85 mmHg, HR 72 bpm, respiratory rate 16 breaths/min, and BMI 27.3 kg/m². The patient reported mild knee pain attributed to osteoarthritis but denied any new symptoms. Assessment revealed well-controlled hypertension and hyperlipidemia. Recommended continuation of current antihypertensive and statin therapy, advised weight management and regular exercise, and scheduled routine laboratory tests to monitor lipid levels. Follow-up in six months unless symptoms change.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('695d0caf-2396-432a-a7fc-cd85b2581292', '2025-12-23T22:56:51.896183', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were stable: BP 118/76 mmHg, HR 72 bpm, temperature 98.6°F. No acute complaints reported; patient mentioned well-managed seasonal allergies with OTC antihistamines. Physical examination was unremarkable. Recommended continuation of current allergy management plan and advised routine screenings and vaccinations as per age-appropriate guidelines.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('695d0caf-2396-432a-a7fc-cd85b2581292', '2025-10-24T22:56:51.896183', 'Follow-up Visit', 'Patient presented for a follow-up visit and general checkup. Vitals were stable with BP 118/76 mmHg, HR 72 bpm. No acute symptoms reported; patient mentioned controlled seasonal allergies with current antihistamine regimen. Recommended continuation of current allergy management and advised routine health maintenance, including annual flu vaccination and regular exercise. Follow-up in one year or as needed for any new concerns.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('775a18f4-7167-4cd6-972b-aba61d2f38cd', '2025-11-25T22:56:55.274492', 'Emergency Visit', 'Patient presented for evaluation of a skin tear on the right forearm sustained after a fall. Physical examination revealed a 3 cm superficial laceration with minimal bleeding and surrounding ecchymosis. Blood pressure was noted at 145/85 mmHg, and heart rate was 78 bpm. The wound was cleaned and dressed with a non-adherent dressing. Recommended follow-up with primary care for wound check and advised to monitor for signs of infection. Discussed fall prevention strategies due to underlying osteoarthritis and vision impairment from cataracts.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('775a18f4-7167-4cd6-972b-aba61d2f38cd', '2025-10-05T22:56:55.274492', 'Urgent Care', 'Patient presented for a skin tear on the right forearm sustained from an accidental fall. On examination, the skin tear was approximately 4 cm long with minimal bleeding and no signs of infection. Blood pressure was 142/86 mmHg and heart rate was 78 bpm. Wound was cleaned and dressed; patient was advised on wound care and to monitor for signs of infection. Follow-up recommended with primary care physician for routine management of hypertension and osteoarthritis.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('775a18f4-7167-4cd6-972b-aba61d2f38cd', '2025-05-16T22:56:55.274492', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 140/85 mmHg, heart rate was 78 bpm, and skin tear noted on the right forearm, approximately 3 cm in length with minimal bleeding. Physical examination revealed well-healed cataract surgery sites and limited range of motion in knees due to osteoarthritis. Recommended continuation of current antihypertensive regimen, application of a protective dressing for the skin tear, and advised use of moisturizers to maintain skin integrity. Follow-up in six months or as needed for any new concerns.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('775a18f4-7167-4cd6-972b-aba61d2f38cd', '2024-11-03T22:56:55.274492', 'Annual Checkup', 'Patient presented for an annual checkup with a current condition of a skin tear on the right forearm. Blood pressure was 138/82 mmHg, heart rate was 76 bpm, and no acute distress was noted. The skin tear was clean but slightly erythematous; advised gentle cleansing and application of a non-adherent dressing. Recommended regular monitoring of blood pressure, continued osteoarthritis management with physical therapy, and scheduled follow-up for cataract evaluation.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('775a18f4-7167-4cd6-972b-aba61d2f38cd', '2024-09-16T22:56:55.274492', 'Consultation', 'Patient presented for evaluation of a skin tear on the right forearm. Physical examination revealed a 3 cm superficial laceration with minimal bleeding, no signs of infection, and surrounding ecchymosis. Blood pressure was 140/85 mmHg, and heart rate was 78 bpm. Skin tear was cleansed with saline, and a non-adherent dressing was applied. Recommended keeping the area clean and dry, and instructed to return if signs of infection develop. Follow-up in one week to assess healing.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('7a97c435-c535-4f18-b3f7-2d62189e5279', '2025-11-09T22:57:06.743419', 'Consultation', 'Patient presented for a consultation regarding symptoms of an upper respiratory infection. She reported a sore throat, nasal congestion, and mild cough lasting four days. Vital signs were stable with BP 118/76 mmHg, HR 78 bpm, and temperature 99.1°F. Exam revealed erythematous pharynx without exudate and clear lung fields. Assessment confirmed viral upper respiratory infection. Recommended increased fluid intake, rest, and over-the-counter analgesics as needed for symptom relief. Follow-up advised if symptoms persist beyond 10 days or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('7a97c435-c535-4f18-b3f7-2d62189e5279', '2025-08-18T22:57:06.743419', 'Annual Checkup', 'Patient presented for an annual checkup, reporting mild symptoms of an upper respiratory infection, including nasal congestion and a sore throat. Vitals were stable with BP at 118/76 mmHg and HR at 72 bpm. Physical examination revealed erythematous pharynx without exudate. Recommended supportive care measures such as increased fluid intake and rest; advised follow-up if symptoms persist beyond 10 days or worsen. Reviewed history of tonsillitis and IBS; no current exacerbation noted.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('136d3e64-4a5f-4242-aa68-dde475ea90f2', '2025-09-30T22:57:11.762042', 'Follow-up Visit', 'Patient presented for follow-up of hyperlipidemia and hypertension management. Blood pressure was 138/82 mmHg, heart rate 76 bpm, and BMI 31.2 kg/m². Patient reported compliance with atorvastatin but admitted occasional missed doses of lisinopril. Recommended continuation of current lipid-lowering therapy and stressed the importance of regular antihypertensive medication adherence. Encouraged weight management and advised referral to a dietitian for nutritional counseling. Follow-up in three months to reassess lipid panel and blood pressure control.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('136d3e64-4a5f-4242-aa68-dde475ea90f2', '2025-06-15T22:57:11.762042', 'Urgent Care', 'Patient presented for evaluation of acute shortness of breath and chest tightness. Vital signs recorded: BP 160/95 mmHg, HR 92 bpm, RR 24 breaths/min, SpO2 91% on room air. Physical examination revealed expiratory wheezing and use of accessory muscles for respiration. Assessment indicated acute exacerbation of asthma likely precipitated by poorly controlled hypertension. Recommended immediate bronchodilator therapy and adjustment of antihypertensive regimen; advised follow-up with primary care provider within one week for further management of hyperlipidemia and reassessment of asthma control.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('136d3e64-4a5f-4242-aa68-dde475ea90f2', '2025-04-05T22:57:11.762042', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 142/88 mmHg, HR 76 bpm, BMI 32.1 kg/m². Physical examination revealed no acute distress, and cardiovascular and respiratory examinations were unremarkable. Continued management of hyperlipidemia and hypertension was advised, with a recommendation to maintain current statin therapy and antihypertensive regimen. Encouraged patient to follow a low-sodium, heart-healthy diet and engage in regular physical activity to address obesity. Follow-up in 6 months for assessment of lipid profile and blood pressure control.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ff58fb71-d143-430e-8023-984b186e43c4', '2025-11-04T22:57:17.597391', 'Follow-up Visit', 'Patient presented for follow-up of acute gastroenteritis. Vital signs were stable: BP 132/84 mmHg, HR 76 bpm. She reported significant improvement in nausea and diarrhea, with no further episodes of vomiting. Continued management of underlying hypertension and obesity was discussed, emphasizing dietary modifications and increased physical activity. Recommended maintaining hydration and a bland diet until full recovery. Follow-up in 2 weeks or as needed for any worsening symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ff58fb71-d143-430e-8023-984b186e43c4', '2025-10-20T22:57:17.597391', 'Follow-up Visit', 'Patient presented for follow-up of acute gastroenteritis. Vitals were stable: BP 128/84 mmHg, HR 76 bpm. Patient reported significant improvement in nausea and diarrhea, with no new symptoms. Advised continuation of oral rehydration and a bland diet, and to monitor for any recurrence of symptoms. Follow-up recommended in 2 weeks to reassess condition and manage chronic hypertension and asthma.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ff58fb71-d143-430e-8023-984b186e43c4', '2025-02-01T22:57:17.597391', 'Annual Checkup', 'Patient presented for annual checkup with ongoing symptoms of acute gastroenteritis, including nausea and diarrhea over the past 3 days. Vital signs noted: BP 145/92 mmHg, HR 88 bpm, temperature 98.6°F, RR 18 breaths/min. On examination, mild abdominal tenderness was observed without guarding or rebound tenderness. Assessment indicated well-managed hypertension and obesity. Recommended dietary modifications and increased fluid intake to manage gastroenteritis symptoms, with follow-up in 1 week if symptoms persist. Continued management of hypertension and obesity emphasized, along with regular monitoring of asthma control and allergic rhinitis symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5d48f11c-bf96-48d0-a963-dada849650b9', '2026-02-07T22:57:21.671117', 'Annual Checkup', 'Patient presented for an annual checkup and evaluation of Tinea Corporis. Vitals were stable: BP 118/76 mmHg, HR 72 bpm, respiratory rate 16 breaths per minute. Skin examination revealed erythematous, scaly patches consistent with ringworm on the right forearm; no signs of secondary infection noted. Continued treatment with topical antifungal cream was recommended, with a follow-up in 4 weeks if no improvement. Asthma and eczema remain well-controlled with current management strategies.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5d48f11c-bf96-48d0-a963-dada849650b9', '2025-07-19T22:57:21.671117', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were stable: BP 118/76 mmHg, HR 72 bpm, RR 16 breaths per minute. Physical examination revealed a circular erythematous rash with central clearing on the left forearm, consistent with Tinea Corporis. History of asthma and eczema was noted, with no recent exacerbations reported. Recommended continuation of topical antifungal treatment for the ringworm and advised on proper hygiene practices to prevent spread. Follow-up in 4 weeks if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5d48f11c-bf96-48d0-a963-dada849650b9', '2025-06-19T22:57:21.671117', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were within normal limits: BP 118/76 mmHg, HR 72 bpm, RR 16 breaths/min, Temp 98.6°F. Patient reported mild pruritus and erythematous patches consistent with tinea corporis, currently managed with topical antifungal medication. Advised continuation of current treatment for tinea corporis and emphasized importance of adherence to prescribed asthma and eczema management plans. Recommended follow-up in one year or as needed for exacerbations.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('76feb04c-3f07-4f31-8388-2a5c5cf69e5d', '2026-01-18T22:57:27.532295', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding hypertension management. Blood pressure was measured at 142/88 mmHg, and heart rate was 78 bpm. She reported occasional headaches but no other new symptoms. It was recommended to continue current antihypertensive medication and increase dietary modification efforts. Follow-up scheduled in 3 months to reassess blood pressure control and review lipid panel results.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('76feb04c-3f07-4f31-8388-2a5c5cf69e5d', '2025-08-18T22:57:27.532295', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding hypertension management. Blood pressure was 142/88 mmHg and heart rate was 78 bpm. Patient reported mild headaches and occasional dizziness, but denied chest pain or dyspnea. Continued current medication regimen was advised with an increase in dietary sodium restriction and regular physical activity. Follow-up in 3 months was recommended to reassess blood pressure control.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('70c6ea08-54cb-498d-823c-28d3fb52db43', '2025-10-07T22:57:30.909897', 'Follow-up Visit', 'Patient presented for follow-up of allergic rhinitis. Mother reports continued nasal congestion and sneezing, particularly in the morning, but noted some improvement with daily loratadine. On examination, nasal mucosa appeared pale and boggy. Vitals: BP 100/60, HR 90, RR 18, Temp 98.6°F. Assessment: Allergic rhinitis, stable with partial improvement. Plan: Continue current antihistamine therapy, consider adding a saline nasal spray, and re-evaluate in 3 months. Advised avoidance of known allergens and discussed potential benefits of environmental control measures at home.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('70c6ea08-54cb-498d-823c-28d3fb52db43', '2025-06-08T22:57:30.909897', 'Urgent Care', 'Patient presented for increased nasal congestion, sneezing, and watery eyes consistent with an exacerbation of allergic rhinitis. Physical examination revealed clear nasal discharge and mild conjunctival injection. Vital signs were within normal limits: HR 100 bpm, BP 90/60 mmHg, RR 20 breaths per minute, Temp 98.6°F. Recommended continuation of oral antihistamines and initiation of a nasal corticosteroid spray. Advised environmental modifications to reduce allergen exposure. Follow-up with primary care provider if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('26958731-b060-49be-9e58-006a28d6d5a6', '2025-10-26T22:57:34.597387', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding obesity management and seasonal allergies. Vitals were as follows: BP 128/82 mmHg, HR 76 bpm, BMI 32.1 kg/m². Patient reported increased nasal congestion and sneezing consistent with seasonal allergies; no changes in depressive symptoms were noted. Recommended continuation of current antihistamine regimen and encouraged adherence to dietary and exercise plan to support weight loss goals. Follow-up in three months to reassess weight management and allergy symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('26958731-b060-49be-9e58-006a28d6d5a6', '2025-10-05T22:57:34.597387', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 138/85 mmHg, HR 78 bpm, BMI 32.1 kg/m². Patient reported no new symptoms but expressed ongoing concerns about weight management and depressive symptoms. Physical examination was unremarkable. Assessment indicated obesity and moderate depression are stable. Recommended continued use of prescribed antidepressants and referred patient to a nutritionist for weight management. Advised regular physical activity and scheduled follow-up in 6 months for reassessment.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ba8d7d4b-3d28-4bee-865f-78b979961f69', '2025-11-13T22:57:39.001364', 'Follow-up Visit', 'Patient presented for follow-up of hay fever and asthma management. Vital signs were stable: BP 118/76 mmHg, HR 72 bpm, SpO2 98% on room air. Patient reported seasonal exacerbation of allergic rhinitis symptoms, with increased nasal congestion and sneezing. Asthma symptoms were controlled with current inhaler regimen; no recent exacerbations reported. Recommended continuation of antihistamines and nasal corticosteroids; advised monitoring for any worsening symptoms or asthma attacks. Follow-up in 6 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ba8d7d4b-3d28-4bee-865f-78b979961f69', '2025-09-19T22:57:39.001364', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were within normal limits: BP 118/76 mmHg, HR 72 bpm, respiratory rate 16 breaths per minute, and SpO2 98% on room air. She reported seasonal nasal congestion and sneezing consistent with hay fever, currently managed with over-the-counter antihistamines. Assessment included well-controlled asthma and anemia under treatment with iron supplements. Recommended continuation of current medications and initiation of a daily nasal corticosteroid spray for hay fever management. Advised follow-up in one year or as needed for any acute concerns.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ba8d7d4b-3d28-4bee-865f-78b979961f69', '2025-04-09T22:57:39.001364', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: BP 118/76 mmHg, HR 72 bpm, RR 16/min, Temp 98.6°F. Patient reported increased nasal congestion and itchy eyes consistent with hay fever, managed with over-the-counter antihistamines. Hemoglobin levels were reviewed, continuing treatment for anemia; advised to maintain iron supplementation. Asthma well-controlled with current inhaler; no recent exacerbations. Recommended follow-up in one year or as needed.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b708b58f-2f6b-4413-b483-f484a5af0691', '2026-01-12T22:57:44.529988', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: blood pressure 145/90 mmHg, heart rate 78 bpm, BMI 32 kg/m². The patient reported no new symptoms but continues to experience frequent migraines managed with medication. Assessment revealed stable prediabetes and controlled GERD symptoms. Recommended dietary modifications and regular exercise to address obesity and hypertension. Scheduled follow-up in 6 months to monitor blood pressure and weight management progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b708b58f-2f6b-4413-b483-f484a5af0691', '2025-08-22T22:57:44.529988', 'Urgent Care', 'Patient presented for evaluation of acute epigastric pain and nausea, worsening over the past 24 hours. Vital signs were notable for elevated blood pressure at 148/92 mmHg and heart rate at 88 bpm. Physical examination revealed mild abdominal tenderness in the upper quadrant, without rebound or guarding. Assessment suggested exacerbation of GERD symptoms. Recommended initiation of a proton pump inhibitor and advised dietary modifications. Follow-up with primary care physician was encouraged for further management of chronic conditions, including hypertension and prediabetes monitoring.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b708b58f-2f6b-4413-b483-f484a5af0691', '2025-06-11T22:57:44.529988', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 150/92 mmHg, HR 78 bpm, BMI 32.5 kg/m². Reports adherence to medication but experiencing occasional headaches and acid reflux. Advised lifestyle modifications to address obesity and control hypertension; recommended referral to a dietitian for weight management. Continued current antihypertensive and GERD treatment; scheduled follow-up in 6 months.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a39b37e3-8c3e-475c-a2c6-7be086d88bc5', '2025-10-24T22:57:50.367592', 'Follow-up Visit', 'Patient presented for follow-up of allergic rhinitis. She reported persistent nasal congestion and sneezing, especially at night, with mild improvement since last visit. Vitals were stable: BP 104/68 mmHg, HR 78 bpm. Examination revealed pale, boggy nasal turbinates and clear nasal discharge. Assessment: allergic rhinitis, stable. Plan: Continue current antihistamine therapy, increase nasal corticosteroid spray to twice daily, and follow environmental control measures. Return for reassessment in 3 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a39b37e3-8c3e-475c-a2c6-7be086d88bc5', '2025-10-06T22:57:50.367592', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: BP 110/70 mmHg, HR 78 bpm, RR 18 breaths per minute, and temperature 98.6°F. Examination revealed clear nasal congestion consistent with her history of allergic rhinitis. Recommended continuation of current antihistamine regimen and advised environmental modifications to minimize allergen exposure. Follow-up in one year unless symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a39b37e3-8c3e-475c-a2c6-7be086d88bc5', '2025-07-01T22:57:50.367592', 'Urgent Care', 'Patient presented for evaluation of worsening nasal congestion and sneezing over the past week, consistent with allergic rhinitis exacerbation. Physical examination revealed nasal mucosa edema and clear rhinorrhea. Vitals were stable with BP 110/70 mmHg, HR 85 bpm, afebrile. Recommended continuation of intranasal corticosteroid and initiation of oral antihistamine for symptom relief. Follow-up advised if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('748cceae-1701-4d59-90bd-63d2cdc36853', '2026-01-08T22:57:55.743796', 'Follow-up Visit', 'Patient presented for a routine follow-up visit. Vital signs were within normal limits: BP 118/76 mmHg, HR 72 bpm, RR 16 breaths/min, Temp 98.6°F. No acute complaints were noted, though patient reported mild nasal congestion consistent with known seasonal allergies. Recommended continuation of current allergy management regimen and advised follow-up if symptoms worsen or new symptoms develop.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('748cceae-1701-4d59-90bd-63d2cdc36853', '2025-08-29T22:57:55.743796', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were within normal limits: BP 120/78 mmHg, HR 72 bpm, Temp 98.6°F, RR 16 breaths per minute. No acute distress noted, and physical examination was unremarkable. Discussed management of seasonal allergies; recommended continuation of current antihistamine regimen and advised monitoring for any changes in symptomatology. Follow-up in one year or as needed for any emergent concerns.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('748cceae-1701-4d59-90bd-63d2cdc36853', '2025-05-10T22:57:55.743796', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: BP 118/76 mmHg, HR 72 bpm, respiratory rate 16 breaths/minute, and temperature 98.6°F. No acute distress noted; examination was unremarkable except for mild nasal congestion, likely related to known seasonal allergies. Recommended continuation of current allergy management plan and advised on lifestyle modifications to improve overall health. Patient was encouraged to return for follow-up if symptoms worsen or new concerns arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('d487aa5b-7bc3-4f27-b205-6bcf4bb07d06', '2025-12-19T22:58:00.662526', 'Urgent Care', 'Patient presented for acute abdominal pain suspected to be related to gallstones. Vital signs: BP 142/88 mmHg, HR 82 bpm, afebrile. Abdominal examination revealed tenderness in the right upper quadrant without rebound tenderness or guarding. Recommended imaging via abdominal ultrasound to further evaluate gallbladder status and advised on dietary modifications to manage symptoms. Pain management discussed, and patient was provided a prescription for analgesics as needed. Follow-up scheduled with gastroenterology.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('d487aa5b-7bc3-4f27-b205-6bcf4bb07d06', '2025-08-08T22:58:00.662526', 'Consultation', 'Patient presented for consultation regarding ongoing management of gallstones. Blood pressure was 142/88 mmHg, and heart rate was 78 bpm. She reported intermittent episodes of abdominal pain and nausea. Physical examination was unremarkable for acute tenderness. Recommended continuing a low-fat diet and monitoring symptoms for any escalation, with a follow-up in 3 months or sooner if symptoms worsen. Advised to consider surgical consultation if episodes become more frequent or severe.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('d487aa5b-7bc3-4f27-b205-6bcf4bb07d06', '2025-02-01T22:58:00.662526', 'Urgent Care', 'Patient presented for acute abdominal pain and nausea, suspected to be related to gallstones. Vital signs were stable: BP 138/82 mmHg, HR 78 bpm. Physical examination revealed tenderness in the right upper quadrant. Assessment indicated probable biliary colic. Recommended ultrasound imaging for further evaluation and prescribed analgesics for pain management, with follow-up in gastroenterology for potential surgical intervention.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('d487aa5b-7bc3-4f27-b205-6bcf4bb07d06', '2024-10-02T22:58:00.662526', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were stable: BP 138/82 mmHg, HR 78 bpm. The patient reported occasional right upper quadrant discomfort, consistent with known gallstones, but denied any acute abdominal pain or jaundice. Recommended continuation of current medication regimen for hypertension and hyperlipidemia, and suggested dietary modifications to manage gallstone symptoms. Scheduled follow-up in six months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('99bf1b5e-886a-4e56-90ae-dd9db3376e68', '2026-01-21T22:58:07.805184', 'Annual Checkup', 'Patient presented for an annual checkup with concurrent symptoms of an upper respiratory infection. Vital signs were stable: BP 110/70 mmHg, HR 78 bpm, RR 18 breaths per minute, SpO2 96% on room air. Physical examination revealed mild nasal congestion and a frequent non-productive cough, with clear lung auscultation. Assessment included mild exacerbation of asthma likely secondary to the upper respiratory infection. Recommended increasing the use of the rescue inhaler as needed and advised on maintaining hydration and rest. Follow-up in 1-2 weeks if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('714b2003-21e2-4ee1-8918-cc7bb28c8763', '2025-11-27T22:58:09.619483', 'Urgent Care', 'Patient presented for evaluation of a pruritic rash on the forearms and neck, suspected to be contact dermatitis. Physical examination revealed erythematous, well-demarcated plaques with vesicles and excoriations. Vital signs were stable: BP 118/76 mmHg, HR 72 bpm. Assessment confirmed contact dermatitis likely due to recent exposure to a new laundry detergent. Recommended discontinuation of the suspected irritant, application of topical corticosteroids, and follow-up with primary care if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5292526d-226a-4b4e-9288-584f96ed2f3f', '2025-10-10T22:58:11.666742', 'Follow-up Visit', 'Patient presented for follow-up of eczema flare. Examination revealed erythematous, dry patches on bilateral antecubital fossae and posterior knees, consistent with atopic dermatitis. Vital signs were stable: BP 100/60 mmHg, HR 88 bpm. Recommended continuation of topical corticosteroid application and moisturizing regimen. Advised avoidance of known allergens and scheduling allergy testing due to history of allergic rhinitis. Follow-up in 4 weeks or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5292526d-226a-4b4e-9288-584f96ed2f3f', '2025-07-03T22:58:11.666742', 'Follow-up Visit', 'Patient presented for follow-up regarding eczema flare. Examination revealed erythematous, pruritic patches on bilateral antecubital fossae and popliteal fossae, consistent with atopic dermatitis. Vitals: BP 100/65 mmHg, HR 88 bpm, afebrile. Continued treatment with topical corticosteroids was advised, and moisturizers were recommended to maintain skin hydration. Discussed potential environmental triggers related to allergic rhinitis and advised follow-up in 4 weeks or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('3bab82fe-d9d5-41ea-9c0b-bb0521adf4a4', '2025-12-21T22:58:15.762655', 'Follow-up Visit', 'Patient presented for a follow-up visit for acute otitis media. On examination, tympanic membranes appeared erythematous and bulging bilaterally. Vitals were stable with HR 110 bpm and temperature 38.2°C. Assessment confirmed persistent otitis media. Recommended continuation of amoxicillin and advised follow-up in one week to reassess ear examination. Discussed signs of complications and instructed caregivers to monitor for any worsening symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('3bab82fe-d9d5-41ea-9c0b-bb0521adf4a4', '2025-07-13T22:58:15.762655', 'Urgent Care', 'Patient presented for evaluation of ear pain and irritability. Physical examination revealed erythematous and bulging tympanic membranes bilaterally, consistent with acute otitis media. Vitals were stable: HR 120 bpm, Temp 101.2°F. Assessment confirmed acute otitis media. Plan included initiating a course of amoxicillin and recommending follow-up with the pediatrician in one week. Parents were advised on symptom management and to return if symptoms worsen or if high fever persists.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('3bab82fe-d9d5-41ea-9c0b-bb0521adf4a4', '2025-06-21T22:58:15.762655', 'Consultation', 'Patient presented for evaluation of ear discomfort and irritability. Examination revealed erythematous and bulging tympanic membrane on the right side, consistent with acute otitis media. Vitals were stable: HR 110 bpm, RR 28, Temp 99.1°F. Recommended amoxicillin suspension for 10 days and advised follow-up in 2 weeks or sooner if symptoms worsen. Parents were educated on signs of complications and the importance of completing the antibiotic course.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('3bab82fe-d9d5-41ea-9c0b-bb0521adf4a4', '2025-02-05T22:58:15.762655', 'Follow-up Visit', 'Patient presented for follow-up of acute otitis media. Vital signs were stable: HR 110 bpm, temperature 37.4°C. Tympanic membrane remained erythematous with decreased mobility on pneumatic otoscopy. Recommended continuation of amoxicillin for the remaining 7 days and advised caregiver to monitor for any signs of worsening infection or fever. Discussed pain management with acetaminophen as needed. Follow-up in one week or sooner if symptoms do not improve.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('3bab82fe-d9d5-41ea-9c0b-bb0521adf4a4', '2024-12-15T22:58:15.762655', 'Urgent Care', 'Patient presented for evaluation of irritability and fever. Physical examination revealed erythematous and bulging tympanic membranes bilaterally. Vital signs: HR 130 bpm, Temp 101.5°F. Assessment indicated acute otitis media. Recommended initiation of amoxicillin therapy and advised parents on symptom management and follow-up if symptoms persist.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c6aa0816-e424-4eb2-abd0-3c9a1e82c359', '2026-02-18T22:58:24.678278', 'Consultation', 'Patient presented for routine consultation. Blood pressure was 142/88 mmHg and heart rate was 78 bpm. Physical examination revealed no acute distress; however, patient reported occasional dyspnea possibly linked to asthma. Assessment showed stable hyperlipidemia with controlled hypertension. Recommended continuation of current antihypertensive and statin therapy, with lifestyle modifications to address prediabetes. Advised follow-up ophthalmology visit for cataract evaluation and routine spirometry to monitor asthma control.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c6aa0816-e424-4eb2-abd0-3c9a1e82c359', '2025-06-27T22:58:24.678278', 'Consultation', 'Patient presented for routine consultation and management of hyperlipidemia. Blood pressure was 138/82 mmHg, and heart rate was 76 bpm. The patient reported mild dyspnea on exertion but denied chest pain or palpitations. Continued current statin therapy was recommended, and dietary modifications were reinforced. Ordered lipid panel to reassess cholesterol levels in 3 months. Follow-up in six months for routine evaluation of chronic conditions.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c6aa0816-e424-4eb2-abd0-3c9a1e82c359', '2025-06-13T22:58:24.678278', 'Consultation', 'Patient presented for routine consultation. Blood pressure was 142/86 mmHg, heart rate was 78 bpm. The patient reported occasional palpitations and mild dyspnea on exertion. Physical examination revealed no acute distress. Hyperlipidemia was stable, with recent lipid panel showing LDL at 135 mg/dL. Continued current statin therapy was advised, with dietary modifications to support lipid management. Recommended follow-up in 6 months and advised monitoring of blood pressure at home due to hypertension history.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c6aa0816-e424-4eb2-abd0-3c9a1e82c359', '2024-12-22T22:58:24.678278', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: BP 138/82 mmHg, HR 76 bpm, and BMI 27.2 kg/m². Physical examination revealed no acute distress; however, mild wheezing was noted on auscultation, likely related to asthma. Recommended continuing current medications for hyperlipidemia and hypertension, and advised lifestyle modifications to manage prediabetes. Suggested ophthalmology follow-up for cataracts and a gastroenterology consult for ongoing GERD management. Advised influenza and pneumococcal vaccinations due to age and respiratory history.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c6aa0816-e424-4eb2-abd0-3c9a1e82c359', '2024-09-03T22:58:24.678278', 'Consultation', 'Patient presented for a routine consultation regarding hyperlipidemia management. Blood pressure was noted at 138/82 mmHg, heart rate at 78 bpm, and BMI at 27.5 kg/m². Physical examination was unremarkable with no acute distress observed. Continued current statin therapy was advised, with a recommendation to maintain a low-cholesterol diet and regular exercise. Follow-up lipid panel was scheduled in 3 months to assess efficacy of management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('70fea18c-382b-40f2-be9d-bc4bd16d3fb9', '2026-01-01T22:58:34.019216', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs: BP 142/88 mmHg, HR 78 bpm, BMI 32.3 kg/m². Noted mild epigastric discomfort, consistent with a history of GERD. Assessment indicated stable hypertension and potential lifestyle modification for weight management was discussed. Recommended dietary changes, increased physical activity, and follow-up in six months to monitor blood pressure and weight.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('70fea18c-382b-40f2-be9d-bc4bd16d3fb9', '2025-07-17T22:58:34.019216', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding obesity management and hypertension control. Vital signs were recorded as BP 150/90 mmHg, HR 78 bpm. The patient reported occasional heartburn, consistent with her history of GERD, and no changes in vision that would suggest cataract progression. Recommended continuation of antihypertensive therapy, dietary modifications for weight management, and follow-up with ophthalmology as previously scheduled.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8c42fea7-0fc3-431c-973b-a2ddaa335ce1', '2026-02-12T22:58:37.984032', 'Urgent Care', 'Patient presented for evaluation of left ear pain and itching, consistent with acute otitis externa. Vital signs were stable: BP 118/76 mmHg, HR 72 bpm, afebrile. Physical examination revealed erythematous and swollen external auditory canal with serous discharge. Assessment confirmed acute otitis externa. Recommended topical antibiotic eardrops and advised on ear canal dryness. Reinforced importance of thyroid function monitoring and discussed sleep hygiene strategies for insomnia management. Follow-up in one week or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8c42fea7-0fc3-431c-973b-a2ddaa335ce1', '2025-08-05T22:58:37.984032', 'Annual Checkup', 'Patient presented for an annual checkup and evaluation of acute otitis externa. Vital signs were within normal limits: BP 118/76 mmHg, HR 72 bpm. Examination revealed erythema and edema of the external auditory canal with serous discharge noted in the left ear. Continued use of prescribed otic antibiotic drops was recommended, and the patient was advised to avoid water exposure to the ear. Hypothyroidism remains well-controlled with current medication; however, insomnia persists. Recommended follow-up with primary care physician for further management of insomnia.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('aee8d18d-928c-42f7-9dea-aac0e5e9e712', '2025-12-27T22:58:42.509711', 'Follow-up Visit', 'Patient presented for follow-up of acute gout flare. Vitals were stable: BP 138/82 mmHg, HR 76 bpm. Patient reported resolution of joint swelling and pain with current colchicine regimen. Recommended continuation of low-purine diet and increase in hydration. Follow-up in 3 months for evaluation of gout management and routine monitoring of chronic conditions.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('aee8d18d-928c-42f7-9dea-aac0e5e9e712', '2025-08-20T22:58:42.509711', 'Follow-up Visit', 'Patient presented for follow-up regarding acute gout flare. Blood pressure was 142/88 mmHg, and heart rate was 78 bpm. Examination revealed swelling and tenderness in the right first metatarsophalangeal joint. Advised continuation of colchicine as prescribed and recommended dietary modifications to lower purine intake. Follow-up in one month for reassessment of gout and monitoring of prediabetes and hypertension.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('aee8d18d-928c-42f7-9dea-aac0e5e9e712', '2025-08-09T22:58:42.509711', 'Follow-up Visit', 'Patient presented for follow-up regarding acute gout flare in the left foot. Vitals were stable: BP 138/86 mmHg, HR 76 bpm. Physical exam revealed erythema and swelling of the left first metatarsophalangeal joint with significant tenderness upon palpation. Continued colchicine regimen was advised, with the addition of NSAIDs as needed for pain management. Encouraged low-purine diet and hydration to prevent future flares. Discussed weight reduction strategies to manage obesity and mitigate osteoarthritis symptoms. Recommended follow-up in 4 weeks or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('14b93067-a5b9-4076-87fb-89865a7f303f', '2025-11-09T22:58:48.327573', 'Follow-up Visit', 'Patient presented for follow-up on jammed finger. Physical examination revealed mild swelling and limited range of motion in the right index finger, with no signs of fracture on recent X-rays. Asthma remains well-controlled with current medication regimen. Recommended continued use of ice packs and NSAIDs for pain management, and advised gentle range-of-motion exercises. Follow-up in two weeks for reassessment.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('14b93067-a5b9-4076-87fb-89865a7f303f', '2025-09-14T22:58:48.327573', 'Annual Checkup', 'Patient presented for an annual checkup and reported a jammed finger sustained during a sports activity. Vital signs were stable: BP 118/76 mmHg, HR 72 bpm, RR 16/min, SpO2 98% on room air. Physical examination revealed mild swelling and tenderness in the right middle finger, with limited range of motion but no deformity noted. Continued management of asthma was discussed, and patient was advised to apply ice and rest the affected finger, with follow-up if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('390584cd-b2fa-471e-90c5-a77efbef6556', '2025-10-14T22:58:51.705828', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 138/86 mmHg, and heart rate was 78 bpm. The patient reported increased stiffness and joint pain in the knees, consistent with osteoarthritis exacerbation. Recommendations included continuing current NSAID regimen, incorporating low-impact exercise, and considering physical therapy for improved joint function. Follow-up in 6 months to reassess osteoarthritis management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('390584cd-b2fa-471e-90c5-a77efbef6556', '2025-09-22T22:58:51.705828', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals recorded: BP 138/86 mmHg, HR 78 bpm. Reported increased knee pain associated with osteoarthritis, especially during activity. Physical examination showed mild tenderness in the right knee with limited range of motion. Recommended continuation of current antihypertensive regimen, initiated physical therapy referral for osteoarthritis management, and advised weight management and regular low-impact exercise to alleviate joint stress. Follow-up in 6 months or as needed for symptom exacerbation.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('390584cd-b2fa-471e-90c5-a77efbef6556', '2025-07-06T22:58:51.705828', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 128/82 mmHg and heart rate was 72 bpm. Reports increased stiffness and pain in knees attributed to osteoarthritis, managed with acetaminophen as needed. Recommended continuation of current antihypertensive regimen and advised weight management and regular low-impact exercise to alleviate joint symptoms. GERD and allergic rhinitis remain stable with current treatment. Follow-up in one year or as needed for acute concerns.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('34bbb002-6fb9-461a-b86d-62bfb9b6babc', '2025-12-01T22:58:57.850932', 'Urgent Care', 'Patient presented for evaluation of acute onset dyspnea and chest discomfort. Vital signs revealed BP 160/95 mmHg, HR 98 bpm, RR 22 breaths per minute, and SpO2 at 92% on room air. Physical examination noted diminished breath sounds in the right lower lobe and mild peripheral edema. Assessment indicated possible pleural effusion secondary to metastatic cancer. Recommended urgent chest X-ray and initiated supplemental oxygen therapy; advised follow-up with oncology for further management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('34bbb002-6fb9-461a-b86d-62bfb9b6babc', '2025-10-23T22:58:57.850932', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: BP 132/78 mmHg, HR 72 bpm, and BMI 31 kg/m². The patient reported mild fatigue and occasional shortness of breath, which were noted as potential side effects of ongoing cancer treatment. Continued management of hypertension and hyperlipidemia with current medications was advised, alongside lifestyle modifications to address obesity. Follow-up with oncology was recommended to monitor cancer progression.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
