INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('34bbb002-6fb9-461a-b86d-62bfb9b6babc', '2024-06-05T22:58:57.850932', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 138/86 mmHg, heart rate was 78 bpm, and BMI was 32. Physical examination revealed mild edema in the lower extremities, consistent with history of stasis dermatitis. Cancer treatment progress was reviewed; patient reported mild fatigue but no new symptoms. Recommended continuation of current antihypertensive and hyperlipidemia medications, and advised lifestyle modifications for obesity management. Follow-up oncology appointment scheduled in one month.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('43a5cc8a-f617-4bfa-a6e5-7453c1aaa41d', '2025-10-12T22:59:07.842475', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were stable: BP 112/70 mmHg, HR 72 bpm, RR 16 breaths/min, and temperature 98.6°F. Physical examination was unremarkable, with normal growth parameters and development appropriate for age. Advised to maintain a balanced diet, engage in regular physical activity, and return in one year or as needed for any health concerns.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('692417a6-7025-4abe-b07c-cba736877b4a', '2025-12-18T22:59:09.482033', 'Annual Checkup', 'Patient presented for an annual checkup with complaints of persistent low back pain. Vitals noted: BP 128/82 mmHg, HR 76 bpm, BMI 27.2 kg/m². Physical examination indicated tenderness in the lumbar region with reduced range of motion; no neurological deficits observed. Assessment: Chronic low back pain, likely exacerbated by arthritis. Plan: Continue current NSAID regimen, initiate physical therapy referral, and recommend weight management to alleviate stress on the back. Advised follow-up for GERD management and reassessment of insomnia medication efficacy.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('692417a6-7025-4abe-b07c-cba736877b4a', '2025-08-06T22:59:09.482033', 'Urgent Care', 'Patient presented for acute exacerbation of low back pain. Vitals: BP 128/82 mmHg, HR 76 bpm. Physical examination revealed tenderness in the lumbar region with limited range of motion; no neurological deficits noted. Assessment: Lumbar strain with a history of previous back strain. Recommended continuation of NSAIDs for pain management, prescribed a muscle relaxant, and advised physical therapy referral for further evaluation. Follow-up in 2 weeks or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('13fa2cae-2bce-4f80-913e-fbf7b5181f29', '2026-02-21T22:59:14.540581', 'Follow-up Visit', 'Patient presented for follow-up on prediabetes and hypertension management. Blood pressure was 138/85 mmHg, and heart rate was 78 bpm. Patient reported improved dietary habits but occasional dyspnea related to asthma, with no recent exacerbations. Assessment indicated stable hypertension, controlled asthma, and obesity contributing to prediabetic status. Recommended continued adherence to a low-carb diet, increased physical activity, and regular blood glucose monitoring. Advised follow-up in 3 months for reassessment of metabolic markers and adjustment of antihypertensive therapy if needed.', NULL);
