INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6211f499-e894-4081-8d90-60da3d2f9192', '2025-09-08T22:59:32.110725', 'Consultation', 'Patient presented for consultation regarding persistent nasal congestion and sneezing associated with hay fever. Blood pressure was recorded at 142/88 mmHg, and heart rate was 78 bpm. Examination revealed nasal mucosa edema consistent with allergic rhinitis. Continued use of antihistamines was recommended, and a nasal corticosteroid was prescribed to manage symptoms. Advised lifestyle modifications to address obesity and prediabetes, including dietary changes and regular physical activity. Follow-up in 3 months to reassess hypertension management and overall condition.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
