INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5b282731-a68e-479a-9d24-b0a1fdbc708c', '2026-02-13T22:59:39.115659', 'Urgent Care', 'Patient presented for acute onset of nausea, vomiting, and diarrhea, consistent with food poisoning. Physical examination revealed mild dehydration; vital signs showed BP 145/90 mmHg, HR 98 bpm, and SpO2 97% on room air. Assessment confirmed foodborne illness exacerbated by underlying obesity and controlled hypertension. Recommended oral rehydration and dietary modifications, with follow-up for persistent symptoms or worsening condition. Advised continuation of current antihypertensive and asthma medications.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5b282731-a68e-479a-9d24-b0a1fdbc708c', '2025-07-20T22:59:39.115659', 'Consultation', 'Patient presented for consultation due to food poisoning symptoms, including nausea, vomiting, and diarrhea over the past 24 hours. Vital signs: BP 150/95 mmHg, HR 88 bpm, RR 18 breaths/min, Temp 99.1°F. Physical examination revealed mild abdominal tenderness with no guarding or rebound tenderness. Assessment indicated acute gastroenteritis likely due to foodborne illness. Recommended oral rehydration and advised adherence to a bland diet. Reviewed asthma and hypertension management to ensure no exacerbations. Follow-up in 48 hours if symptoms persist or worsen.', NULL);
