INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a1ac7a2f-5a4e-43ba-a31a-ac607067f22d', '2025-10-13T22:59:58.061418', 'Consultation', 'Patient presented for consultation regarding hand, foot, and mouth disease. Physical examination revealed vesicular lesions on the hands, feet, and oral cavity, consistent with the diagnosis. Vital signs were stable: HR 98 bpm, RR 20/min, afebrile. Recommended supportive care including hydration, pain management with acetaminophen as needed, and monitoring for any signs of dehydration or secondary infection. Advised to continue asthma management plan and to return if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a1ac7a2f-5a4e-43ba-a31a-ac607067f22d', '2025-10-11T22:59:58.061418', 'Emergency Visit', 'Patient presented for evaluation due to symptoms consistent with Hand, Foot, and Mouth Disease, including a rash on extremities and mild fever. Vital signs were stable, with HR at 100 bpm, RR at 20 breaths per minute, and temperature at 38.0°C. Physical examination revealed vesicular lesions on the hands, feet, and oral mucosa. Asthma was noted as part of the patient''s medical history, but no respiratory distress was observed during the visit. Recommended supportive care with hydration, antipyretics as needed, and close monitoring of symptoms. Advised follow-up with pediatrician if symptoms worsen or if respiratory issues arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a1ac7a2f-5a4e-43ba-a31a-ac607067f22d', '2025-06-16T22:59:58.061418', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding Hand, Foot, and Mouth Disease. Physical examination revealed healing vesicular lesions on the hands and feet; oral mucosa appeared clear. No fever was noted, and respiratory status was stable with clear lung auscultation, relevant due to his history of asthma. Recommended symptomatic treatment with hydration and analgesics, and advised monitoring for any new respiratory symptoms due to asthmatic history.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
