VALUES ('727eeb7f-f808-4639-97bb-ec45df4f51cc', '2025-03-09T23:00:27.973404', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were as follows: BP 118/76 mmHg, HR 82 bpm, and BMI 32 kg/m², indicating obesity. No acute distress noted. Discussed the importance of a balanced diet and regular physical activity to address excess weight. Recommended referral to a nutritionist for dietary counseling and encouraged participation in physical activities. Follow-up in 6 months to monitor progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('cbd1fc6f-c112-4f83-b6e2-e5b6131d81a2', '2025-10-12T23:00:34.252246', 'Follow-up Visit', 'Patient presented for a follow-up visit for asthma management. Vitals were within normal limits: HR 110 bpm, RR 28 breaths/min, SpO2 98% on room air. Examination revealed mild wheezing on auscultation of the lungs. Assessment indicated stable asthma with a recent mild exacerbation. Continued current inhaled corticosteroid regimen was advised, with a recommendation to monitor for any increase in respiratory symptoms. Follow-up in 3 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('cbd1fc6f-c112-4f83-b6e2-e5b6131d81a2', '2025-07-11T23:00:34.252246', 'Emergency Visit', 'Patient presented for acute respiratory distress. Physical examination revealed wheezing, nasal flaring, and use of accessory muscles for breathing. Vital signs: HR 140 bpm, RR 40 breaths/min, SpO2 92% on room air. Assessment: Acute exacerbation of asthma. Administered nebulized albuterol with improvement in respiratory effort and oxygen saturation. Recommended continuation of inhaled corticosteroids and follow-up with primary care provider for asthma management plan.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('cbd1fc6f-c112-4f83-b6e2-e5b6131d81a2', '2025-04-07T23:00:34.252246', 'Follow-up Visit', 'Patient presented for a follow-up visit for asthma management. Vital signs were stable: HR 110, RR 28, and oxygen saturation 97% on room air. Mild wheezing noted on auscultation, without signs of respiratory distress. Assessment confirmed well-controlled asthma with occasional exacerbations. Continued current asthma action plan with montelukast 4 mg daily and albuterol as needed. Recommended daily moisturizing regimen for eczema and discussed allergen avoidance strategies for allergic rhinitis. Follow-up in 3 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('cbd1fc6f-c112-4f83-b6e2-e5b6131d81a2', '2024-12-22T23:00:34.252246', 'Annual Checkup', 'Patient presented for an annual checkup. Physical examination revealed clear lung sounds with no wheezing or respiratory distress noted. Height and weight were within normal percentiles for age; vital signs were stable with HR 98 bpm and RR 28 breaths per minute. Eczema was well-controlled, with no active lesions observed. Continued use of daily inhaled corticosteroid was recommended for asthma management, and parents were advised on maintaining an asthma action plan and monitoring environmental triggers. Follow-up in one year or sooner if symptoms exacerbate.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('cbd1fc6f-c112-4f83-b6e2-e5b6131d81a2', '2024-10-04T23:00:34.252246', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were stable: HR 110 bpm, RR 30 breaths/min, temp 98.6°F. Wheezing noted upon auscultation of the lungs, consistent with asthma. Recommended continuation of current asthma management plan, including albuterol as needed, and advised follow-up with allergist for ongoing allergic rhinitis and eczema management. Parents were educated on asthma action plan and triggers to avoid.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('534044e4-2598-4e87-aae7-15e2ca48b050', '2025-11-28T23:00:46.704870', 'Follow-up Visit', 'Patient presented for a follow-up evaluation of hypertension and management of chronic conditions. Blood pressure was 142/88 mmHg, and heart rate was 78 bpm. The patient reported no new symptoms but expressed concerns regarding joint stiffness attributed to osteoarthritis. Recommended continuation of current antihypertensive regimen, advised weight management strategies for obesity, and discussed potential benefits of physical therapy for osteoarthritis symptom relief. Follow-up in 3 months for reassessment.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('534044e4-2598-4e87-aae7-15e2ca48b050', '2025-08-01T23:00:46.704870', 'Consultation', 'Patient presented for routine hypertension management. Blood pressure was 150/92 mmHg, heart rate 78 bpm. Physical examination revealed mild swelling in the knees consistent with osteoarthritis, and erythematous patches on the scalp indicative of seborrheic dermatitis. Discussed importance of medication adherence for hypertension and diabetes, and advised continuation of current antihypertensive regimen. Recommended dietary adjustments for weight management and referral to dermatology for skin condition. Follow-up in three months or sooner if new symptoms arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('534044e4-2598-4e87-aae7-15e2ca48b050', '2025-06-13T23:00:46.704870', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was measured at 142/88 mmHg, and heart rate was 78 bpm. The patient reported stable management of hypertension and diabetes, with no new symptoms. Recommended continued adherence to current medication regimen and lifestyle modifications, including diet and exercise. Follow-up in 6 months to monitor blood pressure and glycemic control.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('534044e4-2598-4e87-aae7-15e2ca48b050', '2025-04-16T23:00:46.704870', 'Urgent Care', 'Patient presented for acute onset of dizziness and headache. Blood pressure measured at 160/95 mmHg, heart rate at 88 bpm. Physical examination revealed no focal neurological deficits. Assessment: Likely hypertensive urgency. Recommended adjustment of antihypertensive medication, increased monitoring of blood pressure at home, and follow-up with primary care provider within one week for further evaluation and management. Advised lifestyle modifications and dietary adjustments to manage overall cardiovascular risk.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('534044e4-2598-4e87-aae7-15e2ca48b050', '2025-02-16T23:00:46.704870', 'Follow-up Visit', 'Patient presented for a follow-up visit to monitor hypertension and diabetes management. Blood pressure was 142/88 mmHg, and heart rate was 78 bpm. Patient reported mild joint pain associated with osteoarthritis but denied any new symptoms. Recommended continuation of current antihypertensive and diabetic medications, and advised weight management and regular exercise to address obesity. Follow-up in three months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('88d071ec-4490-4c95-85e5-ee960189ce91', '2025-12-11T23:00:59.895810', 'Consultation', 'Patient presented for a routine consultation regarding management of hypertension and review of current medications. Blood pressure was 148/92 mmHg, heart rate was 76 bpm, and respiratory rate was 18 breaths per minute. The patient reported occasional dizziness and mild shortness of breath, particularly with exertion. It was recommended to adjust the antihypertensive medication dosage and schedule a follow-up appointment in 3 months to monitor blood pressure and assess the need for further adjustments. Additionally, lifestyle modifications including dietary changes and increased physical activity were advised to better control blood pressure and manage hyperlipidemia.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('88d071ec-4490-4c95-85e5-ee960189ce91', '2025-07-23T23:00:59.895810', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 145/92 mmHg, heart rate 82 bpm. Physical examination revealed no acute distress; however, patient reported occasional episodes of dizziness and mild fatigue. Assessment includes poorly controlled hypertension and stable prediabetes. Recommended continuation of current antihypertensive regimen with consideration of dose adjustment, reinforced dietary modifications for hyperlipidemia, and advised follow-up in 3 months for blood pressure re-evaluation.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('88d071ec-4490-4c95-85e5-ee960189ce91', '2025-07-05T23:00:59.895810', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure measured at 145/90 mmHg, heart rate at 78 bpm, and BMI at 28.2. Physical examination was unremarkable except for mild bilateral cataracts. Recommended continuation of current antihypertensive regimen and lifestyle modifications for prediabetes management; advised follow-up with ophthalmology for cataract evaluation. Encouraged adherence to lipid-lowering therapy and reviewed strategies for managing anxiety and depression symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('88d071ec-4490-4c95-85e5-ee960189ce91', '2025-01-31T23:00:59.895810', 'Urgent Care', 'Patient presented for acute shortness of breath and chest tightness. Vital signs: BP 160/95 mmHg, HR 102 bpm, RR 24 breaths per minute, SpO2 92% on room air. Physical examination revealed wheezing on auscultation and mild tachypnea. Assessment indicated an exacerbation of asthma with possible respiratory infection. Recommended initiation of nebulized bronchodilator therapy, oral corticosteroids, and advised follow-up with primary care physician for further management and monitoring of hypertension.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('88d071ec-4490-4c95-85e5-ee960189ce91', '2024-12-28T23:00:59.895810', 'Follow-up Visit', 'Patient presented for a follow-up on hypertension management. Blood pressure was stable at 128/76 mmHg, and heart rate was 72 bpm. Patient reported mild dizziness, which may be attributed to recent medication adjustment. Recommended continued monitoring of blood pressure at home, and advised dietary modifications to assist with both hyperlipidemia and prediabetes management. Advised follow-up in three months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('7ade3aa7-e208-4e3d-bff1-8814746e9473', '2025-11-11T23:01:21.951405', 'Consultation', 'Patient presented for evaluation of a minor laceration on the left forearm sustained from a fall. The wound measured approximately 2 cm in length, with mild erythema and no signs of infection. Vital signs were stable: HR 90 bpm, RR 20 breaths/min, BP 98/60 mmHg. Assessment revealed superficial laceration; wound was cleaned and dressed. Recommended keeping the area clean and applying an antibiotic ointment twice daily. Advised follow-up if signs of infection develop. Eczema and allergic rhinitis were stable, with no exacerbation noted.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('7ade3aa7-e208-4e3d-bff1-8814746e9473', '2025-08-26T23:01:21.951405', 'Follow-up Visit', 'Patient presented for follow-up of a minor laceration on the right forearm. The wound was healing well with no signs of infection or excessive swelling. Patient''s vital signs were normal for age: HR 98 bpm, RR 22 breaths/min. Recommended continued application of topical antibiotic ointment and protective dressing until fully healed. Advised parents to monitor for any signs of infection and return if concerns arise. Eczema and allergic rhinitis remained stable with current management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('7ade3aa7-e208-4e3d-bff1-8814746e9473', '2025-08-13T23:01:21.951405', 'Follow-up Visit', 'Patient presented for follow-up of a minor laceration on the right forearm. Physical examination revealed the wound healing well, with no signs of infection, and sutures intact. The patient also reported mild nasal congestion, consistent with her history of allergic rhinitis. Recommended continuation of topical emollients for eczema management and advised parents to apply sunscreen to the healing area to prevent scar hyperpigmentation. Vital signs were stable: BP 100/60, HR 90 bpm.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('9b8fabfe-cc98-4940-bca3-e6bf14d779ac', '2025-11-07T23:01:46.175667', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals: BP 128/82 mmHg, HR 76 bpm, BMI 32 kg/m². She reported intermittent right upper quadrant pain consistent with her known gallstones, but no recent episodes of biliary colic. Physical examination was unremarkable. Recommended maintaining a low-fat diet to manage gallstone symptoms and scheduling an abdominal ultrasound to evaluate gallstone status. Continued management of migraines with current medication was advised, and weight management strategies were discussed to address obesity. Follow-up in 6 months or sooner if symptoms exacerbate.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('9b8fabfe-cc98-4940-bca3-e6bf14d779ac', '2025-08-14T23:01:46.175667', 'Annual Checkup', 'Patient presented for an annual checkup and reported intermittent abdominal pain related to known gallstones. Vitals were stable: BP 128/82 mmHg, HR 76 bpm. Physical examination revealed mild tenderness in the right upper quadrant. Recommended continuation of dietary modifications and scheduled an ultrasound to assess gallbladder status. Discussed management options for gallstones, including potential surgical intervention if symptoms worsen. Follow-up for routine cancer screenings was also advised.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6d6435f0-4bbb-4b8b-802b-6f8ef5244357', '2025-09-28T23:01:51.317028', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding hay fever management and asthma history. Vitals were stable: BP 110/70 mmHg, HR 78 bpm. The patient reported persistent nasal congestion and sneezing, with seasonal exacerbations. Assessment confirmed allergic rhinitis with well-controlled asthma. Recommended continuation of current antihistamine regimen and added a nasal corticosteroid spray for improved symptom management. Follow-up in three months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ebb50d16-5d6f-4f78-a23f-7c9dd0dc50ca', '2026-01-05T23:01:53.571525', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding management of hyperlipidemia and associated comorbidities. Blood pressure was 142/88 mmHg, heart rate was 78 bpm, and BMI calculated at 32.1 kg/m². Patient reported adherence to prescribed statin with no new symptoms but expressed concerns regarding weight management and persistent low mood. Recommended continuation of current medication regimen, referral to dietitian for weight management, and follow-up with mental health services for ongoing management of moderate depression. Advised monitoring of blood glucose levels given history of prediabetes.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ebb50d16-5d6f-4f78-a23f-7c9dd0dc50ca', '2025-10-22T23:01:53.571525', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was recorded at 138/86 mmHg, heart rate at 78 bpm, and BMI at 31.2 kg/m². Patient reported no new symptoms but expressed concerns about managing weight and stress levels. Continued management of hyperlipidemia with current statin therapy was advised. Recommended lifestyle modifications including a low-carbohydrate diet and increased physical activity to address obesity and prediabetes. Referred to mental health services for ongoing moderate depression support. Follow-up in 6 months for reevaluation of metabolic control and mental health status.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('93b18da8-79f1-4b49-9e24-73d7c920f7ab', '2025-11-04T23:01:58.486925', 'Follow-up Visit', 'Patient presented for a follow-up visit concerning diabetes management. Vitals were as follows: BP 128/82 mmHg, HR 88 bpm, weight 150 lbs, height 4''10''''. Recent A1C showed improvement to 7.5%. Patient reported occasional episodes of hypoglycemia. Asthma was well-controlled with current medication regimen. Recommended continuation of current insulin dosing with adjustments as needed for hypoglycemic episodes, and advised on dietary modifications to address obesity. Follow-up in 3 months to reassess diabetes management and overall health status.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('93b18da8-79f1-4b49-9e24-73d7c920f7ab', '2025-09-02T23:01:58.486925', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were as follows: BP 122/78 mmHg, HR 88 bpm, weight 62 kg, height 148 cm, BMI 28.3 kg/m². Patient reported no new symptoms but continues with proper diabetes management; HbA1c was 7.1%. Recommendations included maintaining a balanced diet, regular physical activity, and continuation of current asthma and diabetes medications. Follow-up in 6 months to monitor HbA1c levels and address any potential complications related to obesity and hypertension.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('414cf045-6aba-46c6-b8a3-ee25a31f3c06', '2026-02-13T23:02:09.339083', 'Urgent Care', 'Patient presented for evaluation of acute urticaria with widespread itchy hives on the trunk and extremities. No respiratory distress noted, but patient has a history of asthma. Vitals: HR 110 bpm, RR 22, SpO2 98% on room air. Assessment indicated likely allergic reaction; advised antihistamine administration and avoidance of suspected allergens. Recommended follow-up with primary care provider if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('414cf045-6aba-46c6-b8a3-ee25a31f3c06', '2025-07-09T23:02:09.339083', 'Annual Checkup', 'Patient presented for an annual checkup. No acute distress noted; however, mild urticaria observed on bilateral arms with no signs of infection or severe reaction. Vitals: HR 98 bpm, RR 20 bpm, BP not applicable due to age. Asthma appeared well-controlled with current medication regimen. Recommended continuation of current asthma management plan and advised antihistamine use for hives as needed. Follow-up in 6 months for asthma management review or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('414cf045-6aba-46c6-b8a3-ee25a31f3c06', '2025-05-22T23:02:09.339083', 'Consultation', 'Patient presented for consultation due to worsening urticaria. Physical examination revealed widespread erythematous wheals predominantly on the trunk and extremities, with no signs of respiratory distress. Assessment determined likely allergic etiology exacerbated by recent environmental changes. Plan included antihistamine therapy, continued monitoring of asthma management, and referral to an allergist for further evaluation.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('dcdf6bf7-753b-475c-b0f8-6e7479cd8b27', '2025-10-06T23:02:16.610680', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: BP 112/70 mmHg, HR 78 bpm, SpO2 98% on room air. The patient reported well-controlled asthma symptoms with no recent exacerbations and maintained on current medication regimen. Advised continued daily use of inhaled corticosteroid and avoidance of known allergens to manage allergic rhinitis. Follow-up in one year or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('dcdf6bf7-753b-475c-b0f8-6e7479cd8b27', '2025-07-03T23:02:16.610680', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding asthma management. Vitals were stable: BP 110/70 mmHg, HR 78 bpm, and SpO2 98% on room air. The patient reported occasional wheezing and increased use of rescue inhaler, especially during outdoor activities. Assessment indicated suboptimal asthma control, likely exacerbated by recent pollen exposure. Recommended adjusting the current inhaled corticosteroid dosage and advised continuation of allergen avoidance strategies. Follow-up in 3 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('dcdf6bf7-753b-475c-b0f8-6e7479cd8b27', '2025-05-05T23:02:16.610680', 'Annual Checkup', 'Patient presented for annual checkup. Vital signs were stable: BP 110/70 mmHg, HR 72 bpm, RR 18 breaths/min, SpO2 98% on room air. She reported no recent asthma exacerbations but noted occasional nasal congestion consistent with allergic rhinitis. Physical examination revealed clear lung fields and no hepatomegaly. Assessment: well-controlled asthma and stable allergic rhinitis, liver condition asymptomatic. Recommendations included continuation of current asthma inhaler regimen, use of antihistamines as needed for allergy symptoms, and liver function tests to be monitored annually.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('53ff28a0-09d2-4390-b1f6-dd0f968f76ed', '2025-11-18T23:02:24.905017', 'Annual Checkup', 'Patient presented for an annual checkup with concurrent management of acute diverticulitis. Vitals were stable: BP 138/82 mmHg, HR 76 bpm, and afebrile. The patient reported left lower quadrant abdominal pain and changes in bowel habits, consistent with diverticulitis. Recommended continuation of antibiotics for diverticulitis, dietary modifications, and follow-up imaging if symptoms persist. Regular management of hyperlipidemia, hypertension, and diabetes was reinforced, with a suggestion to maintain NSAIDs minimally due to osteoarthritis to prevent exacerbating GERD.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('53ff28a0-09d2-4390-b1f6-dd0f968f76ed', '2025-06-08T23:02:24.905017', 'Annual Checkup', 'Patient presented for her annual checkup, with a recent history of acute diverticulitis. Vital signs were stable: BP 138/82 mmHg, HR 72 bpm, and BMI 28.3 kg/m². She reported mild abdominal discomfort, which has improved since starting antibiotics. Assessment included well-managed hyperlipidemia, hypertension, and diabetes, with controlled GERD symptoms. Osteoarthritis remains symptomatic, particularly in the knees. Recommended continuation of current medications, dietary adjustments to include more fiber for diverticulitis management, and follow-up in three months to monitor chronic conditions.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('53ff28a0-09d2-4390-b1f6-dd0f968f76ed', '2025-05-25T23:02:24.905017', 'Follow-up Visit', 'Patient presented for follow-up visit regarding acute diverticulitis. Vital signs: BP 138/82 mmHg, HR 76 bpm, Temp 98.6°F. Patient reported mild abdominal discomfort and improved bowel movements since starting antibiotics. Physical examination revealed mild tenderness in the left lower quadrant without guarding or rebound tenderness. Assessment: resolving acute diverticulitis. Plan: continue current antibiotic regimen, maintain a high-fiber diet, and follow up in two weeks or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('53ff28a0-09d2-4390-b1f6-dd0f968f76ed', '2024-11-08T23:02:24.905017', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 140/85 mmHg, heart rate 78 bpm. Patient reported abdominal pain consistent with recent acute diverticulitis diagnosis; advised continuation of current antibiotic regimen. Discussed management of chronic conditions including hyperlipidemia, hypertension, and diabetes; recommended dietary modifications and review of current medications. Encouraged follow-up with gastroenterology for GERD and surveillance for previous cancer history. Plan includes monitoring osteoarthritis symptoms and ensuring compliance with diabetic foot care.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('53ff28a0-09d2-4390-b1f6-dd0f968f76ed', '2024-06-26T23:02:24.905017', 'Annual Checkup', 'Patient presented for an annual checkup with a current acute diverticulitis episode. Vitals were as follows: BP 145/88 mmHg, HR 78 bpm, Temp 98.6°F. She reported mild abdominal pain with no nausea or vomiting. Assessment confirmed stable diverticulitis, well-managed chronic conditions, and no acute distress. Recommended continuation of current medications, dietary modifications, and follow-up in four weeks to reassess diverticulitis response.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('49d7b491-49aa-467c-aefc-48263c55deb1', '2026-02-23T23:02:39.446084', 'Consultation', 'Patient presented for a follow-up consultation regarding prediabetes management. Blood pressure was 138/86 mmHg, and heart rate was 78 bpm. Patient reported no new symptoms but expressed concerns about maintaining dietary changes. Encouraged continued adherence to a low-carbohydrate diet and regular physical activity; follow-up with nutritional counseling was recommended. Discussed the importance of monitoring blood glucose levels and scheduling regular check-ups to track progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('49d7b491-49aa-467c-aefc-48263c55deb1', '2025-10-23T23:02:39.446084', 'Emergency Visit', 'Patient presented for acute onset chest pain radiating to the left arm and shortness of breath. Vital signs: BP 160/95 mmHg, HR 110 bpm, RR 22 breaths/min, SpO2 96% on room air. Physical examination revealed diaphoresis and mild wheezing on lung auscultation. Differential diagnosis included myocardial ischemia versus anxiety-induced chest pain. The patient was administered aspirin 325 mg orally and nitroglycerin sublingually, and an ECG was ordered. Advised admission for further cardiac evaluation and monitoring.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('70f9f3e2-47e3-4eb5-af16-12675df97573', '2026-01-21T23:02:45.794923', 'Follow-up Visit', 'Patient presented for follow-up on obesity management and hyperlipidemia. Vital signs were stable with a blood pressure of 132/85 mmHg and heart rate of 78 bpm. Physical examination noted no acute distress; BMI calculated at 32.1 kg/m². Recommended continuation of statin therapy, discussed dietary modifications, and advised increased physical activity. Follow-up in 3 months to assess progress and lipid panel.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('70f9f3e2-47e3-4eb5-af16-12675df97573', '2025-08-13T23:02:45.794923', 'Follow-up Visit', 'Patient presented for a follow-up on obesity management and hyperlipidemia. Vital signs were as follows: BP 138/85 mmHg, HR 78 bpm. The patient reported no new symptoms but expressed concern about weight management. Continued emphasis on lifestyle modifications was advised, including a balanced diet and regular physical activity. Lipid panel was reviewed, showing slight improvement in LDL levels. Recommended continuation of atorvastatin and scheduled a follow-up visit in 3 months for further monitoring.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('70f9f3e2-47e3-4eb5-af16-12675df97573', '2025-06-28T23:02:45.794923', 'Follow-up Visit', 'Patient presented for follow-up on obesity management and assessment of hyperlipidemia. Vitals recorded: BP 138/85 mmHg, HR 78 bpm. The patient reported no new symptoms but expressed concerns about difficulty losing weight. Continued recommendation of a low-calorie diet and regular exercise was reinforced; a referral to a dietitian was provided. Lipid panel results were reviewed, and current statin therapy was continued. Next follow-up scheduled in 3 months to reassess weight management progress and lipid levels.', NULL);
