VALUES ('800d2abe-3460-44b0-900b-bc9aebed970d', '2026-01-22T23:02:57.265332', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding chronic conditions management. Blood pressure was 138/82 mmHg, and heart rate was 76 bpm. The patient reported increased nasal congestion and sneezing, consistent with hay fever, and no other acute symptoms. Continued management of hyperlipidemia, GERD, prediabetes, and hypertension was discussed, with emphasis on adherence to current medication regimen and lifestyle modifications. Recommended starting intranasal corticosteroid for hay fever symptoms and advised follow-up in 3 months.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('800d2abe-3460-44b0-900b-bc9aebed970d', '2025-06-14T23:02:57.265332', 'Follow-up Visit', 'Patient presented for follow-up regarding chronic conditions management. Vitals were recorded as BP 138/82 mmHg, HR 78 bpm, and BMI 28.1 kg/m². He reported increased nasal congestion and sneezing consistent with hay fever. Advised continuation of antihistamine therapy and reviewed the importance of dietary modifications and regular exercise to manage hyperlipidemia and prediabetes. Follow-up lab work was scheduled for lipid panel and HbA1c in 3 months.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('800d2abe-3460-44b0-900b-bc9aebed970d', '2025-05-12T23:02:57.265332', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable with blood pressure at 138/82 mmHg and heart rate at 76 bpm. No acute symptoms were reported, but the patient noted ongoing hay fever symptoms managed with over-the-counter antihistamines. Recommended continued lifestyle modifications for hyperlipidemia and prediabetes, and advised follow-up on blood work to monitor lipid profile and glucose levels.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('800d2abe-3460-44b0-900b-bc9aebed970d', '2025-04-18T23:02:57.265332', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 138/85 mmHg, heart rate 78 bpm, and BMI was 28.2, indicating overweight status. He reported increased nasal congestion and sneezing consistent with hay fever, particularly in the spring season. Assessment: Stable hypertension, controlled hyperlipidemia, GERD managed with current medication, and prediabetes without progression. Plan: Continue current antihypertensive and statin therapy, recommend over-the-counter antihistamines for hay fever symptoms, and advise follow-up in 6 months to monitor metabolic parameters.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('d90615d1-9220-4c4b-9124-a98052ee2cfa', '2026-01-25T23:03:06.684863', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were within normal limits: BP 110/70 mmHg, HR 78 bpm. She reported experiencing migraines approximately twice a month, with symptoms including throbbing pain, photophobia, and nausea. Physical examination was unremarkable. It was recommended to continue current migraine management plan with an emphasis on maintaining a regular sleep schedule and identifying potential triggers. Follow-up was advised if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('d90615d1-9220-4c4b-9124-a98052ee2cfa', '2025-10-18T23:03:06.684863', 'Follow-up Visit', 'Patient presented for follow-up on migraine management. Vitals were stable: BP 110/70 mmHg, HR 78 bpm. Patient reported a decrease in migraine frequency with the current medication regimen; however, she still experiences mild headaches twice weekly, often associated with bright light exposure. Recommended continuation of current prophylactic treatment and advised on lifestyle modifications, including maintaining a headache diary and avoiding known triggers. Follow-up in three months for further evaluation.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('db535980-6262-44c7-9d98-f1177c712d32', '2025-10-31T23:03:11.877485', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were notable for blood pressure of 145/90 mmHg and heart rate of 82 bpm. Physical examination revealed BMI of 32, consistent with obesity. Patient reported increased knee pain related to osteoarthritis. Assessment included poorly controlled hypertension and obesity. Recommended dietary modifications and regular exercise to aid weight management. Prescribed a higher dose of antihypertensive medication and advised follow-up in 3 months to reassess blood pressure and overall health status.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('db535980-6262-44c7-9d98-f1177c712d32', '2025-07-06T23:03:11.877485', 'Follow-up Visit', 'Patient presented for a follow-up visit to monitor chronic conditions. Vital signs were as follows: BP 142/88 mmHg, HR 82 bpm, BMI 32 kg/m². The patient reported increased knee pain consistent with osteoarthritis and occasional shortness of breath, possibly related to asthma. Continued current medication regimen was advised, with a recommendation to initiate physical therapy for osteoarthritis and a referral to a dietitian for weight management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('db535980-6262-44c7-9d98-f1177c712d32', '2025-02-12T23:03:11.877485', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding management of obesity and associated comorbidities. Vital signs were as follows: BP 145/90 mmHg, HR 78 bpm, weight 102 kg, BMI 34.7 kg/m². Physical examination revealed mild wheezing upon auscultation and joint tenderness in the knees. Blood pressure control remains suboptimal; recommended increasing antihypertensive medication and initiating a weight loss program. Advised continued use of inhalers for asthma and dietary modifications to manage hyperlipidemia and GERD symptoms. Follow-up scheduled in 3 months to reassess cardiovascular risk factors and adjust treatment as necessary.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('db535980-6262-44c7-9d98-f1177c712d32', '2024-12-12T23:03:11.877485', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding hypertension and obesity management. Blood pressure was recorded at 145/90 mmHg, heart rate at 78 bpm, and BMI at 32.1 kg/m². The patient reported occasional shortness of breath, likely related to asthma, and mild knee pain consistent with osteoarthritis. Recommended continuation of antihypertensive and lipid-lowering medications, initiation of a structured weight loss program, and advised use of a rescue inhaler as needed for asthma symptoms. Follow-up in 3 months for reassessment and further evaluation of weight management progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('1834613d-806d-46af-8b41-8da5f32c04f7', '2025-12-10T23:03:23.683011', 'Consultation', 'Patient presented for consultation regarding ongoing shingles outbreak. Reported severe burning pain and vesicular rash localized to the right thoracic region, consistent with dermatomal distribution. Blood pressure was 142/88 mmHg, heart rate 74 bpm, and blood glucose level was 145 mg/dL. Continued antiviral therapy was recommended, along with gabapentin for neuropathic pain management. Advised follow-up in two weeks to reassess symptoms and pain control.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('1834613d-806d-46af-8b41-8da5f32c04f7', '2025-07-30T23:03:23.683011', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 138/82 mmHg, heart rate 76 bpm, and blood glucose was stable at 110 mg/dL. She reported persistent neuropathic pain and rash from recent shingles outbreak, with lesions healing well. Recommended continuation of gabapentin for pain management and advised follow-up with ophthalmology for cataract evaluation. Encouraged adherence to current medication regimen for hypertension, hyperlipidemia, and diabetes, and discussed dietary modifications to manage GERD symptoms effectively.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('1834613d-806d-46af-8b41-8da5f32c04f7', '2025-04-25T23:03:23.683011', 'Annual Checkup', 'Patient presented for annual checkup and evaluation of ongoing shingles. Vitals were stable: BP 138/86 mmHg, HR 78 bpm. Physical examination revealed a healing vesicular rash over the right thoracic region consistent with herpes zoster. Patient reported mild neuropathic pain, managed with gabapentin. Blood glucose levels were well-controlled with current diabetic regimen. Recommended continuation of current antihypertensive and lipid-lowering therapies. Advised annual ophthalmology follow-up for cataracts and to continue dietary modifications for GERD management. Discussed shingles vaccination for future prevention.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('1834613d-806d-46af-8b41-8da5f32c04f7', '2024-12-09T23:03:23.683011', 'Urgent Care', 'Patient presented for evaluation of a painful, vesicular rash consistent with shingles, located on the left thoracic region. Vital signs were stable: BP 142/85 mmHg, HR 76 bpm. Examination revealed a well-demarcated, erythematous rash with vesicles distributed in a dermatomal pattern. Assessment confirmed acute herpes zoster without complications. Recommended starting antiviral therapy with valacyclovir and advised on pain management options. Follow-up in one week to monitor progression and discuss potential postherpetic neuralgia prevention.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('1834613d-806d-46af-8b41-8da5f32c04f7', '2024-10-25T23:03:23.683011', 'Annual Checkup', 'Patient presented for an annual checkup with a recent diagnosis of shingles. Blood pressure was 142/88 mmHg, heart rate was 78 bpm, and blood glucose levels were noted to be mildly elevated. The shingles rash was observed on the left thoracic region, with complaints of sharp, burning pain consistent with postherpetic neuralgia. Advised continuation of acyclovir and recommended gabapentin for pain management. Reviewed management of chronic conditions including hypertension and diabetes, emphasizing lifestyle modifications and adherence to prescribed medications. Follow-up scheduled in three months to monitor progress and adjust treatment as necessary.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('2b90b0f9-bce3-4f3f-aa46-fbca65d0602b', '2025-12-28T23:03:35.769896', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding management of depression and chronic conditions. Blood pressure was 138/85 mmHg, heart rate was 76 bpm, and respiratory rate was 18 breaths per minute. The patient reported improved mood stability but continues to experience intermittent insomnia. Reviewed current medication regimen; recommended continuation of sertraline with an adjustment to bedtime dosing for better sleep management. Discussed potential benefits of physical therapy for osteoarthritis and emphasized adherence to antihypertensive therapy. Follow-up in 3 months to reassess symptoms and medication efficacy.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('2b90b0f9-bce3-4f3f-aa46-fbca65d0602b', '2025-10-21T23:03:35.769896', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding depression and ongoing management of chronic conditions. Blood pressure was 138/86 mmHg, and heart rate was 72 bpm. Patient reported increased joint pain and stiffness, especially in the mornings, and occasional shortness of breath managed with current asthma inhalers. Depression symptoms have slightly improved with current medication, but insomnia persists. Continue current medication regimen, adjust dosage of sleep aid, and refer to physical therapy for osteoarthritis management. Follow-up in three months for reassessment of depression and insomnia.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('2b90b0f9-bce3-4f3f-aa46-fbca65d0602b', '2025-08-17T23:03:35.769896', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were stable with BP at 132/78 mmHg and HR at 72 bpm. The patient reported stable depressive symptoms with current management but expressed concerns about worsening joint pain affecting mobility. Recommended continuation of current antidepressant regimen, increased dose of acetaminophen for osteoarthritis pain management, and referral to physical therapy. Encouraged adherence to hypertension and heart failure medications, and scheduled follow-up in six months to monitor cardiovascular and ocular health.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
