VALUES ('5deb14a3-1ce1-48b5-87bb-1d899e6e6a68', '2024-12-10T23:04:04.340017', 'Follow-up Visit', 'Patient presented for follow-up on hypertension and review of hay fever symptoms. Blood pressure was 138/85 mmHg, heart rate 78 bpm, and BMI was 32.3 kg/m². Patient reported mild improvement in hay fever symptoms with recent antihistamine use, though occasional sneezing and nasal congestion persist. Recommended continuation of current antihypertensive regimen, advised weight management strategies, and suggested using a nasal corticosteroid spray for persistent allergic symptoms. Follow-up in 3 months.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5c91fadc-c3aa-4b26-9a98-3441a2a8d48b', '2025-10-21T23:04:13.119841', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were stable with BP at 118/72 mmHg and HR at 72 bpm. Examination revealed mild acne on the face and back, consistent with prior assessments. Continued management of acne with topical retinoids was advised, and patient was counseled on skincare routine and potential triggers. Discussed ongoing management of allergic rhinitis with antihistamines and provided reassurance regarding anxiety, recommending follow-up with mental health support as needed.', NULL);
