INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8a679499-7055-4e79-aba5-30c50abe02eb', '2025-12-01T23:04:16.931583', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding hypertension management. Blood pressure was recorded at 142/88 mmHg, and heart rate was 78 bpm. The patient reported occasional headaches and mild shortness of breath, particularly during exertion. Assessment indicates suboptimal blood pressure control and lifestyle factors contributing to obesity. Recommended adjustment of antihypertensive medication, increased physical activity, and dietary modifications to address hypertension and weight management. Follow-up in 3 months or sooner if symptoms persist.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8a679499-7055-4e79-aba5-30c50abe02eb', '2025-06-14T23:04:16.931583', 'Annual Checkup', 'Patient presented for an annual checkup with a history of hypertension, hyperlipidemia, and other chronic conditions. Blood pressure measured at 138/86 mmHg and heart rate at 78 bpm. Patient reported occasional shortness of breath, likely related to asthma, and episodes of heartburn consistent with GERD. Recommended continuation of current antihypertensive and statin therapy, increased physical activity, and dietary modifications to manage prediabetes and obesity. Advised follow-up in 6 months for reassessment and further evaluation of asthma management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('66c4fd57-1183-4392-867f-a21974fa0b22', '2025-10-15T23:04:20.618879', 'Consultation', 'Patient presented for consultation due to worsening migraine frequency and severity over the past three months. Blood pressure was 110/70 mmHg, and heart rate was 72 bpm. Patient reported associated symptoms of photophobia and nausea, with migraines occurring approximately four times per week. Assessment included probable exacerbation due to stress related to social anxiety. Recommended initiation of prophylactic treatment with low-dose propranolol and advised continuation of cognitive behavioral therapy for anxiety management. Follow-up scheduled in four weeks to evaluate treatment efficacy.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('66c4fd57-1183-4392-867f-a21974fa0b22', '2025-06-03T23:04:20.618879', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 110/70 mmHg, heart rate 72 bpm, both within normal limits. Reported experiencing migraines approximately twice a month, managed with ibuprofen as needed; no new symptoms noted. Advised continued use of current migraine regimen and recommended follow-up with neurology if frequency increases. Social anxiety remains stable with current coping strategies; encouraged continuation of supportive therapy.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b79e705c-47bb-490e-8c29-c311a8bda2e4', '2025-10-16T23:04:24.921369', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding urinary incontinence. Blood pressure was 130/80 mmHg, heart rate was 72 bpm. Patient reported increased frequency of urinary leakage despite adherence to pelvic floor exercises. Assessment indicated progression of urinary incontinence likely exacerbated by underlying diabetes; recommended initiation of oxybutynin and continued pelvic floor therapy. Advised monitoring blood glucose levels closely and maintaining current management for GERD, osteoarthritis, and osteoporosis. Follow-up in 3 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b79e705c-47bb-490e-8c29-c311a8bda2e4', '2025-07-04T23:04:24.921369', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were stable with BP 130/85 mmHg and HR 72 bpm. She reported increased episodes of urinary incontinence impacting daily activities. Examination revealed no acute distress. Management of urinary incontinence was discussed, and pelvic floor exercises were recommended. Continued management of Type 2 Diabetes and osteoporosis with current medication regimen was advised. Follow-up in 6 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b79e705c-47bb-490e-8c29-c311a8bda2e4', '2025-03-04T23:04:24.921369', 'Urgent Care', 'Patient presented for evaluation of worsening urinary incontinence, reporting increased frequency and urgency over the past week. Vital signs were within normal limits: BP 128/78 mmHg, HR 72 bpm. Examination revealed no acute distress, but mild suprapubic tenderness was noted. Assessment suggests possible overactive bladder; advised patient on timed voiding techniques and started on oxybutynin. Follow-up with primary care for further management of diabetes and osteoporosis is recommended.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b79e705c-47bb-490e-8c29-c311a8bda2e4', '2024-10-06T23:04:24.921369', 'Annual Checkup', 'Patient presented for an annual checkup with ongoing urinary incontinence. Vital signs were as follows: BP 132/78 mmHg, HR 72 bpm. Patient reported increased frequency and urgency of urination. Physical examination was unremarkable except for mild abdominal distension. Assessment included stable GERD, well-controlled Type 2 Diabetes with A1c at 7.1%, and no acute changes in osteoarthritis or osteoporosis. Recommended continuation of current medications, advised pelvic floor exercises for incontinence, and scheduled follow-up with ophthalmology for monitoring of cataracts.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e18884fc-1506-4be0-8823-81379818bfb7', '2025-11-29T23:04:33.417203', 'Urgent Care', 'Patient presented for acute shortness of breath and chest tightness. Vitals were significant for BP 150/90 mmHg, HR 92 bpm, and SpO2 94% on room air. Physical examination revealed wheezing on auscultation and mild peripheral edema. Assessment indicated an exacerbation of asthma, likely triggered by an upper respiratory infection. Recommended initiation of a short course of oral corticosteroids and an increase in inhaler use frequency. Advised follow-up with primary care for further management of underlying conditions, including ongoing hypertension and hyperlipidemia.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e18884fc-1506-4be0-8823-81379818bfb7', '2025-06-04T23:04:33.417203', 'Follow-up Visit', 'Patient presented for a follow-up visit for management of hyperlipidemia and review of chronic conditions. Vitals were stable: BP 128/82 mmHg, HR 72 bpm. The patient reported occasional joint pain consistent with osteoarthritis, but denied any new symptoms such as chest pain or respiratory distress. Lipid panel reviewed; LDL cholesterol remained elevated. Recommended continuation of atorvastatin 20 mg daily and advised dietary modifications. Follow-up in 3 months to reassess lipid levels and control of hypertension and asthma symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a89a3052-dfca-4485-90f4-10346aea0c3f', '2025-09-30T23:04:39.152353', 'Urgent Care', 'Patient presented for evaluation of severe right upper quadrant abdominal pain and nausea persisting for 48 hours. Vital signs showed BP 128/82 mmHg, HR 88 bpm, RR 18 breaths/min, and temperature 98.6°F. Physical examination revealed tenderness in the right upper quadrant without rebound or guarding. Assessment confirmed symptomatic gallstones. Recommended initiation of a low-fat diet and scheduled an outpatient surgical consultation for potential cholecystectomy. Advised continued use of albuterol inhaler as needed for asthma.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a89a3052-dfca-4485-90f4-10346aea0c3f', '2025-08-25T23:04:39.152353', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were stable: BP 118/76 mmHg, HR 72 bpm. Patient reported intermittent right upper quadrant pain, consistent with known gallstones, but no recent episodes of asthma exacerbation. Recommended avoiding high-fat meals and advised follow-up with gastroenterology for potential cholecystectomy evaluation. Asthma management plan to continue as previously outlined, with emphasis on regular use of inhaler as needed.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a89a3052-dfca-4485-90f4-10346aea0c3f', '2025-07-15T23:04:39.152353', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: BP 118/76 mmHg, HR 72 bpm, RR 16 breaths/min, Temp 98.6°F. The patient reported intermittent right upper quadrant pain consistent with known gallstones and no recent asthma exacerbations. Recommended continuation of low-fat diet to manage gallstone symptoms and advised follow-up with gastroenterology for possible elective cholecystectomy. Asthma remains well-controlled on current inhaler regimen; advised to continue current management and follow up in one year or as needed.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8307dcf6-d910-4cff-b651-bec6dbd2e258', '2026-02-08T23:04:45.810345', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding management of obesity and review of chronic conditions. Vitals: BP 145/90 mmHg, HR 82 bpm, BMI 32.8 kg/m². Patient reported mild fatigue and occasional headaches but denied any significant changes in vision or chest pain. Assessment included poorly controlled hypertension and stable diabetes. Recommended continuation of current antihypertensive and antidiabetic medications, initiation of a structured weight loss program, and referral to a dietitian for nutritional counseling. Follow-up in three months to assess progress and adjust treatment as necessary.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8307dcf6-d910-4cff-b651-bec6dbd2e258', '2025-06-18T23:04:45.810345', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding diabetes and hypertension management. Vitals were recorded as BP 145/90 mmHg, HR 82 bpm; patient reported no new symptoms but expressed difficulty in maintaining weight loss. Physical exam revealed a BMI of 32.5 kg/m², consistent with obesity. Recommended dietary modifications and increased physical activity; adjusted antihypertensive medication dosage for better blood pressure control. Follow-up scheduled in three months to monitor progress and reassess treatment efficacy.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('2638d404-7a53-4e75-aec2-274aace1b888', '2026-01-10T23:04:50.212133', 'Consultation', 'Patient presented for evaluation of chronic constipation. Physical examination was unremarkable, with normal abdominal inspection and auscultation. Vital signs were stable: BP 90/60 mmHg, HR 84 bpm, RR 18, Temp 98.6°F. Assessment indicated constipation likely exacerbated by dietary factors, with no acute distress. Recommended increasing dietary fiber and fluid intake, and advised a follow-up in 4 weeks to assess symptom improvement. Asthma remains well-controlled with current medication regimen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('2638d404-7a53-4e75-aec2-274aace1b888', '2025-10-04T23:04:50.212133', 'Annual Checkup', 'Patient presented for annual checkup. Vitals were within normal limits: BP 100/65 mmHg, HR 85 bpm, RR 18 breaths/min. Reported ongoing constipation with infrequent bowel movements over the past month, managed with dietary fiber increase. Physical exam was unremarkable, and no signs of acute distress were noted. Assessment: Chronic constipation likely secondary to dietary habits. Plan: Increase dietary fiber and hydration, consider stool softeners if symptoms persist. Advised follow-up in 6 months or sooner if symptoms worsen. Asthma remains well-controlled with current medication regimen; no recent exacerbations noted.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('2df3d241-b3ad-4f12-9d73-5670599a83fb', '2025-12-04T23:04:54.717754', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding asthma management. Vital signs were stable with a blood pressure of 122/78 mmHg and heart rate of 76 bpm. The patient reported occasional wheezing and shortness of breath, particularly during exercise. Assessment indicated well-controlled asthma with no recent exacerbations. Recommended continuation of current inhaler regimen and advised on lifestyle modifications, including regular exercise and dietary adjustments to manage hyperlipidemia. Follow-up in 6 months was scheduled.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('2df3d241-b3ad-4f12-9d73-5670599a83fb', '2025-08-03T23:04:54.717754', 'Urgent Care', 'Patient presented for evaluation due to an acute exacerbation of asthma, reporting increased wheezing and shortness of breath over the past 24 hours. Vital signs were as follows: BP 128/82 mmHg, HR 96 bpm, RR 22 breaths per minute, SpO2 92% on room air. Physical examination revealed bilateral wheezing on auscultation. Assessment confirmed asthma exacerbation likely triggered by recent environmental allergens. Recommended initiation of a short course of oral corticosteroids and advised continuation of current inhaled bronchodilator regimen. Patient was instructed to follow up with primary care within one week for reassessment.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('2df3d241-b3ad-4f12-9d73-5670599a83fb', '2025-06-29T23:04:54.717754', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable with BP 122/78 mmHg and HR 76 bpm. Patient reported no recent asthma exacerbations but mentioned occasional shortness of breath during exercise. Recommended continuation of current asthma management plan, advised lifestyle modifications to manage hyperlipidemia, and scheduled follow-up lipid panel in 6 months.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ff526ab9-b431-491f-b501-171aa4887899', '2025-11-15T23:05:01.272179', 'Follow-up Visit', 'Patient presented for a routine follow-up visit. Vital signs were within normal limits: BP 90/60 mmHg, HR 100 bpm. Skin examination revealed mild erythema and dryness consistent with eczema on the antecubital fossa and behind the knees. Recommended continued use of emollients and prescribed a mild topical corticosteroid for flare-ups. No other concerns noted at this time.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ff526ab9-b431-491f-b501-171aa4887899', '2025-09-11T23:05:01.272179', 'Annual Checkup', 'Patient presented for an annual checkup. No acute complaints noted. Physical exam was unremarkable; vital signs were within normal limits: HR 92 bpm, RR 20 breaths/min, BP unobtainable (as per standard for age). Skin examination revealed mild eczema on bilateral antecubital fossae, consistent with medical history; no signs of infection or significant exacerbation. Assessment: Well-child visit; eczema stable. Plan: Continue current moisturizing regimen; follow-up in one year or as needed for any concerns.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('9b82c54f-c330-4adb-97dc-ba127b21935f', '2025-10-14T23:05:05.879491', 'Consultation', 'Patient presented for a follow-up consultation regarding ongoing cancer treatment. Vital signs were recorded: BP 138/82 mmHg, HR 76 bpm. The patient reported increased fatigue and mild nausea, likely related to chemotherapy. Recommended continuation of current oncological treatment regimen, with supportive care for managing symptoms; advised monitoring of blood glucose levels due to diabetes and follow-up in four weeks.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('9b82c54f-c330-4adb-97dc-ba127b21935f', '2025-07-24T23:05:05.879491', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding cancer management and monitoring of chronic conditions. Blood pressure was 138/82 mmHg, heart rate 78 bpm. The patient reported fatigue and mild joint pain, consistent with osteoarthritis. Assessment revealed stable cancer status with no new complications. Recommended continuation of current medication regimen, with emphasis on blood sugar and blood pressure control, and advised regular follow-up with oncology and primary care.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('d9fa1b77-38d7-4f7a-b0d2-2e99ae18d32e', '2026-01-24T23:05:10.078640', 'Annual Checkup', 'Patient presented for an annual checkup and management of a urinary tract infection. Vital signs were stable: BP 118/76 mmHg, HR 72 bpm, Temp 98.6°F. Patient reported dysuria and increased frequency of urination. Labs indicated mild anemia, consistent with known history, and depression was reported as stable on current medication regimen. Prescribed a 5-day course of nitrofurantoin for UTI, advised increased fluid intake, and recommended follow-up in 4 weeks to reassess anemia and review mental health status.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('d9fa1b77-38d7-4f7a-b0d2-2e99ae18d32e', '2025-09-14T23:05:10.078640', 'Follow-up Visit', 'Patient presented for follow-up regarding urinary tract infection and ongoing management of anemia and moderate depression. Vitals were stable: BP 118/76 mmHg, HR 72 bpm. Patient reported mild dysuria and increased urinary frequency; no fever or back pain noted. Plan included continuation of current antibiotic regimen for UTI, regular monitoring of hemoglobin levels for anemia, and adjustment of antidepressant dosage as per recent mental health assessment. Advised to increase fluid intake and return if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('825db683-3cef-44f3-bb64-523296f568d2', '2025-12-10T23:05:14.278015', 'Follow-up Visit', 'Patient presented for follow-up on hay fever and allergic rhinitis. Physical examination revealed nasal congestion and watery eyes with mild erythema. Vitals were stable with BP 110/70 mmHg and HR 80 bpm. Recommended continuation of antihistamine therapy and advised environmental control measures to reduce allergen exposure. Follow-up in 3 months to reassess symptoms and treatment efficacy.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('825db683-3cef-44f3-bb64-523296f568d2', '2025-08-13T23:05:14.278015', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were stable with BP 110/70 mmHg and HR 78 bpm. Physical examination revealed mild nasal congestion and erythematous nasal turbinates consistent with allergic rhinitis. It was recommended to continue current antihistamine regimen and consider an allergen avoidance strategy for symptomatic relief during peak pollen seasons.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('825db683-3cef-44f3-bb64-523296f568d2', '2025-05-16T23:05:14.278015', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were stable, with BP at 110/70 mmHg and HR at 78 bpm. Reported increased nasal congestion and sneezing consistent with hay fever, particularly during springtime. Continued management of allergic rhinitis with current antihistamine therapy was recommended, and advised to avoid known allergens. Follow-up in one year unless symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('825db683-3cef-44f3-bb64-523296f568d2', '2024-12-27T23:05:14.278015', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding ongoing hay fever symptoms. Physical examination revealed clear nasal discharge and bilateral nasal congestion, with no signs of infection. Assessment confirmed continued allergic rhinitis, with controlled symptoms using current antihistamine regimen. Recommended continuation of current medication and advised to monitor for any exacerbation during peak pollen season; instructed on environmental control measures to reduce allergen exposure. Vitals were stable: BP 104/68 mmHg, HR 78 bpm. Follow-up in 6 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('91f59546-f096-4ee0-a942-20a0cb2b2064', '2026-01-15T23:05:21.956473', 'Follow-up Visit', 'Patient presented for follow-up regarding management of food allergies. Vital signs were stable: BP 90/60 mmHg, HR 100 bpm, Temp 98.6°F. No new allergic reactions reported since last visit; skin examination revealed no signs of urticaria or eczema. Assessment confirmed well-controlled allergies with current avoidance measures and antihistamine use. Recommended continuation of current management plan and provided an updated emergency action plan. Follow-up in six months unless new symptoms arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('91f59546-f096-4ee0-a942-20a0cb2b2064', '2025-09-04T23:05:21.956473', 'Urgent Care', 'Patient presented for evaluation of a rash and swelling following ingestion of an unknown food item. Vital signs on presentation: BP 98/60 mmHg, HR 110 bpm, Temp 98.6°F. Physical examination revealed urticaria over the trunk and mild facial edema. Assessment determined an acute allergic reaction, likely secondary to food exposure. Administered oral antihistamine with observed improvement. Advised strict avoidance of known allergens and follow-up with an allergist for further evaluation and management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b3978eaf-87cf-4107-946b-2e15fb8f8f0e', '2026-01-31T23:05:26.360090', 'Urgent Care', 'Patient presented for evaluation of fever, sore throat, and a rash on hands and feet, consistent with Hand, Foot, and Mouth Disease. On examination, the patient was afebrile, with a heart rate of 90 bpm and respiratory rate of 20 breaths per minute. Oral ulcers and a vesicular rash on palms and soles were noted. The assessment confirmed Hand, Foot, and Mouth Disease, with no complications observed. Recommended supportive care with hydration, acetaminophen for fever, and monitoring for any signs of dehydration or respiratory difficulty, especially considering the patient''s history of asthma.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b3978eaf-87cf-4107-946b-2e15fb8f8f0e', '2025-05-30T23:05:26.360090', 'Emergency Visit', 'Patient presented for evaluation of fever, sore throat, and rash consistent with Hand, Foot, and Mouth Disease. Physical examination revealed vesicular lesions on the hands, feet, and oral mucosa. Vital signs were stable: BP 98/60 mmHg, HR 98 bpm, Temp 100.4°F. Assessment confirmed Hand, Foot, and Mouth Disease. Recommended supportive care, including hydration and antipyretics for fever management. Instructed guardians to monitor for any difficulty breathing due to the patient''s history of asthma and to follow up with the primary care provider if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b3978eaf-87cf-4107-946b-2e15fb8f8f0e', '2025-05-23T23:05:26.360090', 'Consultation', 'Patient presented for a follow-up consultation for Hand, Foot, and Mouth Disease. Physical examination revealed vesicular lesions on the hands and feet, with mild oral lesions noted. Patient''s asthma and hay fever are currently well-managed, with no acute exacerbations reported. Recommended supportive care with hydration and pain management; advised monitoring for any signs of secondary infection. Vitals were stable: BP 102/68, HR 88, afebrile.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e15c9094-1c84-459b-b3a3-5893eeb80e61', '2025-12-09T23:05:32.812477', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding ongoing cancer treatment. Blood pressure was 145/90 mmHg, heart rate was 82 bpm, and BMI was 32 kg/m². The patient reported persistent fatigue and occasional nausea, consistent with chemotherapy side effects. Recommended continuation of current chemotherapy regimen, with supportive care for symptom management, including antiemetics for nausea. Advised monitoring of blood pressure and lipid levels, and discussed potential lifestyle modifications to address obesity and hypertension.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e15c9094-1c84-459b-b3a3-5893eeb80e61', '2025-08-21T23:05:32.812477', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs: BP 138/85 mmHg, HR 78 bpm. The patient reported experiencing increased fatigue and occasional shortness of breath. On examination, there were no acute distress signs, and weight was noted to be stable. Assessment included poorly controlled hypertension and the need for better management of hyperlipidemia in the context of ongoing cancer treatment. Recommended continuation of current cancer therapy, adjustment of antihypertensive medication, and dietary consultation to assist with weight management and lipid control. Follow-up in 3 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e15c9094-1c84-459b-b3a3-5893eeb80e61', '2025-03-21T23:05:32.812477', 'Emergency Visit', 'Patient presented for evaluation of acute chest pain and shortness of breath. Vital signs: BP 162/94 mmHg, HR 98 bpm, RR 24 breaths/min, SpO2 90% on room air. Physical examination revealed decreased breath sounds in the right lower lung field and mild tachycardia. Assessment includes possible pulmonary embolism or pneumonia, given the history of cancer. Recommended immediate chest CT scan and initiation of supplemental oxygen therapy. Further management to be determined based on imaging results.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ebbe7b5d-230a-4dbc-9c2a-3028941c6e5c', '2025-12-24T23:05:39.569653', 'Consultation', 'Patient presented for consultation regarding gallstones. Vital signs were stable with BP at 130/82 mmHg and HR at 76 bpm. The patient reported intermittent right upper quadrant abdominal pain with episodes of nausea, which are exacerbated postprandially. Recommended scheduling a cholecystectomy evaluation and advised dietary modifications to include a low-fat diet. Follow-up planned for management of current conditions including monitoring for symptoms of GERD and prediabetes, and continued management of moderate depression.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ebbe7b5d-230a-4dbc-9c2a-3028941c6e5c', '2025-09-29T23:05:39.569653', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were recorded as follows: BP 130/85 mmHg, HR 76 bpm, BMI 26.2. Patient reported occasional abdominal pain associated with gallstones, but no new symptoms of note. Depression and GERD remain stable with current medications; cataracts do not impair daily activities. Prediabetes is managed with diet and exercise. Recommended continuation of current management for gallstones, and advised follow-up with ophthalmology for cataract assessment. Encouraged routine blood glucose monitoring and adherence to dietary recommendations.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ebbe7b5d-230a-4dbc-9c2a-3028941c6e5c', '2025-05-08T23:05:39.569653', 'Follow-up Visit', 'Patient presented for follow-up regarding gallstones. Vital signs were stable with BP 132/78 mmHg, HR 72 bpm. She reported intermittent abdominal pain and nausea, which have been managed with dietary modifications. Recommended continuation of current dietary plan and scheduled an ultrasound to monitor gallstone progression. Discussed the importance of managing prediabetes through lifestyle changes and reviewed current medications for GERD and moderate depression. Advised follow-up in 3 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ebbe7b5d-230a-4dbc-9c2a-3028941c6e5c', '2025-02-25T23:05:39.569653', 'Consultation', 'Patient presented for a consultation regarding gallstones. Vital signs were within normal limits: BP 130/82 mmHg, HR 72 bpm. The patient reported intermittent right upper quadrant pain and episodes of nausea, correlating with meals high in fat. Recommended dietary modifications to reduce fat intake and referred for a surgical consultation to discuss potential cholecystectomy. Advised continuation of current medications for GERD and monitoring of prediabetes through regular blood glucose checks. Follow-up in 4 weeks to reassess symptoms and review surgical consultation results.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ebbe7b5d-230a-4dbc-9c2a-3028941c6e5c', '2024-07-30T23:05:39.569653', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 130/78 mmHg, heart rate was 72 bpm, and BMI was 28.3. Patient reported mild abdominal discomfort and intermittent nausea, likely related to gallstones. Depression is stable on current medication regimen; no changes recommended. GERD symptoms are managed with lifestyle modifications and over-the-counter antacids. Cataracts are unchanged; follow-up with ophthalmology as previously scheduled. Advised lifestyle modifications to address prediabetes, including diet and exercise. Follow-up in 6 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('7a507336-1079-4b34-b479-b4f052534bce', '2026-02-02T23:05:55.855558', 'Consultation', 'Patient presented for evaluation of symptoms consistent with Hand, Foot, and Mouth Disease. Physical examination revealed vesicular lesions on the hands, feet, and oral mucosa, and the patient reported mild fever and sore throat. Vitals were within normal ranges: BP 105/70 mmHg, HR 88 bpm, Temp 100.1°F. Assessment confirmed viral etiology. Recommended supportive care including hydration, antipyretics for fever, and topical analgesics for oral discomfort. Advised close monitoring for any signs of complications and follow-up if symptoms persist beyond 10 days. Discussed management strategies for ADHD as part of ongoing care.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('7a507336-1079-4b34-b479-b4f052534bce', '2025-10-17T23:05:55.855558', 'Annual Checkup', 'Patient presented for an annual checkup and was concurrently experiencing symptoms of Hand, Foot, and Mouth Disease, including mild fever and oral lesions. Vital signs were stable: BP 105/68 mmHg, HR 92 bpm, Temp 100.2°F. ADHD remains well-managed with current medication regimen. Recommended supportive care for viral illness, including hydration and antipyretics as needed; advised follow-up if symptoms persist beyond a week or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('7a507336-1079-4b34-b479-b4f052534bce', '2025-04-02T23:05:55.855558', 'Annual Checkup', 'Patient presented for annual checkup with concurrent symptoms of hand, foot, and mouth disease, including vesicular lesions on palms and soles. Vital signs were stable: BP 100/60 mmHg, HR 88 bpm. ADHD was well-managed with current medication regimen. Recommended supportive care for viral infection, including hydration and analgesics for discomfort, and advised follow-up if symptoms persist beyond expected duration.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('7a507336-1079-4b34-b479-b4f052534bce', '2025-03-22T23:05:55.855558', 'Annual Checkup', 'Patient presented for an annual checkup and evaluation of current symptoms related to Hand, Foot, and Mouth Disease. Physical examination revealed maculopapular rash on hands and feet, with no new lesions noted; oral examination showed mild vesicular lesions. Vital signs were within normal limits: BP 104/68 mmHg, HR 88 bpm, Temp 37.1°C. ADHD was stable on current medication. Recommended supportive care for Hand, Foot, and Mouth Disease, including hydration and pain management, and advised follow-up if symptoms worsen or new symptoms develop.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a43c4cdd-65b0-4389-8f67-3942a922b467', '2025-10-22T23:06:04.972692', 'Urgent Care', 'Patient presented for evaluation of increased fatigue and dizziness over the past week. Vital signs were as follows: BP 118/75 mmHg, HR 88 bpm, Temp 98.6°F, SpO2 99% on room air. Physical examination showed conjunctival pallor. Assessment revealed likely worsening anemia, potentially related to current treatment regimen. Recommended CBC and iron studies, and advised continuation of iron supplementation with possible dosage adjustment pending lab results. Follow-up in two weeks or sooner if symptoms exacerbate.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
