VALUES ('24034ce7-0cf1-40aa-bd16-490a423e5335', '2025-02-27T23:06:10.494248', 'Follow-up Visit', 'Patient presented for a follow-up visit for general checkup. Vital signs were within normal limits: HR 120 bpm, RR 30 breaths/min, temperature 98.6°F. Physical examination was unremarkable with no acute distress noted. Assessment confirmed stable allergic rhinitis with no exacerbation. Recommended continuation of current management plan, including avoidance of known allergens, and advised follow-up if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('24034ce7-0cf1-40aa-bd16-490a423e5335', '2025-02-24T23:06:10.494248', 'Follow-up Visit', 'Patient presented for a follow-up visit and general checkup. Vital signs were within normal limits: HR 110 bpm, respiratory rate 28 breaths/min, weight 10 kg. No acute symptoms were reported; previous history of allergic rhinitis remains stable. Recommended continuation of current management plan, with emphasis on environmental allergen avoidance and regular follow-ups to monitor potential development of new allergy symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('24034ce7-0cf1-40aa-bd16-490a423e5335', '2024-08-18T23:06:10.494248', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were within normal limits for age: BP not applicable, HR 110 bpm, RR 30/min, Temp 98.6°F. No acute distress noted; nasal mucosa showed mild congestion consistent with history of allergic rhinitis. Recommended continuation of current allergen avoidance strategies and follow-up in one year unless symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8d840c6a-29c0-43a6-80a7-624910093266', '2025-12-02T23:06:21.713663', 'Follow-up Visit', 'Patient presented for a follow-up visit for asthma management. Vital signs were stable: BP 128/84 mmHg, HR 76 bpm, SpO2 97% on room air. Patient reported experiencing mild wheezing and shortness of breath, primarily during physical exertion, with recent increase in nighttime symptoms. Lung auscultation revealed scattered wheezes bilaterally. Assessment: Suboptimal asthma control. Plan: Adjusted inhaled corticosteroid dosage, recommended continuation of short-acting beta-agonist as needed, and advised avoidance of known allergens. Follow-up in 3 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8d840c6a-29c0-43a6-80a7-624910093266', '2025-08-13T23:06:21.713663', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: BP 128/82 mmHg, HR 72 bpm, RR 16 breaths/min, SpO2 98% on room air. Patient reported intermittent dyspnea, particularly during physical exertion, and occasional wheezing, consistent with his asthma history. On assessment, lung auscultation revealed clear breath sounds bilaterally with no wheezing noted today. It was recommended to continue current asthma management plan, including the use of a rescue inhaler as needed and daily inhaled corticosteroids. Advised to monitor peak flow readings and follow up in 6 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('18f8e004-a461-4d96-ada4-628e48902573', '2025-12-02T23:06:26.675303', 'Follow-up Visit', 'Patient presented for a follow-up visit to monitor hypothyroidism. Vitals were stable: BP 118/76 mmHg, HR 72 bpm. The patient reported no new symptoms and adherence to levothyroxine therapy. TSH levels were within normal range. Recommended continuation of current medication dosage and advised follow-up in six months for thyroid function re-evaluation.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('18f8e004-a461-4d96-ada4-628e48902573', '2025-07-31T23:06:26.675303', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: BP 118/76 mmHg, HR 72 bpm, Temp 98.6°F. The patient reported adherence to levothyroxine therapy with no current symptoms of hypothyroidism. Recommended continuation of current medication dosage and advised follow-up thyroid function tests in six months. No new concerns were identified during the examination.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4960f7a4-1098-4a4e-b2c3-ca1aa27fa4ae', '2025-11-09T23:06:29.845425', 'Follow-up Visit', 'Patient presented for follow-up on obesity management. Vital signs were as follows: BP 130/85 mmHg, HR 78 bpm, BMI 32 kg/m². Patient reported no new symptoms and adhered to dietary modifications with minimal weight change. Recommended continuation of current lifestyle changes and discussed potential referral to a nutritionist for further support. Follow-up scheduled in 3 months to monitor progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4960f7a4-1098-4a4e-b2c3-ca1aa27fa4ae', '2025-09-06T23:06:29.845425', 'Follow-up Visit', 'Patient presented for a follow-up regarding obesity management. Vitals were recorded as follows: BP 130/85 mmHg, HR 78 bpm, BMI 32 kg/m². The patient reported no new symptoms and expressed continued motivation for lifestyle modification. Recommended maintaining a balanced diet, increasing physical activity to at least 150 minutes per week, and scheduling a follow-up in 3 months to monitor progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5ee5cca1-2b2d-450f-9765-e34cb2eb6fe8', '2025-12-19T23:06:33.387919', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals recorded were BP 128/82 mmHg, HR 76 bpm, weight 220 lbs, height 5''5", BMI 36.6 indicating obesity. The patient reported no new symptoms or significant changes in health status. Recommended lifestyle modifications including a balanced diet and regular exercise to address obesity; follow-up scheduled in 6 months to monitor progress and reassess management plan.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5ee5cca1-2b2d-450f-9765-e34cb2eb6fe8', '2025-09-23T23:06:33.387919', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 138/86 mmHg, HR 78 bpm, BMI 32.4 kg/m². The patient reported no new symptoms and physical examination was unremarkable. Assessment indicated obesity without complications. Recommended initiating a weight management program, including dietary modifications and increased physical activity. Follow-up scheduled in 6 months to monitor progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5ee5cca1-2b2d-450f-9765-e34cb2eb6fe8', '2025-08-13T23:06:33.387919', 'Urgent Care', 'Patient presented for acute onset of shortness of breath and palpitations. Vitals were notable for BP 142/88 mmHg, HR 110 bpm, and SpO2 97% on room air. Physical examination revealed no wheezing or rales, but tachycardia was appreciated. Assessment: likely anxiety-induced palpitations exacerbated by obesity. Plan included reassurance, recommendation for weight management, and referral to a cardiologist for further evaluation.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b4178321-165d-4024-a6c8-381980fab92c', '2025-11-26T23:06:39.167753', 'Urgent Care', 'Patient presented for acute exacerbation of hay fever symptoms, including sneezing, nasal congestion, and itchy eyes. Vitals were stable: BP 112/70, HR 88, Temp 98.6°F, RR 18. Physical examination revealed swollen nasal turbinates and clear rhinorrhea. Assessment indicated an acute allergic rhinitis flare. Recommended continuation of current antihistamine treatment with the addition of a nasal corticosteroid spray. Advised follow-up with primary care for obesity management and possible allergy testing.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b4178321-165d-4024-a6c8-381980fab92c', '2025-10-11T23:06:39.167753', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable with BP 110/70 mmHg, HR 82 bpm, height at 150 cm, and weight at 55 kg, indicating persistent obesity. Symptoms of hay fever included nasal congestion and sneezing; no new allergic triggers reported. Recommended continued use of antihistamines for allergic rhinitis and discussed nutritional guidance and physical activity to address obesity. Follow-up scheduled in six months to monitor progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b4178321-165d-4024-a6c8-381980fab92c', '2025-04-04T23:06:39.167753', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were within normal limits: BP 110/70 mmHg, HR 82 bpm. The patient continues to experience symptoms of allergic rhinitis, including nasal congestion and sneezing, consistent with hay fever exacerbation. Mild obesity was noted, BMI at the 95th percentile for age; dietary modifications and increased physical activity were recommended. Continuation of current antihistamine treatment was advised, and a follow-up visit was scheduled to monitor weight and allergy symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b4178321-165d-4024-a6c8-381980fab92c', '2025-04-03T23:06:39.167753', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were within normal limits: BP 110/70 mmHg, HR 78 bpm. Physical examination showed mild nasal congestion and watery eyes consistent with allergic rhinitis. Patient''s BMI indicated ongoing obesity; dietary and exercise modifications were reinforced. Recommended continuation of antihistamines for hay fever management and scheduled follow-up in 6 months for obesity monitoring.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('7e3f858a-2eed-4851-9260-a48ed51f19db', '2025-10-02T23:06:46.298704', 'Follow-up Visit', 'Patient presented for follow-up on hyperlipidemia management. Blood pressure was 138/86 mmHg, and heart rate was 78 bpm. The patient reported stable energy levels with no new symptoms but noted occasional heartburn, likely related to GERD. Continued statin therapy was recommended, and dietary modifications were reinforced. Follow-up in 6 months to re-evaluate lipid levels and adjust treatment as necessary.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('7e3f858a-2eed-4851-9260-a48ed51f19db', '2025-06-01T23:06:46.298704', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was elevated at 145/92 mmHg, and heart rate was 78 bpm. He reported experiencing occasional insomnia and mild heartburn despite current GERD management. Assessment indicated controlled hyperlipidemia but poorly controlled hypertension. Recommended dietary modifications and continuation of current statin therapy; adjusted antihypertensive medication dosage. Advised follow-up in 3 months to reassess blood pressure and review sleep hygiene strategies.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('7e3f858a-2eed-4851-9260-a48ed51f19db', '2025-05-06T23:06:46.298704', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were BP 130/85 mmHg, HR 78 bpm, BMI 27.2. Physical examination was unremarkable except for mild rhinorrhea consistent with allergic rhinitis. Lipid panel from last month showed elevated LDL levels; patient advised to continue statin therapy and follow a low-fat diet. Discussed insomnia management; patient reported occasional use of melatonin with some benefit. Follow-up in 6 months for blood pressure management and lipid profile reassessment.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6f510f6e-5bb5-4cdf-b661-a8408677f206', '2025-11-07T23:06:51.967673', 'Annual Checkup', 'Patient presented for annual checkup. Vitals were stable: BP 100/65 mmHg, HR 82 bpm, weight and height appropriate for age. Physical examination revealed mild erythematous patches on the antecubital fossa consistent with eczema; no signs of secondary infection noted. Recommended continuation of emollient use and prescribed a low-potency topical steroid for flare-ups. Discussed importance of avoiding known irritants and maintaining hydration. Follow-up in one year or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6f510f6e-5bb5-4cdf-b661-a8408677f206', '2025-10-12T23:06:51.967673', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: BP 102/64 mmHg, HR 88 bpm, Temp 98.4°F. Examination revealed mild erythematous patches on the antecubital fossae consistent with eczema, with no signs of secondary infection. Recommended continuation of current emollient regimen and prescribed a low-dose topical corticosteroid for flare-ups. Advised to avoid known irritants and maintain skin hydration. Follow-up in one year or as needed for any exacerbations.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('453ec0d0-26c2-4dc4-b469-3715f1565fe6', '2025-12-11T23:06:56.167726', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: BP 100/60 mmHg, HR 88 bpm, afebrile. The patient has a history of eczema; skin examination revealed mild erythematous patches on the antecubital fossae with no signs of infection. Advised continuation of emollients and prescribed a low-potency topical corticosteroid for flare-ups. Previous fracture site on the right arm was well-healed with no residual issues. Recommended follow-up in one year or as needed for eczema management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('453ec0d0-26c2-4dc4-b469-3715f1565fe6', '2025-10-20T23:06:56.167726', 'Follow-up Visit', 'Patient presented for follow-up evaluation of eczema. On examination, erythematous and mildly excoriated patches were noted on bilateral antecubital fossae, with no signs of infection. Previous fracture site was asymptomatic with no deformity observed. Recommended continuation of emollient therapy and topical corticosteroids as needed; advised to avoid known irritants and maintain regular dermatologic follow-up. Vital signs were stable with HR 82 bpm, BP 100/62 mmHg.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('453ec0d0-26c2-4dc4-b469-3715f1565fe6', '2025-02-25T23:06:56.167726', 'Urgent Care', 'Patient presented for evaluation of worsening eczema with increased pruritus. Physical examination revealed erythematous, dry, and excoriated patches on bilateral antecubital and popliteal fossae. Vital signs were stable: BP 100/70 mmHg, HR 88 bpm, Temp 98.4°F. Assessment concluded an acute exacerbation of atopic dermatitis. Recommended a topical corticosteroid twice daily and advised maintaining regular application of emollients. Follow-up with primary care physician in 2 weeks or sooner if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('d64c52b9-3e02-4c15-b0ef-7f2dac6757f8', '2026-02-21T23:07:02.412570', 'Follow-up Visit', 'Patient presented for follow-up on hypertension management. Blood pressure was measured at 138/86 mmHg, and heart rate was 78 bpm. Patient reported no new symptoms but noted occasional headaches, consistent with her history of migraines. Continued monitoring of blood pressure was advised, and the patient was counseled on lifestyle modifications, including dietary changes and regular exercise. Adjustments to her antihypertensive medication will be considered at the next visit if blood pressure remains elevated.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('d64c52b9-3e02-4c15-b0ef-7f2dac6757f8', '2025-09-20T23:07:02.412570', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding hypertension management. Blood pressure was 138/86 mmHg, heart rate 76 bpm. Patient reported occasional headaches but noted improvement in anxiety symptoms. Continued current antihypertensive therapy; recommended maintaining a low-sodium diet and regular exercise. Scheduled follow-up in three months, advised to monitor BP at home, and instructed to return if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('d64c52b9-3e02-4c15-b0ef-7f2dac6757f8', '2025-04-22T23:07:02.412570', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was recorded at 138/86 mmHg and heart rate at 76 bpm. Physical examination was unremarkable; however, the patient reported occasional headaches and increased anxiety episodes. Assessment included controlled hypertension with subclinical anxiety and migraines. Plan included continuing current antihypertensive and proton pump inhibitor therapy, referring for cognitive behavioral therapy for anxiety management, and maintaining a headache diary for migraine tracking. Follow-up scheduled in 6 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e923027e-e1de-4b3b-b362-6c79d00c09a4', '2025-12-04T23:07:08.026668', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: BP 102/68 mmHg, HR 78 bpm, Temp 98.6°F. Notable for a minor laceration on the left forearm, approximately 2 cm in length, clean and healing well, with no signs of infection. History of eczema noted, currently managed with topical emollients; no flare-ups reported. Recommended continued use of moisturizers and monitoring the laceration for any signs of infection. Advised follow-up if any new symptoms arise or if the laceration does not heal as expected.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e923027e-e1de-4b3b-b362-6c79d00c09a4', '2025-09-16T23:07:08.026668', 'Follow-up Visit', 'Patient presented for follow-up of a minor laceration on the right forearm. On examination, the wound showed signs of healing with no signs of infection; minimal erythema and well-approximated edges were noted. Vitals: BP 110/70 mmHg, HR 88 bpm, Temp 98.6°F. Continued wound care with daily cleaning and application of antibiotic ointment was recommended. The patient''s eczema was stable, with no flare-ups reported. Follow-up in one month or sooner if any issues arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e923027e-e1de-4b3b-b362-6c79d00c09a4', '2025-04-23T23:07:08.026668', 'Emergency Visit', 'Patient presented for evaluation of a minor laceration on the right forearm sustained during a playground incident. Physical examination revealed a 3 cm superficial laceration with minimal bleeding and no signs of infection. Vital signs were stable: BP 108/72 mmHg, HR 88 bpm, temp 98.6°F. The laceration was cleaned thoroughly and closed with adhesive strips. Patient was advised to keep the area clean and dry, and instructed on signs of infection. Follow-up recommended with primary care for eczema management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e923027e-e1de-4b3b-b362-6c79d00c09a4', '2025-02-01T23:07:08.026668', 'Annual Checkup', 'Patient presented for an annual checkup and evaluation of a minor laceration on the left forearm. Vital signs were stable: BP 102/65 mmHg, HR 88 bpm, Temp 98.6°F. The laceration was superficial, approximately 3 cm in length, with no signs of infection or foreign bodies. The patient has a history of eczema, currently well-managed with emollients. Recommended continued wound care with antiseptic ointment and protective dressing. Advised maintaining regular moisturizing routine to prevent eczema exacerbations. Follow-up in one year or sooner if any concerns arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4ef30128-6a89-4d61-a7dd-83027cb97166', '2026-01-27T23:07:16.749091', 'Urgent Care', 'Patient presented for evaluation of acute lower extremity swelling and erythema. Vital signs showed BP 148/92 mmHg, HR 82 bpm, and BMI 32 kg/m². Examination revealed bilateral pitting edema and hyperpigmented patches consistent with exacerbation of stasis dermatitis. Assessment included worsening venous insufficiency and possible cellulitis. Recommended initiation of compression therapy, elevation of legs, and prescribed a course of oral antibiotics. Advised follow-up with primary care for further management of chronic conditions.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4ef30128-6a89-4d61-a7dd-83027cb97166', '2025-08-20T23:07:16.749091', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 138/85 mmHg, HR 78 bpm, and BMI 32.4 kg/m². The patient reported stable mood with current antidepressant therapy and no new dermatological issues. Recommended continuation of current medication regimen for hypertension, hyperlipidemia, and diabetes management, with a follow-up lipid panel and HbA1c in three months. Advised on dietary modifications and regular physical activity to address obesity and improve overall cardiovascular health.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4ef30128-6a89-4d61-a7dd-83027cb97166', '2025-05-25T23:07:16.749091', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were as follows: BP 140/90 mmHg, HR 78 bpm, BMI 32 kg/m². Patient reported stable mood but noted occasional fatigue. Lipid panel indicated LDL levels remain elevated despite current statin therapy. Continued management of hyperlipidemia with atorvastatin was advised, and dietary modifications were recommended. Blood glucose levels were within target range; diabetes management with metformin to be continued. Advised monitoring of stasis dermatitis and maintaining compression therapy for symptom control. Follow-up in 6 months for routine monitoring and assessment of management plans.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ccf5383c-eceb-45f3-a2ee-c55a7ee3b5f4', '2026-01-21T23:07:23.907777', 'Follow-up Visit', 'Patient presented for a follow-up visit concerning sleep apnea management. Blood pressure measured at 138/85 mmHg, heart rate 78 bpm, and SpO2 at 96% on room air. Patient reported occasional daytime fatigue and mild increased anxiety but denied any new respiratory symptoms. Advised continuation of CPAP therapy, adjustment of antihypertensive medication, and recommended behavioral therapy for anxiety management. Scheduled follow-up in 3 months to reassess symptoms and medication efficacy.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ccf5383c-eceb-45f3-a2ee-c55a7ee3b5f4', '2025-10-17T23:07:23.907777', 'Consultation', 'Patient presented for consultation regarding management of sleep apnea and associated symptoms. Blood pressure was 138/86 mmHg, heart rate was 78 bpm, and BMI was 32 kg/m². Noted increased daytime fatigue and difficulty concentrating, potentially exacerbated by suboptimal CPAP adherence. Recommended reinforcing CPAP use and considering a follow-up sleep study to reassess titration needs. Discussed potential benefits of weight management, ongoing monitoring of blood pressure, and continued management of GERD and hyperlipidemia. Advised follow-up in 3 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ccf5383c-eceb-45f3-a2ee-c55a7ee3b5f4', '2025-05-03T23:07:23.907777', 'Emergency Visit', 'Patient presented for acute shortness of breath and chest tightness. Vitals: BP 150/95 mmHg, HR 98 bpm, SpO2 89% on room air. Physical examination revealed wheezing on auscultation and mild accessory muscle use. Assessment: Acute asthma exacerbation, likely triggered by GERD. Plan: Administered nebulized albuterol and initiated supplemental oxygen therapy. Recommended follow-up with primary care for further management of asthma and to evaluate sleep apnea treatment adherence.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('438b1c3f-f404-43e9-be56-26985a487234', '2025-10-06T23:07:30.534929', 'Follow-up Visit', 'Patient presented for a follow-up visit for asthma management. Vital signs were stable: HR 88 bpm, RR 20 breaths/min, SpO2 98% on room air. Caregiver reported occasional coughing and wheezing, particularly at night, but noted improvement with current inhaler regimen. Lung auscultation revealed mild expiratory wheezing. Assessment: Asthma, well-controlled with mild nocturnal symptoms. Plan: Continue current asthma action plan, refill albuterol inhaler, and monitor for any changes in symptoms. Recommended use of a humidifier in the bedroom and scheduled a follow-up in three months.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('438b1c3f-f404-43e9-be56-26985a487234', '2025-06-09T23:07:30.534929', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals: BP 90/60 mmHg, HR 88 bpm, RR 20/min, SpO2 98% on room air. Physical examination revealed clear lung fields with no wheezing, and mild eczema present on the antecubital fossae. Asthma is well-controlled; patient uses albuterol inhaler as needed, with no recent exacerbations. Recommended continuation of current asthma action plan and advised on moisturizing regimen for eczema. Follow-up in one year unless symptoms change.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('aee8bea6-0b0c-4fa0-b9e7-dbe89a1093be', '2025-09-27T23:07:34.772301', 'Emergency Visit', 'Patient presented for acute shortness of breath and chest pain. Vital signs showed BP 160/95 mmHg, HR 110 bpm, RR 22 breaths/min, SpO2 90% on room air. Physical examination revealed bilateral lower extremity edema and jugular venous distension. Assessment indicated possible congestive heart failure exacerbation. Recommended immediate diuresis with IV furosemide and cardiology consultation for further evaluation and management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('aee8bea6-0b0c-4fa0-b9e7-dbe89a1093be', '2025-08-06T23:07:34.772301', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding diabetes management and obesity. Blood pressure was 142/88 mmHg, heart rate was 78 bpm, and BMI was recorded at 32.2 kg/m². The patient reported improved dietary habits but noted occasional episodes of dizziness. Assessment revealed suboptimal glycemic control with an HbA1c of 7.8%. Recommended adjustments to the current medication regimen, increased physical activity, and referral to a dietitian for further nutritional guidance. Follow-up in 3 months to reassess diabetes management and weight loss progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('aee8bea6-0b0c-4fa0-b9e7-dbe89a1093be', '2025-06-11T23:07:34.772301', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding obesity and diabetes management. Vitals were as follows: BP 142/88 mmHg, HR 78 bpm, weight 245 lbs, BMI 34.5 kg/m². The patient reported stable blood glucose levels but expressed difficulty with weight loss despite dietary modifications. Advised continuation of current diabetic medications and referred to a nutritionist for further dietary guidance, and encouraged increased physical activity. Follow-up scheduled in 3 months for reassessment.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('aee8bea6-0b0c-4fa0-b9e7-dbe89a1093be', '2025-03-06T23:07:34.772301', 'Emergency Visit', 'Patient presented for acute shortness of breath and chest pain. On examination, blood pressure was 150/95 mmHg, heart rate 110 bpm, and SpO2 92% on room air. The patient, with a history of diabetes and obesity, was assessed for potential acute coronary syndrome. Recommended immediate ECG and cardiac enzyme testing, initiated supplemental oxygen, and advised cardiology consultation for further evaluation and management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('9e091d57-a24f-4bee-84c3-e7b788b780f2', '2026-02-07T23:07:41.429368', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding hay fever management and hypertension monitoring. Blood pressure was 128/82 mmHg, and heart rate was 76 bpm. Patient reported persistent nasal congestion and sneezing despite current antihistamine regimen. Advised to continue with the current antihypertensive medication and recommended adding a nasal corticosteroid spray for better symptom control. Follow-up in 3 months to reassess symptoms and blood pressure management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('9e091d57-a24f-4bee-84c3-e7b788b780f2', '2025-09-14T23:07:41.429368', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were as follows: BP 128/82 mmHg, HR 76 bpm, Temp 98.6°F. Patient reported experiencing seasonal allergic rhinitis symptoms consistent with hay fever, including nasal congestion and sneezing. Hypertension was well-controlled with current medication regimen. Recommended continuation of antihypertensive therapy and advised use of over-the-counter antihistamines for allergy management. Follow-up in one year or as needed for acute issues.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('2eda73aa-415c-4b2b-bedb-371be1dcec1a', '2025-10-15T23:07:46.139824', 'Follow-up Visit', 'Patient presented for follow-up of anxiety and management of related conditions. Vital signs were stable: BP 118/76 mmHg, HR 72 bpm. Patient reported improved mood and decreased anxiety symptoms since starting cognitive behavioral therapy and adjusting medication dosage. Recommended continuation of current treatment plan, with follow-up in 3 months to reassess mental health status and evaluate sleep patterns.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('2eda73aa-415c-4b2b-bedb-371be1dcec1a', '2025-10-06T23:07:46.139824', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 118/76 mmHg and heart rate was 72 bpm. The patient reported increased anxiety levels over the past few months, with occasional episodes of insomnia, but denied any depressive symptoms currently. Seasonal allergies are well-controlled with current antihistamine regimen. Recommended continuation of current SSRI for anxiety, with a follow-up in three months to reassess mental health status and adjust treatment if necessary. Advised routine blood work to monitor any potential side effects of long-term medication use.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('2eda73aa-415c-4b2b-bedb-371be1dcec1a', '2025-06-15T23:07:46.139824', 'Consultation', 'Patient presented for a consultation regarding management of anxiety. Vitals were stable: BP 118/76 mmHg, HR 72 bpm. The patient reported increased anxiety symptoms, particularly restlessness and difficulty concentrating, over the past month. Reviewed current treatment plan; recommended continuation of SSRIs with a potential dose adjustment. Advised cognitive behavioral therapy to address anxiety and insomnia. Follow-up scheduled in 4 weeks to assess treatment efficacy.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('55b42556-b906-40fa-b963-c4b9f6552a5f', '2026-01-24T23:07:51.564209', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding a right knee abrasion sustained from a fall one week prior. Physical examination revealed the abrasion to be healing well with minimal erythema and no signs of infection. Vital signs were stable: HR 98 bpm, RR 22 breaths/min, BP 90/60 mmHg. Advised continued use of antibiotic ointment and keeping the area clean and covered. Follow-up recommended if signs of infection develop.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('55b42556-b906-40fa-b963-c4b9f6552a5f', '2025-08-26T23:07:51.564209', 'Urgent Care', 'Patient presented for evaluation of an abrasion on the right knee sustained from a fall at a playground. Vital signs were within normal limits for age: HR 100 bpm, RR 22 breaths/min, T 98.6°F. Examination revealed a superficial abrasion approximately 2 cm in diameter with mild erythema and no signs of infection. Wound was cleansed with saline and covered with a sterile dressing. Recommended keeping the area clean and dry, changing the dressing daily, and monitoring for any signs of infection such as increased redness, swelling, or discharge. Advised follow-up with primary care provider if symptoms do not improve.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('55b42556-b906-40fa-b963-c4b9f6552a5f', '2025-03-26T23:07:51.564209', 'Annual Checkup', 'Patient presented for annual checkup. Vital signs were within normal limits: HR 100 bpm, RR 22 breaths/min, temperature 98.6°F. Noted a minor abrasion on the right knee, healing well, with no signs of infection. Recommended keeping the area clean and covered, and advised on a balanced diet, regular physical activity, and up-to-date vaccinations. No additional concerns were noted during the visit.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4e88d0ee-bffd-4578-b88e-fb242d5ff9a4', '2026-01-16T23:07:57.121816', 'Follow-up Visit', 'Patient presented for a follow-up visit for asthma management. Blood pressure was 138/85 mmHg, heart rate was 78 bpm, and respiratory rate was 18 breaths per minute. He reported occasional wheezing and dyspnea, especially during physical exertion, but no recent exacerbations. Continued current asthma management plan with inhaled corticosteroid and advised on weight loss strategies to aid asthma control. Follow-up in 3 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4e88d0ee-bffd-4578-b88e-fb242d5ff9a4', '2025-07-02T23:07:57.121816', 'Follow-up Visit', 'Patient presented for follow-up of asthma and management of comorbid conditions. Blood pressure was 135/85 mmHg and heart rate was 78 bpm. The patient reported mild wheezing and shortness of breath, particularly at night, but denied any recent asthma exacerbations. Assessment indicated well-controlled asthma with current inhaler regimen; however, recommended maintaining regular use of a peak flow meter and scheduling a pulmonary function test to monitor lung function. Advised continuation of antihypertensive and statin therapy, with emphasis on dietary modifications and increased physical activity for weight management. Scheduled a follow-up appointment in three months.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4e88d0ee-bffd-4578-b88e-fb242d5ff9a4', '2025-06-06T23:07:57.121816', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 138/85 mmHg, HR 76 bpm, Respirations 18/min, and SpO2 97% on room air. The patient reported stable asthma symptoms with occasional use of an inhaler and no recent exacerbations. Continued management of hyperlipidemia and hypertension advised; recommended lifestyle modifications including diet and exercise to address obesity. Follow-up in six months for routine monitoring and reassessment of asthma control.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('3244f352-12c9-4f48-b50f-95ea7c069494', '2025-10-24T23:08:04.160294', 'Follow-up Visit', 'Patient presented for follow-up of upper respiratory infection. Reports persistent cough and mild dyspnea, but denies fever or chest pain. Vital signs: BP 138/86 mmHg, HR 82 bpm, Temp 98.6°F, SpO2 95% on room air. Examination revealed mild wheezing on auscultation. Assessment: Upper respiratory infection with underlying asthma exacerbation. Plan: Continued use of albuterol inhaler as needed, advised to increase hydration, and follow-up in one week if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('3244f352-12c9-4f48-b50f-95ea7c069494', '2025-09-08T23:08:04.160294', 'Annual Checkup', 'Patient presented for an annual checkup, reporting symptoms consistent with an upper respiratory infection, including nasal congestion and mild cough. Vitals were as follows: BP 138/86 mmHg, HR 78 bpm, SpO2 96% on room air. Examination revealed mild wheezing on auscultation, likely exacerbated by current infection and underlying asthma. Recommended continuation of inhaler use as needed, increase in fluid intake, and rest. Advised follow-up if symptoms persist beyond two weeks or worsen. Discussed weight management strategies given history of obesity.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('3244f352-12c9-4f48-b50f-95ea7c069494', '2025-03-18T23:08:04.160294', 'Annual Checkup', 'Patient presented for an annual checkup and reported symptoms consistent with an upper respiratory infection, including cough and nasal congestion. Vitals were as follows: BP 138/85 mmHg, HR 78 bpm, RR 18 breaths/min, and temperature 99.1°F. Lung auscultation revealed mild wheezing, consistent with asthma exacerbation. Advised continuation of inhaler as needed, and recommended hydration and rest for URI, with follow-up if symptoms persist beyond 10 days. Discussed weight management strategies given patient''s obesity. Cataracts noted as stable on ophthalmologic review last year.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('3cdee7ec-48c3-4871-b399-9decafbe4354', '2026-02-04T23:08:10.919170', 'Follow-up Visit', 'Patient presented for a routine follow-up visit. Vital signs were within normal limits: BP 90/60 mmHg, HR 100 bpm, Temp 98.6°F, RR 20 breaths per minute. Physical examination revealed a well-nourished, active child with normal growth parameters for age. Assessment indicated no acute concerns. Recommended continuation of a balanced diet, regular physical activity, and scheduled immunizations. Follow-up visit in one year unless concerns arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('3cdee7ec-48c3-4871-b399-9decafbe4354', '2025-07-23T23:08:10.919170', 'Urgent Care', 'Patient presented for an urgent care visit due to a mild fever and cough lasting 2 days. Vital signs were stable with a temperature of 100.4°F, heart rate 110 bpm, and respiratory rate 24 breaths per minute. Lungs were clear to auscultation bilaterally, and no signs of distress were noted. Assessment indicated a likely viral upper respiratory infection. Recommended supportive care, including adequate hydration and antipyretics as needed, and advised follow-up if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('3cdee7ec-48c3-4871-b399-9decafbe4354', '2025-06-12T23:08:10.919170', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were as follows: HR 90 bpm, RR 20 breaths/min, BP 98/60 mmHg, Temp 98.6°F. Physical exam was unremarkable with normal growth and development noted for age. No acute distress observed; patient appeared well-nourished and well-hydrated. Recommended continuation of regular diet and activity, with follow-up in one year unless concerns arise. Updated vaccinations according to schedule.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('3cdee7ec-48c3-4871-b399-9decafbe4354', '2025-05-22T23:08:10.919170', 'Follow-up Visit', 'Patient presented for a routine follow-up visit. Vital signs were within normal limits: HR 90 bpm, BP 90/60 mmHg, Temp 98.6°F, RR 20 breaths/min. Physical examination revealed normal growth and development for age with no acute distress. Recommended continuation of a balanced diet, regular physical activity, and scheduled vaccinations as per pediatric guidelines. Follow-up in one year for annual check-up or sooner if concerns arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c25319c5-71f1-4efb-8983-c8f3d51f1f63', '2025-10-20T23:08:18.395950', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 138/82 mmHg, HR 76 bpm. Physical examination was unremarkable with no acute distress noted. Lipid panel results indicated elevated LDL cholesterol. Continued management of hyperlipidemia, diabetes, and hypertension was advised, with an emphasis on dietary modifications and adherence to prescribed medications. Follow-up labs were ordered to monitor cholesterol and glucose levels.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c25319c5-71f1-4efb-8983-c8f3d51f1f63', '2025-08-18T23:08:18.395950', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs: BP 142/88 mmHg, HR 78 bpm, BMI 29. Physical examination revealed no acute distress, clear lung sounds, and regular heart rhythm. Lipid panel results indicated LDL cholesterol levels above target range. Recommended continuation of statin therapy, lifestyle modifications including diet and exercise, and follow-up in 6 months to reassess lipid levels and blood pressure management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c25319c5-71f1-4efb-8983-c8f3d51f1f63', '2025-04-30T23:08:18.395950', 'Urgent Care', 'Patient presented for evaluation of acute chest pain experienced over the past 24 hours. On examination, blood pressure was 142/88 mmHg, heart rate was 88 bpm, and no acute distress was noted. ECG showed no evidence of acute ischemia; however, further investigation was deemed necessary given the patient''s history of hypertension and diabetes. Recommended immediate cardiology referral for further evaluation and advised continuation of current antihypertensive and lipid-lowering medications.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c25319c5-71f1-4efb-8983-c8f3d51f1f63', '2025-02-05T23:08:18.395950', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 142/88 mmHg, heart rate was 76 bpm, and BMI was noted to be 28.5 kg/m². No acute symptoms were reported. Labs showed elevated LDL cholesterol levels. Recommended continuation of atorvastatin and metformin, and advised dietary modifications and regular exercise to manage hyperlipidemia and control glucose levels. Follow-up in 6 months to reassess lipid profile and blood pressure management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('17a4a0af-23f3-48a8-84c4-a2861c35f836', '2026-01-24T23:08:28.011215', 'Follow-up Visit', 'Patient presented for a follow-up visit to manage hypertension and review current treatment efficacy. Blood pressure was recorded at 142/88 mmHg and heart rate at 76 bpm. The patient reported mild joint stiffness attributed to osteoarthritis but denied any recent episodes of GERD or anemia-related symptoms. Assessment indicated stable hypertension and controlled hyperlipidemia. Recommended continuing current antihypertensive and lipid-lowering medications, reinforcing dietary modifications, and scheduling a follow-up in three months to monitor progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('17a4a0af-23f3-48a8-84c4-a2861c35f836', '2025-06-08T23:08:28.011215', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals recorded: BP 140/85, HR 78 bpm, and BMI 27.2. Examination revealed mild joint stiffness associated with osteoarthritis and controlled symptoms of GERD. Hypertension and hyperlipidemia appeared well-managed with current medication regimen. Recommended continuation of current antihypertensive and statin therapy, advised dietary modifications for hyperlipidemia, and suggested routine follow-up for anemia management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('17a4a0af-23f3-48a8-84c4-a2861c35f836', '2025-05-30T23:08:28.011215', 'Follow-up Visit', 'Patient presented for routine follow-up of hypertension and management of chronic conditions. Blood pressure was elevated at 148/92 mmHg, heart rate was 76 bpm, and no acute distress noted. Continued symptoms of joint pain were reported, consistent with osteoarthritis, and occasional heartburn was mentioned, indicating ongoing GERD. Recommended adjustment of antihypertensive medication and advised continuation of current lipid-lowering and anemia treatment. Emphasized importance of dietary modifications and adherence to medication regimen for optimal blood pressure control. Follow-up in 3 months for reassessment.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5472ecaf-3f91-4e44-a217-89b25a8f7d45', '2025-10-17T23:08:35.497031', 'Follow-up Visit', 'Patient presented for follow-up evaluation of low back pain. Vitals were as follows: BP 128/82 mmHg, HR 72 bpm. The patient reported persistent dull ache in the lumbar region, exacerbated by prolonged sitting. Physical examination revealed mild tenderness over the paraspinal muscles with no radicular symptoms. Assessment indicated ongoing mechanical back pain likely related to previous strain and obesity. Recommended continuation of physical therapy, weight management, and initiated a trial of NSAIDs for pain relief. Follow-up in 4 weeks to assess progress and adjust treatment as necessary.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5472ecaf-3f91-4e44-a217-89b25a8f7d45', '2025-10-16T23:08:35.497031', 'Annual Checkup', 'Patient presented for an annual checkup with complaints of persistent low back pain. Vitals were as follows: BP 128/82 mmHg, HR 76 bpm, BMI 31.2. Physical examination revealed tenderness in the lumbar region with limited range of motion. Assessment indicated exacerbation of previous back strain likely due to obesity. Recommended continuation of physical therapy, weight management strategies, and prescribed NSAIDs for pain management. Follow-up in three months to monitor progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5472ecaf-3f91-4e44-a217-89b25a8f7d45', '2025-07-11T23:08:35.497031', 'Annual Checkup', 'Patient presented for annual checkup, reporting persistent low back pain exacerbated by prolonged sitting. Vital signs were stable: BP 128/82 mmHg, HR 72 bpm, BMI 32 kg/m² indicating obesity. Physical examination revealed tenderness in the lumbar region with no neurological deficits noted. Assessment included chronic low back pain likely related to obesity and previous back strain. Recommended initiation of a weight management program, physical therapy referral, and NSAIDs for pain management. Advised follow-up in three months to assess progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('1e4000ed-d86c-4e3c-b4c2-085a0d5bef0d', '2026-02-20T23:08:40.410649', 'Annual Checkup', 'Patient presented for an annual checkup with ongoing management for depression. Vital signs were recorded as BP 118/76 mmHg, HR 72 bpm, and BMI 24.3 kg/m². The patient reported improved mood stability and reduced anxiety episodes since starting current SSRI therapy. Recommended continuation of current medication regimen, and suggested follow-up in six months to monitor progress and adjust treatment as necessary.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('1e4000ed-d86c-4e3c-b4c2-085a0d5bef0d', '2025-07-18T23:08:40.410649', 'Urgent Care', 'Patient presented for acute exacerbation of depressive symptoms, reporting increased feelings of hopelessness and tearfulness over the past two weeks. Vital signs were stable: BP 120/80 mmHg, HR 72 bpm. Physical exam was unremarkable. Assessment included major depressive disorder with a history of anxiety. Recommended adjustment of current SSRI medication and referral to a mental health specialist for further evaluation and therapy options. Follow-up scheduled in two weeks to assess response to medication changes.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('1e4000ed-d86c-4e3c-b4c2-085a0d5bef0d', '2025-05-31T23:08:40.410649', 'Urgent Care', 'Patient presented for worsening depressive symptoms, including increased fatigue and difficulty concentrating over the past two weeks. Vital signs were within normal limits: BP 118/75 mmHg, HR 72 bpm. Mental status exam revealed a flat affect and limited eye contact. Assessment: Exacerbation of depression. Plan: Adjusted fluoxetine dosage to 40 mg daily, advised follow-up with primary care physician in two weeks, and provided resources for cognitive behavioral therapy.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('235ab57e-2471-466e-9c66-c70f29562f05', '2025-12-24T23:08:45.633358', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding food allergies. Vital signs were within normal limits: BP 110/70, HR 78, Temp 98.6°F. No new allergic reactions reported since last visit; patient continues to adhere to dietary restrictions. Recommended continuation of avoidance of known allergens and reviewed emergency action plan for accidental exposure. Follow-up in 6 months or sooner if symptoms recur.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('235ab57e-2471-466e-9c66-c70f29562f05', '2025-09-07T23:08:45.633358', 'Consultation', 'Patient presented for consultation regarding management of known food allergies. Physical examination revealed no acute distress, skin was clear, and respiratory assessment was unremarkable. Vital signs: BP 110/70, HR 80, RR 18, Temp 98.6°F. Assessment confirmed stable condition with well-controlled symptoms through dietary avoidance. Recommended continuation of current allergen avoidance strategy and prescribed an epinephrine auto-injector for emergency use. Follow-up in six months unless symptoms exacerbate.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('3f2eab7d-3e48-4b62-a30e-3bec59964edd', '2026-01-17T23:08:49.362218', 'Follow-up Visit', 'Patient presented for follow-up evaluation of a contusion sustained to the left forearm. Physical examination revealed mild ecchymosis with no significant swelling or tenderness upon palpation. Vital signs were stable with BP 100/60 mmHg, HR 88 bpm, and temperature 98.6°F. Recommended continued application of cold compress and advised on gentle range of motion exercises. Follow-up in two weeks to reassess healing progress. Patient''s allergic rhinitis remains well-controlled with current management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('3f2eab7d-3e48-4b62-a30e-3bec59964edd', '2025-06-25T23:08:49.362218', 'Annual Checkup', 'Patient presented for her annual checkup with a noted contusion on the right forearm, reportedly from a fall while playing. Vitals were within normal limits: BP 100/60 mmHg, HR 88 bpm. Physical examination was otherwise unremarkable, with no signs of infection or additional injuries. Assessment confirmed the contusion to be minor; ice and rest were recommended. Continued management of allergic rhinitis with antihistamines was advised. Follow-up is scheduled for one year unless symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('3f2eab7d-3e48-4b62-a30e-3bec59964edd', '2025-02-15T23:08:49.362218', 'Follow-up Visit', 'Patient presented for follow-up regarding contusion on the right forearm sustained during a fall. Physical examination revealed mild swelling with resolving ecchymosis; no tenderness or restricted range of motion noted. Past history of allergic rhinitis was noted but not relevant to the current condition. Recommended continued application of cold compresses as needed and advised on monitoring for any signs of infection. Vitals were stable: BP 100/60 mmHg, HR 88 bpm.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('3f2eab7d-3e48-4b62-a30e-3bec59964edd', '2025-01-29T23:08:49.362218', 'Follow-up Visit', 'Patient presented for follow-up on contusion sustained to the right knee. Physical examination revealed mild swelling with no significant tenderness or restricted range of motion; the skin over the area was intact. Vitals were stable: BP 100/60 mmHg, HR 85 bpm, afebrile. Assessment indicated healing contusion with no complications. Recommended continued application of cold compresses and advised over-the-counter analgesics for pain management as needed. Follow-up in two weeks if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('7e3748b6-f4ba-4d26-9b0f-439a005d12c6', '2025-09-26T23:08:56.385383', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were as follows: BP 142/88 mmHg, HR 78 bpm. Patient reported increased knee pain attributed to osteoarthritis but denied any changes in asthma control or cancer-related symptoms. Assessment revealed stable hyperlipidemia and hypertension. Advised continuation of current medications, recommended weight management strategies, and suggested follow-up with a dietitian to address obesity. Ordered routine blood work to monitor lipid levels and scheduled imaging to further evaluate joint health.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
