INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('7e3748b6-f4ba-4d26-9b0f-439a005d12c6', '2025-05-31T23:08:56.385383', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals: BP 142/88 mmHg, HR 78 bpm, BMI 32.1 kg/m². Physical examination revealed crepitus in bilateral knees, consistent with osteoarthritis, and wheezing upon auscultation, likely related to asthma. Lipid panel showed elevated LDL levels. Recommended continuation of antihypertensive and statin therapy, increased physical activity to support weight management, and follow-up with pulmonology for asthma management. Advised routine cancer screening as per guidelines.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('7e3748b6-f4ba-4d26-9b0f-439a005d12c6', '2025-01-29T23:08:56.385383', 'Emergency Visit', 'Patient presented for acute shortness of breath and chest tightness. Vitals on arrival: BP 142/88 mmHg, HR 92 bpm, SpO2 90% on room air. Physical examination revealed wheezing on auscultation and mild respiratory distress. Assessment indicated an exacerbation of asthma, possibly triggered by upper respiratory infection. Administered albuterol nebulizer treatment with improvement in symptoms. Patient advised on the use of inhalers, and oral corticosteroids were prescribed. Recommended follow-up with primary care physician and pulmonologist for asthma management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('7e3748b6-f4ba-4d26-9b0f-439a005d12c6', '2024-12-26T23:08:56.385383', 'Emergency Visit', 'Patient presented for acute shortness of breath and chest tightness. Vital signs showed BP 160/95 mmHg, HR 110 bpm, RR 24 breaths/min, oxygen saturation at 91% on room air. Physical examination revealed wheezing upon auscultation and mild bilateral lower extremity edema. Assessment included acute exacerbation of asthma, likely triggered by recent upper respiratory tract infection. Patient was administered nebulized bronchodilators and systemic corticosteroids with notable improvement in respiratory status. Recommended follow-up with primary care and pulmonary specialist for asthma management and medication review.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b9b9c36c-ee12-431b-abe0-beff19671bc4', '2025-10-03T23:09:04.885324', 'Urgent Care', 'Patient presented for acute onset of chest discomfort and shortness of breath. Vital signs recorded: BP 145/88 mmHg, HR 92 bpm, RR 20 breaths/min, SpO2 96% on room air. Physical exam revealed mild bilateral wheezing and no peripheral edema. Differential diagnosis included cardiac ischemia and exacerbation of GERD; an EKG was performed showing no acute ischemic changes. Recommended immediate referral to cardiology for further evaluation and adjustment of GERD management. Advised patient to avoid heavy meals and maintain head elevation during sleep.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b9b9c36c-ee12-431b-abe0-beff19671bc4', '2025-06-26T23:09:04.885324', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 138/86 mmHg, heart rate 78 bpm, BMI 28.2. Patient reported occasional knee pain attributed to osteoarthritis but otherwise stable. Lipid levels reviewed; LDL remains elevated at 145 mg/dL. Recommended continuation of current statin therapy with dietary modifications to manage hyperlipidemia. Advised routine ophthalmology follow-up for cataract monitoring and gastrointestinal management for GERD symptoms. Scheduled follow-up in 6 months or sooner if symptoms change.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b9b9c36c-ee12-431b-abe0-beff19671bc4', '2025-05-16T23:09:04.885324', 'Urgent Care', 'Patient presented for acute onset of chest discomfort and shortness of breath. Vital signs were as follows: BP 150/92 mmHg, HR 88 bpm, RR 20 breaths per minute, SpO2 96% on room air. Physical examination revealed mild wheezing on auscultation. EKG showed no acute ischemic changes. The assessment was likely GERD exacerbation and possible musculoskeletal chest pain. Recommended continuation of proton pump inhibitor therapy, lifestyle modification including dietary adjustments, and advised follow-up with primary care for further lipid management. Reassured patient and instructed to return if symptoms worsen or new symptoms develop.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b9b9c36c-ee12-431b-abe0-beff19671bc4', '2025-05-13T23:09:04.885324', 'Emergency Visit', 'Patient presented for acute onset of chest pain radiating to the left arm, accompanied by shortness of breath and diaphoresis. Vital signs upon arrival: BP 148/92 mmHg, HR 98 bpm, RR 22 breaths/min, SpO2 95% on room air. Physical examination revealed no jugular venous distention or peripheral edema; however, an ECG showed ST elevation in leads II, III, and aVF. Assessment indicated a likely inferior wall myocardial infarction. Immediate treatment with aspirin and nitroglycerin was administered, and the patient was transferred to the cardiology unit for further management and possible percutaneous coronary intervention.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('2f4b2e29-b063-461d-b276-c670b95aba97', '2025-10-16T23:09:14.409321', 'Annual Checkup', 'Patient presented for an annual checkup. Physical examination revealed a BMI of 32, classifying the patient as obese. Blood pressure was measured at 128/82 mmHg, and heart rate at 76 bpm. The patient reported no recent asthma exacerbations and no other acute symptoms. Recommended lifestyle modifications include a balanced diet and increased physical activity. Follow-up with a nutritionist was advised, and routine asthma management with inhaler use was reinforced.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('2f4b2e29-b063-461d-b276-c670b95aba97', '2025-09-10T23:09:14.409321', 'Consultation', 'Patient presented for consultation regarding obesity management. Vitals: BP 120/78 mmHg, HR 88 bpm, weight 240 lbs, BMI 36.5. Patient reported occasional shortness of breath, particularly during physical activity, likely exacerbated by both asthma and excess weight. Recommended a structured weight loss program including dietary modifications and initiation of a moderate exercise regimen. Advised follow-up with a dietitian and scheduled a review in 3 months to monitor progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('0b2e94a0-eff4-4b2b-aa1a-d21dc913937f', '2025-10-25T23:09:18.434546', 'Consultation', 'Patient presented for consultation regarding worsening symptoms of cellulitis on the left lower extremity. Physical examination revealed erythema, warmth, and mild edema extending from the ankle to mid-calf. Vital signs were stable with BP 122/78 mmHg, HR 76 bpm, Temp 98.6°F. Recommended continuation of current antibiotic regimen (cephalexin 500 mg q6h) and advised elevation of the affected limb. Patient was also counseled on signs of potential complications and instructed to follow up in one week or sooner if symptoms escalate.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('0b2e94a0-eff4-4b2b-aa1a-d21dc913937f', '2025-07-23T23:09:18.434546', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding cellulitis. On examination, erythema and swelling at the affected site on the left lower extremity showed significant improvement. Vital signs were stable: BP 122/78 mmHg, HR 76 bpm, afebrile. Recommended continuation of current antibiotic regimen for another 5 days and advised elevation of the leg to reduce swelling. Discussed management strategies for anxiety and IBS to address overall well-being. Follow-up in one week or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('cad4e6e6-bdc7-4914-84fc-1a0e6b24ec78', '2025-12-04T23:09:21.883651', 'Follow-up Visit', 'Patient presented for follow-up on allergic rhinitis management. Vital signs were stable, with BP 118/76 mmHg and HR 72 bpm. Patient reported persistent nasal congestion and sneezing, particularly worsening during spring and fall, but noted improvement with regular use of antihistamines. Recommended continuation of current antihistamine regimen and advised initiation of a saline nasal spray for symptomatic relief. Discussed the importance of avoiding known allergens and considering environmental control measures. GERD remains stable with ongoing PPI therapy. Follow-up in 6 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('cad4e6e6-bdc7-4914-84fc-1a0e6b24ec78', '2025-08-21T23:09:21.883651', 'Follow-up Visit', 'Patient presented for follow-up on hay fever symptoms. Vitals were stable: BP 118/76 mmHg, HR 74 bpm. Patient reported persistent rhinorrhea and nasal congestion despite current antihistamine therapy. Advised continuation of antihistamine and added a nasal corticosteroid spray for symptom control. Recommended follow-up in 4 weeks to assess response to treatment.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('d4dff81d-0ce3-4fdb-ba8f-25e2188c2fea', '2025-10-25T23:09:25.261319', 'Consultation', 'Patient presented for consultation regarding management of gallstones. Vital signs were stable: BP 138/82 mmHg, HR 74 bpm, RR 18 breaths/min, SpO2 97% on room air. Patient reported intermittent right upper quadrant abdominal pain, exacerbated by fatty meals. Recommended dietary modifications to reduce fatty food intake and consider elective cholecystectomy given symptom severity and impact on quality of life. Advised continuation of current medications for diabetes, hypertension, and asthma management, and scheduled follow-up in one month to reassess symptoms and discuss surgical options.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('d4dff81d-0ce3-4fdb-ba8f-25e2188c2fea', '2025-07-05T23:09:25.261319', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals: BP 142/88 mmHg, HR 76 bpm, weight 198 lbs, BMI 31.2. Patient reported occasional right upper quadrant pain consistent with gallstones, with no new exacerbations of asthma or joint pain. Diabetes management remains stable with HbA1c at 7.1%. Advised continuation of current medications for hypertension and diabetes, and recommended dietary modifications for weight management. Referred for an abdominal ultrasound to evaluate gallstones further. Follow-up in 6 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('d4dff81d-0ce3-4fdb-ba8f-25e2188c2fea', '2025-06-08T23:09:25.261319', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were recorded as follows: BP 142/88 mmHg, HR 78 bpm, RR 18 breaths/min, and BMI 32.1 kg/m². Patient reported intermittent right upper quadrant abdominal pain consistent with known gallstones, but no acute distress was noted. Diabetes and hypertension remain well-managed with current medications; however, HbA1c was 7.2%, indicating a need for tighter glucose control. Recommended continuation of current antihypertensive regimen, adjustment of diabetic medications, and a referral to a dietitian for weight management. Advised monitoring of gallstone symptoms and potential surgical consultation if symptoms worsen. Follow-up in 6 months or sooner if new symptoms arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('d4dff81d-0ce3-4fdb-ba8f-25e2188c2fea', '2025-03-12T23:09:25.261319', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 142/88 mmHg, heart rate 78 bpm, and BMI was 32.1 kg/m². Complained of intermittent right upper quadrant pain, likely related to known gallstones. Diabetes and hypertension were well-managed with current medications; however, advised on dietary modifications to aid in weight management and reduce gallstone symptoms. Recommended follow-up with gastroenterology for further evaluation of gallstones and possible surgical consultation. Continued current asthma and osteoarthritis management plans; reviewed inhaler technique and pain management strategies.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('d88e1a4d-4556-4f45-9c48-f217ad7a051f', '2025-12-07T23:09:32.840486', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 145/92 mmHg, and heart rate was 78 bpm. The patient reported manageable joint pain related to osteoarthritis, with no new symptoms. Assessment revealed poorly controlled hypertension; advised dietary modifications, increased physical activity, and adherence to antihypertensive medication regimen. Follow-up scheduled in 3 months to re-evaluate blood pressure management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('d88e1a4d-4556-4f45-9c48-f217ad7a051f', '2025-08-02T23:09:32.840486', 'Emergency Visit', 'Patient presented for acute onset chest pain radiating to the left arm, accompanied by shortness of breath and diaphoresis. Blood pressure was elevated at 160/98 mmHg, heart rate was 102 bpm, and oxygen saturation was 95% on room air. ECG showed signs suggestive of myocardial ischemia. Patient was assessed for possible acute coronary syndrome and was urgently referred to cardiology for further evaluation and management. Recommended continuation of antihypertensive medication and advised weight management for obesity, along with follow-up for osteoarthritis management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('db059ea6-cb42-4752-b8cb-9dd48c508972', '2025-12-25T23:09:36.222699', 'Annual Checkup', 'Patient presented for annual checkup. Blood pressure was 138/85 mmHg, heart rate was 78 bpm, and BMI was 29.2 kg/m². She reported intermittent right upper quadrant pain consistent with gallstone symptoms but denied any recent acute episodes. Assessment included stable chronic conditions of hyperlipidemia, diabetes, and hypertension, with no new findings. Recommended continuation of current medication regimen, dietary modifications to manage gallstones, and scheduled follow-up ultrasound to monitor gallbladder status.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('db059ea6-cb42-4752-b8cb-9dd48c508972', '2025-07-26T23:09:36.222699', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals: BP 138/85 mmHg, HR 78 bpm, BMI 29.6 kg/m². Physical examination revealed mild tenderness in the right upper quadrant, consistent with known gallstones, but no acute distress noted. Lipid panel and HbA1c were reviewed; both slightly elevated. Recommended dietary modifications to address hyperlipidemia and discussed potential management options for gallstones, including surgical consultation if symptoms worsen. Follow-up in 6 months advised for ongoing management of chronic conditions.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('db059ea6-cb42-4752-b8cb-9dd48c508972', '2025-05-09T23:09:36.222699', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding gallstones. Vital signs were stable with blood pressure at 130/85 mmHg and heart rate at 78 bpm. The patient reported intermittent upper right abdominal pain but denied nausea or vomiting. Assessment confirmed gallstone-related discomfort without acute cholecystitis. Recommended dietary modifications to manage symptoms and discussed possible surgical consultation for elective cholecystectomy if symptoms persist. Follow-up in 3 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('0b009003-e386-40df-81b5-0a9ab9b2f47a', '2025-12-04T23:09:43.183716', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals recorded: BP 142/88 mmHg, HR 78 bpm, BMI 32.4 kg/m². Physical examination was unremarkable except for continued obesity. Recommended dietary modifications and increased physical activity to address weight management. Continued management of GERD and hyperlipidemia with current medications. Advised regular use of antihistamines for allergic rhinitis. Follow-up in 6 months to monitor progress on lifestyle changes and reassess cardiovascular risk factors.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('0b009003-e386-40df-81b5-0a9ab9b2f47a', '2025-08-08T23:09:43.183716', 'Follow-up Visit', 'Patient presented for a follow-up visit to assess ongoing management of obesity and hyperlipidemia. Vitals recorded as BP: 138/85 mmHg, HR: 78 bpm. Patient reported improved dietary habits but expressed difficulty with consistent exercise due to knee discomfort. Assessment indicated stable GERD symptoms and control of allergic rhinitis with current medications. Recommended continuation of statin therapy, initiation of a low-impact exercise regimen, and follow-up in 3 months for further weight management and lipid profile evaluation.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('0b009003-e386-40df-81b5-0a9ab9b2f47a', '2025-06-10T23:09:43.183716', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 138/86 mmHg, HR 78 bpm, BMI 32.8 kg/m². Patient reported intermittent heartburn, managed with OTC antacids, and occasional nasal congestion. Assessment included obesity, controlled GERD, and stable hyperlipidemia. Recommended continued dietary modifications and regular physical activity for weight management, and follow-up in six months for lipid profile re-evaluation. Reinforced adherence to current GERD and hyperlipidemia management plans.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c7e96b20-58e9-42c3-b2d5-8282a10e1bf1', '2026-02-13T23:09:48.303961', 'Urgent Care', 'Patient presented for acute exacerbation of hay fever symptoms. Vitals were stable: BP 118/76 mmHg, HR 72 bpm, afebrile. Physical examination revealed nasal congestion, watery eyes, and mild erythema of the nasal mucosa. Assessment indicated allergic rhinitis; instructed patient to continue antihistamines and advised starting intranasal corticosteroids. Follow-up recommended if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c7e96b20-58e9-42c3-b2d5-8282a10e1bf1', '2025-06-20T23:09:48.303961', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 118/76 mmHg, heart rate 72 bpm, temperature 98.6°F. Reports experiencing increased nasal congestion and sneezing consistent with hay fever exacerbation. Advised continuation of current antihistamine regimen and recommended using a saline nasal spray as needed. Follow-up in 12 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('cf036368-6558-465d-b43c-61804e8446e0', '2025-12-26T23:09:51.271959', 'Follow-up Visit', 'Patient presented for a follow-up visit to monitor hypertension and associated conditions. Blood pressure was measured at 138/86 mmHg, heart rate at 78 bpm. Patient reported adherence to prescribed antihypertensive medication but noted occasional headaches. Assessment indicated controlled hypertension, though further lipid management was advised due to persistent hyperlipidemia. Recommended continuation of current medication, dietary modifications focusing on reduced saturated fat intake, and regular physical activity. Follow-up lipid panel scheduled in 3 months.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('cf036368-6558-465d-b43c-61804e8446e0', '2025-07-02T23:09:51.271959', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were noted: BP 138/85 mmHg, HR 78 bpm, weight 198 lbs (BMI 32.9). Patient reported no new symptoms but expressed concerns about maintaining blood pressure control. Assessment revealed stable hypertension and well-managed hyperlipidemia; GERD symptoms remain controlled with current medication. Recommendations included continuation of antihypertensive and statin therapy, dietary modifications for weight management, and follow-up in 6 months for reevaluation.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('9593b7bf-277d-4d2d-9275-20d8dc038b90', '2026-01-10T23:09:54.549885', 'Follow-up Visit', 'Patient presented for follow-up of urinary tract infection. Reports continued dysuria and increased urinary frequency. Vital signs were stable: BP 110/70 mmHg, HR 78 bpm, afebrile. Urinalysis confirmed presence of leukocytes and nitrites. Assessment: Persistent urinary tract infection. Plan: Continue current antibiotic regimen for an additional 5 days, increase fluid intake, and follow up if symptoms persist or worsen. Monitor for signs of depression relapse; advised to continue regular counseling sessions.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('9593b7bf-277d-4d2d-9275-20d8dc038b90', '2025-08-28T23:09:54.549885', 'Annual Checkup', 'Patient presented for an annual checkup with a recent urinary tract infection. Vitals: BP 110/70 mmHg, HR 80 bpm, afebrile. Physical examination revealed mild suprapubic tenderness. Assessment indicated UTI currently being managed with antibiotics; no new symptoms of depression were noted, and previous fracture healed well with no complications. Recommendations included completing the antibiotic course, maintaining adequate hydration, and follow-up in 6 months for depression management evaluation.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ffd2128a-aec6-4c15-a9b0-1e704d94bef7', '2025-10-18T23:09:58.038877', 'Follow-up Visit', 'Patient presented for follow-up on low back pain. Blood pressure was 142/88 mmHg, heart rate 78 bpm. She reported persistent pain with occasional radiation to the left leg, worsened by prolonged sitting. Examination revealed tenderness in the lumbar region with limited range of motion. Continued current medication regimen for hypertension and osteoarthritis; advised on weight management and physical therapy referral for back pain. Recommended follow-up in 6 weeks to reassess symptoms and treatment efficacy.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ffd2128a-aec6-4c15-a9b0-1e704d94bef7', '2025-08-07T23:09:58.038877', 'Consultation', 'Patient presented for consultation regarding persistent low back pain. Blood pressure was 142/88 mmHg, heart rate 76 bpm. Physical examination revealed tenderness in the lumbar region with limited range of motion. Assessment: Chronic low back pain, likely exacerbated by obesity and osteoarthritis. Plan: Recommended physical therapy, weight management, and continuation of current antihypertensive and GERD medications. Advised follow-up in 4 weeks to assess progress and response to treatment.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5fd0bff6-9706-4ec0-a54a-42deccfd0bbc', '2025-10-15T23:10:01.163551', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: BP 128/76 mmHg, HR 72 bpm, respirations 16/min, SpO2 97% on room air. He reported well-controlled asthma with occasional shortness of breath alleviated by albuterol inhaler; no recent exacerbations noted. Physical exam revealed clear lung fields and no wheezing. Continued current asthma management plan, recommended annual flu vaccination, and discussed dietary modifications for hyperlipidemia. Follow-up in 6 months or as needed for any acute symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5fd0bff6-9706-4ec0-a54a-42deccfd0bbc', '2025-09-12T23:10:01.163551', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding asthma management. Vitals were stable: BP 128/82 mmHg, HR 76 bpm, SpO2 98% on room air. Patient reported increased frequency of wheezing and shortness of breath over the past month, particularly at night. Assessment indicated suboptimal asthma control, likely exacerbated by recent seasonal allergies. Plan included adjusting the inhaled corticosteroid dosage and reinforcing adherence to daily use, alongside recommending an allergy evaluation for potential modifications to antihistamine therapy. Follow-up in 4 weeks to reassess symptom control and medication efficacy.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5fd0bff6-9706-4ec0-a54a-42deccfd0bbc', '2025-03-06T23:10:01.163551', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 128/82 mmHg, heart rate 76 bpm, respiratory rate 18 breaths per minute, and oxygen saturation at 97% on room air. Patient reported stable asthma control with occasional use of rescue inhaler and no recent exacerbations. Recommended continuation of current asthma management plan, lipid-lowering therapy, proton pump inhibitor for GERD, and advised seasonal antihistamines for allergic rhinitis. Suggested follow-up with mental health provider for ongoing management of moderate depression. Encouraged lifestyle modifications, including dietary adjustments and regular physical activity for overall health maintenance.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('1308a574-3c08-40b9-b660-47963aa0da3e', '2025-12-20T23:10:08.885825', 'Follow-up Visit', 'Patient presented for follow-up regarding gallstones and management of chronic conditions. Blood pressure was 138/82 mmHg and heart rate was 78 bpm. Patient reported intermittent right upper quadrant pain, without fever or jaundice. Assessment indicated stable gallstones with no acute complications, controlled hypertension, and osteoarthritis managed with NSAIDs. Recommended continuation of current antihypertensive regimen, advised dietary modifications to manage gallstones, and encouraged low-impact exercises for osteoarthritis. Follow-up in 3 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('1308a574-3c08-40b9-b660-47963aa0da3e', '2025-10-23T23:10:08.885825', 'Annual Checkup', 'Patient presented for annual checkup. Blood pressure was 142/88 mmHg, and heart rate was 76 bpm. Patient reported occasional right upper quadrant pain related to known gallstones but denied fever or jaundice. Osteoarthritis symptoms in knees remain stable; patient continues to manage with NSAIDs as needed. Depression is well-controlled on current medication regimen. Recommended dietary modification for gallstones and continued monitoring of hypertension. Follow-up scheduled in six months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('1308a574-3c08-40b9-b660-47963aa0da3e', '2025-05-13T23:10:08.885825', 'Consultation', 'Patient presented for consultation regarding gallstones. Physical examination revealed mild right upper quadrant tenderness, but no jaundice or fever. Blood pressure was 135/85 mmHg and heart rate was 78 bpm. Assessment indicated symptomatic cholelithiasis. Recommended dietary modifications and scheduled for an abdominal ultrasound to evaluate gallstone size and potential surgical intervention. Follow-up in two weeks to discuss imaging results and management options.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('1308a574-3c08-40b9-b660-47963aa0da3e', '2024-12-05T23:10:08.885825', 'Follow-up Visit', 'Patient presented for follow-up on gallstones and management of chronic conditions. Blood pressure was 138/85 mmHg, and heart rate was 76 bpm. The patient reported intermittent upper abdominal pain but denied any fever, jaundice, or changes in bowel habits. Osteoarthritis symptoms were stable with current medication regimen, and depressive symptoms were managed effectively with continued therapy. Recommended dietary modifications to manage gallstones and advised follow-up in three months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('099c5916-f1e0-4e61-a909-40d4d6614609', '2026-01-04T23:10:17.795115', 'Annual Checkup', 'Patient presented for an annual checkup. Physical examination revealed a BMI above the 95th percentile for age, consistent with obesity. Blood pressure was measured at 110/70 mmHg, and heart rate was 90 bpm, both within normal limits for age. No acute symptoms were reported, but history of allergic rhinitis noted. Recommended lifestyle modifications including increased physical activity and a balanced diet to manage obesity. Follow-up in 6 months suggested to monitor progress and reassess weight management strategies.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('099c5916-f1e0-4e61-a909-40d4d6614609', '2025-08-05T23:10:17.795115', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding obesity management. Vital signs were stable: BP 100/60 mmHg, HR 88 bpm. The patient reported experiencing fatigue and difficulty engaging in physical activities. Assessment indicated continued obesity with BMI in the 98th percentile. Recommended dietary modifications, increased physical activity, and scheduled follow-up in three months to monitor progress. Additionally, advised monitoring for any exacerbation of allergic rhinitis symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('099c5916-f1e0-4e61-a909-40d4d6614609', '2025-07-06T23:10:17.795115', 'Urgent Care', 'Patient presented for evaluation of acute wheezing and nasal congestion. Physical examination revealed a BMI in the 98th percentile for age and gender, nasal turbinates were edematous, and expiratory wheezing was noted on auscultation. Assessment indicated exacerbation of allergic rhinitis with reactive airway symptoms, likely triggered by environmental allergens. Plan included initiating a short course of oral corticosteroids, continuation of antihistamines, and referral to a pediatric nutritionist for obesity management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('249337f8-0512-4d39-afab-80d3dee1790e', '2025-10-17T23:10:23.019112', 'Consultation', 'Patient presented for a routine asthma management consultation. Vital signs were stable: BP 130/85 mmHg, HR 78 bpm, and SpO2 98% on room air. The patient reported occasional wheezing and shortness of breath, particularly at night, and recent exacerbation of GERD symptoms. Assessment indicated well-managed asthma with a possible need for adjustment in GERD medication. Recommended continuing current inhaler regimen, advised dietary modifications to address GERD, and scheduled follow-up in three months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('249337f8-0512-4d39-afab-80d3dee1790e', '2025-07-02T23:10:23.019112', 'Emergency Visit', 'Patient presented for acute shortness of breath and wheezing, consistent with an asthma exacerbation. Vital signs: BP 145/88 mmHg, HR 102 bpm, SpO2 90% on room air. Physical examination revealed bilateral wheezing and use of accessory muscles for respiration. Administered nebulized albuterol with improvement in respiratory distress. Recommended continuation of inhaled corticosteroids and follow-up with primary care for asthma management. Advised weight management and dietary modifications for GERD control.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('249337f8-0512-4d39-afab-80d3dee1790e', '2025-05-01T23:10:23.019112', 'Annual Checkup', 'Patient presented for annual checkup. Vitals: BP 130/85 mmHg, HR 76 bpm, SpO2 98% on room air. Lung auscultation revealed mild wheezing; no acute distress noted. Patient reported occasional shortness of breath controlled with current asthma regimen. GERD and eczema are stable with current management. Discussed weight management strategies due to obesity; recommended dietary modifications and increased physical activity. Follow-up in 6 months for asthma management review.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('cea354e8-2b8d-450b-99cb-4ecd79a81bf9', '2025-11-24T23:10:27.799316', 'Consultation', 'Patient presented for consultation regarding acute diverticulitis. Vital signs were stable with BP 138/82 mmHg, HR 78 bpm. Physical examination revealed mild abdominal tenderness in the left lower quadrant without rebound or guarding. Assessment confirmed acute diverticulitis, likely exacerbated by dietary factors. Recommended a clear liquid diet for 48 hours, followed by gradual reintroduction of low-fiber foods, and prescribed antibiotics (ciprofloxacin and metronidazole) for 10 days. Advised follow-up in one week or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('cea354e8-2b8d-450b-99cb-4ecd79a81bf9', '2025-10-02T23:10:27.799316', 'Follow-up Visit', 'Patient presented for follow-up of acute diverticulitis. Vital signs were stable: BP 138/82 mmHg, HR 78 bpm. Patient reported decreased abdominal pain and improved bowel habits. Assessment showed significant improvement with current antibiotic therapy and dietary modifications. Recommended continuation of high-fiber diet and follow-up in four weeks to reassess symptoms and adjust treatment if necessary.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('cea354e8-2b8d-450b-99cb-4ecd79a81bf9', '2025-04-24T23:10:27.799316', 'Annual Checkup', 'Patient presented for an annual checkup with a primary concern of managing acute diverticulitis. Vitals were as follows: BP 150/85 mmHg, HR 78 bpm, BMI 32 kg/m². The patient reported intermittent abdominal pain and bloating, which has been more pronounced over the past week. Physical examination revealed mild tenderness in the left lower quadrant. Continued management of hyperlipidemia, GERD, hypertension, and obesity was discussed, with emphasis on dietary modifications and adherence to prescribed medications. Recommended follow-up in four weeks to reassess diverticulitis symptoms and ensure effective management of chronic conditions.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('7a6ced83-5c8f-4adf-8275-8b1cbbc5070b', '2025-12-15T23:10:33.462829', 'Follow-up Visit', 'Patient presented for follow-up of acute otitis media. Physical examination revealed mild erythema of the left tympanic membrane with reduced mobility upon pneumatic otoscopy. Patient reported decreased otalgia and improved hearing. Assessment: resolving acute otitis media. Plan: continue amoxicillin as prescribed for the remaining course, advise on nasal saline irrigation for congestion related to hay fever, and monitor asthma symptoms; follow-up in two weeks or sooner if symptoms worsen. Vitals were stable: HR 92 bpm, BP 100/65 mmHg, Temp 98.6°F.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('7a6ced83-5c8f-4adf-8275-8b1cbbc5070b', '2025-06-06T23:10:33.462829', 'Annual Checkup', 'Patient presented for annual checkup with a history of acute otitis media, hay fever, and asthma. Vitals were stable: BP 100/65 mmHg, HR 88 bpm, RR 18/min, temperature 98.6°F. Examination revealed mild erythema and fluid behind the tympanic membrane in the right ear. Recommended continuation of current asthma management plan, advised antihistamines for hay fever as needed, and prescribed amoxicillin for otitis media. Follow-up in two weeks to reassess ear infection.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f18f7620-5a4d-44da-885f-bf71bce92308', '2025-11-08T23:10:37.659835', 'Consultation', 'Patient presented for a routine general checkup. Vital signs were within normal limits: BP 112/70 mmHg, HR 72 bpm, RR 16 breaths/min, Temp 98.6°F. Physical examination was unremarkable, with no acute distress noted. Advised to maintain a balanced diet, regular physical activity, and follow up annually for wellness checks.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f18f7620-5a4d-44da-885f-bf71bce92308', '2025-08-16T23:10:37.659835', 'Emergency Visit', 'Patient presented for an emergency visit following a fall during a sports activity, with complaints of left ankle pain and swelling. Vital signs were stable: BP 110/70 mmHg, HR 78 bpm, RR 16/min, Temp 98.6°F. Physical examination revealed tenderness over the lateral malleolus with limited range of motion and bruising. Assessment indicated a potential sprain; X-ray was ordered to rule out fracture. Recommended RICE (rest, ice, compression, elevation) therapy and follow-up with primary care for further evaluation.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f18f7620-5a4d-44da-885f-bf71bce92308', '2025-06-08T23:10:37.659835', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: BP 112/70 mmHg, HR 72 bpm, RR 16 breaths/min, Temp 98.6°F. Physical examination was unremarkable, with normal growth and development observed for age. No acute concerns were identified; patient was advised to maintain a balanced diet, regular physical activity, and follow up in one year unless symptoms arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c071bc7b-4432-4cc2-8f2c-5e5cd9a36f1e', '2025-10-28T23:10:42.371233', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 138/86 mmHg, HR 78 bpm, BMI 31.2 kg/m². Physical examination was unremarkable. Lipid panel indicates elevated LDL. Continued management of hyperlipidemia and hypertension was discussed, with a recommendation to maintain current medication regimen and incorporate dietary modifications and increased physical activity. Advised follow-up in 6 months to reassess lipid levels and blood pressure.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c071bc7b-4432-4cc2-8f2c-5e5cd9a36f1e', '2025-07-11T23:10:42.371233', 'Urgent Care', 'Patient presented for acute chest discomfort. Vitals were recorded as BP 158/92 mmHg, HR 88 bpm, and weight 260 lbs. Physical examination revealed no acute distress, but patient reported intermittent episodes of chest tightness over the past week. Assessment suggests possible angina; recommended immediate referral to cardiology for further evaluation. Advised continuation of antihypertensive regimen and lipid-lowering therapy, along with lifestyle modifications to address obesity.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c071bc7b-4432-4cc2-8f2c-5e5cd9a36f1e', '2025-06-21T23:10:42.371233', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 130/85 mmHg, heart rate 78 bpm, BMI 32 kg/m². Patient reported no acute symptoms but expressed concerns about cholesterol management. Assessment noted stable hypertension and obesity with well-controlled allergic rhinitis. Recommendations included continuation of current antihypertensive regimen, dietary modifications to address hyperlipidemia, and follow-up lipid panel in six months. Advised regular physical activity and weight loss strategies.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ecc3976a-5c32-4915-ae25-f4040e7399f3', '2025-11-09T23:10:47.184119', 'Follow-up Visit', 'Patient presented for a routine follow-up visit. Vitals were as follows: BP 118/76 mmHg, HR 72 bpm, RR 16 breaths per minute, temperature 98.6°F. No acute symptoms reported; patient appeared well-nourished and in no distress. Recommended continuation of current health maintenance practices, including balanced diet and regular physical activity. Advised to return for annual check-up or as needed if symptoms arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ecc3976a-5c32-4915-ae25-f4040e7399f3', '2025-10-08T23:10:47.184119', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were within normal limits: BP 112/68 mmHg, HR 72 bpm, RR 16 breaths per minute, temperature 98.4°F. Physical examination revealed no abnormalities; growth and development appropriate for age. Recommended continuation of a balanced diet, regular exercise, and updated immunizations as per guidelines. Follow-up in one year unless concerns arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a4e6dbfe-9e83-493f-9dcd-d5393b69fa30', '2025-10-02T23:10:50.462612', 'Urgent Care', 'Patient presented for increased joint pain and swelling in the knees. Vital signs: BP 150/90 mmHg, HR 78 bpm. On examination, bilateral knee crepitus and decreased range of motion were noted, consistent with exacerbation of osteoarthritis. Recommended initiation of a low-impact exercise regimen and prescribed NSAIDs for pain management. Advised follow-up with primary care for ongoing hypertension and lipid management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a4e6dbfe-9e83-493f-9dcd-d5393b69fa30', '2025-06-20T23:10:50.462612', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 140/90 mmHg, and heart rate was 78 bpm. No new symptoms reported; however, patient noted increased joint stiffness, consistent with osteoarthritis. Continued management of hyperlipidemia with statins was advised, and dietary modifications were recommended to support weight reduction and blood pressure control. Follow-up in 6 months was planned to reassess cardiovascular risk factors and joint health.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('799d30b6-32d7-4282-a57b-ad38c4f71c73', '2025-12-24T23:10:53.327446', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding hyperlipidemia management. Blood pressure was 135/80 mmHg and heart rate was 76 bpm. Patient reported no new symptoms and has been adhering to prescribed simvastatin regimen. Recommended continuation of current lipid-lowering therapy and advised maintaining a low-cholesterol diet. Follow-up in 6 months to reassess lipid profile and BP control.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('799d30b6-32d7-4282-a57b-ad38c4f71c73', '2025-10-11T23:10:53.327446', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were stable with BP at 128/82 mmHg and HR at 72 bpm. No new symptoms reported; however, patient noted increased stiffness in the knees, consistent with osteoarthritis history. Recommended continuation of current antihypertensive and statin therapy, advised on low-impact exercises to manage joint stiffness, and scheduled follow-up in six months to monitor hyperlipidemia.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('799d30b6-32d7-4282-a57b-ad38c4f71c73', '2025-03-10T23:10:53.327446', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals: BP 138/82 mmHg, HR 76 bpm, BMI 28 kg/m². Physical examination revealed mild crepitus in bilateral knees consistent with osteoarthritis, otherwise unremarkable. Assessment: Well-controlled hypertension, stable hyperlipidemia. Plan: Continue current antihypertensive and statin therapy, recommend lipid panel in 3 months, and encourage weight management and joint-friendly exercise to alleviate osteoarthritis symptoms. Follow-up in 6 months or as needed.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('2a52833d-e338-465c-a1e0-f072335ce241', '2025-10-06T23:10:58.660728', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding eczema management. No new symptoms reported; skin examination revealed mild erythema and dryness on the antecubital fossa, with no signs of infection. Vital signs were stable: BP 100/60 mmHg, HR 78 bpm. Continued use of topical corticosteroids and emollients was advised, and a referral to a dermatologist was provided for further management if symptoms persist.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('2a52833d-e338-465c-a1e0-f072335ce241', '2025-09-21T23:10:58.660728', 'Urgent Care', 'Patient presented for evaluation of worsening eczema flare-ups. Physical examination revealed erythematous, scaly patches on bilateral antecubital fossae, with mild excoriation noted. Vitals: BP 110/70 mmHg, HR 88 bpm, afebrile. Assessment: Acute exacerbation of eczema. Plan: Initiated topical corticosteroid therapy and recommended moisturizing regimen; advised follow-up with primary care for ongoing management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('2a52833d-e338-465c-a1e0-f072335ce241', '2025-04-22T23:10:58.660728', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were stable with a BP of 100/65 mmHg, HR of 88 bpm, RR of 18 breaths per minute, and temperature of 98.6°F. Examination revealed mild erythematous patches consistent with eczema on the antecubital fossae and popliteal areas. Assessment confirmed controlled eczema; recommended continuing current emollient use and prescribed a low-potency topical corticosteroid for flare-ups. Advised follow-up in one year or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('2a52833d-e338-465c-a1e0-f072335ce241', '2024-10-14T23:10:58.660728', 'Annual Checkup', 'Patient presented for an annual checkup. Physical examination revealed mild erythematous patches consistent with eczema, primarily on the antecubital fossa and popliteal regions. Vitals were stable: BP 102/68 mmHg, HR 88 bpm, RR 18 per minute, Temp 98.2°F. Recommended continued use of emollients and prescribed a low-potency topical corticosteroid for flare-ups. Advised avoidance of known irritants and follow-up in 6 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
