INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('170a1203-2416-4bee-b0f6-7e16e619d771', '2025-04-25T23:11:05.412235', 'Follow-up Visit', 'Patient presented for a follow-up visit concerning ongoing cancer treatment. Blood pressure was 138/82 mmHg, heart rate was 76 bpm, and weight remained stable. The patient reported mild nausea and fatigue, consistent with chemotherapy side effects. Recommended continuation of current oncological treatment regimen, with antiemetic medication prescribed for nausea management. Advised regular monitoring of blood pressure and lipid levels, and scheduled a follow-up in three months.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('170a1203-2416-4bee-b0f6-7e16e619d771', '2025-01-27T23:11:05.412235', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding ongoing cancer treatment. Vital signs were stable: BP 132/78 mmHg, HR 72 bpm. The patient reported mild fatigue and occasional nausea, likely secondary to chemotherapy. Recommended continuation of current treatment regimen and scheduled a follow-up in four weeks to monitor response and manage any side effects. Advised to maintain a low-fat diet for hyperlipidemia management and continue prescribed antihypertensives and proton pump inhibitors.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('90263789-8473-408a-8e12-da5d093a94be', '2025-12-20T23:11:16.818642', 'Follow-up Visit', 'Patient presented for follow-up of urticaria. On examination, there were scattered erythematous wheals over the trunk and arms, but no angioedema was noted. Vital signs were stable with HR 110 bpm, BP 90/60 mmHg, and temperature 98.6°F. Assessment indicated mild improvement since last visit. Advised continuation of antihistamine therapy and recommended avoiding known allergens. Follow-up in 2 weeks or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('90263789-8473-408a-8e12-da5d093a94be', '2025-05-31T23:11:16.818642', 'Emergency Visit', 'Patient presented to the emergency department with generalized urticaria, noted as raised, erythematous, and pruritic wheals over the trunk and extremities. Vitals were stable: BP 90/60 mmHg, HR 110 bpm, RR 30/min, Temp 37.5°C. Assessment suggested an acute allergic reaction, likely triggered by an unknown allergen. Administered oral antihistamine and monitored for any signs of respiratory distress; advised parents on avoidance strategies and provided a prescription for an epinephrine auto-injector in case of future anaphylactic episodes. Follow-up with pediatrician recommended within the week.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('90263789-8473-408a-8e12-da5d093a94be', '2025-05-25T23:11:16.818642', 'Annual Checkup', 'Patient presented for an annual checkup with a recent history of urticaria. Physical examination revealed scattered wheals on the trunk and extremities, no respiratory distress, and no angioedema. Vitals: HR 110 bpm, RR 30 breaths/min, temperature 37.2°C. Assessment: Urticaria likely due to an allergic reaction. Plan: Continue monitoring symptoms, advised to use antihistamines as needed, and avoid known allergens. Follow-up in one month or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
