INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('90263789-8473-408a-8e12-da5d093a94be', '2024-09-28T23:11:16.818642', 'Follow-up Visit', 'Patient presented for follow-up of urticaria. Physical examination revealed diffuse, erythematous, raised wheals on the trunk and extremities, with no evidence of angioedema. Vitals were within normal limits for age. It was assessed that the urticaria is likely allergic in nature. Recommended continuation of antihistamine therapy with cetirizine and advised avoidance of potential allergens. Follow-up in two weeks or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('90263789-8473-408a-8e12-da5d093a94be', '2024-06-30T23:11:16.818642', 'Follow-up Visit', 'Patient presented for follow-up evaluation of urticaria. The mother reported that the hives have decreased in frequency and intensity since the last visit. On examination, the child appeared well-nourished and in no distress, with no active urticarial lesions observed. Vitals were stable: HR 110 bpm, RR 30 breaths/min. Assessment indicated improvement with current antihistamine regimen. Recommended continuation of antihistamine treatment and advised to monitor for any new triggers or worsening of symptoms. Follow-up scheduled in one month or sooner if symptoms exacerbate.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
