INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6d2d80ad-1dda-4384-9f3a-d2a6104e8bdb', '2025-07-07T23:11:26.609171', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 130/85 mmHg, HR 72 bpm, SpO2 95% on room air. The patient reported fatigue and occasional shortness of breath, which could be attributed to her ongoing cancer treatment. Recommended continuation of current asthma management and lipid-lowering therapy, with follow-up in three months to monitor cancer progression and treatment side effects.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
