VALUES ('60a219a9-e0c2-4462-8961-43d8f02f3dbb', '2025-03-01T23:11:39.902504', 'Consultation', 'Patient presented for a routine consultation regarding management of hypertension. Blood pressure was recorded at 145/90 mmHg, and heart rate was 76 bpm. Patient reported occasional headaches but denied chest pain or shortness of breath. Assessment showed poorly controlled hypertension. Recommended adjustment of antihypertensive medication, increased physical activity, and dietary modifications to address hyperlipidemia and prediabetes. Follow-up scheduled in three months to evaluate blood pressure control and lipid profile.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e343cc21-75b6-4418-9f90-f4616c65c4de', '2025-10-04T23:11:44.837537', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 142/86 mmHg, HR 72 bpm, RR 18/min, Temp 98.4°F. The patient reported mild joint stiffness, which is consistent with her history of osteoarthritis, and occasional shortness of breath, likely due to asthma. Cancer treatment is ongoing, and anemia is being managed with iron supplementation. Recommended continuation of current medications for hypertension, diabetes, and hyperlipidemia, and advised follow-up with oncology for cancer management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e343cc21-75b6-4418-9f90-f4616c65c4de', '2025-08-27T23:11:44.837537', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding cancer management. Vital signs were stable: BP 130/78 mmHg, HR 72 bpm. Patient reported increased fatigue and mild dyspnea on exertion. Physical examination revealed pallor, but no acute distress. Assessment indicated progression of anemia. Recommended continuation of current cancer and anemia treatment protocols, with an adjustment in iron supplementation. Follow-up labs were ordered to monitor hemoglobin levels and assess treatment efficacy.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e343cc21-75b6-4418-9f90-f4616c65c4de', '2025-07-31T23:11:44.837537', 'Urgent Care', 'Patient presented for increased shortness of breath and fatigue. Vitals were notable for BP 150/88 mmHg, HR 98 bpm, SpO2 91% on room air. Physical examination revealed bilateral wheezing and mild pallor. Assessment indicated exacerbation of asthma and possible anemia-related fatigue. Plan included initiating nebulized bronchodilator therapy, adjusting anemia treatment, and arranging follow-up with oncology for further evaluation of cancer status.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e343cc21-75b6-4418-9f90-f4616c65c4de', '2025-04-24T23:11:44.837537', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding ongoing cancer management and monitoring of chronic conditions. Vital signs were as follows: BP 138/82 mmHg, HR 78 bpm, RR 18/min, and temperature 98.2°F. She reported mild fatigue and joint pain, consistent with her osteoarthritis and anemia, but denied any new symptoms. Continued current cancer treatment regimen, recommended adjustments in diet to better manage hyperlipidemia and diabetes, and advised follow-up in three months for reassessment of treatment efficacy and further management of comorbid conditions.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e343cc21-75b6-4418-9f90-f4616c65c4de', '2024-12-04T23:11:44.837537', 'Urgent Care', 'Patient presented for evaluation of increased shortness of breath and fatigue over the past week. Vitals were noted as BP 142/85 mmHg, HR 88 bpm, SpO2 92% on room air. Physical examination revealed wheezing bilaterally and mild pallor. Assessment indicated potential exacerbation of asthma and anemia. Recommended continuation and adjustment of bronchodilator therapy, ordered CBC to evaluate anemia status, and advised follow-up with oncology for cancer-related symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('402a5579-89e2-49a0-b033-ba507473876b', '2025-11-24T23:11:52.997669', 'Urgent Care', 'Patient presented for acute onset of severe headache and dizziness. Blood pressure was elevated at 160/100 mmHg, heart rate at 82 bpm. Physical examination revealed no focal neurological deficits. Assessment suggested hypertensive urgency; advised strict BP control, initiated lisinopril 10 mg daily, recommended follow-up with primary care for BP management and adjustment of current antihypertensive regimen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('402a5579-89e2-49a0-b033-ba507473876b', '2025-08-17T23:11:52.997669', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding hypertension management. Blood pressure was recorded at 142/88 mmHg, and heart rate was 78 bpm. Patient reports occasional headaches but denies chest pain or shortness of breath. Assessment indicates suboptimal blood pressure control; advised continuation of current antihypertensive regimen with the addition of lifestyle modifications, including dietary adjustments and increased physical activity to address hyperlipidemia and prediabetes. Follow-up scheduled in three months for reassessment.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('402a5579-89e2-49a0-b033-ba507473876b', '2025-06-22T23:11:52.997669', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 138/88 mmHg, and heart rate was 76 bpm. Physical examination revealed no acute distress, and cardiovascular and respiratory examinations were normal. Assessment included well-controlled hypertension and ongoing management of hyperlipidemia and prediabetes. Recommended continuation of current antihypertensive and statin therapy, and advised lifestyle modifications including diet and exercise to aid glycemic control. Follow-up in six months to monitor cardiovascular risk factors.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6e866673-d98c-4013-b59e-e34048014609', '2026-02-13T23:11:58.813761', 'Urgent Care', 'Patient presented for worsening depressive symptoms and reported increased episodes of anxiety. Vital signs were within normal limits: BP 118/76 mmHg, HR 72 bpm. Physical exam was unremarkable, but patient appeared tearful and expressed difficulty sleeping. Assessment included exacerbation of depression and anxiety; recommended follow-up with mental health services, adjustment of current antidepressant regimen, and initiation of cognitive behavioral therapy.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6e866673-d98c-4013-b59e-e34048014609', '2025-06-02T23:11:58.813761', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were as follows: BP 118/76 mmHg, HR 72 bpm. Patient reported ongoing symptoms of depression, with occasional insomnia and anxiety, but no recent episodes of tonsillitis. Assessment noted stable mental health with current medication regimen. Recommended continuation of current antidepressant therapy, with follow-up for mental health counseling. Advised sleep hygiene practices to address insomnia.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6e866673-d98c-4013-b59e-e34048014609', '2025-05-30T23:11:58.813761', 'Consultation', 'Patient presented for a follow-up consultation regarding depression management. Vital signs were stable with BP 118/76 mmHg and HR 72 bpm. Patient reported persistent low mood and difficulty maintaining sleep, consistent with her history of insomnia and anxiety. Recommended adjustment of current antidepressant medication and initiation of cognitive behavioral therapy to address depressive symptoms and improve sleep hygiene. Follow-up scheduled in four weeks to assess treatment efficacy and symptom progression.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e1093474-4c17-465b-ac7d-d39e820982a0', '2025-10-17T23:12:03.778450', 'Urgent Care', 'Patient presented for acute right upper quadrant abdominal pain and nausea, suspected to be due to gallstones. Physical examination revealed tenderness in the right upper quadrant with a positive Murphy''s sign. Vital signs: BP 142/88 mmHg, HR 82 bpm. Recommended ultrasound imaging for confirmation and advised dietary modifications to manage symptoms. Discussed potential surgical options if symptoms persist. Patient advised to monitor for any signs of infection or increased pain and to follow up with their primary care provider.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e1093474-4c17-465b-ac7d-d39e820982a0', '2025-09-26T23:12:03.778450', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding gallstones. Blood pressure was 138/85 mmHg, and heart rate was 78 bpm. Patient reported occasional right upper quadrant pain but denied nausea or vomiting. Physical examination revealed mild tenderness in the right upper quadrant. Recommended continuation of current management plan, with dietary modifications to reduce fatty food intake, and scheduled an appointment for a surgical consultation to discuss potential cholecystectomy. Advised monitoring for any worsening symptoms or signs of cholecystitis.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e1093474-4c17-465b-ac7d-d39e820982a0', '2025-02-13T23:12:03.778450', 'Follow-up Visit', 'Patient presented for follow-up on gallstones. Vitals were stable: BP 130/85 mmHg, HR 72 bpm. He reported occasional episodes of right upper quadrant pain, though less frequent than prior to the last visit. Abdominal ultrasound confirmed presence of multiple gallstones with no signs of acute cholecystitis. Recommended continuation of low-fat diet and scheduled for elective cholecystectomy consultation. Advised to monitor for any signs of acute biliary colic or jaundice and to maintain adherence to medication regimen for hyperlipidemia and hypertension.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('32f6fe70-16a1-4b0e-b01d-fce36c304622', '2026-01-30T23:12:09.823541', 'Annual Checkup', 'Patient presented for an annual checkup with a current condition of an insect bite reaction. Vital signs were within normal limits for age: BP 90/60 mmHg, HR 110 bpm, and temperature 98.6°F. Mild erythema and swelling noted at the site of the insect bite on the right forearm, consistent with a localized allergic reaction. No systemic symptoms observed. Assessment included allergic rhinitis and hay fever, well-managed. Recommended continued use of antihistamines as needed for insect bite reaction and routine follow-up for allergy management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('32f6fe70-16a1-4b0e-b01d-fce36c304622', '2025-08-07T23:12:09.823541', 'Annual Checkup', 'Patient presented for an annual checkup with a recent history of insect bite reaction. Physical examination revealed a localized erythematous and slightly swollen area on the left forearm with no signs of secondary infection. Vitals were within normal limits: BP 94/60 mmHg, HR 98 bpm, Temp 98.6°F. Assessment confirmed a mild localized allergic reaction. Recommended applying a cool compress and over-the-counter antihistamine for symptomatic relief. Advised follow-up if symptoms persist or worsen. Regular management of allergic rhinitis and hay fever to continue as previously instructed.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('32f6fe70-16a1-4b0e-b01d-fce36c304622', '2025-05-28T23:12:09.823541', 'Follow-up Visit', 'Patient presented for follow-up of insect bite reaction. Mild erythema and slight swelling were noted on the left forearm, with no signs of infection. The patient remained afebrile with stable vitals: HR 90 bpm, RR 20 breaths/min. Assessment indicated a resolving localized allergic reaction. Recommended continuing oral antihistamines and applying cool compresses. Advised parents to monitor for any increased swelling or systemic symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5d5d527a-e66b-479a-8320-1bae186ae90e', '2025-10-30T23:12:15.392987', 'Follow-up Visit', 'Patient presented for follow-up on depression and other chronic conditions. Vitals were stable: BP 118/76 mmHg, HR 72 bpm. Patient reported persistent depressive symptoms, including low mood and fatigue, despite current medication regimen; also noted occasional wheezing, possibly related to asthma. Recommended increasing dose of current antidepressant and advised continuation of inhaler for asthma management; encouraged CBT for anxiety and insomnia. Follow-up in 4 weeks to assess response to medication adjustments.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5d5d527a-e66b-479a-8320-1bae186ae90e', '2025-10-08T23:12:15.392987', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were stable with BP at 118/72 mmHg and HR at 76 bpm. Patient reported persistent depressive symptoms despite current treatment, with exacerbations of anxiety contributing to insomnia. Eczema and asthma were well-controlled with current management, though chronic pain remains a concern, impacting daily activities. Recommended adjusting current antidepressant regimen and referred to a pain specialist for further evaluation. Encouraged continuation of skin care routine for eczema and regular use of inhaler for asthma control. Follow-up scheduled in 3 months for medication review and mental health assessment.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f79f8369-0dab-4aa1-a27d-d69a0ab23e3b', '2026-01-14T23:12:19.244099', 'Annual Checkup', 'Patient presented for an annual checkup with a known history of gallstones. Vitals were stable with BP 128/82 mmHg, HR 76 bpm. Patient reported intermittent right upper quadrant abdominal pain, consistent with gallstone symptoms, but no acute distress noted. Recommended continued monitoring of symptoms and advised dietary modifications to manage hyperlipidemia and prevent gallstone exacerbation. Follow-up scheduled in six months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f79f8369-0dab-4aa1-a27d-d69a0ab23e3b', '2025-08-06T23:12:19.244099', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were within normal limits: BP 122/78 mmHg, HR 72 bpm. No acute complaints reported; however, the patient continues to experience intermittent episodes of biliary colic due to gallstones. Recommended dietary modifications to manage hyperlipidemia and scheduled a follow-up ultrasound to evaluate gallstone status. Advised continuation of current antihistamine regimen for allergic rhinitis.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f79f8369-0dab-4aa1-a27d-d69a0ab23e3b', '2025-06-04T23:12:19.244099', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding gallstones. Vital signs were stable with BP 124/82 mmHg and HR 78 bpm. Patient reported intermittent right upper quadrant abdominal pain, exacerbated by fatty meals, but no fever or jaundice. Ultrasound confirmed the presence of multiple gallstones without evidence of cholecystitis. Recommended continuation of a low-fat diet and discussed potential surgical options, including laparoscopic cholecystectomy. Follow-up scheduled in 6 weeks to reassess symptoms and review any further imaging if necessary.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('230d14e8-27c3-407d-b3bd-54a7b1ccc940', '2025-11-18T23:12:24.054029', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 138/86 mmHg, HR 78 bpm, BMI 32 kg/m². The patient reported no acute asthma exacerbations but noted occasional shortness of breath with exertion. Physical examination revealed bilateral expiratory wheezes. Diabetes and hypertension remain well-controlled with current medication regimen. Recommended continuation of current asthma management plan, encouraged weight loss through diet and exercise, and scheduled follow-up in six months for routine monitoring.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('230d14e8-27c3-407d-b3bd-54a7b1ccc940', '2025-06-15T23:12:24.054029', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 138/85 mmHg, HR 76 bpm, BMI 32.5 kg/m². Patient reported well-controlled asthma with occasional use of rescue inhaler and no recent exacerbations. Blood glucose levels were noted to be adequately managed with current diabetes medication. Continued management of hypertension and hyperlipidemia was advised, with a recommendation to maintain a low-sodium, low-fat diet and to increase physical activity. Follow-up in six months for routine monitoring.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ec34e7e7-db64-4ab6-b36e-a4af46a1e6a2', '2026-01-20T23:12:27.641781', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were within normal limits: BP 130/82 mmHg, HR 72 bpm. The patient reported occasional abdominal pain consistent with gallstones but no acute symptoms at the time of the visit. Recommended continued monitoring of gallstones and advised dietary modifications to manage hyperlipidemia. Discussed ongoing management of GERD, prediabetes, and hypertension, emphasizing adherence to current medications. Follow-up in six months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ec34e7e7-db64-4ab6-b36e-a4af46a1e6a2', '2025-07-29T23:12:27.641781', 'Follow-up Visit', 'Patient presented for follow-up evaluation of gallstones. Vital signs were stable, with blood pressure at 138/82 mmHg and heart rate at 72 bpm. The patient reported occasional right upper quadrant discomfort but no acute abdominal pain or jaundice. Continued monitoring of gallstone symptoms was advised, with a recommendation for dietary modifications to manage hyperlipidemia and regular follow-up for prediabetes and hypertension management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ec34e7e7-db64-4ab6-b36e-a4af46a1e6a2', '2025-06-24T23:12:27.641781', 'Annual Checkup', 'Patient presented for an annual checkup with a history of gallstones and multiple chronic conditions. Vital signs were as follows: BP 142/88 mmHg, HR 78 bpm, and BMI 28.5 kg/m². The patient reported occasional abdominal discomfort, consistent with gallstones, and managed with dietary modifications. Assessment included stable hypertension and hyperlipidemia, with no acute concerns noted. Recommended continuation of current medications, routine follow-up with gastroenterology for GERD management, and advised an ophthalmology review for cataracts. Discussed lifestyle modifications to address prediabetes and emphasized adherence to dietary recommendations.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('030f77f4-8871-4d34-86f4-d67495891f5e', '2026-01-10T23:12:33.375172', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 138/86 mmHg, HR 78 bpm, BMI 32.4 kg/m². The patient reported occasional shortness of breath, consistent with asthma history, and ongoing allergic rhinitis symptoms. Assessment indicated stable asthma and hyperlipidemia, with obesity being a concern for cardiovascular risk. Recommended continuation of current asthma medications, initiation of a lipid-lowering agent, and referral to a nutritionist for weight management. Follow-up scheduled in six months.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('030f77f4-8871-4d34-86f4-d67495891f5e', '2025-08-06T23:12:33.375172', 'Consultation', 'Patient presented for routine consultation. Vital signs were as follows: BP 138/85 mmHg, HR 78 bpm, BMI 32.5 kg/m². Patient reported increased shortness of breath with exertion and occasional wheezing, which were consistent with known asthma. Assessment indicated suboptimal asthma control and poorly managed hyperlipidemia, likely exacerbated by obesity. Recommended adjustment of inhaler regimen and initiation of lifestyle modifications including a structured weight loss program and dietary consultation. Follow-up in three months to reassess asthma management and lipid profile.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('da07c672-931e-4d90-a265-60d0bebcc4f0', '2025-10-07T23:12:37.574113', 'Consultation', 'Patient presented for evaluation of viral gastroenteritis symptoms. Physical examination revealed mild dehydration with dry mucous membranes; no fever was noted, and vital signs were stable with HR 120 bpm and BP 72/45 mmHg. Assessment confirmed viral gastroenteritis. Recommended oral rehydration solutions and advised monitoring for signs of increased dehydration; follow-up in 48 hours if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('da07c672-931e-4d90-a265-60d0bebcc4f0', '2025-10-06T23:12:37.574113', 'Annual Checkup', 'Patient presented for an annual checkup. The infant was noted to have symptoms consistent with viral gastroenteritis, including mild diarrhea and occasional vomiting. Vital signs were stable, with a heart rate of 120 bpm and a normal temperature of 98.6°F. Assessment confirmed viral gastroenteritis with a history of allergic rhinitis. Recommended oral rehydration solutions and monitoring for any signs of dehydration, advising parents to follow up if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('da07c672-931e-4d90-a265-60d0bebcc4f0', '2025-02-23T23:12:37.574113', 'Consultation', 'Patient presented for evaluation of viral gastroenteritis. Physical examination revealed mild dehydration and increased irritability. No signs of acute distress were noted. Assessment confirmed viral gastroenteritis, likely self-limiting. Recommended supportive care with oral rehydration solutions and monitoring of hydration status. Advised parents on signs of dehydration and when to seek further medical attention. Follow-up in 2-3 days if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('da07c672-931e-4d90-a265-60d0bebcc4f0', '2024-12-12T23:12:37.574113', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: HR 130 bpm, RR 30 breaths/min, Temp 37.5°C. The infant exhibited mild dehydration and irritability consistent with recent viral gastroenteritis. Recommended maintaining hydration with oral rehydration solution and monitoring for any signs of worsening symptoms. Follow-up advised if symptoms persist beyond one week or if condition deteriorates. Allergic rhinitis noted in medical history but no current exacerbation observed.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('da07c672-931e-4d90-a265-60d0bebcc4f0', '2024-07-11T23:12:37.574113', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were not taken as patient is a newborn. Currently experiencing symptoms of viral gastroenteritis, including mild diarrhea and occasional vomiting, without signs of dehydration. Noted history of allergic rhinitis. Recommended continued breastfeeding for hydration and immune support, and advised parents to monitor for any signs of dehydration or worsening symptoms. Follow-up in one week or sooner if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('da07c672-931e-4d90-a265-60d0bebcc4f0', '2024-07-01T23:12:37.574113', 'Annual Checkup', 'Patient presented for an annual checkup. Currently experiencing symptoms of viral gastroenteritis, including diarrhea and mild dehydration; no fever noted. Vital signs: HR 130 bpm, RR 40 breaths/min, temperature 37.1°C. History of allergic rhinitis was reviewed without changes. Recommended continued hydration and monitoring of symptoms for viral gastroenteritis; advised parents to return if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8ae4ada7-58e9-4c2f-861e-b4b50f11dd55', '2025-12-21T23:12:47.813329', 'Urgent Care', 'Patient presented for evaluation following a fall resulting in a contusion on the left hip. Vital signs were BP 138/82, HR 78 bpm, RR 18, SpO2 96% on room air. Noted mild ecchymosis and tenderness over the left trochanteric area, but no signs of fracture on examination or imaging. Recommended pain management with acetaminophen, continued use of her walker to prevent further falls, and follow-up with primary care for ongoing management of osteoporosis and diabetes.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8ae4ada7-58e9-4c2f-861e-b4b50f11dd55', '2025-07-17T23:12:47.813329', 'Emergency Visit', 'Patient presented for evaluation following a fall resulting in a contusion on the left hip. Vital signs were stable: BP 132/78, HR 88, RR 18, Temp 98.1°F, SpO2 96% on room air. Physical examination revealed a 5 cm hematoma with tenderness over the left hip and mild swelling, but no apparent fracture on X-ray. Assessment: contusion of the left hip in the setting of underlying osteoporosis and osteoarthritis. Recommended application of cold compresses, analgesics for pain management, and follow-up with primary care for reassessment. Patient advised on fall prevention strategies and was discharged with instructions for monitoring.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8ae4ada7-58e9-4c2f-861e-b4b50f11dd55', '2025-05-21T23:12:47.813329', 'Urgent Care', 'Patient presented for evaluation following a fall, resulting in a contusion on the left hip. Physical examination revealed mild bruising and tenderness over the affected area, with no signs of fracture or dislocation; range of motion was limited due to pain. Vitals: BP 138/82, HR 76, RR 18, SpO2 96% on room air. Assessment: contusion secondary to fall, with background of osteoporosis increasing fracture risk. Plan includes pain management with acetaminophen, ice application, and follow-up with primary care for further assessment of osteoporosis management. Advised to use a walker to prevent future falls and referred to physical therapy for balance training.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8ae4ada7-58e9-4c2f-861e-b4b50f11dd55', '2025-04-12T23:12:47.813329', 'Urgent Care', 'Patient presented for evaluation following a fall resulting in a contusion on the right hip. Vital signs noted: BP 138/82 mmHg, HR 78 bpm, RR 18 breaths/min, SpO2 97% on room air. Physical examination revealed bruising and tenderness over the contused area, with no signs of fracture or dislocation upon imaging. Recommended ice application, rest, and acetaminophen for pain management; advised follow-up with primary care for reassessment of fall risk and potential adjustment of osteoporosis management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('147e12d7-1059-4255-a302-af58e8930e9a', '2026-01-19T23:12:57.029904', 'Follow-up Visit', 'Patient presented for a routine follow-up visit. Vitals were stable: BP 102/64 mmHg, HR 76 bpm, RR 18 breaths/min, Temp 98.3°F. Physical examination revealed normal growth and development with no abnormalities noted. Assessment: Patient is in good health with no new concerns. Plan: Continue current health regimen, encourage balanced diet and regular physical activity, and schedule next annual check-up in one year.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
