VALUES ('d32bab57-5ea7-46df-b411-83ceeb696d10', '2025-10-16T23:14:06.048294', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding management of chronic conditions. Vital signs were stable, with blood pressure at 138/85 mmHg and heart rate at 78 bpm. The patient reported no new symptoms, and asthma was well-controlled with current inhaler regimen. Continued emphasis on lifestyle modifications for weight management and advised adherence to current antihypertensive and lipid-lowering medications. Recommended routine ophthalmology follow-up for cataract monitoring.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('d32bab57-5ea7-46df-b411-83ceeb696d10', '2025-06-14T23:14:06.048294', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 142/88 mmHg, HR 78 bpm, BMI 32.4 kg/m². Patient reported occasional shortness of breath, managed with as-needed inhaler use, and no significant changes in vision or allergy symptoms. Assessment showed well-controlled asthma and hypertension, but continued hyperlipidemia. Recommended maintaining current medication regimen, encouraged lifestyle modifications for weight management, and scheduled follow-up for lipid panel in 3 months.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a1890009-e3ad-4754-b906-e7a3f22bd893', '2025-12-10T23:14:10.966653', 'Urgent Care', 'Patient presented for evaluation of a sports-related contusion on the right thigh sustained during a soccer game. Physical examination revealed localized swelling and ecchymosis without signs of fracture or compartment syndrome. Vitals were stable: BP 118/76 mmHg, HR 72 bpm, RR 16 breaths/min. Assessment indicated a mild contusion, and the patient was advised to apply ice, elevate the affected limb, and use analgesics as needed. Additionally, recommended follow-up with primary care for asthma management and weight control strategies.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a1890009-e3ad-4754-b906-e7a3f22bd893', '2025-07-30T23:14:10.966653', 'Urgent Care', 'Patient presented for evaluation of a sports-related contusion to the right thigh sustained during a soccer match. Vital signs were stable: BP 118/76 mmHg, HR 72 bpm, RR 16 breaths/min, SpO2 98% on room air. Physical exam revealed localized swelling and tenderness with no significant hematoma or joint involvement. Assessment indicated a mild contusion; advised RICE (rest, ice, compression, elevation) and over-the-counter analgesics for pain management. Follow-up recommended if symptoms worsen or do not improve within one week. Patient also reminded to continue asthma and allergy medications as prescribed.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('064d07a2-b164-408b-b783-134fa3423a84', '2026-02-16T23:14:14.651356', 'Urgent Care', 'Patient presented for evaluation of a worsening pressure ulcer on the sacral region. Vital signs were stable: BP 140/85 mmHg, HR 78 bpm, SpO2 96% on room air. The ulcer was noted to be stage 3, with moderate exudate and surrounding erythema. Recommended wound care with daily dressing changes, application of hydrocolloid dressings, and consultation with wound care specialist. Advised pressure offloading and reassessment in one week.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('064d07a2-b164-408b-b783-134fa3423a84', '2025-08-26T23:14:14.651356', 'Follow-up Visit', 'Patient presented for follow-up of pressure ulcer on the right heel. On examination, the ulcer measured 3 cm x 2 cm with serous drainage and no signs of infection. Vitals were stable: BP 138/82 mmHg, HR 76 bpm. Advised on continued wound care with hydrocolloid dressing changes every 48 hours and pressure offloading. Recommended monitoring blood glucose levels due to obesity and hyperlipidemia, and scheduled a follow-up in four weeks.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('064d07a2-b164-408b-b783-134fa3423a84', '2025-06-07T23:14:14.651356', 'Urgent Care', 'Patient presented for evaluation of a pressure ulcer on the sacral region. Physical examination revealed a Stage II ulcer with surrounding erythema and minimal drainage. Blood pressure was 145/88 mmHg, heart rate 78 bpm, and respiratory rate 18 breaths per minute. Assessment indicated the need for wound care management and pressure relief strategies. Recommended daily dressing changes, repositioning every two hours, and a follow-up with a wound care specialist. Advised monitoring blood pressure closely due to history of hypertension and adjusting medication if needed.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('064d07a2-b164-408b-b783-134fa3423a84', '2025-03-23T23:14:14.651356', 'Follow-up Visit', 'Patient presented for follow-up regarding a pressure ulcer on the sacral region. Physical examination revealed a Stage 2 ulcer with partial-thickness skin loss, measuring 3 cm x 2 cm, with no signs of infection. Blood pressure was 142/88 mmHg, heart rate 78 bpm, and respiratory rate 18 breaths per minute. Assessment indicated stable ulcer condition with no new complications. Recommended continued use of pressure-relieving surfaces, wound care regimen, and monitoring of blood pressure and lipids due to past medical history of hypertension and hyperlipidemia.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c9e350aa-563c-4ef3-94fa-7fd72692a815', '2025-10-29T23:14:20.896587', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 138/85 mmHg, and heart rate was 76 bpm. Patient reported no new symptoms but expressed concern over maintaining blood sugar levels. Assessment revealed stable prediabetes with no progression to diabetes. Recommended continuation of current antihypertensive therapy, lifestyle modifications including regular exercise and dietary adjustments, and follow-up fasting glucose testing in six months.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c9e350aa-563c-4ef3-94fa-7fd72692a815', '2025-06-25T23:14:20.896587', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 140/85 mmHg, HR 78 bpm, RR 16 breaths/min, and BMI 27.5 kg/m². Physical examination was unremarkable. Assessment indicated stable prediabetes and controlled hypertension. Recommended continuation of current antihypertensive regimen and emphasized lifestyle modifications, including diet and exercise, to manage prediabetes. Scheduled follow-up in 6 months for routine monitoring of blood glucose levels.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c9e350aa-563c-4ef3-94fa-7fd72692a815', '2025-05-18T23:14:20.896587', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: BP 138/82 mmHg, HR 76 bpm, BMI 26.3. Patient reported no new symptoms but expressed concerns about managing prediabetes. Recommended continuation of current antihypertensive medication and advised dietary modifications and regular physical activity to manage blood glucose levels. Follow-up in 6 months for routine monitoring of blood pressure and glucose levels.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c9e350aa-563c-4ef3-94fa-7fd72692a815', '2025-03-07T23:14:20.896587', 'Urgent Care', 'Patient presented for evaluation of acute-onset chest pain and shortness of breath. Vital signs were notable for blood pressure of 150/90 mmHg, heart rate of 92 bpm, respiratory rate of 20 breaths per minute, and oxygen saturation of 95% on room air. Physical examination revealed diminished breath sounds bilaterally but no wheezing or crackles. Given the patient''s history of hypertension and age, an ECG and chest X-ray were performed to rule out cardiac or pulmonary causes. The assessment indicated possible angina; aspirin was administered, and the patient was advised to follow up with her primary care physician for further cardiac evaluation.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b1e5aabc-a83a-4ed8-b9a4-7ea7587077eb', '2025-12-29T23:14:29.808979', 'Consultation', 'Patient presented for evaluation of constipation. Physical examination revealed mild abdominal distension and tenderness in the lower abdomen, but no palpable masses. Bowel sounds were present and normal. Assessment indicated functional constipation. Recommended dietary modifications including increased fiber and fluid intake, and advised continuation of over-the-counter pediatric glycerin suppositories as needed. Follow-up in two weeks if symptoms persist.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b1e5aabc-a83a-4ed8-b9a4-7ea7587077eb', '2025-07-26T23:14:29.808979', 'Annual Checkup', 'Patient presented for an annual checkup. Parent reported concerns about constipation over the past two weeks, characterized by infrequent bowel movements and straining. Vitals were stable: HR 100 bpm, RR 22, and temperature 98.6°F. Physical examination showed a soft abdomen with no palpable masses. Assessment: chronic constipation likely related to dietary habits. Recommended increasing fiber intake and fluid consumption, and advised follow-up if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b1e5aabc-a83a-4ed8-b9a4-7ea7587077eb', '2025-03-26T23:14:29.808979', 'Emergency Visit', 'Patient presented for acute constipation. Physical exam revealed a soft, non-distended abdomen with mild tenderness in the lower quadrants. Bowel sounds were present and normal. Assessment indicated functional constipation likely exacerbated by dietary factors. Recommended increased fluid intake, dietary fiber supplementation, and the use of polyethylene glycol as needed. Follow-up with primary care pediatrician in one week if symptoms persist or worsen. Vitals: HR 98 bpm, RR 22 breaths per minute, Temp 98.6°F.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b1e5aabc-a83a-4ed8-b9a4-7ea7587077eb', '2024-12-12T23:14:29.808979', 'Annual Checkup', 'Patient presented for an annual checkup. Mother reported concerns about ongoing constipation. Vitals were within normal limits: HR 110 bpm, RR 22/min, Temp 98.6°F. Abdominal examination revealed mild distension without tenderness. Assessment: Functional constipation. Recommended increased dietary fiber and fluid intake; advised to continue monitoring bowel habits and follow up if symptoms persist.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4027025a-2652-45b7-be51-f777301ec791', '2026-02-09T23:14:36.359024', 'Consultation', 'Patient presented for routine asthma management consultation. Vital signs were stable: BP 118/72 mmHg, HR 76 bpm, SpO2 98% on room air. Reported occasional wheezing and shortness of breath, particularly during physical exertion. Examination revealed clear lung fields with no wheezes or crackles. Continued current inhaler regimen with Albuterol PRN and Fluticasone daily. Advised to monitor symptoms and follow up in six months or sooner if symptoms exacerbate.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4027025a-2652-45b7-be51-f777301ec791', '2025-10-07T23:14:36.359024', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were stable with BP 118/76 mmHg, HR 72 bpm, and SpO2 at 98% on room air. Reported no acute exacerbations of asthma recently, and asthma was well-controlled with current inhaler regimen. Recommended continuation of current asthma management plan and follow-up in one year unless symptoms worsen. Advised patient to avoid known allergens and discussed strategies for managing seasonal hay fever.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4027025a-2652-45b7-be51-f777301ec791', '2025-03-22T23:14:36.359024', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding asthma management. Vital signs were within normal limits: BP 118/72 mmHg, HR 78 bpm, RR 16 breaths/min. The patient reported occasional wheezing and shortness of breath, particularly during physical exertion. Spirometry showed stable lung function compared to previous measurements. Continued current asthma medication regimen was recommended, along with the use of a rescue inhaler as needed. Advised to avoid known allergens and follow-up in 6 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('2f4c30d1-e4d3-4803-8be2-566226f89ba1', '2025-10-25T23:14:41.681746', 'Follow-up Visit', 'Patient presented for follow-up of bacterial pharyngitis. On examination, the oropharynx remained erythematous with mild exudate. Vital signs were stable: BP 138/86 mmHg, HR 78 bpm, SpO2 98% on room air. Continued on current antibiotic regimen, advised to complete the full course, and recommended increased fluid intake. Discussed weight management strategies and reinforced adherence to antihypertensive medication. Follow-up in 2 weeks to reassess symptoms and hypertension control.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('2f4c30d1-e4d3-4803-8be2-566226f89ba1', '2025-08-10T23:14:41.681746', 'Follow-up Visit', 'Patient presented for follow-up on bacterial pharyngitis. Complained of persistent sore throat and dysphagia, though fever has subsided. Vital signs: BP 142/88 mmHg, HR 78 bpm, RR 16/min, Temp 98.6°F. Oropharyngeal examination revealed mild erythema, no exudates. Assessment: Improving bacterial pharyngitis. Plan: Continue current antibiotic therapy for 5 more days, advised hydration and rest, follow-up in one week if symptoms persist or worsen. Discussed weight management and hypertension control strategies.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f4bc5f50-6307-46dd-98e2-b123a4284f6b', '2026-01-28T23:14:45.882854', 'Follow-up Visit', 'Patient presented for follow-up on gallstones and management of chronic conditions. Blood pressure was 138/84 mmHg, heart rate 76 bpm, and blood glucose levels were slightly elevated at 150 mg/dL. Noted mild increase in joint pain due to osteoarthritis and stable mood under current antidepressant therapy. Recommended continuation of current medication regimen, dietary modifications to manage gallstones and diabetes, and scheduled an ultrasound to monitor gallstone status.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f4bc5f50-6307-46dd-98e2-b123a4284f6b', '2025-10-06T23:14:45.882854', 'Annual Checkup', 'Patient presented for an annual checkup with a history of gallstones. Vitals were stable: BP 138/82 mmHg, HR 72 bpm, BMI 29.6 kg/m². Patient reported occasional right upper quadrant pain and persistent heartburn, consistent with GERD. Continue current medication regimen, including omeprazole for GERD, and initiate dietary modifications to manage gallstone symptoms. Recommended follow-up in 6 months to monitor gallstone progression and reassess hypertension management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f4bc5f50-6307-46dd-98e2-b123a4284f6b', '2025-03-19T23:14:45.882854', 'Follow-up Visit', 'Patient presented for follow-up regarding gallstones and management of chronic conditions. Blood pressure was 142/88 mmHg, heart rate 76 bpm. Patient reported persistent right upper quadrant abdominal pain and occasional nausea, consistent with cholelithiasis. Recommended continuation of low-fat diet and analgesics as needed for pain; referral to gastroenterology for further evaluation of potential cholecystectomy was discussed. Diabetes and hypertension were stable with current medication regimen; advised to continue monitoring blood glucose levels and follow-up in three months.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f4bc5f50-6307-46dd-98e2-b123a4284f6b', '2024-12-07T23:14:45.882854', 'Follow-up Visit', 'Patient presented for follow-up on gallstones and management of chronic conditions. Vital signs were stable: BP 135/82 mmHg, HR 78 bpm. Reports occasional right upper quadrant pain and nausea, managed with dietary modifications. Osteoarthritis noted to cause increased joint stiffness, especially in the mornings. Depression remains stable with current medication regimen. Blood glucose levels have been well-controlled; however, emphasis on maintaining dietary and exercise routines was reinforced. Recommended continuation of current medications, initiation of Ursodeoxycholic acid for gallstones, and scheduled follow-up in three months.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f4bc5f50-6307-46dd-98e2-b123a4284f6b', '2024-08-25T23:14:45.882854', 'Urgent Care', 'Patient presented for acute right upper quadrant abdominal pain, nausea, and vomiting, consistent with a possible gallstone attack. Vital signs revealed BP 145/88 mmHg, HR 84 bpm, Temp 98.6°F. Physical examination noted tenderness in the RUQ without rebound tenderness or guarding. Recommended imaging studies to confirm diagnosis and advised pain management with analgesics. Discussed potential referral to a surgeon for further evaluation and management of gallstones. Advised to monitor blood glucose closely due to diabetes and adjust antihypertensive therapy as needed.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('63a94f41-d673-4627-87ac-fbd61c361b44', '2026-02-21T23:14:56.225298', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding obesity management and diabetes control. Blood pressure was elevated at 145/90 mmHg, and heart rate was 78 bpm. The patient reported occasional shortness of breath but denied any new or worsening symptoms of asthma or allergic rhinitis. Assessment included stable diabetes and controlled hyperlipidemia, but obesity and hypertension require further management. Recommended continuation of current asthma and anemia treatments, initiation of a low-sodium diet, and increased physical activity to aid weight loss and blood pressure reduction. Follow-up in 3 months to reassess blood pressure and weight management progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('63a94f41-d673-4627-87ac-fbd61c361b44', '2025-08-25T23:14:56.225298', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding management of obesity and diabetes. Vitals were stable: BP 130/85 mmHg, HR 78 bpm. Patient reported increased fatigue and difficulty managing blood glucose levels, with recent HbA1c noted at 8.2%. Continued current medication regimen, advised dietary modifications and increased physical activity, and scheduled follow-up in 3 months.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('63a94f41-d673-4627-87ac-fbd61c361b44', '2025-05-14T23:14:56.225298', 'Urgent Care', 'Patient presented for evaluation of shortness of breath and wheezing. Vital signs were as follows: BP 142/88 mmHg, HR 92 bpm, RR 20 breaths/min, SpO2 94% on room air. On examination, diffuse wheezing was noted bilaterally. Assessment included exacerbation of asthma likely triggered by allergic rhinitis. The plan included administration of a nebulized bronchodilator, initiation of a short course of oral corticosteroids, and recommendation to follow up with primary care for ongoing asthma management. Additionally, advised on weight management strategies and adherence to diabetic and hyperlipidemia treatment regimens.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ba397d2b-91c1-42f4-a85e-ad6d2901ca81', '2025-10-01T23:15:01.755118', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 142/88 mmHg, HR 78 bpm, BMI 32 kg/m². Patient reported increased daytime fatigue, consistent with known sleep apnea, and occasional heartburn, likely related to GERD. Assessment indicated well-controlled hyperlipidemia with stable medication regimen; however, hypertension required further management. Recommended lifestyle modifications to address obesity and increase physical activity. Referred to nutritionist for dietary counseling and advised follow-up in 3 months to reassess blood pressure management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ba397d2b-91c1-42f4-a85e-ad6d2901ca81', '2025-06-23T23:15:01.755118', 'Urgent Care', 'Patient presented with acute onset of chest pain radiating to the left arm and dyspnea. Vital signs revealed BP at 150/95 mmHg, HR 98 bpm, and SpO2 at 94% on room air. Physical examination noted obesity and mild wheezing upon auscultation. Differential diagnosis included angina; patient was advised to undergo an immediate ECG and referred to the emergency department for further evaluation and management. Additionally, recommendations were made to continue lifestyle modifications and follow up with primary care for ongoing management of hyperlipidemia and hypertension.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ec273114-3bf9-4550-985f-6dcf3912e0a6', '2026-01-03T23:15:06.465465', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding obesity management and monitoring of chronic conditions. Blood pressure was recorded at 140/88 mmHg, and heart rate was 76 bpm. Physical examination revealed no acute distress, but the patient reported occasional heartburn, consistent with GERD history. Continued management with lifestyle modifications was advised, including dietary changes and increased physical activity, and initiation of metformin was discussed to address prediabetes. Follow-up in three months recommended to reassess metabolic control and blood pressure management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ec273114-3bf9-4550-985f-6dcf3912e0a6', '2025-07-05T23:15:06.465465', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 145/88 mmHg, HR 82 bpm, BMI 32 kg/m². Physical examination revealed no acute distress, but the patient reported occasional heartburn and blurred vision. Assessment indicated stable hypertension and well-controlled GERD with current medication, but recommended further evaluation for cataracts given vision complaints. Advised lifestyle modifications to address obesity and prediabetes, including dietary changes and increased physical activity. Follow-up scheduled in six months for reassessment.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ec273114-3bf9-4550-985f-6dcf3912e0a6', '2025-04-16T23:15:06.465465', 'Follow-up Visit', 'Patient presented for a follow-up visit to monitor chronic conditions. Vitals: BP 150/92 mmHg, HR 78 bpm, BMI 32. Patient reported occasional heartburn and blurred vision. Assessment indicated well-controlled blood pressure on current regimen, but advised further weight management and dietary modifications to address obesity and prediabetes. Recommended continuation of current medications, with follow-up in 3 months to reassess blood pressure, weight, and glycemic control.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ec273114-3bf9-4550-985f-6dcf3912e0a6', '2025-04-14T23:15:06.465465', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were as follows: BP 142/88 mmHg, HR 78 bpm, BMI 32.4 kg/m². The patient reported no new symptoms but continues to experience occasional heartburn controlled with OTC antacids. Assessment included stable hypertension, managed prediabetes, and controlled GERD. Recommended continuation of current antihypertensive and metformin therapy, advised dietary modifications for weight management, and scheduled follow-up for cataract evaluation.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ec273114-3bf9-4550-985f-6dcf3912e0a6', '2024-11-26T23:15:06.465465', 'Consultation', 'Patient presented for routine consultation and management of chronic conditions. Vitals were as follows: BP 145/90 mmHg, HR 78 bpm. The patient reported occasional dyspepsia, but no significant changes in vision or blood glucose levels since the last visit. Assessment included controlled hypertension and stable GERD symptoms. Recommended continuation of current antihypertensive and proton pump inhibitor medications, along with lifestyle modifications to address obesity and prediabetes, emphasizing dietary changes and increased physical activity. Follow-up scheduled in three months for further evaluation and monitoring.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5da4d60b-cbf6-4597-a085-a348cf2b2446', '2026-01-20T23:15:16.193403', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were as follows: BP 138/85 mmHg, HR 78 bpm. Patient reported good control of blood glucose levels with occasional mild hypoglycemic episodes. Physical examination was unremarkable except for mild nasal congestion. Recommended continuation of current antihypertensive and lipid-lowering therapy, with an adjustment to insulin dosing to prevent hypoglycemia. Advised patient to follow up with an allergist regarding persistent allergic rhinitis and to maintain regular diabetes monitoring.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5da4d60b-cbf6-4597-a085-a348cf2b2446', '2025-10-26T23:15:16.193403', 'Emergency Visit', 'Patient presented for acute shortness of breath and wheezing. Vitals: BP 148/92 mmHg, HR 98 bpm, RR 24 breaths/min, SpO2 89% on room air. Physical examination revealed bilateral wheezing and use of accessory muscles for respiration. Assessment indicated an exacerbation of asthma likely triggered by an upper respiratory infection. Administered nebulized albuterol in the ED with subsequent improvement in respiratory distress. Recommended continuation of inhaled corticosteroids and advised follow-up with primary care for asthma management review and diabetes monitoring.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5da4d60b-cbf6-4597-a085-a348cf2b2446', '2025-03-29T23:15:16.193403', 'Follow-up Visit', 'Patient presented for follow-up on diabetes management. Blood pressure was 132/80 mmHg and heart rate was 78 bpm. Patient reported occasional dizziness and episodes of fatigue. Assessment revealed suboptimal glycemic control with HbA1c at 8.1%. Recommended continuation of metformin and advised dietary modifications and increased physical activity. Scheduled follow-up in 3 months to reassess glycemic control.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('1f41adf7-d1e9-4fcd-b398-38b6eaff8951', '2025-12-08T23:15:22.235639', 'Emergency Visit', 'Patient presented for acute exacerbation of chronic depression with increased anxiety and insomnia. Blood pressure was 142/86 mmHg, heart rate 78 bpm. Patient reported worsening symptoms over the past two weeks with difficulty concentrating and anhedonia. Assessment indicated a need for adjustment of current SSRI dosage and initiation of cognitive behavioral therapy. Patient was advised to follow up with primary care within one week and was provided with resources for mental health support.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('1f41adf7-d1e9-4fcd-b398-38b6eaff8951', '2025-07-22T23:15:22.235639', 'Annual Checkup', 'Patient presented for an annual checkup with ongoing management of depression. Vitals were stable: BP 128/82 mmHg, HR 76 bpm. The patient reported improved mood stability on current antidepressant regimen but noted persistent insomnia and intermittent anxiety. Recommended continuation of current medications with the addition of cognitive behavioral therapy for insomnia and anxiety management. Advised follow-up in 3 months to reassess mental health and monitor lipid levels.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('1f41adf7-d1e9-4fcd-b398-38b6eaff8951', '2025-04-05T23:15:22.235639', 'Urgent Care', 'Patient presented for exacerbation of depressive symptoms, reporting increased fatigue and difficulty concentrating over the past two weeks. Vital signs were stable: BP 128/82 mmHg, HR 76 bpm. Physical examination was unremarkable except for a flat affect. Assessment indicated worsening depression potentially linked to chronic pain and insomnia. Recommended adjustment of current antidepressant dosage and referral for cognitive behavioral therapy. Advised follow-up with primary care provider to evaluate management of concurrent chronic conditions.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('dd1956ae-d988-4757-b46a-b5b4855106d0', '2026-01-13T23:15:28.481847', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 138/86 mmHg and heart rate was 76 bpm. Patient reported increased nasal congestion and sneezing consistent with hay fever, but no significant changes in cardiovascular symptoms. Assessment indicated well-controlled hypertension and hyperlipidemia. Recommended continuation of current antihypertensive and statin therapy, and advised on allergen avoidance strategies and use of antihistamines as needed for hay fever symptoms. Follow-up in one year or as needed if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('dd1956ae-d988-4757-b46a-b5b4855106d0', '2025-06-26T23:15:28.481847', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 138/84 mmHg, and heart rate was 78 bpm. Patient reported mild increase in nasal congestion and sneezing due to hay fever, but no other acute symptoms. Assessment indicated stable hypertension and hyperlipidemia; cholesterol levels to be monitored with routine labs. Recommended continuing current antihypertensive and statin therapy, and advised use of antihistamines as needed for allergy symptoms. Follow-up in one year or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c2eea81e-bbf8-4fd0-b339-a10c1d1ff00e', '2025-11-18T23:15:32.678531', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 142/86 mmHg, and heart rate was 78 bpm. Physical examination revealed mild joint stiffness consistent with osteoarthritis, but no acute distress. Continued management of hypertension and hyperlipidemia was advised, with emphasis on lifestyle modification and adherence to current medication regimen. Recommended dietary adjustments and regular exercise to address prediabetes. Follow-up in six months or as needed for any new symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c2eea81e-bbf8-4fd0-b339-a10c1d1ff00e', '2025-07-19T23:15:32.678531', 'Consultation', 'Patient presented for routine consultation regarding management of chronic conditions. Blood pressure was 142/86 mmHg and heart rate was 78 bpm. Physical examination revealed mild joint stiffness in the knees with no acute distress. Assessment indicated stable hypertension with well-managed hyperlipidemia, though there was concern for worsening osteoarthritis symptoms. Recommended continuation of current antihypertensive and statin therapy, initiation of a low-impact exercise regimen for joint health, and dietary modifications to prevent progression of prediabetes. Follow-up scheduled in three months for re-evaluation.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c2eea81e-bbf8-4fd0-b339-a10c1d1ff00e', '2025-04-16T23:15:32.678531', 'Follow-up Visit', 'Patient presented for a follow-up visit to evaluate hypertension management. Blood pressure was recorded at 142/88 mmHg and heart rate at 78 bpm. She reported occasional dizziness and mild joint pain, with no new gastrointestinal symptoms. Assessment revealed stable hypertension and well-controlled GERD, but noted need for improved glycemic control. Recommended dietary modifications and increased physical activity to address prediabetes. Continued current antihypertensive and lipid-lowering therapy, with follow-up in three months to reassess cardiovascular risk and joint pain management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c2eea81e-bbf8-4fd0-b339-a10c1d1ff00e', '2024-11-29T23:15:32.678531', 'Follow-up Visit', 'Patient presented for a follow-up visit to monitor hypertension and review current management of chronic conditions. Blood pressure was recorded at 142/88 mmHg, and heart rate was 78 bpm. Patient reported occasional dizziness and joint stiffness, particularly in the knees. Continued management with current antihypertensive medication was recommended, and lifestyle modifications were reinforced to address prediabetes and hyperlipidemia. Advised patient to follow up in 3 months and consider physical therapy for osteoarthritis symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('10dc37e9-4098-408e-9ded-cebe441633d0', '2025-12-14T23:15:39.542043', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: BP 102/68 mmHg, HR 88 bpm, RR 18 breaths/min, Temp 98.6°F. Currently experiencing mild congestion and cough consistent with a viral upper respiratory infection, with no wheezing or respiratory distress noted. Advised supportive care including hydration and rest; instructed to use inhaler as needed for asthma symptoms. Reviewed history of food allergies and emphasized the importance of avoiding allergens. Discussed fracture history, noting full recovery with no current issues. Recommended follow-up if symptoms worsen or do not improve in 7-10 days.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('10dc37e9-4098-408e-9ded-cebe441633d0', '2025-08-10T23:15:39.542043', 'Urgent Care', 'Patient presented for evaluation of symptoms consistent with a viral upper respiratory infection, including rhinorrhea, cough, and mild fever. Vital signs were stable: BP 102/66 mmHg, HR 88 bpm, Temp 99.1°F. Physical examination revealed nasal congestion and mild wheezing on auscultation. Assessment confirmed viral URI exacerbating asthma. Recommended symptomatic treatment with increased hydration, rest, and use of albuterol inhaler as needed for wheezing. Advised caregiver to monitor for any signs of respiratory distress and return if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('10dc37e9-4098-408e-9ded-cebe441633d0', '2025-01-29T23:15:39.542043', 'Annual Checkup', 'Patient presented for an annual checkup with a concurrent viral upper respiratory infection. Vital signs were stable: BP 100/60, HR 88, RR 20, Temp 99.1°F. Notable symptoms included mild cough and nasal congestion; lungs were clear to auscultation despite asthma history. Advised supportive care and hydration; instructed to monitor symptoms and use albuterol inhaler as needed. Reviewed food allergy management and reinforced avoidance strategies. Immunizations were up to date. Follow-up in 1 year unless symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e9003080-15b8-4854-849f-890d8735398f', '2026-01-03T23:15:46.197559', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding hypertension management. Blood pressure was recorded at 145/90 mmHg, and heart rate was 78 bpm. Patient reported occasional headaches and dizziness. Physical examination was unremarkable. Assessment indicated poorly controlled hypertension, likely exacerbated by obesity and hyperlipidemia. Recommended adjustment of antihypertensive medication and advised on dietary modifications and weight management to address obesity. Follow-up scheduled in 3 months to reassess blood pressure control and lipid profile.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e9003080-15b8-4854-849f-890d8735398f', '2025-09-30T23:15:46.197559', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 140/85 mmHg, heart rate 78 bpm, and BMI 32 kg/m². Physical examination revealed mild crepitus in bilateral knees consistent with osteoarthritis. Recommended continuation of current antihypertensive and lipid-lowering therapy, advised weight management, and discussed potential benefits of low-impact exercise to alleviate joint symptoms. Follow-up in six months or as needed.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e9003080-15b8-4854-849f-890d8735398f', '2025-03-12T23:15:46.197559', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 142/88 mmHg and heart rate was 78 bpm. Physical examination revealed mild tenderness in the knees, consistent with history of osteoarthritis, but no acute distress. The patient''s hypertension and hyperlipidemia remain stable under current medication regimen. Recommended continuation of lifestyle modifications, including diet and exercise, to manage obesity. Follow-up in six months for routine hypertension monitoring.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('0cc36fda-5f8e-4cbf-aa4d-fd9759fb9555', '2025-12-04T23:15:50.600685', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 138/85 mmHg and heart rate was 78 bpm. The patient reported well-controlled asthma symptoms with occasional use of albuterol inhaler and noted increased frequency of GERD symptoms. Recommended continuation of current antihypertensive regimen, adjustment of GERD medication dosage, and advised follow-up with pulmonology for asthma management. Advised lifestyle modifications for hypertension and GERD, including dietary adjustments and regular exercise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('0cc36fda-5f8e-4cbf-aa4d-fd9759fb9555', '2025-10-02T23:15:50.600685', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding asthma management. Blood pressure was 138/85 mmHg, heart rate was 78 bpm, and respiratory exam revealed mild wheezing. Patient reported increased frequency of nocturnal asthma symptoms over the past two weeks. Assessment: Asthma exacerbation likely secondary to recent changes in weather and potential allergen exposure. Plan: Adjusted inhaler regimen to include a higher dose of corticosteroid, recommended allergen avoidance measures, and scheduled a follow-up in one month to reassess control.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('0cc36fda-5f8e-4cbf-aa4d-fd9759fb9555', '2025-08-13T23:15:50.600685', 'Annual Checkup', 'Patient presented for annual checkup. Vital signs were as follows: BP 138/82 mmHg, HR 76 bpm, RR 18 breaths/min, SpO2 97% on room air. The patient reported stable asthma symptoms with no recent exacerbations; using her inhaler as needed with good effect. GERD and hypertension well-managed on current medication regimen. Recommended continued use of current asthma and antihypertensive medications, dietary modifications for GERD, and regular follow-up for blood pressure monitoring. Advised flu vaccination for upcoming season.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6f6e2764-76fa-4c1a-9048-bd2d88f3f911', '2025-09-28T23:15:55.926027', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 138/86 mmHg, heart rate was 76 bpm, BMI was 32.3 kg/m². Noted controlled hyperlipidemia with current statin therapy; no new symptoms related to allergic rhinitis, hypertension, or GERD. Recommended continuation of current medication regimen, advised dietary modifications to address obesity, and encouraged regular physical activity. Follow-up in six months for hypertension and weight management evaluation.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6f6e2764-76fa-4c1a-9048-bd2d88f3f911', '2025-06-18T23:15:55.926027', 'Urgent Care', 'Patient presented with complaints of chest discomfort and shortness of breath onset two hours prior to arrival. Vital signs: BP 145/92 mmHg, HR 88 bpm, RR 18 breaths/min, SpO2 98% on room air. Physical examination revealed no acute distress, clear lung fields, and regular heart rhythm. Given her history of hypertension and hyperlipidemia, differential diagnosis includes angina. Recommended immediate ECG and cardiac enzyme testing. Advised continuation of current antihypertensive regimen and statin therapy, with follow-up in cardiology for further evaluation.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6f6e2764-76fa-4c1a-9048-bd2d88f3f911', '2025-03-28T23:15:55.926027', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were as follows: BP 142/88 mmHg, HR 78 bpm, BMI 32.1 kg/m². Patient reported occasional heartburn, well-controlled with current GERD medication, and denied any new symptoms. Assessment revealed stable hyperlipidemia and hypertension. Recommended continuation of current medications, lifestyle modifications for weight management, and a follow-up lipid panel in 6 months. Advised annual flu vaccination and updated allergy management plan.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('23d363f8-287d-4517-8647-715f2dfe12e9', '2025-10-11T23:16:01.559363', 'Follow-up Visit', 'Patient presented for follow-up regarding obesity management and diabetes control. Vitals were stable, with BP at 128/82 mmHg and HR at 78 bpm. Patient reported occasional heartburn and frequent migraines despite current management. Recommended continuation of current diabetes regimen, advised dietary modifications to address obesity, and suggested a trial of a different migraine prophylactic medication. Follow-up in 3 months to reassess weight management and migraine frequency.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('23d363f8-287d-4517-8647-715f2dfe12e9', '2025-09-05T23:16:01.559363', 'Urgent Care', 'Patient presented for evaluation of acute abdominal pain and nausea. Vital signs were as follows: BP 138/88 mmHg, HR 92 bpm, Temp 98.6°F. Physical examination revealed moderate tenderness in the epigastric region without rebound tenderness or guarding. Assessment indicated likely exacerbation of GERD symptoms. Recommended initiation of a proton pump inhibitor and advised dietary modifications. Patient was counseled on the importance of weight management and referred to a nutritionist for further guidance. Follow-up with primary care physician in one week was advised.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('23d363f8-287d-4517-8647-715f2dfe12e9', '2025-03-27T23:16:01.559363', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 140/88 mmHg, HR 78 bpm, weight 220 lbs, BMI 35.6 kg/m². Patient reported occasional headaches and heartburn, consistent with known history of migraines and GERD, but no acute distress noted. Recommended continuation of current diabetes management plan with emphasis on dietary modifications and increased physical activity to address obesity. Advised follow-up in 3 months for blood pressure monitoring and reassessment of migraine management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('41d08326-2ac7-4764-ad8b-358ed2c965ae', '2025-10-31T23:16:07.085563', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: BP 110/70 mmHg, HR 72 bpm. Examination revealed mild folliculitis on the upper back with no signs of infection. Patient reported ongoing anxiety and depression, managed with current medications. Recommended continuation of skincare routine for folliculitis and follow-up with mental health provider to reassess anxiety and depression management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('41d08326-2ac7-4764-ad8b-358ed2c965ae', '2025-07-04T23:16:07.085563', 'Urgent Care', 'Patient presented for evaluation of worsening folliculitis. Physical examination revealed multiple erythematous papules with surrounding inflammation on the posterior neck and upper back. Vital signs were stable: BP 110/70 mmHg, HR 78 bpm. Assessment confirmed bacterial folliculitis exacerbated by stress-related factors. Recommended topical antibiotic therapy and advised warm compresses. Discussed stress management techniques in light of patient''s history of anxiety and depression. Follow-up suggested with primary care provider to monitor mental health and skin condition.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('32965d71-29fd-4c14-8764-2d11abb7ad19', '2026-01-07T23:16:09.955278', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding asthma management. Vital signs were stable: BP 128/82 mmHg, HR 76 bpm, RR 18 breaths/min, SpO2 97% on room air. The patient reported occasional shortness of breath but no recent exacerbations. Examination revealed clear lung fields with no wheezing. Recommended continuation of current inhaler regimen and advised monitoring symptoms with peak flow meter. Follow-up scheduled in 3 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('32965d71-29fd-4c14-8764-2d11abb7ad19', '2025-07-01T23:16:09.955278', 'Consultation', 'Patient presented for routine asthma management consultation. Vital signs were stable: BP 128/82 mmHg, HR 76 bpm, SpO2 96% on room air. Patient reported increased wheezing and dyspnea with exertion over the past month. Physical examination revealed bilateral wheezing on auscultation. Assessment indicated suboptimal asthma control. Plan included adjusting inhaled corticosteroid dosage and scheduling a follow-up in 6 weeks to reassess symptoms and lung function. Advised patient to avoid known allergens and to use rescue inhaler as needed.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('32965d71-29fd-4c14-8764-2d11abb7ad19', '2025-05-24T23:16:09.955278', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: BP 128/76 mmHg, HR 72 bpm, respiratory rate 16 breaths per minute, SpO2 98% on room air. Auscultation revealed clear lung fields, with no wheezing noted. Asthma is well-controlled with current inhaler regimen. Skin examination showed mild eczema on forearms, managed with emollients. Recommended continuation of current asthma management plan and regular use of moisturizers for eczema. Advised to schedule a follow-up in one year or sooner if symptoms exacerbate.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('32965d71-29fd-4c14-8764-2d11abb7ad19', '2025-05-20T23:16:09.955278', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were within normal limits: BP 128/78 mmHg, HR 72 bpm, SpO2 98% on room air. Patient reported occasional wheezing, with no recent asthma exacerbations. On examination, lung auscultation revealed mild expiratory wheezing. Recommended continuation of current asthma management plan, including daily inhaled corticosteroids, and advised on lifestyle modifications to manage eczema. Follow-up scheduled in 6 months or prn exacerbations.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('32965d71-29fd-4c14-8764-2d11abb7ad19', '2024-08-19T23:16:09.955278', 'Urgent Care', 'Patient presented for increased shortness of breath and wheezing, not alleviated by usual bronchodilator use. Vital signs were BP 135/82 mmHg, HR 88 bpm, RR 22 breaths/min, SpO2 90% on room air. Lung examination revealed diffuse expiratory wheezes bilaterally. Assessment: Acute asthma exacerbation. Plan included administration of nebulized albuterol, initiation of a short course of oral prednisone, and advised close follow-up with primary care or pulmonology. Patient was educated on asthma action plan and signs of worsening symptoms requiring immediate attention.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f481a697-11fd-4d96-917d-5306db5ec61c', '2025-10-29T23:16:20.401972', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were stable: BP 130/82 mmHg, HR 72 bpm. Patient reported mild joint stiffness consistent with osteoarthritis but denied any new or worsening symptoms related to cancer treatment. Recommended continuation of current medication regimen for GERD and osteoarthritis, and advised scheduling a follow-up with oncology for cancer management. Discussed strategies for fall prevention given age and history of cataracts.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f481a697-11fd-4d96-917d-5306db5ec61c', '2025-08-12T23:16:20.401972', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding cancer management. Vital signs were stable: BP 128/82 mmHg, HR 76 bpm. Patient reported mild fatigue and occasional nausea, but no significant weight loss since the last visit. Physical examination was unremarkable. Recommended continuation of current chemotherapy regimen and advised monitoring for any new symptoms. Follow-up scheduled in 3 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f481a697-11fd-4d96-917d-5306db5ec61c', '2025-03-05T23:16:20.401972', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: BP 128/76 mmHg, HR 72 bpm. No acute distress noted. The patient reported mild joint pain consistent with osteoarthritis but no new or worsening symptoms related to his cancer diagnosis. Recommended continuation of current cancer treatment regimen and follow-up with oncology. Advised to maintain regular ophthalmology and gastroenterology follow-ups for cataracts and GERD management, respectively. Encouraged routine exercise and weight management to alleviate osteoarthritis symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f481a697-11fd-4d96-917d-5306db5ec61c', '2025-03-05T23:16:20.401972', 'Emergency Visit', 'Patient presented for severe abdominal pain and nausea, with a history of cancer. Vitals were notable for BP 145/88 mmHg, HR 102 bpm, and fever of 38.5°C. Physical examination revealed guarding in the right lower quadrant. Assessment included possible bowel obstruction or cancer metastasis. Recommended immediate imaging studies and initiated IV fluids and analgesics. Consulted oncology for further evaluation.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f481a697-11fd-4d96-917d-5306db5ec61c', '2024-09-08T23:16:20.401972', 'Urgent Care', 'Patient presented for evaluation of increased fatigue and weight loss over the past month. Blood pressure was 138/82 mmHg, heart rate 78 bpm, and temperature 98.6°F. Physical examination revealed pallor and mild abdominal tenderness. Assessment indicated possible progression of underlying cancer. Recommended further oncological assessment and scheduled a CT scan to evaluate for metastasis. Advised dietary modifications to manage GERD symptoms and prescribed a proton pump inhibitor. Follow-up appointment scheduled in two weeks.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('d4e2bfab-3fc4-4fc9-a1ca-dac17135cccc', '2025-10-18T23:16:29.513077', 'Urgent Care', 'Patient presented for increased nasal congestion, sneezing, and itchy eyes consistent with exacerbation of allergic rhinitis. Vital signs were within normal limits: BP 110/70 mmHg, HR 80 bpm, Temp 98.4°F. Physical examination revealed nasal mucosa edema and clear nasal discharge. Assessment: Exacerbation of hay fever. Plan included continuation of current antihistamine therapy and initiation of intranasal corticosteroids. Advised to follow up with primary care for ongoing management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ff8d7a1d-64d0-4cab-ab88-b2c0302df415', '2025-11-14T23:16:31.254507', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding an insect bite reaction. On examination, the site showed mild erythema with no evidence of infection or significant swelling. The patient has a history of eczema, but no exacerbation was noted at this time. Recommended continuation of topical corticosteroid for bite site and emollient for skin hydration. Advised monitoring for any signs of worsening symptoms. Vitals were stable: HR 98 bpm, RR 22/min.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ff8d7a1d-64d0-4cab-ab88-b2c0302df415', '2025-07-19T23:16:31.254507', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding an insect bite reaction. On examination, the affected area on the right forearm appeared erythematous with mild edema and pruritus, but no signs of infection were noted. The patient’s past history of eczema was considered, and skin care recommendations were reinforced. Advised the use of topical corticosteroids for inflammation and antihistamines for itching, with a follow-up in one week if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a7478690-f913-4e68-8711-a4e9bc07da1b', '2025-11-19T23:16:35.654855', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 132/85 mmHg, heart rate was 76 bpm, and BMI was 28.3 kg/m². No acute respiratory distress noted; lungs clear to auscultation. Assessment: Hypertension well-controlled, hyperlipidemia managed with current regimen. Recommended continuation of current medication, annual lipid panel, and lifestyle modifications to address dyslipidemia. Follow-up in 12 months unless new symptoms arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a7478690-f913-4e68-8711-a4e9bc07da1b', '2025-08-07T23:16:35.654855', 'Urgent Care', 'Patient presented for acute shortness of breath and wheezing, reporting a 2-day history of exacerbated asthma symptoms. Vital signs showed BP 142/85 mmHg, HR 88 bpm, RR 22 breaths/min, and SpO2 at 93% on room air. On examination, diffuse wheezing was noted on auscultation. Assessment indicated an acute asthma exacerbation likely triggered by recent allergic rhinitis flare. Patient was administered nebulized albuterol and advised to continue inhaled corticosteroids; follow-up with primary care for asthma management and medication adjustment was recommended.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('560bb5a4-671b-4a11-bd60-67fb0656c05d', '2026-01-05T23:16:40.060179', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure measured at 128/82 mmHg and heart rate at 76 bpm. Physical examination was unremarkable with no acute distress noted. The patient was counseled on maintaining a healthy diet and regular exercise to manage prediabetes and hyperlipidemia. Recommended continuation of current antihistamine for allergic rhinitis and lipid-lowering therapy. Follow-up blood work was ordered to monitor glucose and lipid levels.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('560bb5a4-671b-4a11-bd60-67fb0656c05d', '2025-07-03T23:16:40.060179', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were as follows: BP 128/82 mmHg, HR 72 bpm, BMI 29.3 kg/m². No acute symptoms reported; however, patient expressed concern over weight management related to prediabetes. Assessment indicated stable prediabetes and controlled allergic rhinitis and hyperlipidemia. Recommended continuation of current lipid-lowering therapy and increased physical activity to manage weight. Advised dietary modifications with a focus on reducing carbohydrate intake to manage blood glucose levels effectively. Follow-up scheduled in six months for further evaluation of metabolic status.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('560bb5a4-671b-4a11-bd60-67fb0656c05d', '2025-06-21T23:16:40.060179', 'Urgent Care', 'Patient presented for evaluation of acute upper respiratory symptoms, including nasal congestion and sore throat, persisting for three days. Vital signs were stable with BP 128/82 mmHg, HR 78 bpm, and temperature 98.6°F. Examination revealed erythematous pharynx and swollen nasal turbinates consistent with allergic rhinitis exacerbation. Assessment indicated viral upper respiratory infection with no signs of bacterial involvement. Advised symptomatic treatment with antihistamines and nasal saline irrigation, and to monitor blood glucose levels given prediabetes. Follow-up recommended if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8afb0deb-6f56-471c-a1a1-cf1efc8bf59f', '2025-12-06T23:16:49.072181', 'Follow-up Visit', 'Patient presented for a follow-up visit for hyperlipidemia management. Blood pressure was 130/78 mmHg, and heart rate was 72 bpm. She reported mild joint stiffness but no significant changes in visual acuity since her cataract surgery. Assessment indicated stable hyperlipidemia with well-controlled cholesterol levels. Recommended continuation of current statin therapy and advised regular low-impact exercises to alleviate osteoarthritis symptoms. Follow-up in six months unless symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8afb0deb-6f56-471c-a1a1-cf1efc8bf59f', '2025-08-26T23:16:49.072181', 'Follow-up Visit', 'Patient presented for follow-up on hyperlipidemia management. Physical examination revealed BP 130/80 mmHg and HR 72 bpm. The patient reported mild joint stiffness, consistent with osteoarthritis history, but no new visual changes post-cataract surgery were noted. Lipid panel results showed LDL cholesterol slightly elevated at 145 mg/dL. Recommended continuation of current statin therapy and encouraged dietary modifications and regular physical activity to manage lipid levels. Scheduled follow-up in 6 months to reassess lipid profile and joint symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8afb0deb-6f56-471c-a1a1-cf1efc8bf59f', '2025-06-01T23:16:49.072181', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable with BP 132/78 mmHg and HR 72 bpm. No new symptoms reported; however, mild joint stiffness was noted consistent with osteoarthritis. Continued management of hyperlipidemia was advised with statin therapy; encouraged regular physical activity and a low-fat diet. Routine follow-up in 6 months or as needed for any acute concerns.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('54ff27e1-31b0-4b67-8b9f-5dcd6889c0c0', '2026-01-15T23:16:54.602457', 'Urgent Care', 'Patient presented for evaluation of dysuria and increased urinary frequency over the past three days. Physical examination revealed mild suprapubic tenderness; no flank pain noted. Vitals: BP 138/84 mmHg, HR 72 bpm, afebrile. Urinalysis confirmed presence of nitrites and leukocyte esterase. Assessment: Urinary Tract Infection. Plan included prescription of a 5-day course of nitrofurantoin and advised increased fluid intake. Follow-up recommended with primary care physician if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('54ff27e1-31b0-4b67-8b9f-5dcd6889c0c0', '2025-08-03T23:16:54.602457', 'Consultation', 'Patient presented for evaluation of urinary tract infection. Reported dysuria, increased frequency, and urgency. Physical examination was unremarkable except for mild suprapubic tenderness. Vital signs: BP 138/82 mmHg, HR 78 bpm, afebrile. Urinalysis confirmed the presence of leukocytes and nitrites. Assessment: Acute uncomplicated UTI. Plan: Prescribed a 5-day course of nitrofurantoin, advised increased fluid intake, and scheduled follow-up to monitor resolution of symptoms. Recommended continuation of current management for hypertension and osteoarthritis.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('54ff27e1-31b0-4b67-8b9f-5dcd6889c0c0', '2025-03-24T23:16:54.602457', 'Follow-up Visit', 'Patient presented for follow-up regarding a urinary tract infection. Vital signs were stable with BP 128/76 mmHg and HR 72 bpm. Patient reported decreased dysuria and improved urinary frequency following completion of antibiotics. Assessment indicated resolution of UTI symptoms; recommended maintaining adequate hydration and follow-up in 3 months for hypertension management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('0fd0e904-eebd-43fe-a3c3-2238e22634f1', '2025-12-05T23:16:59.927368', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was elevated at 145/92 mmHg, heart rate was 78 bpm, and BMI was calculated at 31.2, indicating obesity. No acute symptoms reported, but patient expressed concerns about weight management. Recommended lifestyle modifications including dietary changes and increased physical activity. Continued monitoring of blood pressure and lipid levels advised, with a follow-up appointment scheduled in three months.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('0fd0e904-eebd-43fe-a3c3-2238e22634f1', '2025-06-13T23:16:59.927368', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was recorded at 145/92 mmHg and heart rate at 78 bpm. The patient reported no new symptoms but expressed a desire to improve his lifestyle. Assessment indicated continued management of hypertension and hyperlipidemia with recommendations for dietary modifications, increased physical activity, and adherence to prescribed antihypertensive and lipid-lowering medications. Follow-up scheduled in 3 months to monitor blood pressure and lipid levels.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('0fd0e904-eebd-43fe-a3c3-2238e22634f1', '2025-02-10T23:16:59.927368', 'Emergency Visit', 'Patient presented for acute headache and dizziness. Blood pressure was elevated at 180/110 mmHg, heart rate 92 bpm. Physical examination revealed no focal neurological deficits. Assessment: Hypertensive crisis likely secondary to non-adherence to medication regimen. Plan: Administered IV labetalol and advised strict adherence to antihypertensive therapy and follow-up with primary care for medication adjustment.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a4824912-b7c8-4d7d-bce4-69422c4750e3', '2025-09-30T23:17:04.536539', 'Follow-up Visit', 'Patient presented for follow-up evaluation of a skin tear on the right forearm. Physical examination revealed a 3 cm superficial laceration with mild erythema but no signs of infection. Blood pressure was 138/82 mmHg and heart rate was 76 bpm. Assessment: Healing skin tear, secondary to fragile skin likely related to age and medication use. Recommended continued use of protective dressing and advised moisturizing to enhance skin integrity. Plan to reassess in two weeks or sooner if signs of infection develop.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a4824912-b7c8-4d7d-bce4-69422c4750e3', '2025-08-07T23:17:04.536539', 'Consultation', 'Patient presented for evaluation of a skin tear on the right forearm. The tear measured approximately 3 cm with mild surrounding erythema and no signs of infection. Blood pressure was 138/82 mmHg, and heart rate was 78 bpm. Assessment indicated a superficial skin tear likely due to fragile skin secondary to age and possibly hypertension. Recommended gentle cleansing, application of a non-adhesive dressing, and monitoring for signs of infection. Discussed importance of using protective clothing and moisturizing to prevent further incidents. Follow-up in one week or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a4824912-b7c8-4d7d-bce4-69422c4750e3', '2025-04-29T23:17:04.536539', 'Annual Checkup', 'Patient presented for an annual checkup and evaluation of a skin tear sustained on the right forearm. Blood pressure was 142/86 mmHg, heart rate was 72 bpm, and BMI was 27.2 kg/m². The skin tear measured approximately 3 cm, with minimal bleeding and no signs of infection. Recommended keeping the area clean and applying a non-adherent dressing. Continued management of hyperlipidemia and hypertension was advised, with a follow-up in three months to reassess blood pressure control.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a4824912-b7c8-4d7d-bce4-69422c4750e3', '2025-03-27T23:17:04.536539', 'Consultation', 'Patient presented for evaluation of a skin tear on the left forearm. Physical examination revealed a superficial laceration approximately 3 cm in length, with mild erythema but no signs of infection. Blood pressure was 142/88 mmHg, heart rate 78 bpm. The wound was cleansed and dressed; the patient was advised to keep the area clean and dry, and to return if signs of infection develop. Regular follow-up for hypertension and hyperlipidemia was recommended.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a4824912-b7c8-4d7d-bce4-69422c4750e3', '2024-11-12T23:17:04.536539', 'Annual Checkup', 'Patient presented for an annual checkup and evaluation of a recent skin tear on the right forearm. Blood pressure was 145/88 mmHg, and heart rate was 78 bpm. The skin tear appeared superficial with minimal surrounding erythema and no signs of infection. Assessment: Hypertension remains controlled; skin tear healing appropriately. Recommendations include continuing current antihypertensive regimen, monitoring cholesterol levels, and applying a sterile dressing to the skin tear with follow-up if signs of infection occur.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a2ec4855-111a-47b8-865c-7466c4f2bf0e', '2025-11-03T23:17:16.207109', 'Follow-up Visit', 'Patient presented for a routine follow-up visit. Vital signs were stable with BP 110/70 mmHg, HR 72 bpm. Skin examination showed mild xerosis associated with eczema, no acute exacerbations. Previous fracture was well-healed with no residual issues. Recommended continued use of emollients for eczema management and advised a balanced diet and regular physical activity. Follow-up in one year unless symptoms change.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a2ec4855-111a-47b8-865c-7466c4f2bf0e', '2025-07-08T23:17:16.207109', 'Follow-up Visit', 'Patient presented for a routine follow-up general checkup. Vitals were stable: BP 110/70 mmHg, HR 72 bpm, afebrile. Skin examination showed mild eczema on the inner arms, consistent with history, but no acute exacerbation. Previous fracture site on the left forearm was well-healed with no tenderness. Recommended continued use of emollient for eczema management and reviewed fracture care; advised follow-up in one year or sooner if symptoms arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4ad1f8bf-4c78-4ae2-9ae2-f90f7451369f', '2025-12-03T23:17:20.407032', 'Urgent Care', 'Patient presented for evaluation of acute shortness of breath and wheezing. Vitals: BP 118/76 mmHg, HR 88 bpm, SpO2 94% on room air. Physical examination revealed diffuse expiratory wheezes upon auscultation. Assessment indicated an exacerbation of asthma likely triggered by seasonal allergies. Administered nebulized albuterol with observed improvement in respiratory status. Recommended continuation of inhaled corticosteroid and advised follow-up with primary care for asthma management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4ad1f8bf-4c78-4ae2-9ae2-f90f7451369f', '2025-09-03T23:17:20.407032', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were within normal limits: BP 118/76 mmHg, HR 72 bpm, RR 16/min, and SpO2 98% on room air. Patient reported no new concerns but noted increased frequency of asthma symptoms, particularly during high pollen periods. Recommended continuation of current inhaler regimen and advised starting a daily antihistamine during peak allergy seasons. Follow-up in 6 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('74f8d825-ae49-4b92-8bf7-7be5cc1ba72e', '2025-12-31T23:17:23.378340', 'Follow-up Visit', 'Patient presented for follow-up visit regarding prediabetes management and assessment of GERD symptoms. Vital signs were stable with BP 128/82 mmHg and HR 76 bpm. Patient reported occasional heartburn, managed with over-the-counter antacids, and no significant changes in vision. Recommended continuation of lifestyle modifications including diet and exercise for glycemic control, and advised ophthalmology consultation for cataracts. Follow-up in 6 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('74f8d825-ae49-4b92-8bf7-7be5cc1ba72e', '2025-09-29T23:17:23.378340', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were as follows: BP 130/85 mmHg, HR 72 bpm, BMI 28.5. Patient reported no new symptoms but noted occasional heartburn consistent with his history of GERD. Physical exam was unremarkable. Assessment: Stable prediabetes with well-managed GERD and history of cataracts. Plan included continuing current lifestyle modifications for prediabetes, recommending annual ophthalmology follow-up for cataracts, and advising on dietary adjustments to further manage GERD symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('74f8d825-ae49-4b92-8bf7-7be5cc1ba72e', '2025-05-13T23:17:23.378340', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding prediabetes management. Vital signs recorded: BP 128/78 mmHg, HR 72 bpm. Patient reported no new symptoms but expressed concerns about maintaining blood sugar levels. Advised continuation of current dietary modifications and to increase physical activity to at least 150 minutes per week. Recommended repeat HbA1c testing in 3 months to monitor glycemic control. Reviewed current medications for GERD and ensured no interactions with lifestyle changes. Cataracts remain stable; no immediate intervention required.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b5beca0b-907b-4d45-a992-06a48c7298b4', '2025-12-31T23:17:29.315472', 'Consultation', 'Patient presented for evaluation of a persistent rash associated with contact dermatitis. On examination, there were erythematous patches with mild scaling over the ventral forearms, consistent with dermatitis; no signs of infection were noted. Recommended avoiding known irritants, applying a topical corticosteroid cream twice daily, and reassessing in two weeks if symptoms persist. Vital signs were stable: BP 98/60 mmHg, HR 85 bpm.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b5beca0b-907b-4d45-a992-06a48c7298b4', '2025-10-04T23:17:29.315472', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: Blood Pressure 102/68 mmHg, Heart Rate 82 bpm, Respiratory Rate 18 breaths per minute, and Temperature 98.1°F. Physical examination revealed mild erythematous rash on the forearms consistent with contact dermatitis; no other abnormalities noted. Recommended continued avoidance of known irritants and application of emollient creams as needed. Follow-up in one year or sooner if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b5beca0b-907b-4d45-a992-06a48c7298b4', '2025-02-15T23:17:29.315472', 'Annual Checkup', 'Patient presented for an annual checkup with a current condition of contact dermatitis. Vital signs were within normal limits: BP 100/65 mmHg, HR 80 bpm, RR 18 breaths/min, Temp 98.6°F. The dermatitis was noted on the left forearm, with erythema and mild pruritus. Recommended continued use of topical corticosteroids and avoidance of known irritants. Follow-up in 6 months or as needed if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('89d95312-af58-4674-add1-73a0c40f2b91', '2025-12-09T23:17:34.436303', 'Follow-up Visit', 'Patient presented for follow-up on hay fever and ongoing management of anemia and moderate depression. Vitals were stable: BP 118/76 mmHg, HR 72 bpm. Patient reported improved control of hay fever symptoms with current antihistamine regimen but noted increased fatigue over the past month. Hemoglobin levels were reviewed, showing slight improvement, indicating compliance with iron therapy. Recommended continuation of current treatment plan, with emphasis on adherence to iron supplementation and scheduled follow-up with psychiatry for depression management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('89d95312-af58-4674-add1-73a0c40f2b91', '2025-09-17T23:17:34.436303', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were stable with BP 118/76 mmHg and HR 72 bpm. Patient reported seasonal exacerbation of hay fever symptoms, including nasal congestion and sneezing, managed with OTC antihistamines. Anemia remains stable under current treatment; CBC to be repeated in 3 months. Moderate depression is controlled with current medication; recommended continuation of current therapy and follow-up with mental health provider as scheduled. Advised on lifestyle modifications for allergy management and encouraged regular follow-ups for chronic conditions.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('89d95312-af58-4674-add1-73a0c40f2b91', '2025-03-10T23:17:34.436303', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding hay fever and ongoing anemia treatment. Blood pressure was 118/76 mmHg, heart rate 72 bpm. Patient reported increased nasal congestion and sneezing, consistent with seasonal allergies; no significant changes in anemia symptoms. Recommended continuation of current antihistamine regimen and iron supplementation, with a review of mental health support strategies for depression management. Follow-up in three months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('575714b0-d28a-4217-9adf-31d5d64128aa', '2026-02-22T23:17:40.586464', 'Follow-up Visit', 'Patient presented for follow-up of a jammed finger sustained during basketball practice two weeks prior. On examination, the left index finger showed mild swelling and tenderness with limited range of motion, but no deformity or bruising was noted. The patient reported reduced pain compared to the initial injury. Recommended continued use of ice and elevation, and advised gentle range of motion exercises. Discussed anxiety management briefly, with no acute concerns noted at this visit. Vitals: BP 110/70, HR 78, afebrile.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('575714b0-d28a-4217-9adf-31d5d64128aa', '2025-06-29T23:17:40.586464', 'Annual Checkup', 'Patient presented for an annual checkup and evaluation of a jammed finger. Physical examination revealed mild swelling and tenderness on the right index finger, with a full range of motion intact. Vitals were within normal limits: BP 110/70 mmHg, HR 75 bpm. Assessment included a jammed finger likely due to recent sports activity, with no fractures suspected; anxiety remains stable. Recommended applying ice and using a splint as needed for the finger, along with a referral to a counselor for ongoing management of anxiety.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('575714b0-d28a-4217-9adf-31d5d64128aa', '2025-03-01T23:17:40.586464', 'Annual Checkup', 'Patient presented for an annual checkup with a complaint of a jammed finger sustained during a basketball game last week. On examination, the left index finger showed mild swelling and tenderness, but no significant deformity or restricted range of motion was noted. Blood pressure was 112/70 mmHg and heart rate was 78 bpm, both within normal limits for age. Managed with reassurance, advised ice application, and to monitor for any worsening symptoms. Discussed ongoing management strategies for anxiety, including potential referral for cognitive behavioral therapy.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('92bceb81-2139-4deb-a17d-8f25cef537dd', '2026-01-17T23:17:47.646913', 'Consultation', 'Patient presented for evaluation of viral gastroenteritis. Physical examination revealed mild dehydration; the patient appeared lethargic but responsive. Vitals were as follows: HR 120 bpm, RR 28 breaths/min, temperature 38.2°C. Recommended oral rehydration solution every 4 hours and advised parents to monitor for signs of dehydration or worsening symptoms. Follow-up visit scheduled in 3 days or sooner if symptoms escalate.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('92bceb81-2139-4deb-a17d-8f25cef537dd', '2025-08-15T23:17:47.646913', 'Annual Checkup', 'Patient presented for an annual checkup. Recent onset of viral gastroenteritis noted; parents report mild diarrhea and vomiting over the past 3 days. Vitals: HR 110 bpm, RR 28 breaths/min, temperature 37.5°C, weight and height tracking appropriately for age. Physical examination revealed mild dehydration, but no acute distress. Assessment: Viral gastroenteritis likely self-limiting. Plan: Encourage oral rehydration with electrolyte solutions, monitor for any worsening symptoms, follow-up if symptoms persist beyond one week, and continue antihistamines as needed for hay fever.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('92bceb81-2139-4deb-a17d-8f25cef537dd', '2025-07-06T23:17:47.646913', 'Follow-up Visit', 'Patient presented for a follow-up visit for viral gastroenteritis. On examination, the patient appeared alert and hydrated, with no signs of distress. Vital signs were stable: HR 110 bpm, RR 30/min, BP 90/60 mmHg, temp 98.6°F. Gastrointestinal symptoms have improved; diarrhea episodes have decreased, and oral intake has increased. Assessment: resolving viral gastroenteritis. Plan: continue supportive care with oral rehydration and monitor for any recurrence of symptoms. Follow-up in one week if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('92bceb81-2139-4deb-a17d-8f25cef537dd', '2025-03-15T23:17:47.646913', 'Urgent Care', 'Patient presented for acute onset of diarrhea and vomiting, characteristic of viral gastroenteritis. Vitals were as follows: HR 110 bpm, RR 28 breaths/min, Temp 101.2°F. Physical exam revealed mild dehydration and moderate abdominal tenderness without guarding. Assessment indicated self-limiting viral gastroenteritis; advised oral rehydration solutions and monitoring of hydration status. Recommended follow-up with primary care if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('92bceb81-2139-4deb-a17d-8f25cef537dd', '2025-01-03T23:17:47.646913', 'Follow-up Visit', 'Patient presented for a follow-up visit for viral gastroenteritis. Mother reports that diarrhea has decreased in frequency, but mild dehydration is still a concern. Physical examination showed the patient is alert and responsive, with mild dry mucous membranes. Vitals were stable: HR 110 bpm, RR 26 breaths/min, no fever. Assessment indicated improvement in gastroenteritis symptoms. Recommended continued oral rehydration solutions and monitoring for any signs of worsening dehydration. Follow-up in one week or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('92bceb81-2139-4deb-a17d-8f25cef537dd', '2024-11-24T23:17:47.646913', 'Follow-up Visit', 'Patient presented for a follow-up visit for viral gastroenteritis. Mother reported improvement in symptoms with decreased frequency of diarrhea and vomiting. On examination, the patient was afebrile with a heart rate of 110 bpm and appeared well-hydrated. Recommended continuation of oral rehydration solutions and gradual reintroduction of age-appropriate diet. Advised to monitor for any signs of dehydration and return if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('371653d2-c9b8-43cd-99e0-e670eb174166', '2025-12-10T23:17:59.525549', 'Follow-up Visit', 'Patient presented for a follow-up visit to monitor hypertension and hyperlipidemia management. Vital signs showed BP 145/90 mmHg, HR 82 bpm. Patient reported mild knee pain consistent with osteoarthritis and occasional fatigue, but no new symptoms. Assessment indicated suboptimal blood pressure control and persistent obesity. Recommended continuation of current antihypertensive regimen with addition of dietary counseling for weight management and lipid control, and referred patient to physical therapy for osteoarthritis-related mobility improvement. Follow-up in 3 months.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('371653d2-c9b8-43cd-99e0-e670eb174166', '2025-07-08T23:17:59.525549', 'Follow-up Visit', 'Patient presented for a follow-up visit to monitor chronic conditions. Vital signs were as follows: BP 145/90 mmHg, HR 78 bpm, weight 102 kg. Notable symptoms included joint pain likely due to osteoarthritis, with no new complaints reported. Assessment indicated well-controlled hypertension with current medication; however, obesity management remains a priority. Recommended continuation of antihypertensive and lipid-lowering medications, and encouraged lifestyle modifications including diet and exercise to address weight management. Follow-up in 3 months to reassess progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('371653d2-c9b8-43cd-99e0-e670eb174166', '2025-03-15T23:17:59.525549', 'Follow-up Visit', 'Patient presented for a follow-up visit concerning management of obesity, hypertension, and hyperlipidemia. Vital signs revealed a blood pressure of 148/92 mmHg and heart rate of 78 bpm. Physical examination noted bilateral knee crepitus associated with osteoarthritis. Recommended continuation of antihypertensive and lipid-lowering medications, with encouragement to increase physical activity and dietary modifications to aid in weight reduction. Follow-up in 3 months to assess progress and adjust treatment as necessary.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('371653d2-c9b8-43cd-99e0-e670eb174166', '2024-12-08T23:17:59.525549', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs showed BP 145/90 mmHg, HR 78 bpm, weight consistent with obesity, BMI 32.5. Physical examination indicated limited range of motion in knees, consistent with osteoarthritis. Assessment revealed uncontrolled hypertension and hyperlipidemia. Recommended dietary modifications and increased physical activity, and adjusted antihypertensive and statin therapy. Follow-up in 3 months to reassess blood pressure and lipid levels.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('371653d2-c9b8-43cd-99e0-e670eb174166', '2024-08-21T23:17:59.525549', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs: BP 142/88 mmHg, HR 78 bpm. Physical exam revealed BMI of 32, consistent with obesity, and limited range of motion in knees due to osteoarthritis. Lipid panel from recent labs showed elevated LDL cholesterol. Recommended continuation of antihypertensive and statin therapy, along with initiation of a structured weight loss program and referral to physical therapy for osteoarthritis management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('7e805d81-a9a9-4b68-a87f-7b72bcad1f25', '2025-10-10T23:18:09.468577', 'Follow-up Visit', 'Patient presented for follow-up concerning persistent low back pain. Vital signs were stable: BP 120/80 mmHg, HR 72 bpm. The patient reported a moderate improvement in pain symptoms with physical therapy but still experiences stiffness in the morning and occasional shooting pains. Assessment indicated a likely exacerbation of underlying arthritis. Recommended continuation of physical therapy, advised on ergonomic adjustments at work, and prescribed a non-steroidal anti-inflammatory drug (NSAID) for breakthrough pain management. Follow-up in 4 weeks to reassess pain and functionality.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('7e805d81-a9a9-4b68-a87f-7b72bcad1f25', '2025-08-09T23:18:09.468577', 'Consultation', 'Patient presented for consultation regarding persistent low back pain, reporting a pain level of 6/10. Vital signs were stable: BP 120/80 mmHg, HR 72 bpm. Physical examination revealed tenderness in the lumbar region with limited range of motion. Assessment included exacerbation of chronic low back pain likely related to existing arthritis. Recommended physical therapy, continuation of NSAIDs, and follow-up in 4 weeks to assess progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b7c9b6a9-224c-436a-b2be-d0dac8279fdc', '2025-12-29T23:18:12.837611', 'Emergency Visit', 'Patient presented for evaluation of a contusion on the right forehead sustained from a fall at home. Physical examination revealed a 3 cm bruise with mild swelling, no laceration, and no signs of neurological compromise. Vital signs: HR 110 bpm, RR 22 breaths/min, temperature 98.6°F, BP not applicable due to age. Assessment indicated a minor contusion with no cranial injury. Recommended application of a cold compress, monitoring for signs of concussion, and follow-up with pediatrician if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b7c9b6a9-224c-436a-b2be-d0dac8279fdc', '2025-07-29T23:18:12.837611', 'Follow-up Visit', 'Patient presented for follow-up of a contusion sustained during a fall. The area of contusion, located on the left knee, showed reduced swelling and bruising compared to the initial visit. No signs of infection were noted. Vital signs were within normal limits: BP 90/60 mmHg, HR 100 bpm. Continued application of ice and elevation were recommended, with a follow-up to be scheduled if symptoms persist.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b7c9b6a9-224c-436a-b2be-d0dac8279fdc', '2025-06-21T23:18:12.837611', 'Annual Checkup', 'Patient presented for annual checkup and evaluation of a contusion sustained on the right shin. Vitals: HR 98 bpm, RR 22, Temp 98.6°F. Physical examination revealed a 3 cm ecchymosis on the right shin, no swelling or tenderness noted. Assessment: Bruise healing well, no signs of infection. Plan: Continue monitoring the site for any changes, apply cold compress to reduce any residual swelling, and advise parental supervision to prevent further injury.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('fb48bfc1-6a15-493e-b817-0360e0ecfff3', '2025-10-14T23:18:18.013489', 'Consultation', 'Patient presented for a general checkup. Vital signs were within normal limits: BP 98/62 mmHg, HR 88 bpm, Temp 98.6°F, RR 18 breaths/min. Skin examination revealed mild eczema on the antecubital fossae, consistent with past medical history. Recommended continuing use of emollients and topical corticosteroids as needed. Discussed importance of skin hydration and avoiding known irritants. Follow-up in one year or as needed for exacerbations.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('fb48bfc1-6a15-493e-b817-0360e0ecfff3', '2025-09-17T23:18:18.013489', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were within normal limits: BP 100/65 mmHg, HR 85 bpm, temperature 98.4°F. Skin examination revealed mild eczema on the antecubital fossae with no signs of infection. Recommended continued use of emollients and hydrocortisone cream as needed. No other abnormalities noted. Follow-up in one year or as needed if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b3f70727-6d74-43ae-aa8f-b4051f411e26', '2025-10-25T23:18:20.995424', 'Follow-up Visit', 'Patient presented for follow-up evaluation of Hand, Foot, and Mouth Disease. Upon examination, vesicular lesions were noted on the hands and feet, but oral lesions have decreased in number. Vital signs were stable: HR 92 bpm, Temp 37.0°C. Assessment indicated improvement, with no complications observed. Advised continuation of supportive care with hydration and pain management as needed. Recommended follow-up if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b3f70727-6d74-43ae-aa8f-b4051f411e26', '2025-09-28T23:18:20.995424', 'Consultation', 'Patient presented for evaluation of rash and fever. Physical examination revealed vesicular lesions on the hands, feet, and oral mucosa, consistent with Hand, Foot, and Mouth Disease. Patient was afebrile at the time of visit, with HR: 100 bpm, and RR: 22 breaths per minute. Assessment confirmed viral etiology. Recommended supportive care including adequate hydration, antipyretics for fever management, and monitoring for any complications. Follow-up advised if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8d75f6d8-2662-45ee-ad30-e24b8912f200', '2025-11-06T23:18:24.716678', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding hypothyroidism management. Vital signs were stable: BP 128/82 mmHg, HR 76 bpm. Patient reported mild fatigue and occasional palpitations, with no significant changes in weight or mood. TSH levels were reviewed, and current levothyroxine dosage was deemed appropriate. Recommended continuation of current medication regimen, with a follow-up lab test in 3 months to reassess thyroid function. Advised on lifestyle modifications to manage anxiety and hyperlipidemia, including regular exercise and a heart-healthy diet.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8d75f6d8-2662-45ee-ad30-e24b8912f200', '2025-08-01T23:18:24.716678', 'Consultation', 'Patient presented for follow-up consultation regarding management of hypothyroidism. Vitals were stable with BP 128/78 mmHg, HR 72 bpm. She reported experiencing persistent fatigue and mild weight gain despite current levothyroxine regimen. Assessment indicated possible suboptimal thyroid hormone levels. Recommended adjusting levothyroxine dosage and scheduled follow-up lab tests to evaluate thyroid function. Additionally, advised continuation of current medications for anxiety, GERD, hyperlipidemia, and allergic rhinitis.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4aa925c2-1b0a-4a9c-8263-27fcd4095236', '2026-01-18T23:18:28.197498', 'Consultation', 'Patient presented for evaluation of a contusion on the right forearm sustained from a fall. Physical examination revealed a 5 cm ecchymosis with mild edema; no signs of fracture or dislocation were noted. Vitals were within normal limits: HR 88 bpm, RR 20 breaths/min, BP 102/64 mmHg. Assessment indicated a simple contusion with no complications. Recommended conservative management with ice application, elevation, and over-the-counter analgesics as needed. Follow-up advised if symptoms persist or worsen. Speech delay was noted in history; no acute concerns related to this condition were discussed during this visit.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4aa925c2-1b0a-4a9c-8263-27fcd4095236', '2025-10-09T23:18:28.197498', 'Emergency Visit', 'Patient presented for evaluation following a fall resulting in a contusion to the right knee. Physical examination revealed mild swelling and bruising without significant tenderness or restriction in range of motion. Vitals were stable: BP 100/60 mmHg, HR 90 bpm, RR 20/min, Temp 98.6°F. Assessment confirmed soft tissue injury without evidence of fracture. Recommended rest, ice application, and elevation of the affected area, with over-the-counter analgesics as needed for pain management. Follow-up advised if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4aa925c2-1b0a-4a9c-8263-27fcd4095236', '2025-04-19T23:18:28.197498', 'Follow-up Visit', 'Patient presented for follow-up of contusion sustained approximately 7 days prior. Physical examination revealed mild ecchymosis on the left lower extremity with no significant swelling or tenderness. No new symptoms reported. Recommended continued application of cold compress and monitoring for any changes. Follow-up with speech therapy for ongoing speech delay was also advised. Vitals: BP 90/60 mmHg, HR 88 bpm, Temp 98.6°F, RR 20 breaths/min.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('45be7811-0706-469a-88d5-c130be31d038', '2026-02-10T23:18:33.270947', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 142/88 mmHg, heart rate 78 bpm. Patient reports occasional shortness of breath and joint pain consistent with osteoarthritis; no acute distress observed. Assessment: Hypertension remains suboptimally controlled; obesity and diabetes management require ongoing monitoring. Recommendations included continuation of current antihypertensive therapy, initiation of a low-impact exercise regimen, and dietary modifications to address obesity and hyperlipidemia. Follow-up in 3 months for further evaluation of blood pressure and metabolic control.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('45be7811-0706-469a-88d5-c130be31d038', '2025-06-22T23:18:33.270947', 'Follow-up Visit', 'Patient presented for a follow-up visit for hypertension management. Blood pressure was 142/88 mmHg, heart rate 78 bpm. She reported occasional dizziness and increased joint pain, likely associated with osteoarthritis. Recommended continuing current antihypertensive regimen and advised weight management strategies to address obesity and improve overall joint health. Suggested follow-up in three months for reevaluation and potential adjustment of diabetic medication due to prediabetes progression.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('45be7811-0706-469a-88d5-c130be31d038', '2025-06-06T23:18:33.270947', 'Follow-up Visit', 'Patient presented for a follow-up visit to manage hypertension. Vital signs revealed blood pressure at 150/90 mmHg and heart rate at 78 bpm. Physical examination was unremarkable except for mild crepitus in both knees related to osteoarthritis. Continued current antihypertensive regimen, advised dietary modifications to address hyperlipidemia and prediabetes, and recommended regular low-impact exercise to improve joint function and weight management. Follow-up in three months for reassessment and blood work.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('45be7811-0706-469a-88d5-c130be31d038', '2025-03-07T23:18:33.270947', 'Consultation', 'Patient presented for routine follow-up of hypertension management. Blood pressure was 150/88 mmHg, and heart rate was 78 bpm. Physical exam revealed mild bilateral knee crepitus with pain on movement, consistent with osteoarthritis. Recommended continuation of current antihypertensive regimen, initiation of low-impact exercise to aid weight management, and referral to physical therapy for joint support. Adjusted statin dosage to better manage hyperlipidemia and advised monitoring fasting glucose levels due to prediabetes history.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('45be7811-0706-469a-88d5-c130be31d038', '2024-12-11T23:18:33.270947', 'Consultation', 'Patient presented for routine consultation and management of chronic conditions. Blood pressure was elevated at 150/88 mmHg, and heart rate was 72 bpm. Assessment indicated suboptimal control of hypertension and diabetes, with HbA1c noted at 7.6% from recent labs. Recommended adjustment of antihypertensive medication and initiation of lifestyle modifications, including increased physical activity and dietary adjustments to address weight management and glycemic control. Follow-up scheduled in 3 months to reassess blood pressure and glucose levels.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c5704643-06bf-4a43-9457-9827117c828c', '2026-02-18T23:18:44.683708', 'Emergency Visit', 'Patient presented for acute onset dyspnea and chest tightness. Vital signs revealed BP 138/85 mmHg, HR 92 bpm, RR 24 breaths/min, and SpO2 96% on room air. Examination noted nasal congestion and bilateral wheezing on auscultation. Assessment indicated exacerbation of allergic rhinitis potentially leading to asthma-like symptoms. Recommended initiation of inhaled corticosteroid therapy and continued use of oral antihistamines, with a follow-up in two weeks or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c5704643-06bf-4a43-9457-9827117c828c', '2025-09-10T23:18:44.683708', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were stable, with BP at 118/76 mmHg and HR at 72 bpm. Reported ongoing issues with hay fever, experiencing nasal congestion and sneezing. Physical exam revealed clear nasal discharge and posterior pharyngeal erythema. Assessment: Allergic rhinitis managed with current antihistamine regimen. Recommended continuation of current medication and advised to use a saline nasal spray as needed for congestion relief. Suggested follow-up if symptoms worsen or new symptoms arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('db2a47f8-ecdd-437d-ab54-c26dfe970f9b', '2026-01-31T23:18:48.270123', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 128/82 mmHg, heart rate was 76 bpm, and BMI was 32.1, consistent with obesity class 1. Respiratory exam was unremarkable with no wheezing noted, and asthma was reported as well-controlled with current inhaler regimen. Recommended continuation of asthma management plan and discussed lifestyle modifications for weight management, including dietary changes and increased physical activity. Follow-up in six months to evaluate progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('db2a47f8-ecdd-437d-ab54-c26dfe970f9b', '2025-09-08T23:18:48.270123', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs: BP 130/85 mmHg, HR 78 bpm, BMI 32 kg/m². Patient reported no acute respiratory symptoms; asthma remains stable with current medication regimen. Recommended weight management through dietary modification and increased physical activity. Follow-up in six months to monitor weight and asthma control.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('9b4e4d0c-5bea-4e50-8976-7c43323cadb7', '2026-02-23T23:18:51.365378', 'Emergency Visit', 'Patient presented for evaluation of a contusion on the right forearm sustained from a fall. On examination, there was localized swelling and tenderness with no open wounds or signs of infection. Vitals stable: BP 128/82 mmHg, HR 76 bpm, RR 18/min, Temp 98.6°F. Advised rest, application of ice, and elevation of the affected limb. Prescribed ibuprofen for pain management. Follow-up with primary care recommended for monitoring and management of underlying conditions: GERD, hyperlipidemia, and hypertension.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('9b4e4d0c-5bea-4e50-8976-7c43323cadb7', '2025-06-09T23:18:51.365378', 'Annual Checkup', 'Patient presented for an annual checkup and follow-up on existing conditions. Vitals were recorded as BP 138/85 mmHg and HR 78 bpm. The patient reported a recent contusion on the right forearm, which appeared to be healing well with no signs of infection. GERD, hyperlipidemia, and hypertension were stable on current medications. Recommended continuation of current treatment regimen and advised maintaining a low-sodium diet and regular exercise. Scheduled follow-up in six months or as needed.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e6d5a0b1-9f35-4cd7-bdca-dfe0da6775fb', '2026-01-29T23:18:54.822584', 'Follow-up Visit', 'Patient presented for follow-up on gallstones. Vital signs were stable with BP 128/82 mmHg and HR 76 bpm. Patient reported intermittent right upper quadrant pain but no fever or jaundice. Physical examination revealed mild tenderness in the right upper quadrant. Recommended continuation of low-fat diet and scheduled for a surgical consultation regarding potential cholecystectomy. Advised to monitor for any signs of acute cholecystitis and return if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e6d5a0b1-9f35-4cd7-bdca-dfe0da6775fb', '2025-09-03T23:18:54.822584', 'Urgent Care', 'Patient presented for severe right upper quadrant abdominal pain, nausea, and vomiting, consistent with symptomatic gallstones. Vital signs: BP 128/82 mmHg, HR 88 bpm, Temp 98.6°F. Physical examination revealed tenderness in the right upper quadrant with a positive Murphy''s sign. Recommended ultrasound of the abdomen to evaluate gallbladder and possible surgical consultation for cholecystectomy. Advised dietary modifications and prescribed analgesics for pain management. Follow-up in 1 week or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e6d5a0b1-9f35-4cd7-bdca-dfe0da6775fb', '2025-08-10T23:18:54.822584', 'Emergency Visit', 'Patient presented for evaluation of acute abdominal pain. Vital signs were stable: BP 128/82 mmHg, HR 76 bpm, afebrile. Physical examination revealed tenderness in the right upper quadrant. Assessment indicated symptomatic cholelithiasis. Recommended dietary modifications, pain management with NSAIDs, and surgical consultation for potential cholecystectomy.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('110079ec-a042-4255-92c1-3598f7cfe342', '2026-01-16T23:18:59.225011', 'Annual Checkup', 'Patient presented for an annual checkup and evaluation of impetigo. Physical examination revealed multiple honey-colored crusted lesions consistent with impetigo on the face and extremities. Vital signs were stable: HR 98 bpm, RR 20 breaths/min, and BP 92/60 mmHg. Asthma remained well-controlled with no recent exacerbations. Recommended continuation of topical antibiotic treatment for impetigo and advised follow-up if lesions do not improve within one week. Reinforced asthma action plan and suggested annual influenza vaccination.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('110079ec-a042-4255-92c1-3598f7cfe342', '2025-09-04T23:18:59.225011', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding impetigo. Physical examination revealed crusted lesions on the face with mild erythema and no signs of secondary infection. The patient’s asthma is well-controlled; lungs were clear to auscultation. Recommended continuation of topical mupirocin and advised maintaining proper skin hygiene. Follow-up in one week to reassess skin condition.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('110079ec-a042-4255-92c1-3598f7cfe342', '2025-05-04T23:18:59.225011', 'Annual Checkup', 'Patient presented for an annual checkup. Noted erythematous lesions with a honey-colored crust around the nose and mouth consistent with impetigo. Vital signs were within normal limits: BP 90/60 mmHg, HR 100 bpm, RR 24 breaths/min. History of asthma was considered; no wheezing or respiratory distress observed. Recommended topical antibiotic ointment for impetigo and to continue current asthma management plan. Advised follow-up in one week if lesions do not improve.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('110079ec-a042-4255-92c1-3598f7cfe342', '2025-02-15T23:18:59.225011', 'Annual Checkup', 'Patient presented for an annual checkup with a recent diagnosis of impetigo. Physical examination revealed erythematous lesions with honey-colored crusts on the face and arms, consistent with impetigo. Vitals were stable with BP 98/62, HR 90 bpm, RR 20 breaths/min, Temp 98.6°F. Assessment confirmed impetigo with a history of asthma, currently well-controlled. Recommended continuation of topical antibiotics for impetigo and reinforced asthma action plan. Follow-up in two weeks advised to reassess skin condition.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5d081dbe-7d97-46ec-a12d-bf8cb08f4d24', '2025-11-06T23:19:08.339079', 'Consultation', 'Patient presented for a follow-up consultation regarding obesity management. Vitals were recorded as BP 142/88 mmHg, HR 78 bpm. Patient reported increased fatigue and difficulty maintaining physical activity. Assessment indicated weight gain since last visit; current BMI noted at 35.2 kg/m². Plan included dietary modification referral to a nutritionist, initiation of a structured exercise program, and consideration of pharmacotherapy for weight management. Follow-up scheduled in 3 months to reassess weight and cardiovascular risk factors.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5d081dbe-7d97-46ec-a12d-bf8cb08f4d24', '2025-10-24T23:19:08.339079', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding management of obesity, hypertension, and hyperlipidemia. Blood pressure was recorded at 142/88 mmHg, and heart rate was 78 bpm. The patient reported no new symptoms but expressed concerns about weight management. Recommended continuation of current antihypertensive and lipid-lowering therapy, and advised initiation of a structured weight loss program with dietary modifications and increased physical activity. Follow-up in 3 months to assess progress and adjust treatment plan as necessary.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5d081dbe-7d97-46ec-a12d-bf8cb08f4d24', '2025-08-13T23:19:08.339079', 'Follow-up Visit', 'Patient presented for routine follow-up regarding management of obesity, hypertension, and hyperlipidemia. Blood pressure was 142/88 mmHg, heart rate 78 bpm. Patient reported occasional headaches but denied chest pain or dyspnea. Weight management through dietary modifications and increased physical activity was emphasized. Continued current antihypertensive and statin therapy, with follow-up in three months to reassess blood pressure and lipid levels.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b8fc7318-03e3-4607-b43c-46ed2902dbe5', '2025-10-15T23:19:13.049189', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: BP 90/60, HR 100, RR 22, Temp 98.6°F. Physical examination was unremarkable with growth parameters within normal range for age. No symptoms or developmental concerns were noted. Recommended continuation of balanced diet, regular physical activity, and updated vaccinations as per schedule. Follow-up in one year unless new concerns arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b8fc7318-03e3-4607-b43c-46ed2902dbe5', '2025-10-08T23:19:13.049189', 'Follow-up Visit', 'Patient presented for a routine well-child follow-up visit. Vitals: HR 100 bpm, RR 22 breaths/min, weight 14 kg, height 92 cm, temperature 36.8°C. No significant abnormalities noted on physical examination; growth and development appropriate for age. Recommended continuation of routine vaccinations and advised parents on maintaining a balanced diet and regular physical activity. Follow-up scheduled in 6 months or as needed.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b8fc7318-03e3-4607-b43c-46ed2902dbe5', '2025-08-14T23:19:13.049189', 'Follow-up Visit', 'Patient presented for a follow-up visit as part of routine pediatric care. Vital signs were within normal limits: HR 100 bpm, RR 24 breaths/min, temperature 98.6°F. No current symptoms or abnormalities noted on physical examination. Recommended continuation of current growth and developmental surveillance and advised parents on maintaining a balanced diet and regular physical activity. Follow-up in one year unless concerns arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b8fc7318-03e3-4607-b43c-46ed2902dbe5', '2024-12-02T23:19:13.049189', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: BP 90/60 mmHg, HR 100 bpm, RR 24 breaths/min, Temp 98.6°F. Physical examination was unremarkable with normal growth parameters, appropriate for age. No current symptoms or concerns; development milestones met. Recommended routine vaccinations and advised to maintain a balanced diet and regular physical activity. Follow-up in one year unless otherwise indicated.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('bcaed7cf-6c56-4cd5-8e1f-9590d2043cd1', '2026-01-15T23:19:20.217227', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding gallstones. Blood pressure was 148/92 mmHg, and heart rate was 82 bpm. The patient reported intermittent right upper quadrant pain, consistent with gallstone symptoms, but denied jaundice or fever. Assessment indicated stable gallstone condition with no acute cholecystitis. Recommended dietary modifications to manage obesity and hyperlipidemia, and advised continued monitoring of blood glucose levels to manage diabetes effectively. Consideration for elective cholecystectomy was discussed if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('bcaed7cf-6c56-4cd5-8e1f-9590d2043cd1', '2025-08-22T23:19:20.217227', 'Follow-up Visit', 'Patient presented for follow-up regarding gallstones. Blood pressure was 142/88 mmHg and heart rate was 78 bpm. Patient reported intermittent upper abdominal pain consistent with previous gallstone symptoms, with no new symptoms of nausea or jaundice. Continued management with dietary modifications and scheduled for surgical consultation to evaluate candidacy for cholecystectomy. Advised ongoing control of diabetes and hypertension, and encouraged regular follow-up to monitor hyperlipidemia and obesity.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('bcaed7cf-6c56-4cd5-8e1f-9590d2043cd1', '2025-07-15T23:19:20.217227', 'Annual Checkup', 'Patient presented for annual checkup and management of gallstones. Blood pressure was 142/88 mmHg, heart rate 78 bpm. The patient reported intermittent right upper quadrant pain. Recommended continuation of low-fat diet and scheduled a follow-up ultrasound to monitor gallstones. Advised to maintain current medications for diabetes, hypertension, and hyperlipidemia. Encouraged weight management and regular physical activity to assist in controlling obesity and enhancing overall health.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a310558c-25d8-46ff-b60f-615c9aba0355', '2026-01-08T23:19:26.874355', 'Follow-up Visit', 'Patient presented for follow-up regarding gallstones. Vital signs were stable with blood pressure 138/85 mmHg and heart rate 78 bpm. He reported intermittent right upper quadrant pain, which has been manageable with dietary modifications and acetaminophen. Recommended continued low-fat diet and scheduled an ultrasound to assess for any changes in gallstones. Follow-up in 3 months unless symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a310558c-25d8-46ff-b60f-615c9aba0355', '2025-08-05T23:19:26.874355', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were recorded as follows: blood pressure 140/88 mmHg, heart rate 78 bpm, respiratory rate 16 breaths per minute, and BMI of 32.2 kg/m². The patient reported intermittent right upper quadrant pain, likely related to known gallstones, with no acute distress noted. Assessment included well-controlled hypertension and asthma, but obesity management was advised. Recommended continuation of current antihypertensive and asthma medications, with dietary modifications and increased physical activity to address obesity and mitigate gallstone symptoms. Follow-up in 6 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a310558c-25d8-46ff-b60f-615c9aba0355', '2025-06-27T23:19:26.874355', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 142/88 mmHg, heart rate 78 bpm. Patient reported mild, intermittent right upper quadrant abdominal pain likely due to gallstones; no acute exacerbation of asthma noted. Continued management of hypertension and obesity was discussed, and patient was advised to maintain a low-fat diet to manage gallstones. Follow-up in 6 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('7cc3cd00-6725-4425-ace7-b819d011689e', '2026-01-08T23:19:34.655927', 'Follow-up Visit', 'Patient presented for a follow-up visit for anxiety management. Vitals were stable: BP 110/70 mmHg, HR 72 bpm. Patient reported ongoing anxiety episodes, but noted some improvement with current therapy. Assessment revealed mild exacerbation of symptoms possibly due to recent academic stressors. Plan included continuing with cognitive behavioral therapy sessions, maintaining current medication regimen, and initiating mindfulness exercises. Follow-up scheduled in four weeks to monitor progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('7cc3cd00-6725-4425-ace7-b819d011689e', '2025-10-09T23:19:34.655927', 'Consultation', 'Patient presented for consultation regarding increased anxiety symptoms. Vital signs were stable: BP 110/70 mmHg, HR 76 bpm. She reported experiencing frequent episodes of restlessness and difficulty concentrating, particularly in school settings. Assessment indicated heightened anxiety potentially exacerbated by insomnia. Recommended cognitive behavioral therapy (CBT) and discussed potential benefits of adjusting sleep hygiene practices. Continue current medication for GERD and manage allergic rhinitis with OTC antihistamines as needed. Follow-up in 4 weeks to assess progress and adjust treatment plan accordingly.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('7cc3cd00-6725-4425-ace7-b819d011689e', '2025-03-05T23:19:34.655927', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding anxiety management. Blood pressure was 110/70 mmHg, heart rate was 72 bpm, and BMI was within normal range. The patient reported persistent anxiety symptoms with occasional insomnia, though GERD symptoms remain stable with current medication. Recommended continuation of cognitive behavioral therapy sessions and prescribed a low-dose SSRI to help manage anxiety symptoms. Advised follow-up in three months to assess medication efficacy and symptom progression.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c94df940-c709-4706-b410-8d2725a4c13d', '2025-12-01T23:19:40.288153', 'Urgent Care', 'Patient presented for evaluation of a pruritic rash on the forearms and neck, suspected to be contact dermatitis. Physical examination revealed erythematous, linear vesicular lesions on the aforementioned areas. Patient has a history of asthma, currently well-controlled with no acute respiratory symptoms noted. Recommended topical corticosteroid application and advised avoiding known irritants. Follow-up in one week if symptoms persist or worsen. Vital signs were stable: HR 88 bpm, BP 100/65 mmHg.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c94df940-c709-4706-b410-8d2725a4c13d', '2025-08-11T23:19:40.288153', 'Follow-up Visit', 'Patient presented for follow-up on contact dermatitis. Exam revealed erythematous, pruritic rash on bilateral forearms, with no signs of infection. Vitals were stable: BP 102/65 mmHg, HR 88 bpm, RR 18 breaths per minute, SpO2 98% on room air. Assessment indicated mild improvement in dermatitis, likely related to compliance with topical corticosteroid use. Recommended continuation of current treatment regimen and advised avoidance of known allergens. Follow-up in 4 weeks to reassess condition and manage any potential exacerbations.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c94df940-c709-4706-b410-8d2725a4c13d', '2025-02-28T23:19:40.288153', 'Follow-up Visit', 'Patient presented for follow-up of contact dermatitis. Physical examination revealed erythematous patches on the forearms and neck, with mild pruritus reported. Asthma remained stable with no recent exacerbations. Recommended continuation of topical corticosteroid application and advised avoidance of known allergens. Follow-up in 4 weeks to assess improvement. Vitals: BP 100/60 mmHg, HR 88 bpm, RR 18/min.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c94df940-c709-4706-b410-8d2725a4c13d', '2024-10-14T23:19:40.288153', 'Follow-up Visit', 'Patient presented for follow-up on contact dermatitis. The rash on the forearms appeared less erythematous with reduced pruritus since last visit. Vital signs were stable: BP 100/65 mmHg, HR 88 bpm. Assessment: Contact dermatitis, improving. Plan: Continue current topical corticosteroid as prescribed and avoid known allergens; follow up in 4 weeks or sooner if symptoms worsen. Asthma remains well-controlled with current medication regimen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('10ecef02-0d1e-4aca-9024-1cea097890f8', '2025-11-16T23:19:49.606870', 'Follow-up Visit', 'Patient presented for a follow-up visit to monitor asthma management. Physical examination revealed clear lung fields with no wheezing or rhonchi. Vitals were stable: BP 118/76 mmHg, HR 72 bpm, SpO2 98% on room air. Assessment indicated well-controlled asthma with no recent exacerbations. Recommended continuation of current inhaler regimen and advised on regular peak flow monitoring. Educated patient on the importance of avoiding known allergens and adhering to asthma action plan.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('10ecef02-0d1e-4aca-9024-1cea097890f8', '2025-06-12T23:19:49.606870', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: BP 118/76 mmHg, HR 72 bpm, RR 16 breaths/min, SpO2 98% on room air. Patient reported occasional wheezing and shortness of breath, particularly during exercise, consistent with asthma. Skin examination revealed mild eczema on the flexural surfaces. Advised continuation of current asthma management plan, including albuterol inhaler as needed, and recommended follow-up with allergist for allergic rhinitis management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a006fd5f-d649-46df-8c79-5de38e085f8e', '2025-10-29T23:19:53.293503', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals: HR 112 bpm, RR 24 breaths/min, BP not applicable for age, SpO2 98% on room air. Physical examination revealed mild wheezing on auscultation and scattered eczematous lesions on the antecubital fossae. Assessment: Asthma and eczema are stable; allergic rhinitis symptoms are under control. Plan: Continue current asthma management with inhaled corticosteroids and recommend moisturizer for eczema; follow up in 6 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a006fd5f-d649-46df-8c79-5de38e085f8e', '2025-06-13T23:19:53.293503', 'Follow-up Visit', 'Patient presented for follow-up of asthma management. Vitals were stable: HR 110 bpm, RR 24 breaths/min, SpO2 96% on room air. No acute respiratory distress noted, but mild wheezing was auscultated bilaterally. Assessment: asthma symptoms are partially controlled; recent increase in nighttime coughing reported. Plan: continue current inhaled corticosteroid regimen, increase frequency of use to twice daily, and review asthma action plan. Advised to follow up in 3 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('3f1aca75-7340-473f-a9cd-0babf8c2b787', '2025-12-08T23:19:57.592844', 'Follow-up Visit', 'Patient presented for follow-up after recent food poisoning episode. Reported improvement in nausea and abdominal cramps; no further vomiting or diarrhea. Vital signs: BP 145/88, HR 82 bpm. Assessment revealed stable condition with no signs of dehydration. Recommended continued hydration and resumption of regular diet as tolerated; advised monitoring blood glucose levels closely given history of diabetes. Suggested follow-up in 2 weeks to reassess overall health status, particularly in relation to hypertension and diabetes management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('3f1aca75-7340-473f-a9cd-0babf8c2b787', '2025-09-18T23:19:57.592844', 'Consultation', 'Patient presented for evaluation of acute gastrointestinal symptoms consistent with food poisoning, including nausea, vomiting, and diarrhea. Vital signs: BP 138/85 mmHg, HR 92 bpm, afebrile. Notable medical history includes GERD, obesity, and diabetes, which may exacerbate symptoms. Advised on hydration, dietary modifications, and close monitoring of blood glucose levels. Recommended follow-up if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('544b4d76-7613-4816-b664-9d50b34dbb02', '2025-12-16T23:20:00.766401', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 138/88 mmHg, HR 82 bpm, RR 16/min, SpO2 96% on room air, and BMI 32.3 kg/m². She reported occasional shortness of breath but no recent asthma exacerbations. Assessment confirmed stable asthma and well-managed diabetes, though noted suboptimal lipid control. Recommended continuation of current asthma management plan, adjustment in lipid-lowering therapy, and encouraged dietary modifications and increased physical activity for weight management. Follow-up in 6 months for lipid panel and diabetes management review.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('544b4d76-7613-4816-b664-9d50b34dbb02', '2025-07-03T23:20:00.766401', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding asthma and diabetes management. Vitals recorded: BP 130/85 mmHg, HR 78 bpm, SpO2 96% on room air. Patient reported increased wheezing and nocturnal cough over the past month. Assessment revealed suboptimal asthma control likely due to seasonal allergies. Recommended adjustment of inhaler therapy and initiation of a daily antihistamine. Advised lifestyle modifications for weight management and scheduled a follow-up visit in 3 months.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4316acf0-04f5-4efc-90d9-4adb568f77d2', '2026-01-16T23:20:05.580838', 'Urgent Care', 'Patient presented for an acute exacerbation of low back strain. Physical examination revealed lumbar tenderness with limited range of motion, but no radicular symptoms. Blood pressure was elevated at 142/88 mmHg, heart rate was 76 bpm. Assessment: Musculoskeletal strain likely aggravated by recent physical activity. Plan: Prescribed NSAIDs for pain management, recommended physical therapy, and advised follow-up with primary care for blood pressure monitoring and management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4316acf0-04f5-4efc-90d9-4adb568f77d2', '2025-08-23T23:20:05.580838', 'Annual Checkup', 'Patient presented for annual checkup with ongoing low back strain. Vitals: BP 138/85 mmHg, HR 78 bpm, RR 18 breaths/min, Temp 98.6°F. Physical exam revealed mild tenderness in the lumbar region with limited range of motion. Assessment included controlled hypertension, stable asthma, and GERD managed with medication. Recommended continuation of current medication regimen, advised gentle stretching exercises for back strain, and encouraged routine follow-up for hypertension management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4316acf0-04f5-4efc-90d9-4adb568f77d2', '2025-06-22T23:20:05.580838', 'Urgent Care', 'Patient presented for acute exacerbation of low back strain. Reported severe lumbar pain radiating to the left leg, worsened with movement. Vital signs noted: BP 142/88 mmHg, HR 76 bpm, RR 18 breaths/min. Physical examination revealed tenderness over the lumbar paraspinal muscles and limited range of motion. Assessment confirmed lumbar strain with radicular symptoms. Advised continuation of NSAIDs, initiation of physical therapy, and a follow-up with primary care for further management. Suggested lifestyle modifications to manage existing hypertension and GERD.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('72485e5a-515c-481f-9dfa-8a12b211d278', '2025-10-27T23:20:11.481937', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were within normal limits: BP 120/80 mmHg, HR 72 bpm, Temp 98.6°F, RR 16 breaths per minute. No acute symptoms reported; GERD and allergic rhinitis remain stable with current management. Recommended continuation of current medications, dietary modifications for GERD, and seasonal allergy precautions. Advised follow-up in one year or as needed for any new symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('72485e5a-515c-481f-9dfa-8a12b211d278', '2025-08-11T23:20:11.481937', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were as follows: BP 128/82 mmHg, HR 72 bpm, Temp 98.6°F. No acute distress noted; patient reported occasional heartburn managed with OTC antacids and persistent seasonal allergy symptoms. Recommended continuation of current GERD management, advised use of antihistamines for allergic rhinitis, and encouraged routine follow-up in one year or as needed for any new symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('92272e3c-7728-42e1-bd65-605ddaa05015', '2025-10-20T23:20:15.309497', 'Consultation', 'Patient presented for consultation regarding weight management and associated comorbidities. Vital signs recorded: BP 145/90 mmHg, HR 88 bpm. Physical examination revealed BMI of 32, consistent with obesity. Assessment included persistent hyperlipidemia and controlled hypertension. Recommended dietary modification, increased physical activity, and follow-up with a nutritionist. Initiated discussion on potential pharmacotherapy for weight management, pending further evaluation of lifestyle modifications.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('92272e3c-7728-42e1-bd65-605ddaa05015', '2025-06-02T23:20:15.309497', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were as follows: BP 142/88 mmHg, HR 78 bpm, BMI 32.4 kg/m². Patient reported occasional heartburn, but no new symptoms. Assessment indicated controlled hypertension, ongoing hyperlipidemia, and obesity. Recommended continuation of current antihypertensive and lipid-lowering medications, lifestyle modifications including dietary changes, and increased physical activity. Scheduled follow-up in 6 months to reassess cardiovascular risk factors.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('92272e3c-7728-42e1-bd65-605ddaa05015', '2025-05-04T23:20:15.309497', 'Annual Checkup', 'Patient presented for annual checkup. Blood pressure was 145/92 mmHg, and heart rate was 78 bpm. Physical examination revealed BMI of 32 kg/m², consistent with obesity. No acute distress noted. Recommended continuation of current antihypertensive and statin therapy, with lifestyle modifications including dietary changes and increased physical activity to address obesity and hyperlipidemia. Scheduled follow-up in 6 months to monitor blood pressure and lipid levels.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f6477e73-cefc-4c96-8156-edd470da23c2', '2025-12-16T23:20:21.557055', 'Emergency Visit', 'Patient presented for acute respiratory distress. On examination, the patient exhibited tachypnea with a respiratory rate of 48/min and mild subcostal retractions; oxygen saturation was 92% on room air. No wheezing or stridor noted. Assessment indicated a likely viral upper respiratory infection exacerbating eczema. Recommended supportive care with humidified air and monitoring of respiratory status. Advised parents on eczema management and to return if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f6477e73-cefc-4c96-8156-edd470da23c2', '2025-08-22T23:20:21.557055', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were age-appropriate with HR 110 bpm, RR 30 breaths/min, and weight in the 50th percentile for age. The patient has a history of ADHD and eczema, both of which appeared well-managed at this time. Assessment showed no acute concerns, but continued monitoring of ADHD symptoms was advised. Recommended maintaining current regimen and follow-up in 6 months or as needed for any emerging issues.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f6477e73-cefc-4c96-8156-edd470da23c2', '2025-06-07T23:20:21.557055', 'Consultation', 'Patient presented for a routine consultation regarding ADHD management. Vitals were stable: HR 110 bpm, BP 85/55 mmHg. No acute distress noted, and the skin exam showed mild eczema without secondary infection. Recommended continuation of current ADHD treatment plan with monitoring for medication side effects and advised on eczema management with emollients and avoidance of known irritants. Follow-up scheduled in 3 months for developmental assessment and ADHD symptom review.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f6477e73-cefc-4c96-8156-edd470da23c2', '2024-10-05T23:20:21.557055', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were within normal limits: HR 110 bpm, BP not applicable for age. No acute distress noted, and developmental milestones appropriate for age. History of eczema controlled with regular emollient use, no recent flare-ups reported. ADHD symptoms managed with behavioral interventions and parental guidance; no pharmacological treatment initiated at this time. Recommended continuation of current management strategies and follow-up in six months or sooner if concerns arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f6477e73-cefc-4c96-8156-edd470da23c2', '2024-09-17T23:20:21.557055', 'Urgent Care', 'Patient presented for persistent irritability and difficulty concentrating, suspected to be exacerbated by current eczema flare-up. Vital signs were stable: BP not applicable, HR 110 bpm, temperature 98.6°F. Physical examination revealed dry, erythematous patches on the elbows and knees. Assessment indicated eczema exacerbation possibly affecting ADHD symptoms. Recommended topical corticosteroids for eczema management and advised follow-up with pediatrician for ADHD symptom evaluation and management adjustment.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f6477e73-cefc-4c96-8156-edd470da23c2', '2024-06-18T23:20:21.557055', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: HR 110 bpm, BP 90/60 mmHg, Temp 98.6°F. No significant dermatological issues noted, and eczema appeared well-managed. Symptoms consistent with ADHD were discussed, and a referral to a pediatric behavioral specialist was recommended to explore management options. Follow-up in 6 months or sooner if concerns arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('826e02c3-cd50-4abb-8a00-fba10306866e', '2025-11-25T23:20:33.332942', 'Follow-up Visit', 'Patient presented for a follow-up visit to evaluate asthma management. Vital signs were stable: BP 110/70 mmHg, HR 80 bpm, RR 18 breaths per minute. Patient reported increased frequency of wheezing and nocturnal cough over the past two weeks, despite adherence to current asthma action plan. Physical examination revealed mild expiratory wheezing. Continued use of inhaled corticosteroid was recommended, with an increase in dosage for better control. Advised to avoid known allergens and follow up in 3 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('86e0a038-3ce5-4c60-b4e5-b919bf6a9538', '2026-01-10T23:20:34.942337', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were stable with BP 110/70 mmHg and HR 72 bpm. Patient''s anemia is being managed with iron supplements; hemoglobin levels have improved, and no new symptoms reported. Patient experiences mild hay fever, managed with antihistamines as needed. Recommended continuation of current anemia treatment and annual CBC monitoring. Reviewed importance of a balanced diet rich in iron and scheduled follow-up in one year unless symptoms change.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('86e0a038-3ce5-4c60-b4e5-b919bf6a9538', '2025-10-26T23:20:34.942337', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: BP 112/70 mmHg, HR 78 bpm. Physical examination was unremarkable, and no new symptoms were reported. Anemia treatment appears effective, with hemoglobin levels improving; advised to continue current iron supplementation regimen. Recommended continuation of antihistamines for hay fever as needed. Follow-up CBC was ordered to monitor anemia status.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('86e0a038-3ce5-4c60-b4e5-b919bf6a9538', '2025-06-24T23:20:34.942337', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were within normal limits: BP 110/70 mmHg, HR 72 bpm. Physical examination was unremarkable. Patient reported compliance with iron supplementation for anemia, with no new symptoms noted. Recommended continuation of current anemia treatment and advised on dietary modifications to support iron levels. Discussed strategies to manage hay fever symptoms as needed. Follow-up in one year unless issues arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ff688691-8488-4650-a8a9-e3d2c0296eb7', '2025-12-18T23:20:39.887015', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding moderate depression. Blood pressure was 132/85 mmHg, and heart rate was 78 bpm. The patient reported improved mood and energy levels with current antidepressant therapy, and denied any new depressive symptoms. Continued current medication regimen and recommended routine follow-up in three months to monitor mental health status and blood pressure management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ff688691-8488-4650-a8a9-e3d2c0296eb7', '2025-10-03T23:20:39.887015', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 138/85 mmHg, heart rate was 78 bpm, and BMI was 27.2. Patient reported stable mood with occasional episodes of low energy and anhedonia. Physical examination was unremarkable except for mild lens opacity in the right eye consistent with cataracts. Depression appears well-managed under current regimen; advised continuation of SSRI and recommended regular exercise. Encouraged adherence to antihypertensive medication and scheduled follow-up in six months for hypertension management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ff688691-8488-4650-a8a9-e3d2c0296eb7', '2025-05-17T23:20:39.887015', 'Annual Checkup', 'Patient presented for annual checkup. Blood pressure was 138/82 mmHg, heart rate was 76 bpm, and BMI was 28.2 kg/m². Patient reported stable mood but occasional low energy levels, consistent with history of moderate depression. Physical examination was unremarkable, and no acute distress was noted. Assessment included well-controlled hypertension and stable depressive symptoms. Recommended continuation of current antihypertensive and antidepressant medication, and advised regular physical activity and follow-up in six months to monitor mental health status.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ff688691-8488-4650-a8a9-e3d2c0296eb7', '2025-04-01T23:20:39.887015', 'Consultation', 'Patient presented for a follow-up consultation on moderate depression management. Vitals were stable: BP 130/85 mmHg, HR 72 bpm. Patient reported persistent low mood and fatigue, with no significant improvement on current antidepressant regimen. Assessment indicated a need for medication adjustment; sertraline dose was increased, and cognitive behavioral therapy sessions were recommended to enhance treatment efficacy. Follow-up scheduled in four weeks to assess response to changes.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ff688691-8488-4650-a8a9-e3d2c0296eb7', '2025-02-14T23:20:39.887015', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding moderate depression and hypertension management. Blood pressure was recorded at 140/85 mmHg and heart rate at 78 bpm. The patient reported improved mood stability with current antidepressant therapy but mentioned occasional fatigue. Recommended continuation of current medication regimen, advised lifestyle modifications to manage blood pressure, and scheduled a follow-up in three months to reassess mental health and hypertension control.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8e35bac7-637f-4fca-92cf-588663ae54e6', '2026-01-24T23:20:49.409709', 'Follow-up Visit', 'Patient presented for follow-up evaluation of cellulitis in the left lower extremity. Physical examination revealed mild erythema and warmth, with decreased swelling compared to the previous visit. Blood pressure was 138/82 mmHg, and heart rate was 76 bpm. The assessment indicated improving cellulitis. Continued current antibiotic regimen was advised, along with elevation of the affected leg and monitoring for any signs of worsening infection. Advised to follow up in two weeks or sooner if symptoms exacerbate.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8e35bac7-637f-4fca-92cf-588663ae54e6', '2025-09-28T23:20:49.409709', 'Consultation', 'Patient presented for consultation regarding cellulitis on the right lower extremity. Physical examination revealed erythema, warmth, and mild edema on the right shin, with tenderness upon palpation. Vital signs were stable: BP 132/78 mmHg, HR 82 bpm, RR 18 breaths/min, Temp 99.2°F. Assessment indicated mild cellulitis likely secondary to a recent minor trauma. Recommended continuation of oral antibiotics and leg elevation, with follow-up in one week to reassess response to treatment. Advised monitoring for any signs of increased redness, fever, or worsening pain, given the patient''s history of hypertension and asthma.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8e35bac7-637f-4fca-92cf-588663ae54e6', '2025-08-14T23:20:49.409709', 'Annual Checkup', 'Patient presented for an annual checkup and follow-up on cellulitis. Vitals were recorded as follows: BP 142/88 mmHg, HR 82 bpm, RR 18 breaths/min, and SpO2 95% on room air. Examination revealed mild erythema and warmth on the right lower extremity consistent with resolving cellulitis. Assessment includes stable osteoarthritis and controlled hypertension; cataracts and asthma remain unchanged. Recommended continuation of current antibiotic therapy for cellulitis, regular follow-up for hypertension management, and discussion of potential cataract surgery options with ophthalmology.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('91f13c89-bf71-48cc-b89a-e9826ee46044', '2025-11-26T23:20:55.217565', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding obesity management. Vitals were as follows: BP 118/76 mmHg, HR 82 bpm, height 160 cm, weight 88 kg, BMI 34.4 kg/m². No acute distress observed. Dietary habits and physical activity levels were discussed; patient reported minimal changes in routine. Recommended continuation of lifestyle modifications, including increased physical activity and nutritional counseling, with a follow-up in 3 months to monitor progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('91f13c89-bf71-48cc-b89a-e9826ee46044', '2025-08-24T23:20:55.217565', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding management of obesity. Vital signs were within normal limits: BP 110/70 mmHg, HR 72 bpm. Patient reported no new symptoms and denied any recent changes in diet or physical activity. Assessment revealed stable weight with a BMI of 32. Recommendations included continuing the current dietary plan and increasing physical activity to at least 150 minutes of moderate exercise per week. Follow-up in 3 months to reassess progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('91f13c89-bf71-48cc-b89a-e9826ee46044', '2025-07-01T23:20:55.217565', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding obesity management. Vitals were within normal limits: BP 118/76 mmHg, HR 72 bpm. Physical examination revealed stable weight since last visit, but BMI remains at the 95th percentile for age and gender. Recommended continuation of dietary modifications and increased physical activity, with a follow-up appointment scheduled in three months to monitor progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('1bf39107-1c9c-489d-bfbe-af590ab81360', '2026-01-06T23:21:00.367735', 'Consultation', 'Patient presented for evaluation of persistent sinusitis. He reported nasal congestion, facial pressure, and purulent nasal discharge. Vital signs were stable: BP 118/76 mmHg, HR 72 bpm, afebrile. Examination revealed bilateral nasal mucosal edema and tenderness over the maxillary sinuses. Assessment confirmed acute sinusitis likely exacerbated by his history of allergic rhinitis. Recommended initiating a course of amoxicillin and advised continued use of intranasal corticosteroids to manage underlying allergic symptoms. Follow-up in two weeks if symptoms persist.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('1bf39107-1c9c-489d-bfbe-af590ab81360', '2025-08-15T23:21:00.367735', 'Follow-up Visit', 'Patient presented for follow-up of sinusitis. Reported persistent nasal congestion and facial pressure, though symptoms have slightly improved. Vital signs were stable with BP 118/72 mmHg and HR 78 bpm. Continued treatment with saline nasal irrigation and recommended starting a short course of oral corticosteroids to further reduce inflammation. Advised follow-up in two weeks or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('1bf39107-1c9c-489d-bfbe-af590ab81360', '2025-06-29T23:21:00.367735', 'Annual Checkup', 'Patient presented for annual checkup with ongoing sinusitis symptoms. Vitals were stable: BP 118/76 mmHg, HR 72 bpm, afebrile. Nasal mucosa appeared edematous and erythematous, consistent with allergic rhinitis and sinusitis. Recommended continuation of saline nasal irrigation and prescribed a 10-day course of amoxicillin for sinusitis. Advised to follow up if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ca473bad-1fb2-47c2-aa72-6b3b2c9b1975', '2025-12-27T23:21:05.589053', 'Urgent Care', 'Patient presented for acute epigastric pain and nausea. Vitals were BP 138/86 mmHg, HR 88 bpm, Temp 98.6°F. Physical examination revealed tenderness in the upper abdomen without rebound tenderness or guarding. Assessment indicated probable exacerbation of GERD. Recommended continuation of proton pump inhibitor therapy and advised dietary modifications, including avoiding spicy foods and late-night meals. Follow-up with primary care physician suggested for further evaluation and weight management support.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ca473bad-1fb2-47c2-aa72-6b3b2c9b1975', '2025-08-01T23:21:05.589053', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 138/86 mmHg, HR 78 bpm, BMI 32 kg/m². The patient reported occasional heartburn but no significant changes in GERD symptoms. Recommended continuation of current GERD management and discussed lifestyle modifications for weight management, including dietary adjustments and increased physical activity. Follow-up in six months to monitor weight and GERD symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('96886e2a-cb09-4159-8931-0e582b551b68', '2025-11-22T23:21:09.380944', 'Annual Checkup', 'Patient presented for an annual check-up. Blood pressure was 138/86 mmHg, and heart rate was 78 bpm. Physical examination revealed no acute distress, with stable respiratory effort and no wheezing noted. Patient continues to manage hypertension with medication and lifestyle modifications. Recommended maintaining current antihypertensive regimen, continued use of inhalers as needed for asthma, and adherence to dietary modifications to manage hyperlipidemia and obesity. Encouraged regular follow-up for anxiety and migraine management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('96886e2a-cb09-4159-8931-0e582b551b68', '2025-08-01T23:21:09.380944', 'Consultation', 'Patient presented for a routine follow-up consultation for hypertension management. Blood pressure was elevated at 148/92 mmHg, heart rate was 78 bpm, and BMI was 32 kg/m². Physical examination was unremarkable, and the patient reported recent episodes of increased migraine frequency and persistent GERD symptoms. Recommended adjustment of antihypertensive medication, continuation of daily aspirin for hyperlipidemia, and advised dietary modifications to address obesity and GERD. Referred to neurology for further evaluation of migraines. Follow-up scheduled in 3 months to reassess hypertension and weight management progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('96886e2a-cb09-4159-8931-0e582b551b68', '2025-07-19T23:21:09.380944', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding hypertension management. Blood pressure was 148/92 mmHg and heart rate was 82 bpm. The patient reported occasional headaches and mild anxiety but denied chest pain, palpitations, or dyspnea. Assessment included suboptimal blood pressure control and ongoing anxiety. Recommended increasing the dosage of current antihypertensive medication and continuing current anxiolytic. Advised dietary modifications and regular exercise for weight management. Follow-up visit scheduled in 3 months to reassess blood pressure and anxiety symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('fb4b935a-2c7f-47b6-bd32-84402a7fdc23', '2025-11-28T23:21:16.954570', 'Urgent Care', 'Patient presented for worsening nasal congestion, sneezing, and itchy eyes consistent with hay fever exacerbation. Vital signs were recorded: BP 118/76 mmHg, HR 72 bpm, afebrile. Examination revealed erythematous nasal mucosa and watery eyes. Assessment included acute allergic rhinitis. Advised continuation of antihistamines and initiated a nasal corticosteroid spray. Follow-up recommended if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('fb4b935a-2c7f-47b6-bd32-84402a7fdc23', '2025-08-24T23:21:16.954570', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were within normal limits: BP 118/76 mmHg, HR 72 bpm. The patient reported experiencing seasonal allergic rhinitis consistent with hay fever, managed with OTC antihistamines. No current exacerbations of eczema were noted. Recommended continuation of antihistamines as needed and advised follow-up if symptoms worsen or new issues arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8fc85381-7878-4b17-b2ae-15e96433bb91', '2025-10-27T23:21:20.877521', 'Urgent Care', 'Patient presented for acute exacerbation of asthma with increased wheezing and shortness of breath over the past 24 hours. On examination, respiratory rate was 28 breaths per minute, and oxygen saturation was 92% on room air. Auscultation revealed diffuse wheezing. Assessment indicated an asthma exacerbation, likely triggered by recent cold weather. Treatment with albuterol nebulization was administered in-clinic, and a short course of oral prednisone was prescribed. Advised continuation of daily inhaled corticosteroid and follow-up with primary care for asthma management review.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8fc85381-7878-4b17-b2ae-15e96433bb91', '2025-09-29T23:21:20.877521', 'Follow-up Visit', 'Patient presented for a follow-up visit for asthma management. Vital signs were stable: BP 102/68 mmHg, HR 88 bpm, and SpO2 98% on room air. The patient reported occasional wheezing, particularly during physical activity, but no recent exacerbations. Examination revealed clear lung sounds bilaterally. Continued current asthma management plan with albuterol as needed; recommended increasing frequency of inhaled corticosteroid during peak allergy months. Advised regular follow-up and monitoring of symptoms, particularly with the upcoming colder months.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8fc85381-7878-4b17-b2ae-15e96433bb91', '2025-02-02T23:21:20.877521', 'Urgent Care', 'Patient presented for acute exacerbation of asthma with increased wheezing and shortness of breath. Physical examination revealed mild intercostal retractions and expiratory wheezes bilaterally. Vital signs: HR 110 bpm, RR 28 breaths/min, SpO2 92% on room air. Albuterol nebulization administered with noted improvement in symptoms. Assessment: Acute asthma exacerbation. Plan: Continue albuterol inhaler every 4-6 hours as needed, start oral prednisone for 5 days, and follow-up with pediatrician in 3-5 days for re-evaluation.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('fbc4d4f8-afd1-4349-bf68-2051997eb6a9', '2026-01-23T23:21:27.297436', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 142/88 mmHg, heart rate 78 bpm, BMI 32.3 kg/m². Patient reported no new symptoms but acknowledged occasional noncompliance with antihypertensive medication. Recommended continuation of lisinopril 10 mg daily, dietary modifications to address obesity and hyperlipidemia, and scheduled follow-up with a dietitian. Reinforced importance of regular blood glucose monitoring due to prediabetes.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('fbc4d4f8-afd1-4349-bf68-2051997eb6a9', '2025-09-18T23:21:27.297436', 'Consultation', 'Patient presented for routine consultation and management of hypertension. Blood pressure recorded at 145/92 mmHg, heart rate at 78 bpm. Physical examination revealed no acute distress, but patient reported occasional headaches. Assessment indicated suboptimal control of hypertension and risk factors due to prediabetes and hyperlipidemia. Recommended dietary modifications, increased physical activity, and adjustment of antihypertensive medication. Follow-up scheduled in 3 months to reassess blood pressure and metabolic parameters.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('56e6d364-613a-48ce-bd6b-5d0c646c53fa', '2025-12-06T23:21:31.803799', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding hyperlipidemia management. Blood pressure was 138/82 mmHg, heart rate was 76 bpm, and respiratory rate was 18 breaths per minute. The patient reported no new symptoms but mentioned occasional joint stiffness consistent with osteoarthritis. Lipid panel results from last week indicated elevated LDL levels. Recommended continuation of atorvastatin and advised dietary modifications to further lower cholesterol levels. Scheduled a follow-up in three months to reassess lipid profile and blood pressure control.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('56e6d364-613a-48ce-bd6b-5d0c646c53fa', '2025-09-28T23:21:31.803799', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 142/88 mmHg, HR 78 bpm, RR 16 breaths/min, and temperature 98.6°F. The patient reported no new symptoms but noted occasional joint stiffness attributed to osteoarthritis, and controlled asthma with current medication. Assessment indicated stable hypertension and hyperlipidemia, managed with lifestyle modifications and current pharmacotherapy. Recommendations included continuation of current medications, adherence to a low-sodium and low-fat diet, regular exercise, and follow-up in six months for routine monitoring and lipid panel evaluation.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('56e6d364-613a-48ce-bd6b-5d0c646c53fa', '2025-02-09T23:21:31.803799', 'Consultation', 'Patient presented for routine consultation regarding hyperlipidemia management. Blood pressure was elevated at 145/90 mmHg, and heart rate was 76 bpm. Patient reported mild joint pain consistent with known osteoarthritis but denied any new respiratory symptoms related to asthma. Continued current statin therapy was recommended, and lifestyle modifications including diet and exercise were emphasized. Follow-up in 6 months was advised to monitor lipid levels and blood pressure control.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5f8f6188-0c3f-4cb5-b23f-6d6c553fcd6d', '2025-10-16T23:21:37.743684', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding hypertension management and overall health maintenance. Blood pressure was recorded at 142/88 mmHg and heart rate at 76 bpm. Patient reported occasional dizziness and mild dyspnea on exertion. Assessment indicated suboptimal blood pressure control, likely exacerbated by obesity and medication non-adherence. Plan included adjusting antihypertensive medication dosage, reinforcing lifestyle modifications, and scheduling a follow-up in 3 months to reassess blood pressure and symptomatology.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5f8f6188-0c3f-4cb5-b23f-6d6c553fcd6d', '2025-08-27T23:21:37.743684', 'Follow-up Visit', 'Patient presented for a follow-up visit for hypertension management. Blood pressure was 148/92 mmHg and heart rate was 78 bpm. The patient reported experiencing occasional headaches and mild dizziness. Assessment indicated suboptimal control of hypertension; recommended increasing lisinopril dosage and advised dietary modifications to reduce sodium intake. Follow-up in two months to reassess blood pressure control and monitor for any side effects.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('5f8f6188-0c3f-4cb5-b23f-6d6c553fcd6d', '2025-07-25T23:21:37.743684', 'Urgent Care', 'Patient presented for acute shortness of breath and chest tightness. Vital signs revealed BP 150/95 mmHg, HR 92 bpm, RR 24 breaths/min, and SpO2 90% on room air. Physical exam noted wheezing on lung auscultation and use of accessory muscles for respiration. Assessment indicated exacerbation of asthma and potential cardiac involvement. Recommended immediate nebulization with bronchodilators, adjustment of antihypertensive therapy, and referral to cardiology for further evaluation.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8bf59939-6bd6-4168-ad30-cf255fd05385', '2026-01-01T23:21:43.969116', 'Annual Checkup', 'Patient presented for an annual checkup and evaluation of a left forearm abscess. Vitals included BP 142/88 mmHg, HR 78 bpm. Abscess measured approximately 3 cm in diameter with surrounding erythema and tenderness, but no drainage. Patient''s asthma and hypertension remain well-managed on current medication regimen; however, lipids require further management due to elevated levels. Recommended incision and drainage of the abscess and initiated a course of antibiotics. Advised continuation of current medications for chronic conditions and discussed lifestyle modifications to address obesity and prediabetes. Follow-up in one week for abscess evaluation and routine lab work.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8bf59939-6bd6-4168-ad30-cf255fd05385', '2025-08-17T23:21:43.969116', 'Urgent Care', 'Patient presented for evaluation of a painful, swollen abscess on the left thigh, noted to be erythematous and warm to touch. Vitals: BP 142/88 mmHg, HR 82 bpm, RR 18 breaths/min, Temp 100.4°F. Clinical examination confirmed a fluctuant mass suggestive of an infected abscess. Recommended incision and drainage procedure followed by a 7-day course of antibiotics. Advised monitoring blood glucose levels closely due to prediabetes and scheduled follow-up with PCP for hypertension management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8bf59939-6bd6-4168-ad30-cf255fd05385', '2025-07-02T23:21:43.969116', 'Urgent Care', 'Patient presented for evaluation of a painful abscess on the left thigh. Physical examination revealed a fluctuant, erythematous mass approximately 3 cm in diameter. Blood pressure was 145/92 mmHg, heart rate 84 bpm, and respiratory rate 18 breaths per minute. Assessment indicated a likely bacterial infection. Recommended incision and drainage procedure, prescribed antibiotics (Amoxicillin-Clavulanate), and advised warm compresses to the affected area. Follow-up in 5-7 days for reassessment. Advised to monitor blood glucose levels and maintain current medications for hypertension, asthma, and hyperlipidemia.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('0d47970c-15fe-4983-988c-e416280fc93b', '2026-02-17T23:21:50.255293', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding acute diverticulitis. Vital signs were stable with a blood pressure of 138/86 mmHg and heart rate of 78 bpm. The patient reported decreased abdominal pain and no fever since last visit. Assessment showed improvement in symptoms, with no signs of complications. Recommended continuation of prescribed antibiotics and advised on a high-fiber diet to prevent recurrence. Follow-up in four weeks to monitor progress and reassess hypertension management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('0d47970c-15fe-4983-988c-e416280fc93b', '2025-09-15T23:21:50.255293', 'Urgent Care', 'Patient presented for acute abdominal pain and tenderness localized to the left lower quadrant, consistent with acute diverticulitis. Vital signs noted: BP 148/92 mmHg, HR 88 bpm, temperature 100.4°F. On exam, there was guarding and rebound tenderness in the affected area. Assessment confirmed acute diverticulitis exacerbation. Recommended a course of oral antibiotics and a clear liquid diet, with instructions to follow up with primary care in 3-5 days or sooner if symptoms worsen. Advised on weight management and blood pressure control to address underlying hypertension and obesity.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('0d47970c-15fe-4983-988c-e416280fc93b', '2025-06-28T23:21:50.255293', 'Annual Checkup', 'Patient presented for an annual checkup with ongoing management of acute diverticulitis. Blood pressure was 150/88 mmHg, and heart rate was 82 bpm. The patient reported mild abdominal discomfort and changes in bowel habits consistent with recent diverticulitis flare-up. Advised continuation of current antibiotic regimen, increase dietary fiber intake gradually, and follow-up in two weeks to reassess diverticulitis symptoms. Addressed hypertension management and encouraged weight loss through lifestyle modifications.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('0d47970c-15fe-4983-988c-e416280fc93b', '2025-01-09T23:21:50.255293', 'Follow-up Visit', 'Patient presented for follow-up of acute diverticulitis. Vital signs were stable, with blood pressure at 138/82 mmHg and heart rate at 76 bpm. The patient reported decreased abdominal pain and improved bowel movements since the last visit. Assessment indicated resolution of acute symptoms; however, continued dietary modification and increased fiber intake were recommended. Follow-up in 4 weeks was advised to monitor progress and manage hypertension and obesity.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('0d47970c-15fe-4983-988c-e416280fc93b', '2024-06-27T23:21:50.255293', 'Follow-up Visit', 'Patient presented for follow-up visit regarding acute diverticulitis. Blood pressure was 145/88 mmHg, and heart rate was 78 bpm. Patient reported a decrease in abdominal pain and no fever, but mild bloating persists. Assessment indicated improvement in diverticulitis symptoms. Recommended continuation of the current antibiotic regimen and advised a high-fiber diet to prevent recurrence. Scheduled a follow-up appointment in four weeks to reassess condition and manage hypertension.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e70223cf-0f37-45e0-a6e4-337212c0c36f', '2025-11-26T23:21:59.247613', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs recorded: BP 138/85 mmHg, HR 78 bpm, BMI 32 kg/m². Patient reported experiencing increased sneezing and congestion consistent with seasonal allergies; no new symptoms noted. Recommended continuation of antihistamine therapy and advised on weight management strategies. Follow-up in 6 months to reassess allergy management and lifestyle modifications.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e70223cf-0f37-45e0-a6e4-337212c0c36f', '2025-06-12T23:21:59.247613', 'Urgent Care', 'Patient presented for exacerbation of seasonal allergies with complaints of nasal congestion, sneezing, and itchy eyes. Vital signs were within normal limits: BP 128/82 mmHg, HR 78 bpm. Physical examination revealed erythematous nasal mucosa and clear postnasal drip. Assessment confirmed allergic rhinitis flare-up. Recommended continuation of antihistamines and initiation of an intranasal corticosteroid. Advised follow-up if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e70223cf-0f37-45e0-a6e4-337212c0c36f', '2025-03-14T23:21:59.247613', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding management of seasonal allergies and ongoing GERD symptoms. Blood pressure was 128/82 mmHg, heart rate was 76 bpm, and BMI was 32.4 kg/m², indicating obesity. Patient reported increased frequency of migraine episodes and persistent nasal congestion. Advised continuation of current antihistamine and PPI regimen, and recommended dietary modifications to manage GERD symptoms. Initiated a referral to a dietitian for weight management and discussed potential prophylactic treatment options for migraines. Follow-up in 3 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('9ca422e4-421b-400b-88a7-66de226f661f', '2025-10-21T23:22:05.389927', 'Follow-up Visit', 'Patient presented for a routine follow-up visit. Vital signs were stable: HR 90 bpm, RR 20 breaths/min, BP 100/60 mmHg, temperature 98.6°F. Physical examination was unremarkable with appropriate growth and development for age. No new concerns were identified. Recommended to continue a balanced diet and regular physical activity; follow-up in one year for annual check-up unless concerns arise sooner.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('9ca422e4-421b-400b-88a7-66de226f661f', '2025-10-18T23:22:05.389927', 'Follow-up Visit', 'Patient presented for a routine follow-up visit. Vital signs were stable: BP 95/60 mmHg, HR 98 bpm, Temp 98.6°F. Growth parameters were within normal limits for age and development was appropriate. No new symptoms or concerns reported. Recommended continuing current vaccination schedule and advised on maintaining a balanced diet and regular physical activity. Follow-up in one year unless new concerns arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('0b580c49-7555-414d-bfb0-2b13ea3612ec', '2025-11-03T23:22:08.669407', 'Follow-up Visit', 'Patient presented for follow-up of urticaria. She reported persistent pruritic hives predominantly on the arms and legs, with episodes occurring 2-3 times per week. Vital signs were stable: BP 118/76 mmHg, HR 72 bpm, RR 16 breaths/min, Temp 98.6°F. Assessment indicated chronic urticaria likely exacerbated by her history of atopy. Recommended continuation of daily nonsedating antihistamines and advised monitoring for any new triggers. Advised follow-up in 4 weeks or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('0b580c49-7555-414d-bfb0-2b13ea3612ec', '2025-10-13T23:22:08.669407', 'Urgent Care', 'Patient presented for evaluation of acute urticaria, reporting widespread pruritic wheals that developed three hours prior to the visit. Vital signs were stable: BP 118/76 mmHg, HR 82 bpm, RR 16 breaths/min, and SpO2 98% on room air. Exam revealed erythematous, raised welts distributed on the trunk and extremities. Assessment confirmed urticaria likely secondary to an allergic reaction. Recommended initiation of oral antihistamines (cetirizine 10 mg daily) and advised avoidance of identified allergens. Follow-up with primary care provider or return if symptoms worsen or do not resolve.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('bb2362ea-3767-4be6-a89b-81a899b99de0', '2026-01-14T23:22:13.275926', 'Follow-up Visit', 'Patient presented for a follow-up visit related to asthma management. Vitals: BP 112/68 mmHg, HR 72 bpm. Patient reported intermittent wheezing and shortness of breath, particularly during physical activity, but noted improvement with current inhaler use. Assessment revealed well-controlled asthma with occasional exacerbations triggered by allergens. Continued current inhaler regimen and advised on allergen avoidance. Recommended follow-up in 3 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('bb2362ea-3767-4be6-a89b-81a899b99de0', '2025-09-26T23:22:13.275926', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were within normal limits: BP 110/70 mmHg, HR 72 bpm, RR 16 breaths per minute, SpO2 97% on room air. Lung auscultation revealed mild wheezing bilaterally. Assessment indicated stable asthma with well-controlled symptoms. Recommended continuation of inhaled corticosteroid therapy and advised follow-up in 6 months or earlier if symptoms worsen. Discussed the importance of avoiding known allergens to manage allergic rhinitis and hay fever.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('15003c61-eb0f-4124-869b-6686de4fd366', '2025-10-01T23:22:17.166317', 'Emergency Visit', 'Patient presented for acute exacerbation of asthma secondary to an upper respiratory infection. On examination, the patient exhibited wheezing and mild respiratory distress, with a respiratory rate of 24 breaths per minute and oxygen saturation at 92% on room air. History of eczema and obesity noted. Administered nebulized albuterol in the emergency department with symptomatic improvement. Advised continuation of inhaled corticosteroids and follow-up with primary care for asthma management and weight counseling.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('514c491e-c14a-478a-b1ad-a3042f83604f', '2025-09-30T23:22:18.702919', 'Emergency Visit', 'Patient presented for acute chest pain radiating to the left arm and shortness of breath. Vital signs included BP 160/95 mmHg, HR 102 bpm, and SpO2 94% on room air. Physical exam revealed diaphoresis and mild wheezing on auscultation. EKG showed ST segment elevation; troponin levels elevated. Assessment indicated possible acute myocardial infarction. Administered aspirin 325 mg, initiated oxygen therapy, and prepared for immediate transfer to cardiology for further evaluation and management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('514c491e-c14a-478a-b1ad-a3042f83604f', '2025-07-11T23:22:18.702919', 'Consultation', 'Patient presented for routine consultation and management of chronic conditions. Vital signs: BP 142/88 mmHg, HR 78 bpm, BMI 32.4 kg/m². Reports mild joint pain associated with osteoarthritis but denies any new symptoms. Lipid panel reviewed, indicating elevated LDL levels. Continued current regimen for hypertension and diabetes. Recommended dietary modifications and increased physical activity to address hyperlipidemia and obesity. Follow-up scheduled in 3 months to reassess lipid levels and overall condition.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('514c491e-c14a-478a-b1ad-a3042f83604f', '2025-06-23T23:22:18.702919', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 138/82 mmHg, heart rate 72 bpm, BMI 31.2 kg/m². Patient reported no new symptoms but noted occasional joint pain related to osteoarthritis. Continued management of hyperlipidemia and hypertension with current medication regimen was advised. Recommended maintaining a balanced diet and regular physical activity to address obesity and improve overall health outcomes. Follow-up scheduled in six months for routine monitoring.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('514c491e-c14a-478a-b1ad-a3042f83604f', '2025-06-17T23:22:18.702919', 'Urgent Care', 'Patient presented for worsening knee pain and swelling over the past week. Physical exam revealed moderate effusion and tenderness in the right knee, with limited range of motion. Vital signs were stable: BP 140/85 mmHg, HR 78 bpm, RR 16/min, Temp 98.6°F. Assessment indicated exacerbation of osteoarthritis likely aggravated by recent increased activity. Recommended rest, ice application, and NSAIDs for pain management. Advised follow-up with primary care for ongoing management of chronic conditions.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('514c491e-c14a-478a-b1ad-a3042f83604f', '2024-09-24T23:22:18.702919', 'Urgent Care', 'Patient presented for acute chest pain and shortness of breath. Vital signs on arrival: BP 160/94 mmHg, HR 98 bpm, RR 22 breaths/min, SpO2 94% on room air. Physical exam revealed mild wheezing and decreased breath sounds bilaterally. ECG showed no acute ischemic changes. Assessment: Likely acute exacerbation of GERD with possible cardiac component. Plan included immediate referral to the emergency department for further cardiac evaluation, continuation of current antihypertensive and statin therapy, and advised follow-up with primary care for further management of underlying chronic conditions.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('2cb5be2c-ab8a-4536-9c07-b77188edaa5d', '2026-01-31T23:22:29.660086', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding hay fever management and review of chronic conditions. Blood pressure was 128/82 mmHg, heart rate was 76 bpm, and respiratory rate was 18 breaths per minute. She reported increased nasal congestion and sneezing consistent with allergic rhinitis but denied any exacerbation of asthma symptoms. Continued current antihistamine and nasal corticosteroid for hay fever, monitored for hypertension with current medication, and advised follow-up with mental health services for ongoing depression management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('2cb5be2c-ab8a-4536-9c07-b77188edaa5d', '2025-08-24T23:22:29.660086', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable with BP at 128/82 mmHg and HR at 76 bpm. The patient reported experiencing increased nasal congestion and sneezing due to hay fever. Assessment revealed controlled asthma and hypertension, with moderate depression symptoms managed with current medication. Recommended continuing antihypertensive and asthma management regimen, and advised using antihistamines as needed for hay fever. Follow-up in six months or as needed for any exacerbations of symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('2cb5be2c-ab8a-4536-9c07-b77188edaa5d', '2025-08-12T23:22:29.660086', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 132/85 mmHg, and heart rate was 78 bpm. She reported increased nasal congestion and sneezing, consistent with exacerbated hay fever symptoms. Asthma remained well-controlled with current medication regimen. Recommended continuation of current antihypertensive therapy and advised initiation of a nasal corticosteroid for hay fever management. Discussed ongoing management of moderate depression with current antidepressants and encouraged regular follow-up with mental health services.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6b71f3a8-276d-44be-b674-229368984ee9', '2025-10-16T23:22:35.804536', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs: BP 112/70 mmHg, HR 76 bpm, weight stable at 60 kg. Patient reported increased anxiety over the past three months, affecting daily activities and sleep. Physical examination was unremarkable for acute issues. Continued management of anxiety and depression with current medication regimen was advised, along with referral to a therapist for cognitive behavioral therapy. Recommended follow-up in three months to reassess mental health status and medication efficacy.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('525b6334-1165-463d-a5be-ea16e286fc4b', '2025-12-30T23:22:38.671262', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were within normal limits: HR 110 bpm, RR 30/min, Temp 98.6°F. Physical examination revealed normal growth and developmental milestones appropriate for age. No abnormalities noted. Recommended continuation of routine vaccinations and provided guidance on age-appropriate nutrition and safety measures.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('525b6334-1165-463d-a5be-ea16e286fc4b', '2025-07-15T23:22:38.671262', 'Consultation', 'Patient presented for a routine 12-month well-child examination. Vitals were stable: HR 110 bpm, RR 30 breaths per minute, weight 10 kg, and height 75 cm. Physical examination was unremarkable, with normal growth and development observed. Recommended continuation of breastfeeding or formula, introduction of age-appropriate solid foods, and adherence to the vaccination schedule. Advised parents on safety measures, including car seat use and childproofing the home environment.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('525b6334-1165-463d-a5be-ea16e286fc4b', '2025-05-30T23:22:38.671262', 'Annual Checkup', 'Patient presented for an annual checkup. Physical examination revealed normal growth and development, with weight and height tracking along the 50th percentile for age. Vital signs were stable: HR 110 bpm, RR 30 breaths/min, and temperature 98.6°F. No abnormalities detected on examination; patient appeared well-nourished and well-hydrated. Assessment indicated healthy status with no concerns. Recommended continuation of age-appropriate vaccinations and routine developmental screenings.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('525b6334-1165-463d-a5be-ea16e286fc4b', '2024-10-25T23:22:38.671262', 'Emergency Visit', 'Patient presented for an emergency visit due to sudden onset of high fever and irritability. Vital signs: Temperature 39.2°C (102.6°F), HR 140 bpm, RR 30 bpm, BP 90/60 mmHg. Physical examination revealed mild nasal congestion and a non-productive cough. Assessment suggested a viral upper respiratory infection. Recommended supportive care with hydration, antipyretics, and monitoring for any worsening symptoms. Follow-up with primary care pediatrician advised.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('9b83ed8f-6a88-4b68-94d6-b0ae32a61a0e', '2025-10-23T23:22:47.899667', 'Follow-up Visit', 'Patient presented for follow-up of asthma management and review of comorbid conditions. Vital signs: BP 142/88 mmHg, HR 78 bpm, SpO2 97% on room air. Patient reported occasional dyspnea and wheezing, particularly at night, and noted improvement with the current inhaler regimen. Assessment: Asthma remains suboptimally controlled; obesity likely contributing to symptoms. Plan: Continue current inhaler, initiate montelukast 10 mg daily, and advised weight management strategies. Recommended follow-up in 3 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('9b83ed8f-6a88-4b68-94d6-b0ae32a61a0e', '2025-10-14T23:22:47.899667', 'Follow-up Visit', 'Patient presented for a follow-up visit to monitor asthma and manage hypertension. Vital signs were stable with BP 130/85 mmHg and HR 78 bpm. Patient reported mild wheezing and occasional dyspnea, which were more pronounced with exertion; however, symptoms have been manageable with current inhaler use. Continued current treatment regimen and advised regular monitoring of peak flow at home. Recommended lifestyle modifications including dietary changes and increased physical activity to address obesity and hyperlipidemia. Follow-up in 3 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('9c9517d5-b43c-4fd4-a967-b8b6488de5e1', '2026-02-12T23:22:51.905149', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were noted as follows: BP 138/82 mmHg, HR 76 bpm, BMI 31 kg/m². The patient reported no new symptoms but expressed concerns about joint stiffness, consistent with osteoarthritis. Hyperlipidemia was managed with atorvastatin; adherence to medication and dietary modifications were emphasized. Recommended continuation of current antihypertensive regimen and follow-up with ophthalmology for cataract monitoring. Regular exercise and weight management were advised to address obesity and support diabetes control.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('9c9517d5-b43c-4fd4-a967-b8b6488de5e1', '2025-06-13T23:22:51.905149', 'Consultation', 'Patient presented for routine consultation and management of hyperlipidemia. Vitals were stable with BP at 138/82 mmHg and HR at 72 bpm. Noted mild joint stiffness consistent with osteoarthritis; no acute distress observed. Continued current statin therapy for hyperlipidemia was recommended, and patient was advised to maintain a balanced diet and regular exercise to manage diabetes and obesity. Follow-up in three months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('9c9517d5-b43c-4fd4-a967-b8b6488de5e1', '2025-05-14T23:22:51.905149', 'Urgent Care', 'Patient presented for evaluation of acute chest pain lasting 2 hours. Vital signs: BP 150/92 mmHg, HR 88 bpm, RR 18 breaths/min, Temp 98.6°F. Physical examination revealed mild diaphoresis and discomfort upon palpation of the left chest area. Assessment suggested possible angina. Recommended immediate ECG and referral to cardiology for further evaluation. Advised patient to avoid exertion and provided nitroglycerin with instructions for use. Follow-up scheduled in 1 week or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('9c9517d5-b43c-4fd4-a967-b8b6488de5e1', '2024-11-03T23:22:51.905149', 'Urgent Care', 'Patient presented for increased shortness of breath and chest discomfort. Vital signs: BP 150/92 mmHg, HR 88 bpm, RR 22 breaths/min, SpO2 94% on room air. Physical examination revealed mild bilateral wheezing and peripheral edema. Assessment: Possible exacerbation of heart failure, consider differential diagnoses of acute coronary syndrome or pneumonia. Plan: Ordered chest X-ray and ECG; initiated diuretic therapy; advised follow-up with cardiology and adjustment of antihypertensive regimen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('336e9997-6563-4504-9c7f-3fc1d7474a66', '2025-10-10T23:23:01.508316', 'Annual Checkup', 'Patient presented for an annual checkup and management of an acute eczema flare. Vital signs were as follows: BP 145/92 mmHg, HR 82 bpm, BMI indicated obesity. Examination revealed erythematous patches with excoriation on the antecubital fossae and popliteal areas, consistent with eczema exacerbation. Assessment included poorly controlled hypertension and eczema flare. Recommendations included starting a topical corticosteroid for eczema, adjusting antihypertensive medication, and reviewing lifestyle modifications for weight management and diabetes control. Follow-up scheduled in 3 months to reassess blood pressure and eczema response.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('336e9997-6563-4504-9c7f-3fc1d7474a66', '2025-08-27T23:23:01.508316', 'Annual Checkup', 'Patient presented for an annual checkup with a chief complaint of an acute eczema flare. Vitals were as follows: BP 145/92 mmHg, HR 82 bpm, BMI 32.5 kg/m². Physical examination revealed erythematous, scaly patches on the forearms and legs consistent with eczema exacerbation. Assessment indicated poor glycemic control with HbA1c of 8.2%. Recommended continuation of emollients and topical corticosteroids for eczema, adjustment of antihypertensive therapy, and initiation of a dietary plan alongside metformin adjustment to better manage diabetes. Follow-up in 3 months for re-evaluation of eczema and overall metabolic control.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c0f2d080-6ba3-48e2-8651-929f7b03bba7', '2025-09-29T23:23:05.810374', 'Follow-up Visit', 'Patient presented for a follow-up visit to manage hyperlipidemia. Blood pressure was 128/76 mmHg and heart rate was 72 bpm. Patient reported occasional knee pain due to osteoarthritis but denied any new respiratory symptoms. Lipid panel results showed elevated LDL levels; atorvastatin dosage was adjusted. Advised to continue current asthma management and to follow a low-fat diet. Recommended routine ophthalmology follow-up for cataracts monitoring.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c0f2d080-6ba3-48e2-8651-929f7b03bba7', '2025-06-19T23:23:05.810374', 'Urgent Care', 'Patient presented for acute shortness of breath and wheezing. Vital signs were recorded as follows: BP 138/82 mmHg, HR 88 bpm, RR 22 breaths/min, SpO2 91% on room air. Physical examination revealed bilateral wheezing on auscultation and mild respiratory distress. Assessment indicated an exacerbation of asthma likely triggered by seasonal allergies. Nebulized bronchodilator therapy was administered with subsequent improvement in respiratory status. Advised continuation of inhaled corticosteroids and antihistamines, and follow-up with primary care for management of hyperlipidemia and review of asthma action plan.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c0f2d080-6ba3-48e2-8651-929f7b03bba7', '2025-04-20T23:23:05.810374', 'Emergency Visit', 'Patient presented for acute shortness of breath and wheezing, reported onset over the past 24 hours. Vital signs: BP 140/88 mmHg, HR 98 bpm, RR 22/min, SpO2 89% on room air. Physical examination revealed diminished breath sounds and bilateral wheezing on auscultation. Assessment indicated an acute exacerbation of asthma. Patient was administered nebulized bronchodilators and oxygen therapy, with subsequent improvement in respiratory status. Recommendations included follow-up with pulmonology and adjustment of asthma management plan.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c0f2d080-6ba3-48e2-8651-929f7b03bba7', '2025-03-23T23:23:05.810374', 'Follow-up Visit', 'Patient presented for a follow-up on hyperlipidemia management. Vitals were stable: BP 128/76 mmHg, HR 72 bpm. The patient reported occasional joint stiffness due to osteoarthritis but denied any new respiratory symptoms related to asthma. Lipid panel results were reviewed, showing improvement with current statin therapy. Recommended continuation of current medication regimen, encouraged adherence to a low-fat diet, and advised regular exercise. Follow-up scheduled in six months to reassess lipid levels and joint function.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c0f2d080-6ba3-48e2-8651-929f7b03bba7', '2024-08-23T23:23:05.810374', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 138/82 mmHg, HR 72 bpm, RR 18 breaths/min, Temp 98.6°F. Physical examination revealed no acute distress, mild crepitus in both knees consistent with osteoarthritis, and clear lung sounds despite history of asthma. Lipid panel reviewed; LDL remains elevated. Advised continuation of current hyperlipidemia medication and recommended dietary modifications to manage cholesterol levels. Encouraged regular exercise and discussed potential cataract surgery options due to progressive vision changes. Follow-up in 6 months or as needed.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c7626364-ce85-475e-9958-d9843848b4fd', '2026-01-20T23:23:18.095733', 'Emergency Visit', 'Patient presented for acute exacerbation of allergic rhinitis characterized by nasal congestion, sneezing, and watery rhinorrhea. Vitals were stable: BP 100/60 mmHg, HR 88 bpm, RR 20 breaths/min, Temp 98.4°F. Physical examination revealed pale, edematous nasal turbinates and clear nasal discharge. Assessment confirmed allergic rhinitis flare-up. Recommended use of an intranasal corticosteroid and advised continuation of oral antihistamine. Follow-up with pediatrician if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c7626364-ce85-475e-9958-d9843848b4fd', '2025-07-10T23:23:18.095733', 'Emergency Visit', 'Patient presented for acute exacerbation of allergic rhinitis with symptoms of nasal congestion, sneezing, and itchy eyes. Vital signs were stable with BP 100/60 mmHg, HR 90 bpm, RR 18 breaths/min. Physical examination revealed boggy, pale nasal turbinates and clear nasal discharge. Assessment indicated exacerbation likely due to seasonal allergen exposure. Recommended continuation of antihistamine therapy and initiation of a nasal corticosteroid spray. Follow-up with primary care provider advised in one week or if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c7626364-ce85-475e-9958-d9843848b4fd', '2025-03-15T23:23:18.095733', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were within normal limits: BP 102/64 mmHg, HR 88 bpm, Temp 98.4°F. Physical examination was unremarkable except for mild nasal congestion consistent with allergic rhinitis. Advised continuation of current antihistamine regimen and recommended avoidance of known allergens. Follow-up in one year or as needed for symptom management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c7626364-ce85-475e-9958-d9843848b4fd', '2024-11-24T23:23:18.095733', 'Follow-up Visit', 'Patient presented for a follow-up visit for allergic rhinitis. Vital signs were within normal limits: BP 105/70 mmHg, HR 85 bpm, Temp 98.1°F. Patient reported improvement in nasal congestion and sneezing with current antihistamine therapy. Assessment: Stable allergic rhinitis. Plan: Continue current antihistamine regimen, recommend use of a saline nasal spray for additional symptom relief, and follow up in 6 months unless symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('7008805d-297d-4958-9714-2ed353493340', '2025-09-27T23:23:26.199495', 'Consultation', 'Patient presented for routine consultation and management of COPD. Vitals were stable with BP at 130/85 mmHg and HR at 78 bpm. Patient reported increased dyspnea on exertion and occasional wheezing. Pulmonary examination revealed diminished breath sounds bilaterally. Assessment indicated potential exacerbation of COPD. Recommended adjustment of bronchodilator therapy and inhaled corticosteroids, and advised follow-up in one month.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('7008805d-297d-4958-9714-2ed353493340', '2025-06-06T23:23:26.199495', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were BP 138/85 mmHg, HR 78 bpm, SpO2 93% on room air. Patient reported increased dyspnea on exertion and persistent cough, consistent with COPD exacerbation. Physical examination revealed wheezing bilaterally and decreased breath sounds. Recommended continuation of bronchodilator therapy and initiation of pulmonary rehabilitation program. Advised lifestyle modifications, including smoking cessation support and dietary adjustments to manage hypertension and GERD. Scheduled follow-up in 6 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('7008805d-297d-4958-9714-2ed353493340', '2025-05-24T23:23:26.199495', 'Consultation', 'Patient presented for routine consultation and management of COPD and associated comorbidities. Vital signs were stable with BP at 135/80 mmHg and HR at 78 bpm. Patient reported increased dyspnea on exertion, managed with albuterol inhaler as needed. Continued with current pharmacotherapy for hypertension and heart failure. Advised on the importance of adhering to medication regimen and regular follow-ups for osteoporosis management. Recommended pulmonary rehabilitation to improve respiratory function and discussed lifestyle modifications to manage GERD symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('7008805d-297d-4958-9714-2ed353493340', '2024-10-01T23:23:26.199495', 'Urgent Care', 'Patient presented for increased shortness of breath and wheezing, exacerbating her COPD. Vital signs revealed BP 145/88 mmHg, HR 92 bpm, SpO2 88% on room air. Physical examination noted bilateral wheezes and decreased breath sounds. Assessment determined acute COPD exacerbation secondary to suspected respiratory infection. Initiated bronchodilator therapy and prescribed a short course of oral corticosteroids. Recommended follow-up with primary care for ongoing management and adjustment of COPD maintenance therapy.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('58a95c3c-9c68-4f7a-9ee8-75e9c329f617', '2026-02-11T23:23:33.594328', 'Follow-up Visit', 'Patient presented for follow-up regarding speech delay. Physical examination was unremarkable with vital signs stable: BP 100/65 mmHg, HR 78 bpm. Speech therapy progress was discussed, noting slight improvements in articulation and vocabulary usage. Continued speech therapy sessions recommended, with a reassessment in 6 months. Additionally, skin examination revealed no active eczema lesions; advised to continue current topical regimen as needed.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('58a95c3c-9c68-4f7a-9ee8-75e9c329f617', '2025-08-16T23:23:33.594328', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were within normal limits: BP 105/70 mmHg, HR 78 bpm, RR 18 breaths/min, Temp 98.6°F. The patient continues to exhibit speech delay, with observable improvement in articulation since the last visit. Eczema was noted to be well-managed with current treatment regimen. Recommended continuation with speech therapy sessions and advised maintaining current skincare routine. Follow-up in one year or as needed for any concerns.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('58a95c3c-9c68-4f7a-9ee8-75e9c329f617', '2025-06-02T23:23:33.594328', 'Follow-up Visit', 'Patient presented for follow-up evaluation of speech delay. Physical examination was unremarkable; vital signs within normal limits for age: BP 104/68 mmHg, HR 78 bpm, Temp 98.6°F. Speech and language assessments indicated mild improvement since last visit. Recommended continuation of speech therapy sessions twice a week and suggested routine follow-up in three months to monitor progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('65796ce5-b863-4511-924e-c8a63ae34d08', '2025-10-02T23:23:38.782564', 'Consultation', 'Patient presented for a general checkup. Vitals were within normal limits: BP 118/76 mmHg, HR 72 bpm. No acute distress noted, nasal mucosa mildly edematous, consistent with history of allergic rhinitis. Advised continuation of current antihistamine regimen and recommended saline nasal irrigation for symptomatic relief. Routine follow-up in one year unless symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('65796ce5-b863-4511-924e-c8a63ae34d08', '2025-07-11T23:23:38.782564', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were stable: BP 118/76 mmHg, HR 72 bpm, afebrile. No acute symptoms reported; ongoing management of allergic rhinitis with cetirizine as needed. Advised continuation of current management plan, recommended routine exercise, and balanced diet. Follow-up in one year unless symptoms arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('d6840a65-5f19-4378-b1f7-eeb3df38865d', '2025-09-28T23:23:41.854550', 'Annual Checkup', 'Patient presented for an annual checkup and reported symptoms consistent with a vaginal yeast infection, including itching and discharge. Vital signs noted: BP 138/85 mmHg, HR 76 bpm, and BMI 28.3 kg/m². GERD, hypertension, diabetes, hyperlipidemia, anemia, and tonsillitis were reviewed and generally well-managed under current treatment protocols. Recommended continuation of current medications, initiation of antifungal therapy for yeast infection, and maintenance of dietary adjustments to manage hyperlipidemia and diabetes. Follow-up in 6 months or sooner if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('d6840a65-5f19-4378-b1f7-eeb3df38865d', '2025-07-04T23:23:41.854550', 'Annual Checkup', 'Patient presented for annual checkup and reported symptoms of itching and discomfort consistent with a vaginal yeast infection. Vital signs were stable with BP 132/85 mmHg, HR 78 bpm. Physical examination was unremarkable aside from mild erythema in the vaginal area. Assessment included controlled hypertension and diabetes, with hyperlipidemia and anemia on appropriate treatment. Recommended antifungal therapy for yeast infection, and advised continuation of current medications for chronic conditions. Follow-up in 6 months to monitor chronic conditions and reassess if symptoms persist.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('d6840a65-5f19-4378-b1f7-eeb3df38865d', '2025-04-30T23:23:41.854550', 'Follow-up Visit', 'Patient presented for follow-up regarding vaginal yeast infection. Vital signs were stable: BP 138/85 mmHg, HR 78 bpm. Patient reported improvement of pruritus and discharge with current antifungal treatment. Continued current regimen and advised on maintaining glycemic control to prevent recurrence. Follow-up in two weeks to reassess symptoms and adjust treatment if necessary.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4d2e35fa-70f5-46e4-9f75-50589e9a9a81', '2026-01-29T23:23:48.406647', 'Urgent Care', 'Patient presented with complaints of increased fatigue and dizziness over the past week. Vital signs were notable for BP 110/70 mmHg, HR 88 bpm. Physical examination revealed pallor and conjunctival paleness. Assessment indicated exacerbation of anemia, likely due to suboptimal response to current treatment. Recommended adjustment of iron supplementation dose and advised follow-up with primary care for further evaluation and labs. Migraines were stable with current management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('4d2e35fa-70f5-46e4-9f75-50589e9a9a81', '2025-07-06T23:23:48.406647', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: BP 118/76 mmHg, HR 72 bpm. Physical examination revealed no acute distress; conjunctival pallor noted, consistent with known anemia. Hemoglobin levels to be rechecked; continue current iron supplementation. Patient reported occasional migraines, managed with sumatriptan as needed, with good effect. Encouraged maintaining hydration and regular follow-up for anemia management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ea19b4b2-e459-4461-b50a-ab587df7a85e', '2025-10-07T23:23:53.527457', 'Follow-up Visit', 'Patient presented for a routine follow-up visit. Vital signs were stable: BP 120/80 mmHg, HR 72 bpm, RR 16 breaths/min, and SpO2 98% on room air. Patient reported well-controlled asthma with no recent exacerbations and minimal seasonal allergy symptoms. Continued current asthma management plan with inhaled corticosteroids; advised to commence antihistamines during peak allergy season as needed. Recommended annual flu vaccination and follow-up in 6 months to reassess asthma control and overall health.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ea19b4b2-e459-4461-b50a-ab587df7a85e', '2025-07-28T23:23:53.527457', 'Follow-up Visit', 'Patient presented for a routine follow-up visit. Vitals were stable: BP 118/76 mmHg, HR 72 bpm, RR 16, Temp 98.6°F. The patient reported no exacerbations of asthma and minimal allergy symptoms controlled with OTC antihistamines. Assessment revealed well-managed asthma and seasonal allergies. Recommended continued use of current inhaler as needed and follow-up in six months unless symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('ea19b4b2-e459-4461-b50a-ab587df7a85e', '2025-07-08T23:23:53.527457', 'Consultation', 'Patient presented for a routine general checkup. Vital signs were within normal limits: BP 118/76 mmHg, HR 72 bpm, SpO2 98% on room air. No acute respiratory distress noted; lungs clear to auscultation bilaterally. Asthma was well-controlled with current inhaler regimen. Advised continuation of current asthma management plan and recommended follow-up in one year or as needed for exacerbations.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f0e35197-dd70-44c9-8fd6-eda5662baf20', '2025-10-05T23:23:58.749740', 'Follow-up Visit', 'Patient presented for follow-up of a contusion on the right forearm sustained 5 days ago. Physical examination revealed mild swelling and bruising with no signs of infection; range of motion was intact. Vitals were stable: HR 95 bpm, BP 100/65 mmHg. Assessment: Healing contusion. Recommended continued application of cold compresses and advised the caregiver to monitor for any worsening symptoms or signs of infection. Follow-up in two weeks or sooner if needed.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f0e35197-dd70-44c9-8fd6-eda5662baf20', '2025-06-01T23:23:58.749740', 'Urgent Care', 'Patient presented for evaluation of a contusion on the right shin sustained from a fall at home. Physical examination revealed a 5cm x 3cm area of ecchymosis with mild tenderness, but no signs of abrasion or laceration. Vitals: HR 98 bpm, RR 22 breaths/min, Temp 37.1°C. Assessment indicated a mild contusion with no complications. Recommended application of a cold compress, elevation of the affected limb, and acetaminophen for pain management as needed. Advised monitoring for any signs of increased swelling or changes in skin color and instructed guardians to follow up with the primary care physician if concerns persist.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f0e35197-dd70-44c9-8fd6-eda5662baf20', '2025-05-13T23:23:58.749740', 'Follow-up Visit', 'Patient presented for a follow-up evaluation of a contusion on the right knee. The area showed decreased swelling and bruising compared to the initial visit, with no signs of infection. Vitals were stable: HR 98, BP 90/58, RR 22, Temp 98.6°F. Assessment noted improvement in contusion healing. Advised continued application of ice as needed and monitored for any signs of worsening. Discussed management of allergic rhinitis and reviewed ADHD medication adherence with the caregiver.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f0e35197-dd70-44c9-8fd6-eda5662baf20', '2024-12-23T23:23:58.749740', 'Follow-up Visit', 'Patient presented for follow-up evaluation of a contusion sustained two weeks prior. On examination, the contusion located on the right forearm showed significant resolution with minimal residual bruising and no signs of infection. The patient remained active and displayed typical behavior for age, consistent with known ADHD. Recommended continued observation and application of cold compress as needed. Advised parents to monitor for any new symptoms and follow-up in two weeks if concerns persist.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('91864fbc-8f83-4645-b717-beb4b567278c', '2026-01-20T23:24:13.905233', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: BP 120/80 mmHg, HR 72 bpm, RR 16 breaths/min, Temp 98.6°F. Physical examination was unremarkable with no acute distress noted. Assessment: General health was good with no new concerns; past appendicitis resolved. Plan: Recommended continuation of a balanced diet and regular exercise; advised routine vaccinations and follow-up in one year unless new symptoms arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('91864fbc-8f83-4645-b717-beb4b567278c', '2025-08-31T23:24:13.905233', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: BP 120/80 mmHg, HR 72 bpm, RR 16 breaths/min, Temp 98.6°F. No acute complaints or new symptoms reported. Physical examination was unremarkable with all systems reviewed showing no abnormalities. Advised maintaining a balanced diet and regular exercise. Recommended routine blood work and follow-up in one year or as needed.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('9268348e-1b95-450b-bc02-d58efad8e733', '2025-11-26T23:24:19.229304', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding shingles. Physical exam revealed a healing vesicular rash on the right thoracic region, with no new lesions noted. Vital signs were stable: BP 118/76 mmHg, HR 72 bpm. Assessment confirmed improvement in rash and reduction in neuropathic pain. Recommended continuation of acyclovir for another week and advised on pain management with gabapentin as needed. Follow-up in two weeks to monitor resolution of symptoms and assess any postherpetic neuralgia.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('9268348e-1b95-450b-bc02-d58efad8e733', '2025-10-01T23:24:19.229304', 'Annual Checkup', 'Patient presented for an annual checkup and management of shingles. Vitals were within normal limits: BP 118/76 mmHg, HR 72 bpm. Patient reported a painful vesicular rash localized to the right thoracic region, consistent with herpes zoster, with mild postherpetic neuralgia. Recommended continuation of antiviral therapy and advised on pain management strategies. Additionally, discussed the importance of receiving the shingles vaccine in the future to reduce recurrence risk. Migraines remain stable with current medication regimen, no recent exacerbations reported. Follow-up scheduled in 6 months or as needed.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('9268348e-1b95-450b-bc02-d58efad8e733', '2025-06-14T23:24:19.229304', 'Annual Checkup', 'Patient presented for an annual checkup and management of shingles. Vitals were within normal limits: BP 118/76 mmHg, HR 72 bpm. The patient reported a vesicular rash along the right thoracic dermatome, consistent with Herpes Zoster, and mild neuralgia. Recommended continuation of antiviral therapy (valacyclovir 1g TID for 7 days) and advised on pain management with acetaminophen as needed. Follow-up in two weeks to assess resolution of shingles and review migraine management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('da07bd57-eead-482b-abbc-72385421fe90', '2026-02-21T23:24:28.241128', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs included BP 140/85 mmHg, HR 78 bpm, and BMI 28 kg/m². Physical examination was unremarkable except for joint stiffness noted in knees, consistent with osteoarthritis. Diabetes management reviewed; HbA1c was 7.2%. Recommended continuation of current medication regimen and advised dietary modifications for better glycemic control. Discussed importance of regular exercise to manage weight and alleviate arthritis symptoms. Follow-up in six months for diabetes monitoring.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('da07bd57-eead-482b-abbc-72385421fe90', '2025-08-07T23:24:28.241128', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals: BP 142/88 mmHg, HR 78 bpm, BMI 28.3. Physical examination revealed mild joint tenderness consistent with osteoarthritis. Blood glucose levels were slightly elevated; advised continuation of current diabetes management plan and dietary modifications. Lipid panel pending. Recommended regular physical activity to aid in hypertension and hyperlipidemia control. Referred to a dietitian for further nutritional guidance. Advised follow-up in 6 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('da07bd57-eead-482b-abbc-72385421fe90', '2025-06-25T23:24:28.241128', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding diabetes management. Vitals indicated blood pressure at 138/82 mmHg and heart rate at 76 bpm. Patient reported increased joint stiffness, particularly in the knees, attributed to osteoarthritis, but denied any new symptoms. Continued tight control of blood glucose levels was advised, with an adjustment in antihypertensive medication recommended to better manage blood pressure. Encouraged regular exercise and dietary adjustments to address hyperlipidemia and support overall health. Follow-up scheduled for three months with an emphasis on monitoring HbA1c levels.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('da07bd57-eead-482b-abbc-72385421fe90', '2025-03-24T23:24:28.241128', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 138/82 mmHg, heart rate 72 bpm, and BMI 29 kg/m². Blood glucose was 145 mg/dL, indicating suboptimal diabetes control. Assessment revealed well-managed hypertension and hyperlipidemia, though osteoarthritis symptoms persist in the knees. Recommended continuation of current antihypertensive and statin therapy, adjustment of diabetic management with a potential increase in metformin dosage, and advised physical therapy for osteoarthritis. Follow-up in 3 months to reassess diabetes management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('62ce7740-a2dd-43c6-8f76-81ea3e94cc23', '2026-02-13T23:24:39.095972', 'Urgent Care', 'Patient presented for evaluation of a red, crusted rash localized to the face, consistent with impetigo. Vital signs were stable: BP 100/60 mmHg, HR 88 bpm, Temp 98.6°F. Physical examination revealed honey-colored crusts and erythematous lesions around the nose and mouth. Assessment confirmed impetigo. Prescribed topical mupirocin ointment to be applied three times daily for 10 days and advised on maintaining good hygiene to prevent spread. Follow-up recommended if no improvement in symptoms within a week or if symptoms worsen. Allergic rhinitis was noted in the patient''s medical history, though no acute symptoms were present during this visit.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('62ce7740-a2dd-43c6-8f76-81ea3e94cc23', '2025-08-18T23:24:39.095972', 'Urgent Care', 'Patient presented for evaluation of a rash on the face. Physical examination revealed honey-colored crusted lesions around the nose and mouth, consistent with impetigo. No fever was noted; vital signs were stable with HR 88 bpm, BP 102/66 mmHg. Recommendation included initiating oral antibiotics and topical mupirocin, and advising on proper hygiene to prevent spread. Follow-up was advised if symptoms do not improve within 7 days or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('62ce7740-a2dd-43c6-8f76-81ea3e94cc23', '2025-04-24T23:24:39.095972', 'Follow-up Visit', 'Patient presented for follow-up of impetigo. Examination revealed crusted lesions on the face and arms with notable improvement since the last visit. No signs of secondary infection were observed. Vital signs were stable: BP 102/64 mmHg, HR 88 bpm. Continued topical mupirocin was recommended, and the patient was advised to maintain good hygiene and return if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('62ce7740-a2dd-43c6-8f76-81ea3e94cc23', '2025-02-26T23:24:39.095972', 'Annual Checkup', 'Patient presented for an annual checkup and evaluation of impetigo. Vital signs were stable with a BP of 100/60 mmHg, HR 90 bpm, and temperature 98.6°F. Physical examination revealed several honey-colored crusted lesions around the nose and mouth, consistent with impetigo. Advised continuation of topical mupirocin application and maintaining good hygiene. Also recommended a follow-up if no improvement in one week. Discussed ongoing management of allergic rhinitis, including regular use of antihistamines.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('fbb37da6-bfb7-41cb-abde-ad87d9987353', '2025-12-15T23:24:47.902598', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 142/88 mmHg, heart rate 78 bpm. Physical examination was unremarkable aside from elevated BMI indicating continued obesity. Assessment includes controlled hypertension but with concern for potential progression of prediabetes. Recommended continuation of antihypertensive therapy, lifestyle modifications for weight management, and follow-up fasting glucose testing in 6 months. Advised patient to maintain dietary changes and engage in regular physical activity to address hyperlipidemia and reduce cardiovascular risk.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('fbb37da6-bfb7-41cb-abde-ad87d9987353', '2025-09-15T23:24:47.902598', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding hypertension management. Blood pressure was elevated at 150/95 mmHg, and heart rate was 82 bpm. Physical examination was unremarkable. Assessment indicated suboptimal blood pressure control, likely exacerbated by ongoing obesity and dietary habits. Recommended adjustments to antihypertensive medication and emphasized the importance of dietary modifications and regular physical activity. Follow-up in 3 months for re-evaluation.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('90b2021b-a3da-4416-bab3-553f5053bcd1', '2026-02-08T23:24:51.383208', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding hypertension management. Blood pressure was 138/85 mmHg, and heart rate was 76 bpm. Patient reported occasional headaches but no other new symptoms. Assessment indicated controlled hypertension but elevated LDL cholesterol levels. Recommended continuation of current antihypertensive therapy, dietary modifications for hyperlipidemia, and follow-up lipid panel in 3 months. Advised monitoring blood pressure at home and lifestyle changes to address prediabetes.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('90b2021b-a3da-4416-bab3-553f5053bcd1', '2025-10-07T23:24:51.383208', 'Urgent Care', 'Patient presented for acute onset of severe headache and dizziness. Blood pressure was elevated at 165/98 mmHg, heart rate was 88 bpm, and respiratory rate was 18 breaths per minute. Assessment indicated poorly controlled hypertension likely contributing to symptoms. Recommended adjustment of antihypertensive medication, advised dietary modifications, and scheduled follow-up in two weeks to monitor blood pressure response.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('90b2021b-a3da-4416-bab3-553f5053bcd1', '2025-08-15T23:24:51.383208', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 138/86 mmHg, heart rate 76 bpm. Physical examination was unremarkable, with no acute distress noted. Recommended continuation of antihypertensive medication and lipid-lowering therapy, adherence to a low-sodium diet, and regular exercise. Advised follow-up in 6 months for hypertension management and to monitor prediabetes progression.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8d347e99-af44-45f9-924f-84057e2dfba5', '2025-11-15T23:24:57.327943', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were as follows: BP 138/86 mmHg, HR 78 bpm, BMI 31.2 kg/m². Physical examination revealed no acute distress, lungs clear to auscultation, and cardiac exam unremarkable. Diabetes management discussed; HbA1c was 7.2% at last measurement. Recommended continuation of current medication regimen with lifestyle modifications including diet and exercise. Follow-up on lipid panel and refer to ophthalmology for cataract evaluation.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8d347e99-af44-45f9-924f-84057e2dfba5', '2025-09-15T23:24:57.327943', 'Follow-up Visit', 'Patient presented for a follow-up visit to manage chronic conditions including diabetes and hypertension. Blood pressure was recorded at 138/82 mmHg, heart rate at 76 bpm, with BMI indicating obesity at 32 kg/m². Patient reported experiencing increased fatigue and occasional shortness of breath, but no acute changes in vision were noted. Assessment showed stable diabetes control with an HbA1c of 7.2%. Recommended continuation of current medications, including metformin and lisinopril, and advised on dietary modifications and regular physical activity to improve overall health outcomes. Follow-up scheduled in three months to reassess glycemic control and cardiovascular status.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8d347e99-af44-45f9-924f-84057e2dfba5', '2025-08-10T23:24:57.327943', 'Urgent Care', 'Patient presented for evaluation of acute dyspnea and chest tightness. Vital signs showed BP 150/90 mmHg, HR 92 bpm, RR 24 breaths/min, and SpO2 89% on room air. Physical examination revealed bilateral wheezing and prolonged expiratory phase. Assessment included acute exacerbation of asthma potentially complicated by underlying cardiovascular issues. Plan included administration of nebulized bronchodilators, supplemental oxygen, and a recommendation to follow up with primary care for further cardiac evaluation and management of chronic conditions.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8d347e99-af44-45f9-924f-84057e2dfba5', '2025-04-25T23:24:57.327943', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals: BP 140/85 mmHg, HR 78 bpm, BMI 32.5 kg/m². Physical examination revealed no acute distress; however, moderate adiposity was noted. Blood glucose levels remain elevated. Assessment: Type 2 diabetes mellitus with suboptimal glycemic control, hypertension, and hyperlipidemia. Plan: Adjusted medication to improve glycemic control, advised dietary modifications, increased physical activity, and scheduled follow-up in 3 months for further evaluation. Recommended an ophthalmology referral for cataract assessment.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('9055a20c-9284-49b7-ac62-9ba4fffb5a3f', '2025-12-19T23:25:06.537760', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding management of hypothyroidism. Vital signs were stable: BP 118/76 mmHg, HR 72 bpm. The patient reported mild fatigue and occasional anxiety symptoms. Thyroid function tests were pending; current medication regimen was reviewed and continued. Recommended lifestyle modifications to support energy levels and advised follow-up in 6 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('9055a20c-9284-49b7-ac62-9ba4fffb5a3f', '2025-10-24T23:25:06.537760', 'Follow-up Visit', 'Patient presented for follow-up regarding management of hypothyroidism. Vital signs were stable: BP 118/76 mmHg, HR 72 bpm. Patient reported feeling generally well, with no new symptoms of fatigue or mood changes. TSH levels from recent labs were within target range. Continued current dose of levothyroxine; advised to maintain regular follow-ups and monitor for any signs of anxiety exacerbation.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a6af647b-36f9-4648-9954-ec78ad07c957', '2025-10-20T23:25:10.635836', 'Annual Checkup', 'Patient presented for annual checkup with concurrent upper respiratory infection. Vitals: BP 122/78 mmHg, HR 76 bpm, RR 18 breaths/min, Temp 99.1°F. Physical examination revealed mild nasal congestion and a non-productive cough; lung auscultation showed clear breath sounds bilaterally. Assessment confirmed upper respiratory infection exacerbated by underlying asthma. Advised continuation of current asthma management plan, prescribed a short course of oral antihistamines for symptom relief, and recommended follow-up if symptoms persist or worsen. Depression remains stable on current pharmacotherapy; no adjustment needed.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a6af647b-36f9-4648-9954-ec78ad07c957', '2025-10-20T23:25:10.635836', 'Annual Checkup', 'Patient presented for an annual checkup and evaluation of an upper respiratory infection. Vital signs: BP 122/78 mmHg, HR 76 bpm, RR 18 breaths/min, Temp 99.1°F. Patient reported nasal congestion and a non-productive cough, with no wheezing noted upon auscultation; asthma well-controlled with current inhaler regimen. Depression stable on current SSRI therapy. Advised symptomatic treatment for URI with increased fluid intake and OTC decongestants, follow-up if symptoms worsen or persist beyond 10 days.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('a6af647b-36f9-4648-9954-ec78ad07c957', '2025-06-09T23:25:10.635836', 'Emergency Visit', 'Patient presented for an emergency visit with complaints of sore throat, congestion, and persistent cough over the past three days. Vital signs: BP 120/78 mmHg, HR 88 bpm, Temp 100.4°F, SpO2 95% on room air. Physical examination revealed nasal congestion, pharyngeal erythema, and diffuse wheezing on lung auscultation. Assessment: Upper respiratory infection exacerbating underlying asthma. Recommended continuation of asthma maintenance therapy, initiation of a short course of oral corticosteroids, and supportive care with increased fluid intake and rest. Follow-up advised if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('d411687e-4b18-4738-a4ce-927a794b02d5', '2025-12-26T23:25:20.886017', 'Urgent Care', 'Patient presented for evaluation of fatigue and dizziness persisting over the last week. Vital signs were recorded as BP: 100/60 mmHg, HR: 88 bpm. Physical examination revealed pallor and mild conjunctival pallor consistent with anemia. Assessment indicated potential worsening of anemia. Recommended continuation of current iron supplementation and advised follow-up with primary care for CBC monitoring to assess hemoglobin levels.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('0fbf96bb-27aa-4fbd-a733-1cbddc8eb5da', '2025-12-01T23:25:23.187868', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 142/88 mmHg, HR 78 bpm, weight 95 kg, height 162 cm. The patient reported occasional heartburn, consistent with known GERD, and ongoing knee pain attributed to osteoarthritis. Assessment indicated stable hypertension and no acute distress. Recommended continuation of current antihypertensive and GERD management, with additional advice on dietary modifications and increased physical activity to address obesity. Follow-up with ophthalmology suggested for cataract evaluation.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('0fbf96bb-27aa-4fbd-a733-1cbddc8eb5da', '2025-06-21T23:25:23.187868', 'Consultation', 'Patient presented for consultation regarding obesity management and worsening joint pain. Blood pressure was 145/90 mmHg, and heart rate was 82 bpm. Examination revealed bilateral knee tenderness consistent with osteoarthritis exacerbation. Recommended initiation of a structured weight loss program, adjustment of antihypertensive medication, and referral to physical therapy for joint support. Discussed dietary modifications to manage GERD symptoms. Follow-up in 3 months to evaluate progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('0fbf96bb-27aa-4fbd-a733-1cbddc8eb5da', '2025-03-19T23:25:23.187868', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals: BP 142/90 mmHg, HR 78 bpm, BMI 32 kg/m². Physical examination revealed mild crepitus in bilateral knees, consistent with osteoarthritis, and no current symptoms of GERD. Recommended continuation of antihypertensive medication and initiation of a weight management program. Advised routine ophthalmology follow-up for cataracts and discussed dietary modifications to manage GERD symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('75cfa18d-b954-408b-9767-ae21ae8e2258', '2025-11-19T23:25:29.889934', 'Follow-up Visit', 'Patient presented for follow-up regarding gallstones and management of chronic conditions. Vital signs were stable: BP 138/86 mmHg, HR 78 bpm. Patient reported intermittent right upper quadrant pain, no jaundice or fever. Continued conservative management of gallstones was advised. Recommendations included maintaining a low-fat diet and monitoring symptoms, with consideration for elective cholecystectomy if symptoms worsen. Hypertension and prediabetes were stable; advised regular monitoring and adherence to medication regimen. Referred to mental health services for ongoing management of moderate depression.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('75cfa18d-b954-408b-9767-ae21ae8e2258', '2025-10-07T23:25:29.889934', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals: BP 142/88 mmHg, HR 78 bpm, BMI 31.2 kg/m². Physical examination revealed mild epigastric tenderness, consistent with known gallstones; no acute distress noted. Assessment included stable hypertension and GERD, with well-managed depression and obesity. Recommendations included continued medication adherence for hypertension and GERD, dietary modifications to address gallstones and prediabetes, and a referral to gastroenterology for further evaluation of gallstones. Follow-up in 6 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('75cfa18d-b954-408b-9767-ae21ae8e2258', '2025-08-22T23:25:29.889934', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 148/92 mmHg, and heart rate was 78 bpm. Patient reported intermittent right upper quadrant pain, likely related to gallstones, and mild dyspepsia, potentially exacerbated by GERD. Recommended dietary modifications and discussed potential surgical consultation for gallstones. Encouraged adherence to antihypertensive regimen and continuation of current antidepressant therapy. Advised weight management strategies to address obesity and prediabetes. Follow-up in six months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b5d81c3d-dc11-47aa-8af6-b31d6849e3af', '2025-11-07T23:25:37.158037', 'Follow-up Visit', 'Patient presented for a follow-up visit for acute sinusitis. Vitals were stable: BP 118/76 mmHg, HR 72 bpm. The patient reported persistent nasal congestion and facial pressure but noted a slight improvement with current antibiotic therapy. Continued current treatment regimen and advised the use of saline nasal spray for symptomatic relief. Recommended follow-up in two weeks or sooner if symptoms worsen. Migraines and depression remain stable under current management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b5d81c3d-dc11-47aa-8af6-b31d6849e3af', '2025-09-11T23:25:37.158037', 'Annual Checkup', 'Patient presented for an annual checkup and was evaluated for acute sinusitis symptoms, including nasal congestion and facial pain. Vitals were stable: BP 118/76 mmHg, HR 72 bpm, Temp 98.4°F. Physical examination revealed tenderness over the maxillary sinuses. Continued management of migraines and moderate depression was discussed, with current medications reviewed. Recommended symptomatic treatment for sinusitis with nasal saline irrigation and advised the patient to follow up if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f756eeb7-27fc-48df-b932-ed3c92150525', '2025-11-19T23:25:42.278200', 'Urgent Care', 'Patient presented for evaluation of acute chest discomfort radiating to the left arm, which began approximately 2 hours prior. Blood pressure was 160/95 mmHg, heart rate 98 bpm, and respiratory rate 20 breaths per minute. Physical examination revealed mild wheezing bilaterally; ECG showed ST-segment elevation. Assessment indicated possible acute coronary syndrome. Recommended immediate transfer to emergency department for further evaluation and management, including cardiology consult and initiation of appropriate acute coronary syndrome protocol.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f756eeb7-27fc-48df-b932-ed3c92150525', '2025-06-06T23:25:42.278200', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were as follows: BP 138/85 mmHg, HR 76 bpm, RR 18 breaths/min, SpO2 98% on room air. The patient reported no new symptoms; asthma and allergic rhinitis were well-controlled with current medications. Lipid panel results from last month indicated LDL cholesterol levels remain elevated. Recommended continuation of current antihypertensive and asthma treatments, with a dietary consultation to address hyperlipidemia. Follow-up lipid panel in 3 months advised.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f756eeb7-27fc-48df-b932-ed3c92150525', '2025-03-21T23:25:42.278200', 'Consultation', 'Patient presented for routine consultation regarding management of hyperlipidemia. Blood pressure was 138/85 mmHg, heart rate was 76 bpm, and respiratory rate was 18 breaths per minute. Physical examination was unremarkable, with no acute distress noted. Assessment showed well-controlled hypertension and asthma, with current lipid levels needing review. Recommended continuation of atorvastatin and lifestyle modifications, including dietary adjustments and increased physical activity. Follow-up lipid panel was ordered to assess efficacy of current treatment regimen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('db918ff1-8ae7-4bf3-b280-cb8c02348d01', '2025-12-16T23:25:49.960261', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding management of seasonal allergies. Vital signs were stable: BP 118/76 mmHg, HR 72 bpm. Patient reported increased sneezing and nasal congestion over the past two weeks. Continued use of antihistamines was advised, and a nasal corticosteroid was prescribed to alleviate symptoms. Follow-up in three months for reassessment of allergy management and review of GERD and migraine status.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('db918ff1-8ae7-4bf3-b280-cb8c02348d01', '2025-08-14T23:25:49.960261', 'Emergency Visit', 'Patient presented for acute onset of shortness of breath and wheezing, suspected to be exacerbation of seasonal allergies. Vitals: BP 118/76 mmHg, HR 88 bpm, RR 22 breaths/min, SpO2 95% on room air. Examination revealed bilateral expiratory wheezes and nasal congestion. Administered albuterol nebulizer treatment with subsequent improvement in symptoms. Advised continuation of antihistamines and initiation of inhaled corticosteroid for control of allergic symptoms. Recommended follow-up with primary care provider in one week for reassessment.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('90c62ef0-a505-492d-bf3a-ad6871b0a7c8', '2026-02-02T23:25:53.746908', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were within normal limits: BP 110/70 mmHg, HR 75 bpm. Examination revealed moderate inflammatory acne primarily on the face and back. Recommended continuation of topical benzoyl peroxide and introduction of a topical retinoid. Advised on skincare routine and monitoring for potential irritation. Follow-up in 3 months or as needed if symptoms worsen. Allergic rhinitis was stable, with no current exacerbation reported.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('90c62ef0-a505-492d-bf3a-ad6871b0a7c8', '2025-09-06T23:25:53.746908', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were within normal limits: BP 110/70 mmHg, HR 72 bpm, afebrile. Noted mild to moderate comedonal and inflammatory acne on the face and upper back. Continued management with topical retinoids was recommended, and advised to maintain a gentle skincare routine. Discussed allergen avoidance strategies for allergic rhinitis, which is currently well-controlled. Follow-up in 6 months or as needed for worsening symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('82e9c112-98c8-44b7-aff9-19b827cb779f', '2025-11-21T23:25:57.331039', 'Urgent Care', 'Patient presented for acute onset of severe migraine, reporting photophobia and nausea. Blood pressure was 152/88 mmHg, heart rate was 78 bpm. Physical examination revealed no focal neurological deficits. Assessment: Migraine exacerbation likely triggered by medication non-compliance. Plan included administration of sumatriptan 50 mg, advising adherence to antihypertensive therapy, and scheduling follow-up with primary care physician for medication review and further management of migraine and hypertension.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('82e9c112-98c8-44b7-aff9-19b827cb779f', '2025-10-11T23:25:57.331039', 'Follow-up Visit', 'Patient presented for follow-up regarding chronic migraine management. Blood pressure was 142/88 mmHg and heart rate was 78 bpm. Patient reported experiencing 3-4 migraine episodes per month, with limited response to current sumatriptan regimen. Recommended adding a beta-blocker to help control both hypertension and migraine frequency, and advised weight management strategies to address obesity. Follow-up scheduled in 3 months to assess treatment efficacy.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('82e9c112-98c8-44b7-aff9-19b827cb779f', '2025-03-10T23:25:57.331039', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 142/88 mmHg, and heart rate was 78 bpm. She reported experiencing an increase in migraine frequency, approximately 3-4 episodes per month, often accompanied by nausea. GERD and hypertension remain under control with current medications. Recommended lifestyle modifications to address obesity, including a low-sodium diet and increased physical activity. Advised to follow up in 3 months to reassess migraine management and monitor hypertension.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('cd9e24da-62e1-4f51-b3b7-c051c869affd', '2025-11-27T23:26:02.860620', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were within normal limits: BP 100/60 mmHg, HR 88 bpm. The patient exhibited typical hyperactivity and impulsivity associated with ADHD but is currently managed with behavioral therapy. Recommended continuation of current ADHD management plan and advised monitoring for any exacerbation of allergic rhinitis symptoms, especially during pollen seasons. Follow-up in one year or as needed for any acute issues.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('cd9e24da-62e1-4f51-b3b7-c051c869affd', '2025-06-22T23:26:02.860620', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were stable: BP 100/60 mmHg, HR 88 bpm. The physical examination was unremarkable, with growth parameters within normal percentiles for age. Patient continues to manage ADHD with behavioral therapy; no medication changes were necessary at this time. Advised continuation of current management strategies for ADHD and recommended annual influenza vaccination due to history of allergic rhinitis. Follow-up in one year unless concerns arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('cd9e24da-62e1-4f51-b3b7-c051c869affd', '2025-03-18T23:26:02.860620', 'Urgent Care', 'Patient presented for evaluation of increased difficulty concentrating and hyperactivity over the past week, impacting school performance. Vital signs: BP 100/60 mmHg, HR 88 bpm, Temp 98.6°F. Physical examination was unremarkable, with no acute distress noted. Assessment indicated exacerbation of ADHD symptoms. Recommended adjusting current ADHD medication and following up with primary care provider in two weeks for reassessment.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c999e844-4c81-4444-9a05-1be6274bb984', '2025-10-29T23:26:08.806018', 'Follow-up Visit', 'Patient presented for follow-up of low back pain. He reported persistent discomfort but noted slight improvement with physical therapy. On examination, lumbar range of motion was mildly restricted with tenderness over the paraspinal muscles. Vital signs were stable: BP 120/80 mmHg, HR 76 bpm. Assessment: Chronic low back pain with gradual improvement. Plan: Continue current physical therapy regimen and NSAIDs as needed; advised on ergonomic adjustments at work and follow-up in 4 weeks.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c999e844-4c81-4444-9a05-1be6274bb984', '2025-10-23T23:26:08.806018', 'Annual Checkup', 'Patient presented for an annual checkup, reporting persistent low back pain for the past 3 months. Vital signs were within normal limits: BP 120/80 mmHg, HR 72 bpm. Physical examination revealed mild tenderness in the lumbar region with no neurological deficits. Assessment indicates mechanical low back pain; recommended continuation of NSAIDs as needed, initiation of physical therapy, and advised on ergonomic modifications at work. Follow-up in 6 weeks to reassess symptoms and response to treatment.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('7330fedb-5d54-466b-91d9-85de8cc5f1b0', '2025-11-11T23:26:12.494438', 'Follow-up Visit', 'Patient presented for follow-up evaluation of neck strain. Reported mild improvement in pain but continues to experience stiffness, particularly in the morning. Physical examination revealed tenderness upon palpation of the cervical paraspinal muscles, with no neurological deficits noted. Vitals were stable: BP 120/78 mmHg, HR 72 bpm. Recommended continuation of physical therapy and advised use of NSAIDs as needed for pain management. Follow-up in 4 weeks to assess progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('7330fedb-5d54-466b-91d9-85de8cc5f1b0', '2025-09-30T23:26:12.494438', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were stable: BP 120/80 mmHg, HR 72 bpm, Temp 98.6°F. The patient reported occasional neck pain, consistent with his history of neck strain, but denied any recent exacerbation of low back pain. Musculoskeletal examination revealed mild tenderness over the cervical paraspinal muscles with full range of motion. Recommended continuation of stretching exercises and advised ergonomic adjustments at work to prevent aggravation of neck strain. Follow-up in one year or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('7330fedb-5d54-466b-91d9-85de8cc5f1b0', '2025-07-04T23:26:12.494438', 'Follow-up Visit', 'Patient presented for follow-up of neck strain. Reports persistent stiffness and intermittent pain rated 5/10, exacerbated by prolonged sitting. Physical examination revealed decreased range of motion in the cervical spine with mild tenderness over the trapezius muscles. Blood pressure was 120/78 mmHg, heart rate 72 bpm. Recommended continuation of physical therapy and NSAIDs as needed, and advised ergonomic adjustments at work. Follow-up in 4 weeks or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e839eda2-5d1b-4af5-b67d-a4b70e74a128', '2025-12-20T23:26:18.432792', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding hypertension management. Blood pressure was recorded at 142/88 mmHg and heart rate was 78 bpm. Physical examination revealed no acute distress, but patient reported occasional headaches and mild fatigue. It was assessed that hypertension remains suboptimally controlled, likely due to non-adherence to lifestyle modifications. Recommended increasing physical activity, dietary adjustments to include more fruits and vegetables, and continuation of current antihypertensive medication. Plan to re-evaluate blood pressure control in 3 months.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e839eda2-5d1b-4af5-b67d-a4b70e74a128', '2025-10-08T23:26:18.432792', 'Urgent Care', 'Patient presented for evaluation of acute onset chest pain and shortness of breath. Blood pressure was 165/92 mmHg, heart rate 98 bpm, and BMI calculated at 32. Physical examination revealed mild wheezing and diaphoresis. Assessment included possible cardiac etiology versus anxiety or respiratory cause; ECG and troponin levels were ordered for further evaluation. Patient was advised to avoid exertion, and follow-up with cardiology was recommended.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e839eda2-5d1b-4af5-b67d-a4b70e74a128', '2025-02-15T23:26:18.432792', 'Urgent Care', 'Patient presented for evaluation of acute chest pain experienced over the past two hours. Blood pressure was elevated at 160/95 mmHg, heart rate at 88 bpm, and BMI calculated at 32.2 kg/m². Physical examination revealed no acute distress, and lung sounds were clear bilaterally; however, ECG indicated nonspecific ST changes. Assessment determined possible unstable angina; patient was advised to undergo further cardiac evaluation and was referred to the emergency department for immediate management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('9f4cbf73-df82-4906-ba68-f8a7c3d5f728', '2025-12-13T23:26:24.508132', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs: BP 128/82 mmHg, HR 76 bpm, BMI 32.1. Patient reported persistent cough and nasal congestion consistent with an upper respiratory infection; no fever or shortness of breath noted. Asthma well-controlled with current inhaler regimen; advised to continue current medications and increase fluid intake. Discussed management of depression and obesity; encouraged regular physical activity and referred to a nutritional counselor. Follow-up scheduled in three months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('9f4cbf73-df82-4906-ba68-f8a7c3d5f728', '2025-09-18T23:26:24.508132', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals: BP 130/85 mmHg, HR 78 bpm, SpO2 96% on room air. The patient reported persistent cough and nasal congestion consistent with an upper respiratory infection; no wheezing or shortness of breath observed. Asthma remains well-controlled; the patient is advised to continue current inhaler regimen. Recommendations made to monitor weight, follow a balanced diet, and engage in regular physical activity to address obesity. Advised to continue current treatment for moderate depression and referred to mental health services for ongoing support. Follow-up in one year or as needed for acute concerns.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b2d57a9e-1595-47d1-b785-8e1a4be25f49', '2025-11-11T23:26:28.658328', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were within normal limits: BP 110/70 mmHg, HR 82 bpm, height and weight in the 50th percentile for age. No acute distress noted. ADHD symptoms managed well on current medication with no reported side effects. Recommended continuation of current medication regimen, regular follow-up with behavioral therapy, and monitoring academic performance. Advised on maintaining a healthy lifestyle with regular physical activity and balanced nutrition.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b2d57a9e-1595-47d1-b785-8e1a4be25f49', '2025-08-20T23:26:28.658328', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were within normal limits: BP 110/70 mmHg, HR 78 bpm. The patient is currently managed for ADHD with medication and reported improved concentration at school, though occasional restlessness persists. Recommended continuation of current medication regimen and follow-up with behavioral therapy to address residual symptoms. Advised routine physical activity and balanced diet to support overall health.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('b2d57a9e-1595-47d1-b785-8e1a4be25f49', '2025-07-20T23:26:28.658328', 'Annual Checkup', 'Patient presented for annual checkup and ADHD management review. Vital signs were within normal limits: BP 110/70 mmHg, HR 85 bpm, temperature 98.6°F. No new symptoms reported; ADHD symptoms remain stable on current medication regimen. Recommended continuation of current treatment plan and follow-up in six months for reassessment.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('83139c2f-569e-4366-a2e5-8536e3e4d71c', '2025-11-14T23:26:36.563966', 'Follow-up Visit', 'Patient presented for a routine follow-up visit. Vital signs were within normal limits: BP 110/70 mmHg, HR 72 bpm. Eczema was well-controlled with current topical treatment, and no acute symptoms of allergic rhinitis were noted. Recommended continuation of current management plan and advised to follow up if any new symptoms arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f231f686-15ef-476f-9ea7-230bc1007396', '2025-10-18T23:26:38.100186', 'Follow-up Visit', 'Patient presented for follow-up of folliculitis. Blood pressure measured at 128/82 mmHg, heart rate 76 bpm. The patient reported mild improvement with current topical antibiotic treatment, but some erythematous papules persist on the forearms. Assessment indicated ongoing folliculitis with no signs of secondary infection. Recommended continuation of topical clindamycin and advised on proper skin hygiene. Follow-up in two weeks to reassess response to treatment. Asthma and hypertension remain well-controlled with current medications; GERD symptoms stable on proton pump inhibitor.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f231f686-15ef-476f-9ea7-230bc1007396', '2025-10-16T23:26:38.100186', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were within normal limits: BP 128/82 mmHg, HR 76 bpm, RR 16 bpm, Temp 98.6°F. Exam revealed mild erythematous papules consistent with folliculitis on the upper arms, with no signs of secondary infection. Asthma and hypertension were stable on current medication regimen. GERD symptoms were well-controlled. Recommended continuing current medications and advised on proper skin care and hygiene for folliculitis. Follow-up in 12 months or as needed for any acute concerns.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f231f686-15ef-476f-9ea7-230bc1007396', '2025-03-07T23:26:38.100186', 'Follow-up Visit', 'Patient presented for follow-up of folliculitis. Physical examination revealed erythematous papules on the scalp, with no signs of secondary infection. Blood pressure was 132/84 mmHg, heart rate 76 bpm. Asthma and GERD are stable on current treatment. Advised continuation of topical antibiotics and maintaining good scalp hygiene. Follow-up in 4 weeks to reassess condition.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('56987479-b1f2-4964-a882-d1c8c064b461', '2025-09-26T23:26:44.781551', 'Follow-up Visit', 'Patient presented for follow-up visit for viral gastroenteritis. Vital signs were stable: BP 90/60 mmHg, HR 98 bpm, temperature 98.6°F. The patient was alert and oriented, with mild abdominal discomfort and improved appetite. Assessment indicated ongoing recovery from viral gastroenteritis. Recommended maintaining hydration and a bland diet, with follow-up as needed for persistent symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('56987479-b1f2-4964-a882-d1c8c064b461', '2025-07-06T23:26:44.781551', 'Annual Checkup', 'Patient presented for an annual checkup. Noted symptoms of mild diarrhea and abdominal discomfort consistent with viral gastroenteritis; no dehydration observed. Vital signs showed age-appropriate BP: 92/60 mmHg, HR: 100 bpm, afebrile. History of allergic rhinitis was stable with no current exacerbation. Recommended maintaining hydration and rest, advised continuation of supportive care for viral symptoms, and follow-up if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('fac2de72-e5f7-4b98-9ac6-e3c8bd2809c7', '2026-01-01T23:26:49.160749', 'Consultation', 'Patient presented for routine consultation and follow-up on hyperlipidemia management. Blood pressure was noted at 138/86 mmHg, heart rate at 78 bpm. Patient reported increased joint pain due to osteoarthritis and occasional shortness of breath exacerbated by asthma. Recommended continuation of current lipid-lowering therapy, adjusted antihypertensive medication, and advised weight management strategies. Referred to physical therapy for osteoarthritis and scheduled follow-up in three months.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('fac2de72-e5f7-4b98-9ac6-e3c8bd2809c7', '2025-09-06T23:26:49.160749', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals: BP 138/85 mmHg, HR 78 bpm, BMI 31.2. Physical exam was unremarkable except for mild wheezing on lung auscultation. Assessment included controlled hypertension and hyperlipidemia, with stable asthma and GERD. Recommended continuation of current medications, an updated lipid panel, and referral to ophthalmology for cataract evaluation. Emphasized lifestyle modifications for weight management and glucose control. Follow-up scheduled in 6 months.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8cf733ef-3bd6-42b5-bbbb-13eb749a46b4', '2026-02-12T23:26:54.593339', 'Follow-up Visit', 'Patient presented for a follow-up visit concerning hyperlipidemia management. Blood pressure was 138/82 mmHg, and heart rate was 76 bpm. Patient reported mild dyspepsia, likely related to GERD, but no significant changes in weight. Lipid panel reviewed; LDL levels remain above target. Recommended continuation of atorvastatin and dietary modifications. Scheduled follow-up in 6 months to reassess lipid profile and monitor blood pressure control.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8cf733ef-3bd6-42b5-bbbb-13eb749a46b4', '2025-07-04T23:26:54.593339', 'Urgent Care', 'Patient presented for acute onset of chest discomfort and shortness of breath. Vital signs revealed BP 160/95 mmHg, HR 88 bpm, and oxygen saturation at 96% on room air. Physical examination showed mild epigastric tenderness without rebound or guarding. Assessment included atypical chest pain likely secondary to GERD exacerbation, with differential of cardiac etiology considered low. Recommended follow-up with primary care for further evaluation of cardiovascular risk factors and continuation of current GERD and hyperlipidemia management. Advised dietary modifications and weight management strategies to address obesity and prediabetes.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8cf733ef-3bd6-42b5-bbbb-13eb749a46b4', '2025-06-22T23:26:54.593339', 'Urgent Care', 'Patient presented for acute onset chest pain and shortness of breath. Vital signs: BP 150/92, HR 88 bpm, RR 20, SpO2 95% on room air. Physical exam revealed mild epigastric tenderness; ECG showed no acute changes. Assessment: Likely GERD exacerbation, but given cardiac risk factors, advised further evaluation with a cardiologist. Recommended continuation of statin for hyperlipidemia, and advised weight management and lifestyle modifications to address obesity and prediabetes.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('8cf733ef-3bd6-42b5-bbbb-13eb749a46b4', '2025-03-21T23:26:54.593339', 'Emergency Visit', 'Patient presented for acute chest pain lasting approximately 2 hours, radiating to the left arm. Vital signs upon arrival: BP 160/95 mmHg, HR 110 bpm, RR 22 breaths/min, SpO2 95% on room air. Physical examination revealed diaphoresis and mild dyspnea. ECG indicated ST-segment elevation in the anterior leads. Assessment was suggestive of an acute myocardial infarction. Patient was administered aspirin and nitroglycerin, and arrangements were made for immediate transfer to the cardiac catheterization lab for further intervention.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('631ebf09-3c72-4efa-a64e-9656a41536d8', '2025-10-07T23:27:03.190359', 'Urgent Care', 'Patient presented for dysuria and increased urinary frequency. Vital signs were stable: BP 118/76 mmHg, HR 72 bpm, afebrile. Urinalysis indicated the presence of leukocytes and nitrites, confirming a urinary tract infection. Recommended a course of trimethoprim-sulfamethoxazole for 7 days and advised increased fluid intake. Patient was instructed to follow up if symptoms persist or worsen. Past medical history of migraines, seasonal allergies, and asthma was noted, but no exacerbation was reported during this visit.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('631ebf09-3c72-4efa-a64e-9656a41536d8', '2025-06-23T23:27:03.190359', 'Annual Checkup', 'Patient presented for an annual checkup with an ongoing urinary tract infection. Vitals were stable: BP 120/78 mmHg, HR 72 bpm, afebrile. Patient reported dysuria and increased urinary frequency over the past week. Assessment confirmed UTI; recommended continuation of prescribed antibiotics and advised increased fluid intake. Reviewed management of migraines, seasonal allergies, and asthma; no changes necessary at this time. Follow-up in 2 weeks to reassess UTI symptoms and overall health status.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('631ebf09-3c72-4efa-a64e-9656a41536d8', '2025-04-28T23:27:03.190359', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding urinary tract infection. Vital signs were stable: BP 120/80 mmHg, HR 72 bpm, afebrile. Patient reported decreased dysuria but noted persistent mild urgency. Assessment indicated improvement, and current antibiotic regimen was continued. Advised increased fluid intake and follow-up if symptoms persist or worsen. Discussed management of chronic migraines and seasonal allergies, with no changes to current treatment plan.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('2ca48bc8-df86-41ee-a662-e1288e7f72c8', '2026-01-19T23:27:09.129889', 'Annual Checkup', 'Patient presented for an annual checkup. Noted a minor abrasion on the left knee, healing well without signs of infection. Vital signs were stable: HR 98 bpm, RR 20 breaths/min, BP not applicable due to age. History of allergic rhinitis and hay fever discussed, with no recent exacerbations reported. Recommended continuation of current allergy management plan and advised on proper wound care to prevent infection. Follow-up in one year unless earlier concerns arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('2ca48bc8-df86-41ee-a662-e1288e7f72c8', '2025-08-19T23:27:09.129889', 'Annual Checkup', 'Patient presented for an annual checkup. Notable findings included a superficial abrasion on the right forearm, healing well with no signs of infection. Vitals were within normal limits: BP 90/60 mmHg, HR 100 bpm. Given the patient''s history of allergic rhinitis and hay fever, advised continued use of antihistamines during high pollen seasons. Recommended keeping the abrasion clean and covered, and follow-up if any signs of infection occur.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('99fe4967-cace-4d1e-8067-b9aeb4c1421e', '2025-10-06T23:27:12.917831', 'Follow-up Visit', 'Patient presented for follow-up regarding management of hypothyroidism. Vital signs were stable: BP 128/82 mmHg, HR 74 bpm. Patient reported mild fatigue but no significant changes in weight or mood. Thyroid function tests were reviewed, showing TSH within target range. Continued current levothyroxine dosage was recommended, with re-evaluation in 6 months. Advised on regular eye check-ups due to history of cataracts and encouraged adherence to anxiety management strategies.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('99fe4967-cace-4d1e-8067-b9aeb4c1421e', '2025-06-28T23:27:12.917831', 'Urgent Care', 'Patient presented for increased fatigue and unexplained weight gain over the past few weeks. Vital signs: BP 132/84 mmHg, HR 78 bpm, Temp 98.6°F. Physical examination revealed mild facial puffiness and dry skin. Assessment suggests possible suboptimal management of hypothyroidism. Recommended thyroid function tests and advised adjustment of levothyroxine dosage based on results. Advised follow-up in 4-6 weeks to re-evaluate symptoms and lab findings.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('99fe4967-cace-4d1e-8067-b9aeb4c1421e', '2025-06-03T23:27:12.917831', 'Urgent Care', 'Patient presented for increased fatigue and palpitations. Physical examination revealed mild tachycardia with a heart rate of 98 bpm and an elevated blood pressure of 145/90 mmHg. Lab tests were ordered to assess thyroid function and electrolyte levels. Recommended follow-up with primary care physician to evaluate current levothyroxine dosage and manage symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('290047fa-6a83-473f-aa38-7e5309a9143d', '2025-11-07T23:27:19.267255', 'Follow-up Visit', 'Patient presented for follow-up of a minor laceration. Physical examination revealed the laceration on the right forearm was healing well with no signs of infection; sutures were intact. Asthma was stable with no recent exacerbations reported. Recommended continued wound care with daily dressing changes and follow-up in one week to reassess healing progress. Vitals: BP 104/68 mmHg, HR 88 bpm, respiratory rate 18 breaths per minute, SpO2 98% on room air.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('290047fa-6a83-473f-aa38-7e5309a9143d', '2025-08-27T23:27:19.267255', 'Urgent Care', 'Patient presented for evaluation of a minor laceration on the right forearm sustained while playing soccer. The laceration measured approximately 2 cm in length, with no signs of infection or foreign bodies present. Vitals were stable: BP 105/70 mmHg, HR 88 bpm, RR 18 breaths/min, SpO2 98% on room air. The wound was cleaned and dressed, and tetanus vaccination status was confirmed as up-to-date. Recommended monitoring for signs of infection and follow-up with primary care provider if needed. Patient''s asthma was stable with no recent exacerbations.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('290047fa-6a83-473f-aa38-7e5309a9143d', '2025-07-15T23:27:19.267255', 'Follow-up Visit', 'Patient presented for follow-up regarding a minor laceration on the left forearm. The laceration demonstrated proper healing with no signs of infection, such as erythema or purulent discharge. The patient reported no pain or discomfort, and range of motion remained intact. Vitals were stable: BP 104/68 mmHg, HR 88 bpm, RR 18 breaths/min. Continued wound care with daily dressing changes was advised, and the patient was reminded to avoid activities that might stress the healing area. Asthma was stable, with no recent exacerbations reported. Follow-up in two weeks if needed.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('290047fa-6a83-473f-aa38-7e5309a9143d', '2025-01-19T23:27:19.267255', 'Annual Checkup', 'Patient presented for an annual checkup and evaluation of a minor laceration. Vitals were stable: BP 100/65 mmHg, HR 85 bpm, RR 18 breaths/min, SpO2 98% on room air. The laceration on the right forearm was superficial, clean, and healing well without signs of infection. The patient has a history of asthma, currently well-controlled with no recent exacerbations. Recommended continued use of current asthma management plan, and advised on proper wound care.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f7fa4743-6d68-4d60-9fc1-2ba1805b2dee', '2025-11-25T23:27:27.528940', 'Follow-up Visit', 'Patient presented for follow-up of a minor laceration on the left forearm. Vitals were stable, with BP 118/72 mmHg and HR 76 bpm. The laceration showed signs of healing with minimal erythema and no signs of infection. Continued care with topical antibiotic ointment was advised, and patient was counseled on wound care. Anxiety was well-managed with current strategies; no acute exacerbations reported. Advised to monitor eczema flare-ups and follow up as needed.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f7fa4743-6d68-4d60-9fc1-2ba1805b2dee', '2025-07-27T23:27:27.528940', 'Follow-up Visit', 'Patient presented for follow-up of a minor laceration on the left forearm. Vitals were stable with BP 112/70 mmHg and HR 78 bpm. The laceration showed signs of healing with no signs of infection or inflammation, and sutures were intact. Recommended continued wound care and advised follow-up in one week. Discussed anxiety management strategies and noted improvement in eczema symptoms with current treatment.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('f7fa4743-6d68-4d60-9fc1-2ba1805b2dee', '2025-03-14T23:27:27.528940', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were stable: BP 112/68 mmHg, HR 72 bpm. On examination, a minor laceration on the left forearm was noted, clean and healing well. Patient reported ongoing anxiety, managed with cognitive behavioral therapy, and eczema under control with topical corticosteroids. Recommended continuation of current management plans and advised follow-up for laceration if signs of infection arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('be5471b9-7d16-4967-bbe7-4def02b13044', '2025-11-25T23:27:32.579382', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 138/82 mmHg, heart rate 78 bpm, and BMI indicated continued obesity. Patient reported intermittent right upper quadrant pain consistent with gallstones, managed with dietary modifications. History of hypertension and diabetes well-managed on current medications; blood glucose levels stable. GERD symptoms remain controlled with PPIs. Recommended maintaining current treatment regimen, emphasizing weight management, and considering surgical consultation for gallstones if symptoms persist or worsen. Follow-up in 6 months or as needed for symptom changes.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('be5471b9-7d16-4967-bbe7-4def02b13044', '2025-08-09T23:27:32.579382', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding gallstones and management of chronic conditions. Blood pressure was 138/82 mmHg, and heart rate was 78 bpm. Patient reported occasional right upper quadrant pain and dyspepsia, consistent with gallstone symptoms, but no acute exacerbations. Continued management of hypertension and diabetes was discussed, with emphasis on dietary modifications to address obesity. Recommended follow-up with gastroenterology to evaluate possible cholecystectomy, and advised continuation of current medications for GERD, anemia, and osteoarthritis.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('be5471b9-7d16-4967-bbe7-4def02b13044', '2025-06-28T23:27:32.579382', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 142/88 mmHg, heart rate 78 bpm, and BMI 32.1 kg/m². Patient reported occasional abdominal pain related to gallstones, with no acute exacerbations noted. Recommended continuation of current treatments for hypertension and anemia, and advised dietary modifications to manage gallstones and obesity. Follow-up scheduled for routine monitoring of diabetes and reassessment of gallstone symptoms.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('be5471b9-7d16-4967-bbe7-4def02b13044', '2025-04-19T23:27:32.579382', 'Consultation', 'Patient presented for consultation regarding gallstones. Vital signs noted: BP 138/86 mmHg, HR 78 bpm. Patient reported intermittent right upper quadrant abdominal pain, worsening after meals. Physical examination revealed mild tenderness in the right upper quadrant with no guarding or rebound tenderness. Assessment confirmed symptomatic cholelithiasis. Recommended elective laparoscopic cholecystectomy pending clearance from cardiology due to hypertension and diabetes management. Advised dietary modifications to reduce fat intake and scheduled follow-up in 1 month to review pre-operative clearance and test results.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6fa2a41b-da8c-4074-8f35-4241e79e457f', '2026-01-11T23:27:41.284365', 'Urgent Care', 'Patient presented for evaluation of acute-onset chest pain and shortness of breath. Blood pressure was 158/92 mmHg, heart rate 88 bpm, respiratory rate 22 breaths per minute, and oxygen saturation was 95% on room air. Physical examination revealed mild wheezing on auscultation. Assessment included likely exacerbation of asthma with possible cardiac component; recommended urgent ECG and chest X-ray, initiated nebulized bronchodilator therapy, and advised follow-up with primary care for further cardiac evaluation.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6fa2a41b-da8c-4074-8f35-4241e79e457f', '2025-07-17T23:27:41.284365', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs: BP 138/82 mmHg, HR 78 bpm. Physical examination revealed no acute distress, with stable osteoarthritic changes and controlled asthma symptoms. Assessment noted well-managed hypertension and hyperlipidemia, with stable prediabetes. Recommended continuation of current medication regimen and lifestyle modifications, including diet and exercise, to manage weight and blood pressure. Advised following up with ophthalmology for cataract monitoring.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6fa2a41b-da8c-4074-8f35-4241e79e457f', '2025-06-05T23:27:41.284365', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 142/88 mmHg, and heart rate was 78 bpm. Physical examination was unremarkable except for mild joint tenderness in the hands, consistent with osteoarthritis. Hypertension remains controlled with current medication regimen; advised continuation of lifestyle modifications and medication adherence. Recommended lipid panel and HbA1c testing to monitor hyperlipidemia and prediabetes, respectively. Advised follow-up with ophthalmology for cataract evaluation. No acute distress noted; patient advised to return in one year for routine evaluation unless symptoms arise.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6fa2a41b-da8c-4074-8f35-4241e79e457f', '2025-04-24T23:27:41.284365', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were recorded as BP 142/86 mmHg, HR 78 bpm, and BMI 28.3 kg/m². Patient reported occasional heartburn and joint stiffness but denied any new symptoms. Assessment included stable hypertension, managed osteoarthritis, and controlled asthma, with recommendations to continue current medications, initiate a low-sodium diet, and increase physical activity to address prediabetes risk. Follow-up lipid panel and A1C tests scheduled in 3 months.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('fe466a4c-2098-4f98-81ed-6c61a74c4630', '2025-10-17T23:27:52.650842', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding ongoing cancer treatment. Vital signs were stable: BP 138/82 mmHg, HR 76 bpm. Complained of increased fatigue and mild shortness of breath, likely exacerbated by underlying asthma. Continued current chemotherapy regimen with the addition of an inhaler for asthma symptom management. Advised routine blood pressure monitoring and scheduled follow-up in one month.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('fe466a4c-2098-4f98-81ed-6c61a74c4630', '2025-09-10T23:27:52.650842', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding ongoing cancer treatment. Vitals were stable: BP 130/78 mmHg, HR 72 bpm. Patient reported increased fatigue and occasional shortness of breath. Physical examination was unremarkable. Assessment indicated symptom management was necessary; recommended continuation of current chemotherapy regimen and advised further evaluation of fatigue in the oncology clinic. Follow-up in four weeks or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('fe466a4c-2098-4f98-81ed-6c61a74c4630', '2025-05-13T23:27:52.650842', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding ongoing cancer treatment. Vital signs were stable with BP at 138/82 mmHg and HR at 78 bpm. The patient reported mild fatigue but denied any new symptoms. Continued current oncology treatment plan with a recommendation to monitor blood pressure daily due to hypertension. Advised to return in 6 weeks for reassessment or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('fe466a4c-2098-4f98-81ed-6c61a74c4630', '2025-02-18T23:27:52.650842', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding her ongoing cancer treatment. Vital signs were stable: BP 130/82 mmHg, HR 76 bpm, respiratory rate 18 breaths per minute, and oxygen saturation 96% on room air. She reported mild fatigue and occasional shortness of breath, which she attributed to her asthma. Assessment revealed well-controlled hypertension and no progression of cataracts. Plan included continuation of current cancer treatment regimen, with a recommendation to monitor asthma symptoms closely and follow up in 3 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6f29cbc4-cd91-409b-911f-c46fd3f5e70b', '2025-10-26T23:28:00.637356', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding asthma management and osteoarthritis. Vital signs were stable: BP 130/85 mmHg, HR 72 bpm, SpO2 96% on room air. Patient reported increased wheezing and joint stiffness, particularly in the mornings. Assessment revealed inadequate asthma control, likely due to seasonal changes and suboptimal adherence to inhaler regimen. Recommended adjusting inhaler use and starting a low-dose oral corticosteroid for asthma exacerbation. Also advised continuation of NSAIDs for osteoarthritis and follow-up in 3 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6f29cbc4-cd91-409b-911f-c46fd3f5e70b', '2025-08-02T23:28:00.637356', 'Urgent Care', 'Patient presented for worsening shortness of breath and wheezing over the past 48 hours. Vital signs noted: BP 138/82 mmHg, HR 92 bpm, RR 22 breaths/min, SpO2 91% on room air. Lung auscultation revealed bilateral wheezing. Assessment indicated an acute exacerbation of asthma possibly triggered by recent allergen exposure. Recommended treatment included initiation of oral corticosteroids, increased use of short-acting beta-agonist inhaler, and follow-up with primary care for further management. Advised to monitor symptoms closely and seek immediate care if condition worsens.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6f29cbc4-cd91-409b-911f-c46fd3f5e70b', '2025-06-15T23:28:00.637356', 'Annual Checkup', 'Patient presented for an annual checkup. Blood pressure was 130/78 mmHg, heart rate 72 bpm, respiratory rate 18 breaths per minute, and oxygen saturation at 97% on room air. The patient reported occasional wheezing, particularly at night, and mild dyspnea on exertion. Assessment revealed stable asthma management with no acute exacerbations; GERD and allergic rhinitis were well-controlled, and osteoarthritis symptoms were managed with NSAIDs. Recommended continuing current asthma inhaler regimen, advised regular use of saline nasal spray for allergic rhinitis, and encouraged weight-bearing exercises to maintain joint function. Follow-up in 12 months or as needed for any acute concerns.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('bcaa1d7a-d888-4963-8539-a7b1b046d3ff', '2026-01-17T23:28:08.728135', 'Follow-up Visit', 'Patient presented for follow-up of gallstones. Vitals were stable with BP 130/85 mmHg and HR 72 bpm. No acute abdominal pain reported, but patient described occasional mild discomfort after meals. Assessment: Gallstones without current complications, managed conservatively. Plan: Continue low-fat diet and monitor symptoms; consider surgical consultation if pain worsens or complications arise. Discussed osteoarthritis management and advised continuation of current regimen for symptom control.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('bcaa1d7a-d888-4963-8539-a7b1b046d3ff', '2025-10-03T23:28:08.728135', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding gallstones. Blood pressure was 130/85 mmHg, heart rate was 78 bpm. Patient reported intermittent right upper quadrant abdominal pain, particularly after meals, and noted mild nausea but denied vomiting or jaundice. Assessment indicated stable gallstone condition without acute cholecystitis. Recommended continuation of a low-fat diet and scheduled an abdominal ultrasound to monitor gallstone progression. Advised patient to return if symptoms worsen or if new symptoms such as fever or jaundice develop. Osteoarthritis management continues with current medication regimen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('bcaa1d7a-d888-4963-8539-a7b1b046d3ff', '2025-07-01T23:28:08.728135', 'Emergency Visit', 'Patient presented for acute right upper quadrant abdominal pain and nausea, suspected to be due to gallstones. Vital signs were stable: BP 130/85 mmHg, HR 78 bpm, afebrile. Abdominal ultrasound confirmed multiple gallstones without signs of cholecystitis. Recommended follow-up with gastroenterology for potential elective cholecystectomy and advised a low-fat diet to manage symptoms. Pain managed with oral analgesics; patient was discharged in stable condition.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('bcaa1d7a-d888-4963-8539-a7b1b046d3ff', '2025-02-13T23:28:08.728135', 'Annual Checkup', 'Patient presented for annual checkup. Vital signs were stable: BP 130/85 mmHg, HR 72 bpm. The patient reported intermittent right upper quadrant pain, consistent with her known gallstone condition, and continued joint stiffness due to osteoarthritis. Recommended dietary modifications to manage gallstone symptoms and advised continuation of physical therapy exercises for osteoarthritis. Follow-up in six months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('bcaa1d7a-d888-4963-8539-a7b1b046d3ff', '2024-11-05T23:28:08.728135', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals noted: BP 128/82 mmHg, HR 72 bpm, Temp 98.6°F. She reported occasional right upper quadrant pain, consistent with known gallstones, but denied nausea or vomiting. Osteoarthritis management continues with acetaminophen as needed, and she was encouraged to maintain physical activity. Recommended follow-up imaging for gallstones if symptoms worsen and advised dietary modifications to reduce fat intake. Follow-up in one year unless symptoms change.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c6a382d5-0eab-4899-ae4c-f7a9708ed5d4', '2025-12-05T23:28:17.737115', 'Follow-up Visit', 'Patient presented for follow-up regarding a recurrent vaginal yeast infection. Vital signs were within normal limits: BP 120/80 mmHg, HR 72 bpm. Patient reported persistent itching and discharge despite completing a recent course of antifungal treatment. Assessment indicated possible resistant strain; recommended prescription of a different antifungal agent and advised on dietary modifications to support treatment efficacy. Follow-up in two weeks to reassess symptoms and response to treatment.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c6a382d5-0eab-4899-ae4c-f7a9708ed5d4', '2025-09-30T23:28:17.737115', 'Follow-up Visit', 'Patient presented for follow-up of a vaginal yeast infection. She reported improvement in symptoms after completing a 7-day course of antifungal medication, with no recurrence of pruritus or discharge noted. Vitals were stable with BP at 120/80 mmHg and HR at 72 bpm. Advised to maintain good hygiene practices and recommended weight management strategies given her medical history of obesity. Follow-up in 4 weeks or sooner if symptoms recur.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c6a382d5-0eab-4899-ae4c-f7a9708ed5d4', '2025-05-05T23:28:17.737115', 'Consultation', 'Patient presented for evaluation of vaginal yeast infection. Reported symptoms included itching, burning, and white discharge without odor. Vitals: BP 128/82 mmHg, HR 76 bpm. On examination, erythema and edema of the vulvar region were noted. Previous medical history includes obesity, tonsillitis, and migraines, currently stable. Assessment confirmed Candida infection. Recommended treatment with oral fluconazole and advised on maintaining proper hygiene and wearing breathable clothing. Follow-up in one week if symptoms persist.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c4047055-461c-4a7b-a905-8a0e06c66802', '2026-02-20T23:28:27.262838', 'Follow-up Visit', 'Patient presented for follow-up on pharyngitis. Vitals were stable with HR 88 bpm, BP 98/60 mmHg. Throat examination revealed mild erythema with no exudate; lymph nodes were non-tender. Symptoms have improved with current treatment; advised to continue hydration and complete the course of prescribed antibiotics. Follow-up in one week if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('c4047055-461c-4a7b-a905-8a0e06c66802', '2025-10-08T23:28:27.262838', 'Annual Checkup', 'Patient presented for an annual checkup and evaluation of pharyngitis. Vital signs were stable: BP 100/60 mmHg, HR 90 bpm, Temp 99.1°F. Throat examination revealed mild erythema without exudate. Assessment: Viral pharyngitis likely; no bacterial infection evident. Recommended supportive care with warm fluids and acetaminophen for fever. Advised follow-up if symptoms worsen or persist beyond one week.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('231cfdfb-28f0-4d86-8e7f-ec24c05b26ff', '2025-10-24T23:28:31.349831', 'Follow-up Visit', 'Patient presented for follow-up of tinea corporis. Examination revealed erythematous, scaly plaques on the trunk and groin, consistent with prior diagnosis. Blood pressure was 130/85 mmHg; heart rate was 78 bpm. The patient''s asthma and hypertension remain well-controlled on current medications. Recommended continuation of topical antifungal treatment for another 4 weeks and advised monitoring for any potential side effects. Follow-up in one month to reassess skin condition and overall health management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('231cfdfb-28f0-4d86-8e7f-ec24c05b26ff', '2025-10-01T23:28:31.349831', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were as follows: BP 145/88 mmHg, HR 78 bpm, RR 16/min, Temp 98.6°F. Dermatological examination revealed erythematous, scaly patches consistent with tinea on the left foot. Asthma and hyperlipidemia were well-controlled; however, hypertension remained suboptimally managed. Recommended continuation of current antifungal treatment for tinea, adjustment of antihypertensive therapy, and lipid panel re-evaluation. Advised dietary modifications and increased physical activity to aid in overall health management. Follow-up in three months for blood pressure evaluation and reassessment of lipid levels.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e3f44422-518c-488a-ba7b-c0c8ac816d72', '2026-01-27T23:28:35.966993', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding irritable bowel syndrome (IBS). Vitals were stable: BP 118/76 mmHg, HR 72 bpm. The patient reported intermittent abdominal pain and bloating, particularly postprandial. Recommended dietary modifications including increased fiber intake and avoidance of trigger foods. Advised continuation of current antispasmodic medication and scheduled a follow-up in three months to reassess symptoms and management efficacy.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e3f44422-518c-488a-ba7b-c0c8ac816d72', '2025-07-06T23:28:35.966993', 'Urgent Care', 'Patient presented for urgent care evaluation due to exacerbation of abdominal pain and diarrhea consistent with known IBS. Vital signs were stable: BP 118/72 mmHg, HR 76 bpm. Physical examination revealed mild abdominal tenderness in the lower quadrants without rebound or guarding. Symptoms managed with dietary modifications and a prescription for antispasmodic medication. Follow-up with primary care recommended for ongoing management.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('e3f44422-518c-488a-ba7b-c0c8ac816d72', '2025-03-27T23:28:35.966993', 'Consultation', 'Patient presented for consultation regarding management of irritable bowel syndrome (IBS). Vitals: BP 118/75 mmHg, HR 72 bpm. She reported experiencing intermittent abdominal pain and bloating, with increased frequency of diarrhea over the past two weeks. Assessment indicated exacerbation of IBS symptoms possibly due to dietary factors. Recommended dietary modifications including a low FODMAP diet and increased fiber intake, and advised follow-up in 4 weeks to assess symptom improvement.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('cfe36024-f1a8-4a8e-8176-418a9b5e7982', '2026-02-04T23:28:41.291703', 'Emergency Visit', 'Patient presented for evaluation of left lower extremity cellulitis. The affected area was erythematous, warm, and tender to palpation, with mild edema. Vitals: BP 138/85 mmHg, HR 82 bpm, Temp 100.4°F. Assessment confirmed cellulitis without signs of systemic involvement. Initiated oral antibiotics (Cephalexin 500 mg QID) and instructed on leg elevation and warm compresses. Advised follow-up with primary care for reassessment in 3-5 days and to return if symptoms worsen or fever persists.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('cfe36024-f1a8-4a8e-8176-418a9b5e7982', '2025-07-13T23:28:41.291703', 'Annual Checkup', 'Patient presented for annual checkup and follow-up on cellulitis. Vital signs were stable: BP 128/82 mmHg, HR 78 bpm, Temp 98.6°F. The cellulitis on the lower left leg showed mild erythema with no signs of abscess formation or systemic involvement. Continued current antibiotic regimen was advised, and patient was counseled on leg elevation and proper skin hygiene. Asthma and hyperlipidemia were stable; recommended adherence to prescribed medications and lifestyle modifications for prediabetes. Follow-up in 4 weeks to reassess cellulitis and management of chronic conditions.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('cfe36024-f1a8-4a8e-8176-418a9b5e7982', '2025-04-22T23:28:41.291703', 'Urgent Care', 'Patient presented for evaluation of worsening left lower extremity cellulitis. Physical examination revealed erythema, warmth, and tenderness over the affected area, extending from the ankle to mid-calf. Vital signs were significant for blood pressure of 138/86 mmHg and heart rate of 84 bpm. Assessment confirmed cellulitis without systemic involvement. Plan included initiating oral antibiotics and advising leg elevation and local wound care. Follow-up recommended in 48-72 hours or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('05486da0-3436-4b14-a198-7d489c3e3d25', '2026-01-31T23:28:47.740500', 'Emergency Visit', 'Patient presented for acute abdominal pain, suspected to be related to gallstones. Vital signs were stable, with blood pressure at 140/85 mmHg and heart rate at 88 bpm. Physical examination revealed tenderness in the right upper quadrant. Recommended ultrasound of the abdomen for further evaluation and advised on pain management. Discussed potential for surgical intervention if symptoms persist or worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('05486da0-3436-4b14-a198-7d489c3e3d25', '2025-08-09T23:28:47.740500', 'Urgent Care', 'Patient presented for acute right upper quadrant abdominal pain and nausea, exacerbated over the past 24 hours. Vital signs revealed BP 145/85 mmHg, HR 86 bpm, afebrile. Physical examination was notable for tenderness in the right upper quadrant with a positive Murphy''s sign. Assessment indicated a likely acute cholecystitis secondary to gallstones. Recommended imaging studies, initiated pain management, and discussed potential surgical intervention pending further evaluation. Advised dietary modifications and follow-up with primary care for comprehensive management of underlying conditions.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('05486da0-3436-4b14-a198-7d489c3e3d25', '2025-04-29T23:28:47.740500', 'Consultation', 'Patient presented for consultation regarding gallstones. Vital signs were stable: BP 138/82 mmHg, HR 78 bpm. Patient reported episodic right upper quadrant pain and bloating, consistent with cholecystitis symptoms. Recommended dietary modifications to reduce fat intake and scheduled an ultrasound for further evaluation. Additionally, discussed the management of her chronic conditions, emphasizing the importance of maintaining glycemic control and lipid levels. Follow-up appointment scheduled in one month to reassess symptoms and review imaging results.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('05486da0-3436-4b14-a198-7d489c3e3d25', '2024-10-25T23:28:47.740500', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were notable for blood pressure at 140/85 mmHg and heart rate of 78 bpm. Physical examination revealed mild epigastric tenderness, consistent with her history of gallstones, and no acute distress. Assessment indicated stable management of chronic conditions; however, blood glucose levels were noted to be slightly elevated, necessitating further monitoring. It was recommended to continue current medications, maintain diet and exercise regimen, and follow up in 6 months or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6489a18e-bceb-4aca-8483-0d01b9c1e479', '2025-11-04T23:28:55.935641', 'Follow-up Visit', 'Patient presented for follow-up on a stage II pressure ulcer on the sacral region. Blood pressure was 142/88 mmHg, heart rate 78 bpm, respiratory rate 16 breaths/min, and SpO2 at 95% on room air. The ulcer showed minimal improvement with surrounding erythema; no signs of infection noted. Continued wound care with daily dressing changes and advised repositioning every 2 hours. Reviewed management of chronic conditions, including hypertension and asthma, and reinforced compliance with antihypertensive and inhaler medications. Recommended dietary consultation to address obesity and hyperlipidemia. Follow-up in two weeks for wound reassessment.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6489a18e-bceb-4aca-8483-0d01b9c1e479', '2025-10-01T23:28:55.935641', 'Annual Checkup', 'Patient presented for an annual checkup with complaints of a pressure ulcer on the sacral region. Vital signs were stable: BP 138/85 mmHg, HR 78 bpm, RR 18 breaths/min, Temp 98.6°F. Examination revealed a Stage II pressure ulcer with surrounding erythema and no signs of infection. Assessment included management of the ulcer with regular repositioning, wound care, and referral to a wound care specialist. Recommendations included continued management of hypertension, hyperlipidemia, and GERD, with routine follow-up for asthma control and cancer surveillance. Advised weight management and dietary modification to address obesity.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('6489a18e-bceb-4aca-8483-0d01b9c1e479', '2025-08-03T23:28:55.935641', 'Annual Checkup', 'Patient presented for an annual checkup with primary concern of a pressure ulcer on the sacral region. Blood pressure was 140/85 mmHg, heart rate 78 bpm, and BMI calculated at 32.2, indicating obesity. The ulcer measured approximately 3 cm in diameter, with erythematous borders and purulent discharge, consistent with Stage 3 pressure injury. Managed hypertension remains stable; however, obesity and hyperlipidemia require continued dietary modifications and lipid-lowering therapy. GERD and asthma symptoms well-controlled with current medication regimen. Recommended wound care consultation for ulcer management and follow-up in four weeks to reassess healing progress.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('537faa50-37a0-4187-8a2d-b90b3988f58c', '2025-10-15T23:29:05.970958', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were within normal limits: BP 110/70 mmHg, HR 72 bpm. Examination revealed mild erythematous patches consistent with ongoing contact dermatitis; patient reported occasional pruritus. Advised continuation of topical corticosteroids as needed and avoidance of known irritants. Discussed menstrual irregularities; recommended monitoring cycle regularity and follow-up if symptoms persist. Anxiety appears well-controlled with current management. Recommended routine follow-up in one year, or sooner if symptoms change.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('537faa50-37a0-4187-8a2d-b90b3988f58c', '2025-09-20T23:29:05.970958', 'Follow-up Visit', 'Patient presented for a follow-up evaluation of contact dermatitis and management of anxiety. Vitals stable: BP 110/70, HR 78. Skin examination revealed mild erythema and dryness on the forearms, with improvement noted since the last visit. Recommended continuation of topical corticosteroid and advised on avoidance of known irritants. Discussed strategies for anxiety management, including potential referral to a counselor. Patient reported ongoing menstrual irregularities; recommended monitoring and possible gynecological consultation if symptoms persist.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('922601a1-2b99-4ff1-af60-b1eb175fd54d', '2026-01-03T23:29:10.885417', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding cancer management. Vital signs were stable: BP 128/82 mmHg, HR 76 bpm. The patient reported experiencing mild fatigue and joint pain, likely exacerbated by osteoarthritis. No new symptoms were noted. Recommended continuation of current oncology treatment regimen and advised maintaining a low-fat diet to manage hyperlipidemia. Follow-up scheduled in three months unless symptoms change.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('922601a1-2b99-4ff1-af60-b1eb175fd54d', '2025-07-06T23:29:10.885417', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs: BP 138/82 mmHg, HR 78 bpm. Patient reported stable management of cancer with ongoing treatment; no new symptoms were noted. Chronic osteoarthritis symptoms persisted with occasional joint stiffness, managed with NSAIDs. Recommended continuation of current cancer treatment regimen, lipid-lowering therapy, and follow-up with ophthalmology for cataracts. Advised lifestyle modifications to support joint health and cardiovascular risk reduction.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('642b3163-4236-46d8-965c-b3dab6d34b22', '2025-12-31T23:29:14.265488', 'Follow-up Visit', 'Patient presented for a follow-up visit regarding gallstones. Vital signs were stable with BP at 128/82 mmHg and HR at 76 bpm. The patient reported intermittent right upper quadrant pain and occasional nausea, but no jaundice or fever. Assessment confirmed the presence of symptomatic cholelithiasis. Recommended continued dietary modifications and scheduled a surgical consultation for potential cholecystectomy. Advised to maintain asthma management and to follow up in one month or sooner if symptoms worsen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('642b3163-4236-46d8-965c-b3dab6d34b22', '2025-07-14T23:29:14.265488', 'Annual Checkup', 'Patient presented for an annual checkup. Vitals were as follows: BP 130/85 mmHg, HR 78 bpm, BMI 31.2 kg/m². Patient reported intermittent upper abdominal pain consistent with gallstone symptoms but denied any recent episodes of jaundice or fever. Physical examination was unremarkable with no abdominal tenderness. Recommended continued weight management and dietary modifications to address obesity and mitigate gallstone symptoms. Follow-up ultrasound advised if symptoms persist or worsen. Asthma and seasonal allergies remain well-controlled with current medication regimen.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('938baff1-706d-4469-a851-83860017a9d0', '2026-01-16T23:29:17.952120', 'Emergency Visit', 'Patient presented for acute exacerbation of depression with increased anxiety and persistent insomnia over the past two weeks. Vitals were stable: BP 118/76 mmHg, HR 72 bpm. Physical examination was unremarkable. Assessment indicated worsening of moderate depression, likely due to increased psychosocial stressors. Recommended adjustment of current antidepressant therapy and follow-up with mental health services for further evaluation and support.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('938baff1-706d-4469-a851-83860017a9d0', '2025-10-08T23:29:17.952120', 'Annual Checkup', 'Patient presented for an annual checkup. Vital signs were within normal limits: BP 118/76 mmHg, HR 72 bpm. Patient reported improved mood and energy levels with current antidepressant regimen, but occasional nasal congestion was noted, consistent with history of allergic rhinitis. Advised continuation of current antidepressant therapy and recommended regular use of intranasal corticosteroids during peak allergy seasons. Follow-up in 12 months or sooner if symptoms exacerbate.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('d39bad96-fb33-41d5-b6b5-10fb51b8111a', '2026-02-21T23:29:22.252857', 'Annual Checkup', 'Patient presented for an annual checkup and evaluation of a jammed finger. Vital signs: BP 118/76 mmHg, HR 72 bpm, Temp 98.1°F. Examination revealed mild swelling and tenderness in the proximal interphalangeal joint of the right index finger with limited range of motion, consistent with a minor soft tissue injury; no fracture was suspected. Recommended rest, intermittent ice application, and NSAIDs for pain management. Social anxiety remains well-managed; patient reported no significant changes in symptoms. Follow-up in one year or as needed for finger reassessment.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('d39bad96-fb33-41d5-b6b5-10fb51b8111a', '2025-08-23T23:29:22.252857', 'Emergency Visit', 'Patient presented for evaluation of a jammed finger sustained during a basketball game. Physical examination revealed swelling and tenderness at the proximal interphalangeal joint of the right middle finger, with limited range of motion but intact neurovascular status. X-ray ruled out fracture, confirming soft tissue injury. Recommended RICE protocol (rest, ice, compression, elevation), NSAIDs for pain management, and follow-up with primary care if symptoms persist or worsen. BP: 118/76, HR: 72 bpm. Discussed potential need for occupational therapy if function does not improve. Managed social anxiety with reassurance throughout the visit.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('0ef23031-9f45-4283-9f9c-49d1e9d1a61c', '2025-12-01T23:29:26.967817', 'Annual Checkup', 'Patient presented for an annual checkup with concurrent symptoms of acute sinusitis. Vitals were within normal limits: BP 118/76 mmHg, HR 72 bpm. She reported nasal congestion, facial pain, and pressure consistent with her history of sinus issues, exacerbated by seasonal hay fever. Recommended continuing saline nasal irrigation and initiated a 10-day course of amoxicillin. Advised follow-up if symptoms persist beyond treatment or worsen. Regular migraine management plan remains unchanged, with instructions to monitor triggers and maintain hydration.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('0ef23031-9f45-4283-9f9c-49d1e9d1a61c', '2025-06-12T23:29:26.967817', 'Annual Checkup', 'Patient presented for an annual checkup and reported ongoing nasal congestion and facial pressure consistent with acute sinusitis, persisting for the past week. Vital signs were stable: BP 118/76 mmHg, HR 72 bpm. Physical examination revealed tenderness over the frontal and maxillary sinuses. Recommended continuation of saline nasal irrigation and initiation of a 10-day course of amoxicillin. Advised follow-up if symptoms do not improve or worsen, and discussed management strategies for chronic hay fever and migraines.', NULL);
INSERT INTO patient_visits (patient_id, visit_date, visit_type, clinical_notes, provider_id)
VALUES ('0ef23031-9f45-4283-9f9c-49d1e9d1a61c', '2025-04-01T23:29:26.967817', 'Emergency Visit', 'Patient presented for emergency evaluation of severe headache and facial pain. Physical examination revealed tenderness over the maxillary sinuses and nasal congestion. Blood pressure was 118/76 mmHg, heart rate 82 bpm. Assessment confirmed acute sinusitis likely exacerbated by underlying hay fever. Recommended initiation of amoxicillin for 10 days, intranasal corticosteroids, and advised continuation of antihistamines for allergy management. Follow-up visit scheduled in one week to assess symptom resolution.', NULL);